def validate_float_in_range(cls, value, min_inclusive, max_inclusive):
    cls.validate_float(value)
    if value < min_inclusive or value > max_inclusive:
        raise ValueError(
            "value must be in range %s to %s inclusive, got %s"
            % (min_inclusive, max_inclusive, value)
        )

def subset_glyphs(self, s):
    self.metrics = _dict_subset(self.metrics, s.glyphs)
    for g in s.glyphs_emptied:
        self.metrics[g] = (0, 0)
    return True  # Required table

def _join(self, path):
    if isinstance(path, str):
        if not self.path:
            return path
        if not path:
            return self.path
        return self.fs.sep.join((self.path, self._strip_protocol(path)))
    if isinstance(path, dict):
        return {self._join(_path): value for _path, value in path.items()}
    return [self._join(_path) for _path in path]

def _get_flint(sympy_ground_types):
    if sympy_ground_types not in ('auto', 'flint'):
        return None

    try:
        import flint
        # Earlier versions of python-flint may not have __version__.
        from flint import __version__ as _flint_version
    except ImportError:
        if sympy_ground_types == 'flint':
            warn("SYMPY_GROUND_TYPES was set to flint but python-flint is not "
                 "installed. Falling back to other ground types.")
        return None

    if _flint_version_okay(_flint_version):
        return flint
    elif sympy_ground_types == 'auto':
        return None
    else:
        warn(f"Using python-flint {_flint_version} because SYMPY_GROUND_TYPES "
             f"is set to flint but this version of SymPy is only tested "
             f"with python-flint versions {_PYTHON_FLINT_VERSION_NEEDED}.")
        return flint

def subset(self, glyphs, remap=False, useClass0=True):
    """Returns ascending list of remaining classes."""
    self.classDefs = {g: v for g, v in self.classDefs.items() if g in glyphs}
    # Note: while class 0 has the special meaning of "not matched",
    # if no glyph will ever /not match/, we can optimize class 0 out too.
    # Only do this if allowed.
    indices = _uniq_sort(
        (
            [0]
            if ((not useClass0) or any(g not in self.classDefs for g in glyphs))
            else []
        )
        + list(self.classDefs.values())
    )
    if remap:
        self.remap(indices)
    return indices

def getctype(var):
    """
    Determines C type
    """
    ctype = 'void'
    if isfunction(var):
        if 'result' in var:
            a = var['result']
        else:
            a = var['name']
        if a in var['vars']:
            return getctype(var['vars'][a])
        else:
            errmess(f'getctype: function {a} has no return value?!\n')
    elif issubroutine(var):
        return ctype
    elif ischaracter_or_characterarray(var):
        return 'character'
    elif isstring_or_stringarray(var):
        return 'string'
    elif 'typespec' in var and var['typespec'].lower() in f2cmap_all:
        typespec = var['typespec'].lower()
        f2cmap = f2cmap_all[typespec]
        ctype = f2cmap['']  # default type
        if 'kindselector' in var:
            if '*' in var['kindselector']:
                try:
                    ctype = f2cmap[var['kindselector']['*']]
                except KeyError:
                    errmess('getctype: "%s %s %s" not supported.\n' %
                            (var['typespec'], '*', var['kindselector']['*']))
            elif 'kind' in var['kindselector']:
                if typespec + 'kind' in f2cmap_all:
                    f2cmap = f2cmap_all[typespec + 'kind']
                try:
                    ctype = f2cmap[var['kindselector']['kind']]
                except KeyError:
                    if typespec in f2cmap_all:
                        f2cmap = f2cmap_all[typespec]
                    try:
                        ctype = f2cmap[str(var['kindselector']['kind'])]
                    except KeyError:
                        errmess('getctype: "%s(kind=%s)" is mapped to C "%s" (to override define dict(%s = dict(%s="<C typespec>")) in %s/.f2py_f2cmap file).\n'
                                % (typespec, var['kindselector']['kind'], ctype,
                                   typespec, var['kindselector']['kind'], os.getcwd()))
    elif not isexternal(var):
        errmess(f'getctype: No C-type found in "{var}", assuming void.\n')
    return ctype

def _get_groups(
    self, data: DataFrame
) -> tuple[str | list[str], Index | MultiIndex]:
    """Return index with Cartesian product of ordered grouping variable levels."""
    levels = {}
    for var, order in self.order.items():
        if var in data:
            if order is None:
                order = categorical_order(data[var])
            levels[var] = order

    grouper: str | list[str]
    groups: Index | MultiIndex
    if not levels:
        grouper = []
        groups = pd.Index([])
    elif len(levels) > 1:
        grouper = list(levels)
        groups = pd.MultiIndex.from_product(levels.values(), names=grouper)
    else:
        grouper, = list(levels)
        groups = pd.Index(levels[grouper], name=grouper)
    return grouper, groups

def parse_filter(
    self, node: t.Optional[nodes.Expr], start_inline: bool = False
) -> t.Optional[nodes.Expr]:
    while self.stream.current.type == "pipe" or start_inline:
        if not start_inline:
            next(self.stream)
        token = self.stream.expect("name")
        name = token.value
        while self.stream.current.type == "dot":
            next(self.stream)
            name += "." + self.stream.expect("name").value
        if self.stream.current.type == "lparen":
            args, kwargs, dyn_args, dyn_kwargs = self.parse_call_args()
        else:
            args = []
            kwargs = []
            dyn_args = dyn_kwargs = None
        node = nodes.Filter(
            node, name, args, kwargs, dyn_args, dyn_kwargs, lineno=token.lineno
        )
        start_inline = False
    return node

def get_not_required(
    self, packages: "_ProcessedDists", options: Values
) -> "_ProcessedDists":
    dep_keys = {
        canonicalize_name(dep.name)
        for dist in packages
        for dep in (dist.iter_dependencies() or ())
    }

    # Create a set to remove duplicate packages, and cast it to a list
    # to keep the return type consistent with get_outdated and
    # get_uptodate
    return list({pkg for pkg in packages if pkg.canonical_name not in dep_keys})

def __init__(self, expr: Union[ParserElement, str]):
    super().__init__(expr)
    self.callPreparse = False

def text_show_operations(
    ops: Iterator[Tuple[List[Any], bytes]],
    fonts: Dict[str, Font],
    strip_rotated: bool = True,
    debug_path: Optional[Path] = None,
) -> List[BTGroup]:
    """
    Extract text from BT/ET operator pairs.

    Args:
        ops (Iterator[Tuple[List, bytes]]): iterator of operators in content stream
        fonts (Dict[str, Font]): font dictionary
        strip_rotated: Removes text if rotated w.r.t. to the page. Defaults to True.
        debug_path (Path, optional): Path to a directory for saving debug output.

    Returns:
        List[BTGroup]: list of dicts of text rendered by each BT operator

    """
    state_mgr = TextStateManager()  # transformation stack manager
    bt_groups: List[BTGroup] = []  # BT operator dict
    tj_ops: List[TextStateParams] = []  # Tj/TJ operator data
    for operands, op in ops:
        if op in (b"BT", b"q"):
            bts, tjs = recurs_to_target_op(
                ops, state_mgr, b"ET" if op == b"BT" else b"Q", fonts, strip_rotated
            )
            bt_groups.extend(bts)
            tj_ops.extend(tjs)
        elif op == b"Tf":
            state_mgr.set_font(fonts[operands[0]], operands[1])
        else:  # set Tc, Tw, Tz, TL, and Ts if required. ignores all other ops
            state_mgr.set_state_param(op, operands)

    if any(tj.rotated for tj in tj_ops):
        if strip_rotated:
            logger_warning(
                "Rotated text discovered. Output will be incomplete.", __name__
            )
        else:
            logger_warning(
                "Rotated text discovered. Layout will be degraded.", __name__
            )
    if not all(tj.font.interpretable for tj in tj_ops):
        logger_warning(
            "PDF contains an uninterpretable font. Output will be incomplete.", __name__
        )

    # left align the data, i.e. decrement all tx values by min(tx)
    min_x = min((x["tx"] for x in bt_groups), default=0.0)
    bt_groups = [
        dict(ogrp, tx=ogrp["tx"] - min_x, displaced_tx=ogrp["displaced_tx"] - min_x)  # type: ignore[misc]
        for ogrp in sorted(
            bt_groups, key=lambda x: (x["ty"] * x["flip_sort"], -x["tx"]), reverse=True
        )
    ]

    if debug_path:  # pragma: no cover
        import json  # noqa: PLC0415

        debug_path.joinpath("bts.json").write_text(
            json.dumps(bt_groups, indent=2, default=str), "utf-8"
        )
        debug_path.joinpath("tjs.json").write_text(
            json.dumps(
                tj_ops, indent=2, default=lambda x: getattr(x, "to_dict", str)(x)
            ),
            "utf-8",
        )
    return bt_groups

def prune_post_subset(self, font, options):
    if self.Value is None:
        assert self.ValueFormat == 0
        return True

    # Shrink ValueFormat
    if self.Format == 1:
        if not options.hinting:
            self.Value.prune_hints()
        self.ValueFormat = self.Value.getEffectiveFormat()
    elif self.Format == 2:
        if None in self.Value:
            assert self.ValueFormat == 0
            assert all(v is None for v in self.Value)
        else:
            if not options.hinting:
                for v in self.Value:
                    v.prune_hints()
            self.ValueFormat = reduce(
                int.__or__, [v.getEffectiveFormat() for v in self.Value], 0
            )

    # Downgrade to Format 1 if all ValueRecords are the same
    if self.Format == 2 and all(v == self.Value[0] for v in self.Value):
        self.Format = 1
        self.Value = self.Value[0] if self.ValueFormat != 0 else None
        del self.ValueCount

    return True

def _neighborhood_aggregate_undirected(G, node, node_labels, edge_attr=None):
    """
    Compute new labels for given node in an undirected graph by aggregating
    the labels of each node's neighbors.
    """
    label_list = []
    for nbr in G.neighbors(node):
        prefix = "" if edge_attr is None else str(G[node][nbr][edge_attr])
        label_list.append(prefix + node_labels[nbr])
    return node_labels[node] + "".join(sorted(label_list))

def _save(
    im: Image.Image, fp: IO[bytes], filename: str | bytes, save_all: bool = False
) -> None:
    # header
    if "palette" in im.encoderinfo or "palette" in im.info:
        palette = im.encoderinfo.get("palette", im.info.get("palette"))
    else:
        palette = None
        im.encoderinfo.setdefault("optimize", True)

    if not save_all or not _write_multiple_frames(im, fp, palette):
        _write_single_frame(im, fp, palette)

    fp.write(b";")  # end of file

    if hasattr(fp, "flush"):
        fp.flush()

def stripped_value(self):
    for token in self:
        if token.token_type.endswith('attrtext'):
            return token.value

def subset_glyphs(self, s):
    self.alternates = {
        g: [v for v in vlist if v in s.glyphs]
        for g, vlist in self.alternates.items()
        if g in s.glyphs and any(v in s.glyphs for v in vlist)
    }
    return bool(self.alternates)

def write(self, data):
    """Write 'data' to the SSL object and return the number of bytes
    written.

    The 'data' argument must support the buffer interface.
    """
    return self._sslobj.write(data)

def _build_writer(self, inferred_schema: pa.Schema):
    self._schema, self._features = self._build_schema(inferred_schema)
    self.pa_writer = pq.ParquetWriter(
        self.stream,
        self._schema,
        use_content_defined_chunking=self.use_content_defined_chunking,
        write_page_index=self.write_page_index,
        compression={
            col: "none" if require_storage_embed(feature) else "snappy" for col, feature in self._features.items()
        },
        use_dictionary=[col for col, feature in self._features.items() if not require_storage_embed(feature)],
        column_encoding={
            col: "PLAIN" for col, feature in self._features.items() if require_storage_embed(feature)
        },
    )
    if self.use_content_defined_chunking is not False:
        self.pa_writer.add_key_value_metadata(
            {"content_defined_chunking": json.dumps(self.use_content_defined_chunking)}
        )

def _starts_expression(self, tok: Optional[_Token] = None) -> bool:
    tok = tok or self._peek()
    if tok is None:
        return False
    return tok.type in _STARTS_EXPRESSION

def subset_glyphs(self, s):
    glyphs = s.glyphs_gsubed
    table = self.table
    if table.LigCaretList:
        indices = table.LigCaretList.Coverage.subset(glyphs)
        table.LigCaretList.LigGlyph = _list_subset(table.LigCaretList.LigGlyph, indices)
        table.LigCaretList.LigGlyphCount = len(table.LigCaretList.LigGlyph)
    if table.MarkAttachClassDef:
        table.MarkAttachClassDef.classDefs = {
            g: v for g, v in table.MarkAttachClassDef.classDefs.items() if g in glyphs
        }
    if table.GlyphClassDef:
        table.GlyphClassDef.classDefs = {
            g: v for g, v in table.GlyphClassDef.classDefs.items() if g in glyphs
        }
    if table.AttachList:
        indices = table.AttachList.Coverage.subset(glyphs)
        GlyphCount = table.AttachList.GlyphCount
        table.AttachList.AttachPoint = [
            table.AttachList.AttachPoint[i] for i in indices if i < GlyphCount
        ]
        table.AttachList.GlyphCount = len(table.AttachList.AttachPoint)
    if hasattr(table, "MarkGlyphSetsDef") and table.MarkGlyphSetsDef:
        markGlyphSets = table.MarkGlyphSetsDef
        for coverage in markGlyphSets.Coverage:
            if coverage:
                coverage.subset(glyphs)

        s.used_mark_sets = [i for i, c in enumerate(markGlyphSets.Coverage) if c.glyphs]
        markGlyphSets.Coverage = [c for c in markGlyphSets.Coverage if c.glyphs]

    return True

def cofactors(f, g):
    if not f and not g:
        zero = f.ring.zero
        return zero, zero, zero
    elif not f:
        h, cff, cfg = f._gcd_zero(g)
        return h, cff, cfg
    elif not g:
        h, cfg, cff = g._gcd_zero(f)
        return h, cff, cfg
    elif len(f) == 1:
        h, cff, cfg = f._gcd_monom(g)
        return h, cff, cfg
    elif len(g) == 1:
        h, cfg, cff = g._gcd_monom(f)
        return h, cff, cfg

    J, (f, g) = f.deflate(g)
    h, cff, cfg = f._gcd(g)

    return (h.inflate(J), cff.inflate(J), cfg.inflate(J))

def draw(self):
    # general widget bits
    group = Group()
    x, y, w, h, c0, c1 = self._flipRectCorners()
    vertical = self.orientation == 'vertical'
    cylinderMode = self.cylinderMode
    linG = getattr(getattr(self,'_canvas',None),'linearGradient',None)
    if linG:
        canv = linG.__self__
        canv.saveState()
        p = canv.beginPath()
        p.rect(x, y, w, h)
        canv.clipPath(p, stroke=0)
        if cylinderMode:
            if vertical:
                linG(x, y, x+w/2, y, (c0,c1), extend=False)
                linG(x+w/2, y, x+w, y, (c1,c0), extend=False)
            else:
                linG(x, y, x, y+h/2, (c0,c1), extend=False)
                linG(x, y+h/2, x, y+h, (c1,c0), extend=False)
        else:
            if vertical:
                linG(x, y, x+w, y, (c0,c1), extend=False)
            else:
                linG(x, y, x, y+h, (c0,c1), extend=False)
        canv.restoreState()
    else:
        numShades = self.numShades
        if cylinderMode:
            if not numShades%2: numShades = numShades+1
            halfNumShades = int((numShades-1)/2) + 1
        num = float(numShades) # must make it float!
        if vertical:
            if numShades == 1:
                V = [x]
            else:
                V = frange(x, x + w, w/num)
        else:
            if numShades == 1:
                V = [y]
            else:
                V = frange(y, y + h, h/num)

        for v in V:
            stripe = vertical and Rect(v, y, w/num, h) or Rect(x, v, w, h/num)
            if cylinderMode:
                if V.index(v)>=halfNumShades:
                    col = colors.linearlyInterpolatedColor(c1,c0,V[halfNumShades],V[-1], v)
                else:
                    col = colors.linearlyInterpolatedColor(c0,c1,V[0],V[halfNumShades], v)
            else:
                col = colors.linearlyInterpolatedColor(c0,c1,V[0],V[-1], v)
            stripe.fillColor = col
            stripe.strokeColor = col
            stripe.strokeWidth = 1
            group.add(stripe)
    if self.strokeColor and self.strokeWidth>=0:
        rect = Rect(x, y, w, h)
        rect.strokeColor = self.strokeColor
        rect.strokeWidth = self.strokeWidth
        rect.fillColor = None
        group.add(rect)
    return group

def assert_no_path_traversal(dest_dir_path: str, target_path: str) -> None:
    if not is_within_directory(dest_dir_path, target_path):
        message = (
            "The wheel {!r} has a file {!r} trying to install"
            " outside the target directory {!r}"
        )
        raise InstallationError(
            message.format(wheel_path, target_path, dest_dir_path)
        )

def solve_typer_info_help(typer_info: TyperInfo) -> str:
    # Priority 1: Explicit value was set in app.add_typer()
    if not isinstance(typer_info.help, DefaultPlaceholder):
        return inspect.cleandoc(typer_info.help or "")
    # Priority 2: Explicit value was set in sub_app.callback()
    if typer_info.typer_instance and typer_info.typer_instance.registered_callback:
        callback_help = typer_info.typer_instance.registered_callback.help
        if not isinstance(callback_help, DefaultPlaceholder):
            return inspect.cleandoc(callback_help or "")
    # Priority 3: Explicit value was set in sub_app = typer.Typer()
    if typer_info.typer_instance and typer_info.typer_instance.info:
        instance_help = typer_info.typer_instance.info.help
        if not isinstance(instance_help, DefaultPlaceholder):
            return inspect.cleandoc(instance_help or "")
    # Priority 4: Implicit inference from callback docstring in app.add_typer()
    if typer_info.callback:
        doc = inspect.getdoc(typer_info.callback)
        if doc:
            return doc
    # Priority 5: Implicit inference from callback docstring in @app.callback()
    if typer_info.typer_instance and typer_info.typer_instance.registered_callback:
        callback = typer_info.typer_instance.registered_callback.callback
        if not isinstance(callback, DefaultPlaceholder):
            doc = inspect.getdoc(callback or "")
            if doc:
                return doc
    # Priority 6: Implicit inference from callback docstring in typer.Typer()
    if typer_info.typer_instance and typer_info.typer_instance.info:
        instance_callback = typer_info.typer_instance.info.callback
        if not isinstance(instance_callback, DefaultPlaceholder):
            doc = inspect.getdoc(instance_callback)
            if doc:
                return doc
    # Value not set, use the default
    return typer_info.help.value

def __int__(a, _index=operator.index):
    """int(a)"""
    if a._numerator < 0:
        return _index(-(-a._numerator // a._denominator))
    else:
        return _index(a._numerator // a._denominator)

def parse_valuerecord_(self, vertical):
    if (
        self.next_token_type_ is Lexer.SYMBOL and self.next_token_ == "("
    ) or self.next_token_type_ is Lexer.NUMBER:
        number, location = (
            self.expect_number_(variable=True),
            self.cur_token_location_,
        )
        if vertical:
            val = self.ast.ValueRecord(
                yAdvance=number, vertical=vertical, location=location
            )
        else:
            val = self.ast.ValueRecord(
                xAdvance=number, vertical=vertical, location=location
            )
        return val
    self.expect_symbol_("<")
    location = self.cur_token_location_
    if self.next_token_type_ is Lexer.NAME:
        name = self.expect_name_()
        if name == "NULL":
            self.expect_symbol_(">")
            return self.ast.ValueRecord()
        vrd = self.valuerecords_.resolve(name)
        if vrd is None:
            raise FeatureLibError(
                'Unknown valueRecordDef "%s"' % name, self.cur_token_location_
            )
        value = vrd.value
        xPlacement, yPlacement = (value.xPlacement, value.yPlacement)
        xAdvance, yAdvance = (value.xAdvance, value.yAdvance)
    else:
        xPlacement, yPlacement, xAdvance, yAdvance = (
            self.expect_number_(variable=True),
            self.expect_number_(variable=True),
            self.expect_number_(variable=True),
            self.expect_number_(variable=True),
        )

    if self.next_token_ == "<":
        xPlaDevice, yPlaDevice, xAdvDevice, yAdvDevice = (
            self.parse_device_(),
            self.parse_device_(),
            self.parse_device_(),
            self.parse_device_(),
        )
        allDeltas = sorted(
            [
                delta
                for size, delta in (xPlaDevice if xPlaDevice else ())
                + (yPlaDevice if yPlaDevice else ())
                + (xAdvDevice if xAdvDevice else ())
                + (yAdvDevice if yAdvDevice else ())
            ]
        )
        if allDeltas[0] < -128 or allDeltas[-1] > 127:
            raise FeatureLibError(
                "Device value out of valid range (-128..127)",
                self.cur_token_location_,
            )
    else:
        xPlaDevice, yPlaDevice, xAdvDevice, yAdvDevice = (None, None, None, None)

    self.expect_symbol_(">")
    return self.ast.ValueRecord(
        xPlacement,
        yPlacement,
        xAdvance,
        yAdvance,
        xPlaDevice,
        yPlaDevice,
        xAdvDevice,
        yAdvDevice,
        vertical=vertical,
        location=location,
    )

def _gather(c_powers):
    common_b = {}  # b:e
    for b, e in c_powers:
        co = e.as_coeff_Mul()
        common_b.setdefault(b, {}).setdefault(
            co[1], []).append(co[0])
    for b, d in common_b.items():
        for di, li in d.items():
            d[di] = Add(*li)
    new_c_powers = []
    for b, e in common_b.items():
        new_c_powers.extend([(b, c*t) for t, c in e.items()])
    return new_c_powers

def decode(s: Union[str, bytes, bytearray], strict: bool = False, uts46: bool = False, std3_rules: bool = False) -> str:
    try:
        if isinstance(s, (bytes, bytearray)):
            s = s.decode('ascii')
    except UnicodeDecodeError:
        raise IDNAError('Invalid ASCII in A-label')
    if uts46:
        s = uts46_remap(s, std3_rules, False)
    trailing_dot = False
    result = []
    if not strict:
        labels = _unicode_dots_re.split(s)
    else:
        labels = s.split('.')
    if not labels or labels == ['']:
        raise IDNAError('Empty domain')
    if not labels[-1]:
        del labels[-1]
        trailing_dot = True
    for label in labels:
        s = ulabel(label)
        if s:
            result.append(s)
        else:
            raise IDNAError('Empty label')
    if trailing_dot:
        result.append('')
    return '.'.join(result)

def _ConvertAnyMessage(self, value, message, path):
  """Convert a JSON representation into Any message."""
  if isinstance(value, dict) and not value:
    return
  try:
    type_url = value['@type']
  except KeyError as e:
    raise ParseError(
        '@type is missing when parsing any message at {0}'.format(path)
    ) from e

  try:
    sub_message = _CreateMessageFromTypeUrl(type_url, self.descriptor_pool)
  except TypeError as e:
    raise ParseError('{0} at {1}'.format(e, path)) from e
  message_descriptor = sub_message.DESCRIPTOR
  full_name = message_descriptor.full_name
  if _IsWrapperMessage(message_descriptor):
    self._ConvertWrapperMessage(
        value['value'], sub_message, '{0}.value'.format(path)
    )
  elif full_name in _WKTJSONMETHODS:
    methodcaller(
        _WKTJSONMETHODS[full_name][1],
        value['value'],
        sub_message,
        '{0}.value'.format(path),
    )(self)
  else:
    del value['@type']
    try:
      self._ConvertFieldValuePair(value, sub_message, path)
    finally:
      value['@type'] = type_url
  # Sets Any message
  message.value = sub_message.SerializeToString()
  message.type_url = type_url

def _interpret_args(self, args):
    f, gradient = None, self.gradient
    atoms, lists = self._sort_args(args)
    s = self._pop_symbol_list(lists)
    s = self._fill_in_vars(s)

    # prepare the error message for lambdification failure
    f_str = ', '.join(str(fa) for fa in atoms)
    s_str = (str(sa) for sa in s)
    s_str = ', '.join(sa for sa in s_str if sa.find('unbound') < 0)
    f_error = ValueError("Could not interpret arguments "
                         "%s as functions of %s." % (f_str, s_str))

    # try to lambdify args
    if len(atoms) == 1:
        fv = atoms[0]
        try:
            f = lambdify(s, [fv, fv, fv])
        except TypeError:
            raise f_error

    elif len(atoms) == 3:
        fr, fg, fb = atoms
        try:
            f = lambdify(s, [fr, fg, fb])
        except TypeError:
            raise f_error

    else:
        raise ValueError("A ColorScheme must provide 1 or 3 "
                         "functions in x, y, z, u, and/or v.")

    # try to intrepret any given color information
    if len(lists) == 0:
        gargs = []

    elif len(lists) == 1:
        gargs = lists[0]

    elif len(lists) == 2:
        try:
            (r1, g1, b1), (r2, g2, b2) = lists
        except TypeError:
            raise ValueError("If two color arguments are given, "
                             "they must be given in the format "
                             "(r1, g1, b1), (r2, g2, b2).")
        gargs = lists

    elif len(lists) == 3:
        try:
            (r1, r2), (g1, g2), (b1, b2) = lists
        except Exception:
            raise ValueError("If three color arguments are given, "
                             "they must be given in the format "
                             "(r1, r2), (g1, g2), (b1, b2). To create "
                             "a multi-step gradient, use the syntax "
                             "[0, colorStart, step1, color1, ..., 1, "
                             "colorEnd].")
        gargs = [[r1, g1, b1], [r2, g2, b2]]

    else:
        raise ValueError("Don't know what to do with collection "
                         "arguments %s." % (', '.join(str(l) for l in lists)))

    if gargs:
        try:
            gradient = ColorGradient(*gargs)
        except Exception as ex:
            raise ValueError(("Could not initialize a gradient "
                              "with arguments %s. Inner "
                              "exception: %s") % (gargs, str(ex)))

    return f, gradient

def stroke_color(self, color):
    if isinstance(color, str):
        color = Color(color)
    if isinstance(color, Color):
        self.options['stroke'] = color.string
    elif color is None:
        del self.options['stroke']
    else:
        raise TypeError('stroke_color must be a wand.color.Color, not ' +
                        repr(color))

def _fit_transformer(self, y):
    """Check transformer and fit transformer.

    Create the default transformer, fit it and make additional inverse
    check on a subset (optional).

    """
    if self.transformer is not None and (
        self.func is not None or self.inverse_func is not None
    ):
        raise ValueError(
            "'transformer' and functions 'func'/'inverse_func' cannot both be set."
        )
    elif self.transformer is not None:
        self.transformer_ = clone(self.transformer)
    else:
        if (self.func is not None and self.inverse_func is None) or (
            self.func is None and self.inverse_func is not None
        ):
            lacking_param, existing_param = (
                ("func", "inverse_func")
                if self.func is None
                else ("inverse_func", "func")
            )
            raise ValueError(
                f"When '{existing_param}' is provided, '{lacking_param}' must also"
                f" be provided. If {lacking_param} is supposed to be the default,"
                " you need to explicitly pass it the identity function."
            )
        self.transformer_ = FunctionTransformer(
            func=self.func,
            inverse_func=self.inverse_func,
            validate=True,
            check_inverse=self.check_inverse,
        )
        # We are transforming the target here and not the features, so we set the
        # output of FunctionTransformer() to be a numpy array (default) and to not
        # depend on the global configuration:
        self.transformer_.set_output(transform="default")
    # XXX: sample_weight is not currently passed to the
    # transformer. However, if transformer starts using sample_weight, the
    # code should be modified accordingly. At the time to consider the
    # sample_prop feature, it is also a good use case to be considered.
    self.transformer_.fit(y)
    if self.check_inverse:
        idx_selected = slice(None, None, max(1, y.shape[0] // 10))
        y_sel = _safe_indexing(y, idx_selected)
        y_sel_t = self.transformer_.transform(y_sel)
        if not np.allclose(y_sel, self.transformer_.inverse_transform(y_sel_t)):
            warnings.warn(
                (
                    "The provided functions or transformer are"
                    " not strictly inverse of each other. If"
                    " you are sure you want to proceed regardless"
                    ", set 'check_inverse=False'"
                ),
                UserWarning,
            )

def _normalize_palette(
    im: Image.Image, palette: _Palette | None, info: dict[str, Any]
) -> Image.Image:
    """
    Normalizes the palette for image.
      - Sets the palette to the incoming palette, if provided.
      - Ensures that there's a palette for L mode images
      - Optimizes the palette if necessary/desired.

    :param im: Image object
    :param palette: bytes object containing the source palette, or ....
    :param info: encoderinfo
    :returns: Image object
    """
    source_palette = None
    if palette:
        # a bytes palette
        if isinstance(palette, (bytes, bytearray, list)):
            source_palette = bytearray(palette[:768])
        if isinstance(palette, ImagePalette.ImagePalette):
            source_palette = bytearray(palette.palette)

    if im.mode == "P":
        if not source_palette:
            im_palette = im.getpalette(None)
            assert im_palette is not None
            source_palette = bytearray(im_palette)
    else:  # L-mode
        if not source_palette:
            source_palette = bytearray(i // 3 for i in range(768))
        im.palette = ImagePalette.ImagePalette("RGB", palette=source_palette)
    assert source_palette is not None

    if palette:
        used_palette_colors: list[int | None] = []
        assert im.palette is not None
        for i in range(0, len(source_palette), 3):
            source_color = tuple(source_palette[i : i + 3])
            index = im.palette.colors.get(source_color)
            if index in used_palette_colors:
                index = None
            used_palette_colors.append(index)
        for i, index in enumerate(used_palette_colors):
            if index is None:
                for j in range(len(used_palette_colors)):
                    if j not in used_palette_colors:
                        used_palette_colors[i] = j
                        break
        dest_map: list[int] = []
        for index in used_palette_colors:
            assert index is not None
            dest_map.append(index)
        im = im.remap_palette(dest_map)
    else:
        optimized_palette_colors = _get_optimize(im, info)
        if optimized_palette_colors is not None:
            im = im.remap_palette(optimized_palette_colors, source_palette)
            if "transparency" in info:
                try:
                    info["transparency"] = optimized_palette_colors.index(
                        info["transparency"]
                    )
                except ValueError:
                    del info["transparency"]
            return im

    assert im.palette is not None
    im.palette.palette = source_palette
    return im

def __init__(self, expr: Union[ParserElement, str], savelist: bool = False):
    super().__init__(savelist)
    if isinstance(expr, str_type):
        expr_str = typing.cast(str, expr)
        if issubclass(self._literalStringClass, Token):
            expr = self._literalStringClass(expr_str)  # type: ignore[call-arg]
        elif issubclass(type(self), self._literalStringClass):
            expr = Literal(expr_str)
        else:
            expr = self._literalStringClass(Literal(expr_str))  # type: ignore[assignment, call-arg]
    expr = typing.cast(ParserElement, expr)
    self.expr = expr
    if expr is not None:
        self.mayIndexError = expr.mayIndexError
        self.mayReturnEmpty = expr.mayReturnEmpty
        self.set_whitespace_chars(
            expr.whiteChars, copy_defaults=expr.copyDefaultWhiteChars
        )
        self.skipWhitespace = expr.skipWhitespace
        self.saveAsList = expr.saveAsList
        self.callPreparse = expr.callPreparse
        self.ignoreExprs.extend(expr.ignoreExprs)

def load_end(self) -> None:
    if self.__frame == 0:
        if self.mode == "P" and LOADING_STRATEGY == LoadingStrategy.RGB_ALWAYS:
            if self._frame_transparency is not None:
                self.im.putpalettealpha(self._frame_transparency, 0)
                self._mode = "RGBA"
            else:
                self._mode = "RGB"
            self.im = self.im.convert(self.mode, Image.Dither.FLOYDSTEINBERG)
        return
    if not self._prev_im:
        return
    if self.size != self._prev_im.size:
        if self._frame_transparency is not None:
            expanded_im = Image.core.fill("RGBA", self.size)
        else:
            expanded_im = Image.core.fill("P", self.size)
            expanded_im.putpalette("RGB", "RGB", self.im.getpalette())
            expanded_im = expanded_im.convert("RGB")
        expanded_im.paste(self._prev_im, (0, 0) + self._prev_im.size)

        self._prev_im = expanded_im
        assert self._prev_im is not None
    if self._frame_transparency is not None:
        if self.mode == "L":
            frame_im = self.im.convert_transparent("LA", self._frame_transparency)
        else:
            self.im.putpalettealpha(self._frame_transparency, 0)
            frame_im = self.im.convert("RGBA")
    else:
        frame_im = self.im.convert("RGB")

    assert self.dispose_extent is not None
    frame_im = self._crop(frame_im, self.dispose_extent)

    self.im = self._prev_im
    self._mode = self.im.mode
    if frame_im.mode in ("LA", "RGBA"):
        self.im.paste(frame_im, self.dispose_extent, frame_im)
    else:
        self.im.paste(frame_im, self.dispose_extent)

def _generateDefaultName(self) -> str:
    not_chars_str = _collapse_string_to_ranges(self.notChars)
    if len(not_chars_str) > 16:
        return f"!W:({self.notChars[: 16 - 3]}...)"
    else:
        return f"!W:({self.notChars})"

def __eq__(self, other):
    """Equality check for ``FirstOrderActivationDeGroote2016``."""
    if type(self) != type(other):
        return False
    self_attrs = (self.name, self.tau_a, self.tau_d, self.b)
    other_attrs = (other.name, other.tau_a, other.tau_d, other.b)
    if self_attrs == other_attrs:
        return True
    return False

def parseImpl(self, instring, loc, doActions=True):
    # pass False as callPreParse arg to _parse for first element, since we already
    # pre-parsed the string as part of our And pre-parsing
    loc, resultlist = self.exprs[0]._parse(
        instring, loc, doActions, callPreParse=False
    )
    errorStop = False
    for e in self.exprs[1:]:
        # if isinstance(e, And._ErrorStop):
        if type(e) is And._ErrorStop:
            errorStop = True
            continue
        if errorStop:
            try:
                loc, exprtokens = e._parse(instring, loc, doActions)
            except ParseSyntaxException:
                raise
            except ParseBaseException as pe:
                pe.__traceback__ = None
                raise ParseSyntaxException._from_exception(pe)
            except IndexError:
                raise ParseSyntaxException(
                    instring, len(instring), self.errmsg, self
                )
        else:
            loc, exprtokens = e._parse(instring, loc, doActions)
        resultlist += exprtokens
    return loc, resultlist

def _have_compatible_abi(executable: str, arch: str) -> bool:
    if arch == "armv7l":
        return _is_linux_armhf(executable)
    if arch == "i686":
        return _is_linux_i686(executable)
    return arch in {"x86_64", "aarch64", "ppc64", "ppc64le", "s390x"}

def ignore(self, other) -> ParserElement:
    if isinstance(other, Suppress):
        if other not in self.ignoreExprs:
            super().ignore(other)
            if self.expr is not None:
                self.expr.ignore(self.ignoreExprs[-1])
    else:
        super().ignore(other)
        if self.expr is not None:
            self.expr.ignore(self.ignoreExprs[-1])
    return self

def convert_value(self, conv_val) -> TermValue:
    """
    convert the expression that is in the term to something that is
    accepted by pytables
    """

    def stringify(value):
        if self.encoding is not None:
            return pprint_thing_encoded(value, encoding=self.encoding)
        return pprint_thing(value)

    kind = ensure_decoded(self.kind)
    meta = ensure_decoded(self.meta)
    if kind == "datetime" or (kind and kind.startswith("datetime64")):
        if isinstance(conv_val, (int, float)):
            conv_val = stringify(conv_val)
        conv_val = ensure_decoded(conv_val)
        conv_val = Timestamp(conv_val).as_unit("ns")
        if conv_val.tz is not None:
            conv_val = conv_val.tz_convert("UTC")
        return TermValue(conv_val, conv_val._value, kind)
    elif kind.startswith("timedelta"):
        unit = "ns"
        if "[" in kind:
            unit = cast("TimeUnit", kind.split("[")[-1][:-1])
        if isinstance(conv_val, str):
            conv_val = Timedelta(conv_val)
        elif lib.is_integer(conv_val) or lib.is_float(conv_val):
            conv_val = Timedelta(conv_val, unit="s")
        else:
            conv_val = Timedelta(conv_val)
        conv_val = conv_val.as_unit(unit)._value
        return TermValue(int(conv_val), conv_val, kind)

    elif meta == "category":
        metadata = extract_array(self.metadata, extract_numpy=True)
        result: npt.NDArray[np.intp] | np.intp | int
        if conv_val not in metadata:
            result = -1
        else:
            # Find the index of the first match of conv_val in metadata
            result = np.flatnonzero(metadata == conv_val)[0]
        return TermValue(result, result, "integer")
    elif kind == "integer":
        try:
            v_dec = Decimal(conv_val)
        except InvalidOperation:
            # GH 54186
            # convert v to float to raise float's ValueError
            float(conv_val)
        else:
            conv_val = int(v_dec.to_integral_exact(rounding="ROUND_HALF_EVEN"))
        return TermValue(conv_val, conv_val, kind)
    elif kind == "float":
        conv_val = float(conv_val)
        return TermValue(conv_val, conv_val, kind)
    elif kind == "bool":
        if isinstance(conv_val, str):
            conv_val = conv_val.strip().lower() not in [
                "false",
                "f",
                "no",
                "n",
                "none",
                "0",
                "[]",
                "{}",
                "",
            ]
        else:
            conv_val = bool(conv_val)
        return TermValue(conv_val, conv_val, kind)
    elif isinstance(conv_val, str):
        # string quoting
        return TermValue(conv_val, stringify(conv_val), "string")
    else:
        raise TypeError(
            f"Cannot compare {conv_val} of type {type(conv_val)} to {kind} column"
        )

def compress_identical_objects(
    self,
    remove_identicals: bool = True,
    remove_orphans: bool = True,
) -> None:
    """
    Parse the PDF file and merge objects that have the same hash.
    This will make objects common to multiple pages.
    Recommended to be used just before writing output.

    Args:
        remove_identicals: Remove identical objects.
        remove_orphans: Remove unreferenced objects.

    """

    def replace_in_obj(
        obj: PdfObject, crossref: Dict[IndirectObject, IndirectObject]
    ) -> None:
        if isinstance(obj, DictionaryObject):
            key_val = obj.items()
        elif isinstance(obj, ArrayObject):
            key_val = enumerate(obj)  # type: ignore
        else:
            return
        assert isinstance(obj, (DictionaryObject, ArrayObject))
        for k, v in key_val:
            if isinstance(v, IndirectObject):
                orphans[v.idnum - 1] = False
                if v in crossref:
                    obj[k] = crossref[v]
            else:
                """the filtering on DictionaryObject and ArrayObject only
                will be performed within replace_in_obj"""
                replace_in_obj(v, crossref)

    # _idnum_hash :dict[hash]=(1st_ind_obj,[other_indir_objs,...])
    self._idnum_hash = {}
    orphans = [True] * len(self._objects)
    # look for similar objects
    for idx, obj in enumerate(self._objects):
        if is_null_or_none(obj):
            continue
        assert obj is not None, "mypy"  # mypy: TypeGuard of `is_null_or_none` does not help here.
        assert isinstance(obj.indirect_reference, IndirectObject)
        h = obj.hash_value()
        if remove_identicals and h in self._idnum_hash:
            self._idnum_hash[h][1].append(obj.indirect_reference)
            self._objects[idx] = None
        else:
            self._idnum_hash[h] = (obj.indirect_reference, [])

    # generate the dict converting others to 1st
    cnv = {v[0]: v[1] for v in self._idnum_hash.values() if len(v[1]) > 0}
    cnv_rev: Dict[IndirectObject, IndirectObject] = {}
    for k, v in cnv.items():
        cnv_rev.update(zip(v, (k,) * len(v)))

    # replace reference to merged objects
    for obj in self._objects:
        if isinstance(obj, (DictionaryObject, ArrayObject)):
            replace_in_obj(obj, cnv_rev)

    # remove orphans (if applicable)
    orphans[self.root_object.indirect_reference.idnum - 1] = False  # type: ignore

    orphans[self._info.indirect_reference.idnum - 1] = False  # type: ignore

    try:
        orphans[self._ID.indirect_reference.idnum - 1] = False  # type: ignore
    except AttributeError:
        pass
    for i in compress(range(len(self._objects)), orphans):
        self._objects[i] = None

def look_for_image_or_link(
    text: str,
    delimiters: list[Delimiter],
    close: int,
    link_ref_defs: dict[str, tuple[str, str]],
    matches: list[MatchObj],
) -> MatchObj | None:
    for i, d in list(enumerate(delimiters))[::-1]:
        if d.content not in ("[", "!["):
            continue
        if not d.active:
            break  # break to remove the delimiter and return None
        if not _is_legal_link_text(text[d.end : close]):
            break
        link_text = Group(d.end, close, text[d.end : close])
        assert link_text.text is not None
        etype = "Image" if d.content == "![" else "Link"
        match = _expect_inline_link(text, close + 1) or _expect_reference_link(
            text, close + 1, link_text.text, link_ref_defs
        )
        if not match:  # not a link
            break
        rv = MatchObj(etype, text, d.start, match[2], link_text, match[0], match[1])
        process_emphasis(text, delimiters, i, matches)
        if etype == "Link":
            for d in delimiters[:i]:
                if d.content == "[":
                    d.active = False
        del delimiters[i]
        return rv

    else:
        # no matching opener is found
        return None

    del delimiters[i]
    return None

def fromXML(self, name, attrs, content, ttFont):
    if not hasattr(self, "yPels"):
        self.yPels = {}
    if name != "yPel":
        return  # ignore unknown tags
    self.yPels[attrs["name"]] = safeEval(attrs["value"])

def _naive_list_centralizer(self, other, af=False):
    from sympy.combinatorics.perm_groups import PermutationGroup
    """
    Return a list of elements for the centralizer of a subgroup/set/element.

    Explanation
    ===========

    This is a brute force implementation that goes over all elements of the
    group and checks for membership in the centralizer. It is used to
    test ``.centralizer()`` from ``sympy.combinatorics.perm_groups``.

    Examples
    ========

    >>> from sympy.combinatorics.testutil import _naive_list_centralizer
    >>> from sympy.combinatorics.named_groups import DihedralGroup
    >>> D = DihedralGroup(4)
    >>> _naive_list_centralizer(D, D)
    [Permutation([0, 1, 2, 3]), Permutation([2, 3, 0, 1])]

    See Also
    ========

    sympy.combinatorics.perm_groups.centralizer

    """
    from sympy.combinatorics.permutations import _af_commutes_with
    if hasattr(other, 'generators'):
        elements = list(self.generate_dimino(af=True))
        gens = [x._array_form for x in other.generators]
        commutes_with_gens = lambda x: all(_af_commutes_with(x, gen) for gen in gens)
        centralizer_list = []
        if not af:
            for element in elements:
                if commutes_with_gens(element):
                    centralizer_list.append(Permutation._af_new(element))
        else:
            for element in elements:
                if commutes_with_gens(element):
                    centralizer_list.append(element)
        return centralizer_list
    elif hasattr(other, 'getitem'):
        return _naive_list_centralizer(self, PermutationGroup(other), af)
    elif hasattr(other, 'array_form'):
        return _naive_list_centralizer(self, PermutationGroup([other]), af)

def _cmp(p1, p2, op):
    if p1.ring.is_element(p2):
        return op(p1.sort_key(), p2.sort_key())
    else:
        return NotImplemented

def subset_features(self, feature_indices, retain_empty):
    # https://bugzilla.mozilla.org/show_bug.cgi?id=1331737#c32
    self.ScriptRecord = [
        s
        for s in self.ScriptRecord
        if s.Script.subset_features(feature_indices, s.ScriptTag == "DFLT")
        or retain_empty
    ]
    self.ScriptCount = len(self.ScriptRecord)
    return bool(self.ScriptCount)

def RC_calc(ctx, x, y, r, pv=True):
    if not (ctx.isnormal(x) and ctx.isnormal(y)):
        if ctx.isinf(x) or ctx.isinf(y):
            return 1/(x*y)
        if y == 0:
            return ctx.inf
        if x == 0:
            return ctx.pi / ctx.sqrt(y) / 2
        raise ValueError
    # Cauchy principal value
    if pv and ctx._im(y) == 0 and ctx._re(y) < 0:
        return ctx.sqrt(x/(x-y)) * RC_calc(ctx, x-y, -y, r)
    if x == y:
        return 1/ctx.sqrt(x)
    extraprec = 2*max(0,-ctx.mag(x-y)+ctx.mag(x))
    ctx.prec += extraprec
    if ctx._is_real_type(x) and ctx._is_real_type(y):
        x = ctx._re(x)
        y = ctx._re(y)
        a = ctx.sqrt(x/y)
        if x < y:
            b = ctx.sqrt(y-x)
            v = ctx.acos(a)/b
        else:
            b = ctx.sqrt(x-y)
            v = ctx.acosh(a)/b
    else:
        sx = ctx.sqrt(x)
        sy = ctx.sqrt(y)
        v = ctx.acos(sx/sy)/(ctx.sqrt((1-x/y))*sy)
    ctx.prec -= extraprec
    return v

def binary_symbols(self):
    if S.true in self.args or S.false in self.args:
        if self.lhs.is_Symbol:
            return {self.lhs}
        elif self.rhs.is_Symbol:
            return {self.rhs}
    return set()

def nnz(self):
    """Returns the number of non-zero elements in Matrix."""
    return len(self.todok())

def _write_custom_labels(self, parent, labels) -> None:
    # Write the <c:showLegendKey> element.
    index = 0

    for label in labels:
        index += 1

        if label is None:
            continue

        use_custom_formatting = True

        self._xml_start_tag("c:dLbl")

        # Write the c:idx element.
        self._write_idx(index - 1)

        delete_label = label.get("delete")

        if delete_label:
            self._write_delete(1)

        elif label.get("formula") or label.get("value") or label.get("position"):

            # Write the c:layout element.
            self._write_layout(None, None)

            if label.get("formula"):
                self._write_custom_label_formula(label)
            elif label.get("value"):
                self._write_custom_label_str(label)
                # String values use spPr formatting.
                use_custom_formatting = False

            if use_custom_formatting:
                self._write_custom_label_format(label)

            if label.get("position"):
                self._write_d_lbl_pos(label["position"])
            elif parent.get("position"):
                self._write_d_lbl_pos(parent["position"])

            if parent.get("value"):
                self._write_show_val()

            if parent.get("category"):
                self._write_show_cat_name()

            if parent.get("series_name"):
                self._write_show_ser_name()

        else:
            self._write_custom_label_format(label)

        self._xml_end_tag("c:dLbl")

def refresh(self):
    """re-fetches attributes from the parent on demand;
    use if you have been hacking the styles.  This is
    used by __init__"""
    if self.parent:
        for key, value in self.parent.__dict__.items():
            if (key not in ['name','parent']):
                self.__dict__[key] = value

def remove_text(self, font_names: Optional[List[str]] = None) -> None:
    """
    Remove text from the PDF.

    Args:
        font_names: List of font names to remove, such as "Helvetica-Bold".
            Optional. If not specified, all text will be removed.
    """
    if not font_names:
        font_names = []

    for page in self.pages:
        resource_ids_to_remove = []

        # Content streams reference fonts and other resources with names like "/F1" or "/T1_0"
        # Font names need to be converted to resource names/IDs for easier removal
        if font_names:
            # Recursively loop through page objects to gather font info
            def get_font_info(
                obj: Any,
                font_info: Optional[Dict[str, Any]] = None,
                key: Optional[str] = None
            ) -> Dict[str, Any]:
                if font_info is None:
                    font_info = {}
                if isinstance(obj, IndirectObject):
                    obj = obj.get_object()
                if isinstance(obj, dict):
                    if obj.get("/Type") == "/Font":
                        font_name = obj.get("/BaseFont", "")
                        # Normalize font names like "/RRXFFV+Palatino-Bold" to "Palatino-Bold"
                        normalized_font_name = font_name.lstrip("/").split("+")[-1]
                        if normalized_font_name not in font_info:
                            font_info[normalized_font_name] = {
                                "normalized_font_name": normalized_font_name,
                                "resource_ids": [],
                            }
                        if key not in font_info[normalized_font_name]["resource_ids"]:
                            font_info[normalized_font_name]["resource_ids"].append(key)
                    for k in obj:
                        font_info = get_font_info(obj[k], font_info, k)
                elif isinstance(obj, (list, ArrayObject)):
                    for child_obj in obj:
                        font_info = get_font_info(child_obj, font_info)
                return font_info

            # Add relevant resource names for removal
            font_info = get_font_info(page.get("/Resources"))
            for font_name in font_names:
                if font_name in font_info:
                    resource_ids_to_remove.extend(font_info[font_name]["resource_ids"])

        text_filters = {}
        if font_names:
            text_filters["font_ids"] = resource_ids_to_remove
        self.remove_objects_from_page(page, ObjectDeletionFlag.TEXT, text_filters=text_filters)

def rem(self, G):
    f = self
    if isinstance(G, PolyElement):
        G = [G]
    if not all(G):
        raise ZeroDivisionError("polynomial division")
    ring = f.ring
    domain = ring.domain
    zero = domain.zero
    monomial_mul = ring.monomial_mul
    r = ring.zero
    term_div = f._term_div()
    ltf = f.LT
    f = f.copy()
    get = f.get
    while f:
        for g in G:
            tq = term_div(ltf, g.LT)
            if tq is not None:
                m, c = tq
                for mg, cg in g.iterterms():
                    m1 = monomial_mul(mg, m)
                    c1 = get(m1, zero) - c*cg
                    if not c1:
                        del f[m1]
                    else:
                        f[m1] = c1
                ltm = f.leading_expv()
                if ltm is not None:
                    ltf = ltm, f[ltm]

                break
        else:
            ltm, ltc = ltf
            if ltm in r:
                r[ltm] += ltc
            else:
                r[ltm] = ltc
            del f[ltm]
            ltm = f.leading_expv()
            if ltm is not None:
                ltf = ltm, f[ltm]

    return r

def fail_if_equal(actual, desired, err_msg='',):
    """
    Raises an assertion error if two items are equal.

    """
    if isinstance(desired, dict):
        if not isinstance(actual, dict):
            raise AssertionError(repr(type(actual)))
        fail_if_equal(len(actual), len(desired), err_msg)
        for k in desired:
            if k not in actual:
                raise AssertionError(repr(k))
            fail_if_equal(actual[k], desired[k], f'key={k!r}\n{err_msg}')
        return
    if isinstance(desired, (list, tuple)) and isinstance(actual, (list, tuple)):
        fail_if_equal(len(actual), len(desired), err_msg)
        for k in range(len(desired)):
            fail_if_equal(actual[k], desired[k], f'item={k!r}\n{err_msg}')
        return
    if isinstance(actual, np.ndarray) or isinstance(desired, np.ndarray):
        return fail_if_array_equal(actual, desired, err_msg)
    msg = build_err_msg([actual, desired], err_msg)
    if not desired != actual:
        raise AssertionError(msg)

def subset_script_tags(self, tags):
    langsys = {}
    script_tags = set()
    for tag in tags:
        script_tag, lang_tag = tag.split(".") if "." in tag else (tag, "*")
        script_tags.add(script_tag.ljust(4))
        langsys.setdefault(script_tag, set()).add(lang_tag.ljust(4))

    if self.table.ScriptList:
        self.table.ScriptList.ScriptRecord = [
            s for s in self.table.ScriptList.ScriptRecord if s.ScriptTag in script_tags
        ]
        self.table.ScriptList.ScriptCount = len(self.table.ScriptList.ScriptRecord)

        for record in self.table.ScriptList.ScriptRecord:
            if record.ScriptTag in langsys and "*   " not in langsys[record.ScriptTag]:
                record.Script.LangSysRecord = [
                    l
                    for l in record.Script.LangSysRecord
                    if l.LangSysTag in langsys[record.ScriptTag]
                ]
                record.Script.LangSysCount = len(record.Script.LangSysRecord)
                if "dflt" not in langsys[record.ScriptTag]:
                    record.Script.DefaultLangSys = None

def _mean(a, axis=None, dtype=None, out=None, keepdims=False, *, where=True):
    arr = asanyarray(a)

    is_float16_result = False

    rcount = _count_reduce_items(arr, axis, keepdims=keepdims, where=where)
    if rcount == 0 if where is True else umr_any(rcount == 0, axis=None):
        warnings.warn("Mean of empty slice", RuntimeWarning, stacklevel=2)

    # Cast bool, unsigned int, and int to float64 by default
    if dtype is None:
        if issubclass(arr.dtype.type, (nt.integer, nt.bool)):
            dtype = mu.dtype('f8')
        elif issubclass(arr.dtype.type, nt.float16):
            dtype = mu.dtype('f4')
            is_float16_result = True

    ret = umr_sum(arr, axis, dtype, out, keepdims, where=where)
    if isinstance(ret, mu.ndarray):
        ret = um.true_divide(
                ret, rcount, out=ret, casting='unsafe', subok=False)
        if is_float16_result and out is None:
            ret = arr.dtype.type(ret)
    elif hasattr(ret, 'dtype'):
        if is_float16_result:
            ret = arr.dtype.type(ret / rcount)
        else:
            ret = ret.dtype.type(ret / rcount)
    else:
        ret = ret / rcount

    return ret

def monic(f):
    """Divides all coefficients by the leading coefficient. """
    if not f:
        return f
    else:
        return f.quo_ground(f.LC)

def get_token(self):
    if self.pushback:
        return self.pushback.pop(0)
    token = ""
    fiter = iter(self._read_char, "")
    for ch in fiter:
        if ch in self.whitespace:
            continue
        if ch == '"':
            for ch in fiter:
                if ch == '"':
                    return token
                elif ch == "\\":
                    ch = self._read_char()
                token += ch
        else:
            if ch == "\\":
                ch = self._read_char()
            token += ch
            for ch in fiter:
                if ch in self.whitespace:
                    return token
                elif ch == "\\":
                    ch = self._read_char()
                token += ch
    return token

def __ne__(self, other):
    equal = self.__eq__(other)
    if equal == NotImplemented:
        return NotImplemented
    else:
        return not equal

def parseImpl(self, instring, loc, doActions=True):
    start = loc
    instrlen = len(instring)
    maxloc = start + len(self.match_string)

    if maxloc <= instrlen:
        match_string = self.match_string
        match_stringloc = 0
        mismatches = []
        maxMismatches = self.maxMismatches

        for match_stringloc, s_m in enumerate(
            zip(instring[loc:maxloc], match_string)
        ):
            src, mat = s_m
            if self.caseless:
                src, mat = src.lower(), mat.lower()

            if src != mat:
                mismatches.append(match_stringloc)
                if len(mismatches) > maxMismatches:
                    break
        else:
            loc = start + match_stringloc + 1
            results = ParseResults([instring[start:loc]])
            results["original"] = match_string
            results["mismatches"] = mismatches
            return loc, results

    raise ParseException(instring, loc, self.errmsg, self)

def subset_glyphs(self, s):
    table = self.table

    used = set()
    advIdxes_ = set()
    retainAdvMap = False

    if table.AdvHeightMap:
        table.AdvHeightMap.mapping = _dict_subset(table.AdvHeightMap.mapping, s.glyphs)
        used.update(table.AdvHeightMap.mapping.values())
    else:
        used.update(s.reverseOrigGlyphMap.values())
        advIdxes_ = used.copy()
        retainAdvMap = s.options.retain_gids

    if table.TsbMap:
        table.TsbMap.mapping = _dict_subset(table.TsbMap.mapping, s.glyphs)
        used.update(table.TsbMap.mapping.values())
    if table.BsbMap:
        table.BsbMap.mapping = _dict_subset(table.BsbMap.mapping, s.glyphs)
        used.update(table.BsbMap.mapping.values())
    if table.VOrgMap:
        table.VOrgMap.mapping = _dict_subset(table.VOrgMap.mapping, s.glyphs)
        used.update(table.VOrgMap.mapping.values())

    varidx_map = table.VarStore.subset_varidxes(
        used, retainFirstMap=retainAdvMap, advIdxes=advIdxes_
    )

    if table.AdvHeightMap:
        table.AdvHeightMap.mapping = _remap_index_map(s, varidx_map, table.AdvHeightMap)
    if table.TsbMap:
        table.TsbMap.mapping = _remap_index_map(s, varidx_map, table.TsbMap)
    if table.BsbMap:
        table.BsbMap.mapping = _remap_index_map(s, varidx_map, table.BsbMap)
    if table.VOrgMap:
        table.VOrgMap.mapping = _remap_index_map(s, varidx_map, table.VOrgMap)

    # TODO Return emptiness...
    return True

def __init__(self, msg: str, parsed_version: int) -> None:
    super().__init__(msg)
    self.parsed_version = parsed_version

def __rxor__(self, other) -> "ParserElement":
    """
    Implementation of ``^`` operator when left operand is not a :class:`ParserElement`
    """
    if isinstance(other, str_type):
        other = self._literalStringClass(other)
    if not isinstance(other, ParserElement):
        return NotImplemented
    return other ^ self

def SetRuleData(r, d):
    (r.Input,) = d
    (r.GlyphCount,) = (len(x) + 1 for x in d)

def _iter_optional_params(cmd: Command):
    """Yield (param, long_name, short_name) for each optional, non-internal param."""
    for p in cmd.params:
        if p.required or p.human_readable_name == "--help":
            continue
        if p.name and p.name.startswith("_"):
            continue
        long_name = None
        short_name = None
        for opt in getattr(p, "opts", []):
            if opt.startswith("--"):
                long_name = long_name or opt
            elif opt.startswith("-"):
                short_name = opt
        if long_name:
            yield p, long_name, short_name

def popitem(self):
    'Remove and return an item pair from maps[0]. Raise KeyError is maps[0] is empty.'
    try:
        return self.maps[0].popitem()
    except KeyError:
        raise KeyError('No keys found in the first mapping.')

def __truediv__(self, other):
    from sympy.matrices.matrixbase import MatrixBase
    from sympy.tensor.array import SparseNDimArray
    from sympy.tensor.array.arrayop import Flatten

    if isinstance(other, (Iterable, NDimArray, MatrixBase)):
        raise ValueError("scalar expected")

    other = sympify(other)
    if isinstance(self, SparseNDimArray) and other != S.Zero:
        return type(self)({k: v/other for (k, v) in self._sparse_array.items()}, self.shape)

    result_list = [i/other for i in Flatten(self)]
    return type(self)(result_list, self.shape)

def f(sh, shape_left, i, j):
    if len(shape_left) == 1:
        return [self[self._get_tuple_index(e)] for e in range(i, j)]
    result = []
    sh //= shape_left[0]
    for e in range(shape_left[0]):
        result.append(f(sh, shape_left[1:], i+e*sh, i+(e+1)*sh))
    return result

def _get_threadlocal_config():
    """Get a threadlocal **mutable** configuration. If the configuration
    does not exist, copy the default global configuration."""
    if not hasattr(_threadlocal, "global_config"):
        _threadlocal.global_config = _global_config.copy()
    return _threadlocal.global_config

def _sum(a, axis=None, dtype=None, out=None, keepdims=False,
         initial=_NoValue, where=True):
    return umr_sum(a, axis, dtype, out, keepdims, initial, where)

def guessFileType(fileName):
    if fileName == "-":
        header = sys.stdin.buffer.peek(256)
        ext = ""
    else:
        base, ext = os.path.splitext(fileName)
        try:
            with open(fileName, "rb") as f:
                header = f.read(256)
        except IOError:
            return None

    if header.startswith(b"\xef\xbb\xbf<?xml"):
        header = header.lstrip(b"\xef\xbb\xbf")
    cr, tp = getMacCreatorAndType(fileName)
    if tp in ("sfnt", "FFIL"):
        return "TTF"
    if ext == ".dfont":
        return "TTF"
    head = Tag(header[:4])
    if head == "OTTO":
        return "OTF"
    elif head == "ttcf":
        return "TTC"
    elif head in ("\0\1\0\0", "true"):
        return "TTF"
    elif head == "wOFF":
        return "WOFF"
    elif head == "wOF2":
        return "WOFF2"
    elif head == "<?xm":
        # Use 'latin1' because that can't fail.
        header = tostr(header, "latin1")
        if opentypeheaderRE.search(header):
            return "OTX"
        else:
            return "TTX"
    return None

def closure_glyphs(self, s):
    tables = [t for t in self.tables if t.isUnicode()]

    # Closure unicodes, which for now is pulling in bidi mirrored variants
    if s.options.bidi_closure:
        additional_unicodes = set()
        for u in s.unicodes_requested:
            mirror_u = mirrored(u)
            if mirror_u is not None:
                additional_unicodes.add(mirror_u)
        s.unicodes_requested.update(additional_unicodes)

    # Close glyphs
    for table in tables:
        if table.format == 14:
            for varSelector, cmap in table.uvsDict.items():
                if varSelector not in s.unicodes_requested:
                    continue
                glyphs = {g for u, g in cmap if u in s.unicodes_requested}
                if None in glyphs:
                    glyphs.remove(None)
                s.glyphs.update(glyphs)
        else:
            cmap = table.cmap
            intersection = s.unicodes_requested.intersection(cmap.keys())
            s.glyphs.update(cmap[u] for u in intersection)

    # Calculate unicodes_missing
    s.unicodes_missing = s.unicodes_requested.copy()
    for table in tables:
        s.unicodes_missing.difference_update(table.cmap)

def _accept(self, token_type: str) -> Optional[_Token]:
    """Conditionally consume next token, only if it's of token_type.

    If it is of the expected type, consume and return it.
    Otherwise, leaves the token intact and returns None.
    """
    tok = self._peek()
    if tok is not None and tok.type == token_type:
        return self._advance()
    return None

def _valid_name(path: _Path) -> bool:
    # Ignore invalid names that cannot be imported directly
    return os.path.basename(path).isidentifier()

def load_prepare(self) -> None:
    temp_mode = "P" if self._frame_palette else "L"
    self._prev_im = None
    if self.__frame == 0:
        if self._frame_transparency is not None:
            self.im = Image.core.fill(
                temp_mode, self.size, self._frame_transparency
            )
    elif self.mode in ("RGB", "RGBA"):
        self._prev_im = self.im
        if self._frame_palette:
            self.im = Image.core.fill("P", self.size, self._frame_transparency or 0)
            self.im.putpalette("RGB", *self._frame_palette.getdata())
        else:
            self._im = None
    if not self._prev_im and self._im is not None and self.size != self.im.size:
        expanded_im = Image.core.fill(self.im.mode, self.size)
        if self._frame_palette:
            expanded_im.putpalette("RGB", *self._frame_palette.getdata())
        expanded_im.paste(self.im, (0, 0) + self.im.size)

        self.im = expanded_im
    self._mode = temp_mode
    self._frame_palette = None

    super().load_prepare()

def _get_tick_type(self, tick_type):
    # Convert user defined display units to internal units.
    if not tick_type:
        return None

    types = {
        "outside": "out",
        "inside": "in",
        "none": "none",
        "cross": "cross",
    }

    if tick_type in types:
        tick_type = types[tick_type]
    else:
        warn(f"Unknown tick_type '{tick_type}'")
        return None

    return tick_type

def parseImpl(self, instring, loc, doActions=True):
    notchars = self.notCharsSet
    if instring[loc] in notchars:
        raise ParseException(instring, loc, self.errmsg, self)

    start = loc
    loc += 1
    maxlen = min(start + self.maxLen, len(instring))
    while loc < maxlen and instring[loc] not in notchars:
        loc += 1

    if loc - start < self.minLen:
        raise ParseException(instring, loc, self.errmsg, self)

    return loc, instring[start:loc]

def _process_names(self, name, name_formula):
    # Switch name and name_formula parameters if required.

    if name is not None:
        if isinstance(name, list):
            # Convert a list of values into a name formula.
            cell = xl_rowcol_to_cell(name[1], name[2], True, True)
            name_formula = quote_sheetname(name[0]) + "!" + cell
            name = ""
        elif re.match(r"^=?[^!]+!\$?[A-Z]+\$?\d+", name):
            # Name looks like a formula, use it to set name_formula.
            name_formula = name
            name = ""

    return name, name_formula

def describe(self, description: str) -> "Locator":
    return Locator(
        self._frame,
        f"{self._selector} >> internal:describe={json.dumps(description)}",
    )

def stripVariableItemsFromTTX(
    string: str,
    ttLibVersion: bool = True,
    checkSumAdjustment: bool = True,
    modified: bool = True,
    created: bool = True,
    sfntVersion: bool = False,  # opt-in only
) -> str:
    """Strip stuff like ttLibVersion, checksums, timestamps, etc. from TTX dumps."""
    # ttlib changes with the fontTools version
    if ttLibVersion:
        string = re.sub(' ttLibVersion="[^"]+"', "", string)
    # sometimes (e.g. some subsetter tests) we don't care whether it's OTF or TTF
    if sfntVersion:
        string = re.sub(' sfntVersion="[^"]+"', "", string)
    # head table checksum and creation and mod date changes with each save.
    if checkSumAdjustment:
        string = re.sub('<checkSumAdjustment value="[^"]+"/>', "", string)
    if modified:
        string = re.sub('<modified value="[^"]+"/>', "", string)
    if created:
        string = re.sub('<created value="[^"]+"/>', "", string)
    return string

def axial_force_at(self,pos = None, **kwargs):
    """
    return the axial/normal force generated at some x-coordinate
    if no x value provided, returns the formula
    """
    if pos is None:
        return self._axial_force
    else:
        x = Symbol('x')
        if 'dir' in kwargs:
            dir = kwargs['dir']
            return limit(self._axial_force,x,pos,dir=dir)
        return self._axial_force.subs(x,pos)

def addr_spec(self):
    nameset = set(self.local_part)
    if len(nameset) > len(nameset-DOT_ATOM_ENDS):
        lp = quote_string(self.local_part)
    else:
        lp = self.local_part
    if self.domain is not None:
        return lp + '@' + self.domain
    return lp

def merge_scalars(self):
    scalars = []
    for arg_with_ind in self.args_with_ind:
        if len(arg_with_ind.indices) == 0:
            scalars.append(arg_with_ind)
    for i in scalars:
        self.args_with_ind.remove(i)
    scalar = Mul.fromiter([i.element for i in scalars])
    if len(self.args_with_ind) == 0:
        self.args_with_ind.append(_ArgE(scalar))
    else:
        from sympy.tensor.array.expressions.from_array_to_matrix import _a2m_tensor_product
        self.args_with_ind[0].element = _a2m_tensor_product(scalar, self.args_with_ind[0].element)

def f(rv, first=True):
    if not rv.is_Mul:
        return rv
    if first:
        n, d = rv.as_numer_denom()
        return f(n, 0)/f(d, 0)

    args = defaultdict(list)
    coss = {}
    other = []
    for c in rv.args:
        b, e = c.as_base_exp()
        if e.is_Integer and isinstance(b, cos):
            co, a = b.args[0].as_coeff_Mul()
            args[a].append(co)
            coss[b] = e
        else:
            other.append(c)

    new = []
    for a in args:
        c = args[a]
        c.sort()
        while c:
            k = 0
            cc = ci = c[0]
            while cc in c:
                k += 1
                cc *= 2
            if k > 1:
                newarg = sin(2**k*ci*a)/2**k/sin(ci*a)
                # see how many times this can be taken
                take = None
                ccs = []
                for i in range(k):
                    cc /= 2
                    key = cos(a*cc, evaluate=False)
                    ccs.append(cc)
                    take = min(coss[key], take or coss[key])
                # update exponent counts
                for i in range(k):
                    cc = ccs.pop()
                    key = cos(a*cc, evaluate=False)
                    coss[key] -= take
                    if not coss[key]:
                        c.remove(cc)
                new.append(newarg**take)
            else:
                b = cos(c.pop(0)*a)
                other.append(b**coss[b])

    if new:
        rv = Mul(*(new + other + [
            cos(k*a, evaluate=False) for a in args for k in args[a]]))

    return rv

def _binary_op(f_real, f_complex):
    def g_complex(ctx, sval, tval):
        return ctx.make_mpc(f_complex(sval, tval, ctx.prec))
    def g_real(ctx, sval, tval):
        try:
            return ctx.make_mpf(f_real(sval, tval, ctx.prec))
        except ComplexResult:
            sval = (sval, mpi_zero)
            tval = (tval, mpi_zero)
            return g_complex(ctx, sval, tval)
    def lop_real(s, t):
        if isinstance(t, _matrix): return NotImplemented
        ctx = s.ctx
        if not isinstance(t, ctx._types): t = ctx.convert(t)
        if hasattr(t, "_mpi_"): return g_real(ctx, s._mpi_, t._mpi_)
        if hasattr(t, "_mpci_"): return g_complex(ctx, (s._mpi_, mpi_zero), t._mpci_)
        return NotImplemented
    def rop_real(s, t):
        ctx = s.ctx
        if not isinstance(t, ctx._types): t = ctx.convert(t)
        if hasattr(t, "_mpi_"): return g_real(ctx, t._mpi_, s._mpi_)
        if hasattr(t, "_mpci_"): return g_complex(ctx, t._mpci_, (s._mpi_, mpi_zero))
        return NotImplemented
    def lop_complex(s, t):
        if isinstance(t, _matrix): return NotImplemented
        ctx = s.ctx
        if not isinstance(t, s.ctx._types):
            try:
                t = s.ctx.convert(t)
            except (ValueError, TypeError):
                return NotImplemented
        return g_complex(ctx, s._mpci_, t._mpci_)
    def rop_complex(s, t):
        ctx = s.ctx
        if not isinstance(t, s.ctx._types):
            t = s.ctx.convert(t)
        return g_complex(ctx, t._mpci_, s._mpci_)
    return lop_real, rop_real, lop_complex, rop_complex

def get_bbox_edge_pos(bbox, loc):
    """
    Return the ``(x, y)`` coordinates of corner *loc* of *bbox*; parameters
    behave as documented for the `.BboxConnector` constructor.
    """
    x0, y0, x1, y1 = bbox.extents
    if loc == 1:
        return x1, y1
    elif loc == 2:
        return x0, y1
    elif loc == 3:
        return x0, y0
    elif loc == 4:
        return x1, y0

def append(self, mailbox, flags, date_time, message):
    """Append message to named mailbox.

    (typ, [data]) = <instance>.append(mailbox, flags, date_time, message)

            All args except `message' can be None.
    """
    name = 'APPEND'
    if not mailbox:
        mailbox = 'INBOX'
    if flags:
        if (flags[0],flags[-1]) != ('(',')'):
            flags = '(%s)' % flags
    else:
        flags = None
    if date_time:
        date_time = Time2Internaldate(date_time)
    else:
        date_time = None
    literal = MapCRLF.sub(CRLF, message)
    if self.utf8_enabled:
        literal = b'UTF8 (' + literal + b')'
    self.literal = literal
    return self._simple_command(name, mailbox, flags, date_time)

def parse_tuple(
    self,
    simplified: bool = False,
    with_condexpr: bool = True,
    extra_end_rules: t.Optional[t.Tuple[str, ...]] = None,
    explicit_parentheses: bool = False,
    with_namespace: bool = False,
) -> t.Union[nodes.Tuple, nodes.Expr]:
    """Works like `parse_expression` but if multiple expressions are
    delimited by a comma a :class:`~jinja2.nodes.Tuple` node is created.
    This method could also return a regular expression instead of a tuple
    if no commas where found.

    The default parsing mode is a full tuple.  If `simplified` is `True`
    only names and literals are parsed; ``with_namespace`` allows namespace
    attr refs as well. The `no_condexpr` parameter is forwarded to
    :meth:`parse_expression`.

    Because tuples do not require delimiters and may end in a bogus comma
    an extra hint is needed that marks the end of a tuple.  For example
    for loops support tuples between `for` and `in`.  In that case the
    `extra_end_rules` is set to ``['name:in']``.

    `explicit_parentheses` is true if the parsing was triggered by an
    expression in parentheses.  This is used to figure out if an empty
    tuple is a valid expression or not.
    """
    lineno = self.stream.current.lineno
    if simplified:

        def parse() -> nodes.Expr:
            return self.parse_primary(with_namespace=with_namespace)

    else:

        def parse() -> nodes.Expr:
            return self.parse_expression(with_condexpr=with_condexpr)

    args: t.List[nodes.Expr] = []
    is_tuple = False

    while True:
        if args:
            self.stream.expect("comma")
        if self.is_tuple_end(extra_end_rules):
            break
        args.append(parse())
        if self.stream.current.type == "comma":
            is_tuple = True
        else:
            break
        lineno = self.stream.current.lineno

    if not is_tuple:
        if args:
            return args[0]

        # if we don't have explicit parentheses, an empty tuple is
        # not a valid expression.  This would mean nothing (literally
        # nothing) in the spot of an expression would be an empty
        # tuple.
        if not explicit_parentheses:
            self.fail(
                "Expected an expression,"
                f" got {describe_token(self.stream.current)!r}"
            )

    return nodes.Tuple(args, "load", lineno=lineno)

def _ArrayContraction_denest_ArrayDiagonal(cls, expr: 'ArrayDiagonal', *contraction_indices):
    diagonal_indices = list(expr.diagonal_indices)
    down_contraction_indices = expr._push_indices_down(expr.diagonal_indices, contraction_indices, get_rank(expr.expr))
    # Flatten diagonally contracted indices:
    down_contraction_indices = [[k for j in i for k in (j if isinstance(j, (tuple, Tuple)) else [j])] for i in down_contraction_indices]
    new_contraction_indices = []
    for contr_indgrp in down_contraction_indices:
        ind = contr_indgrp[:]
        for j, diag_indgrp in enumerate(diagonal_indices):
            if diag_indgrp is None:
                continue
            if any(i in diag_indgrp for i in contr_indgrp):
                ind.extend(diag_indgrp)
                diagonal_indices[j] = None
        new_contraction_indices.append(sorted(set(ind)))

    new_diagonal_indices_down = [i for i in diagonal_indices if i is not None]
    new_diagonal_indices = ArrayContraction._push_indices_up(new_contraction_indices, new_diagonal_indices_down)
    return _array_diagonal(
        _array_contraction(expr.expr, *new_contraction_indices),
        *new_diagonal_indices
    )

def _parse_cubehelix_args(argstr):
    """Turn stringified cubehelix params into args/kwargs."""

    if argstr.startswith("ch:"):
        argstr = argstr[3:]

    if argstr.endswith("_r"):
        reverse = True
        argstr = argstr[:-2]
    else:
        reverse = False

    if not argstr:
        return [], {"reverse": reverse}

    all_args = argstr.split(",")

    args = [float(a.strip(" ")) for a in all_args if "=" not in a]

    kwargs = [a.split("=") for a in all_args if "=" in a]
    kwargs = {k.strip(" "): float(v.strip(" ")) for k, v in kwargs}

    kwarg_map = dict(
        s="start", r="rot", g="gamma",
        h="hue", l="light", d="dark",  # noqa: E741
    )

    kwargs = {kwarg_map.get(k, k): v for k, v in kwargs.items()}

    if reverse:
        kwargs["reverse"] = True

    return args, kwargs

def move_object(obj: T_obj, axis: str, value: T_num) -> T_obj:
    assert axis in ("h", "v")
    if axis == "h":
        new_items = [
            ("x0", obj["x0"] + value),
            ("x1", obj["x1"] + value),
        ]
    if axis == "v":
        new_items = [
            ("top", obj["top"] + value),
            ("bottom", obj["bottom"] + value),
        ]
        if "doctop" in obj:
            new_items += [("doctop", obj["doctop"] + value)]
        if "y0" in obj:
            new_items += [
                ("y0", obj["y0"] - value),
                ("y1", obj["y1"] - value),
            ]
    return obj.__class__(tuple(obj.items()) + tuple(new_items))

def _parse_designator(self) -> c_ast.Node:
    if self._accept("LBRACKET"):
        expr = self._parse_constant_expression()
        self._expect("RBRACKET")
        return expr
    if self._accept("PERIOD"):
        return self._parse_identifier_or_typeid()
    self._parse_error("Invalid designator", self.clex.filename)

def makeLigatureRecords(data, coverage, c, classCount):
    records = [None] * len(coverage.glyphs)
    idx = {g: i for i, g in enumerate(coverage.glyphs)}

    for (glyph, klass, compIdx, compCount), anchor in data.items():
        record = records[idx[glyph]]
        if record is None:
            record = records[idx[glyph]] = ot.LigatureAttach()
            record.ComponentCount = compCount
            record.ComponentRecord = [ot.ComponentRecord() for i in range(compCount)]
            for compRec in record.ComponentRecord:
                compRec.LigatureAnchor = [None] * classCount
        assert record.ComponentCount == compCount, (
            glyph,
            record.ComponentCount,
            compCount,
        )

        anchors = record.ComponentRecord[compIdx - 1].LigatureAnchor
        assert anchors[klass] is None, (glyph, compIdx, klass)
        anchors[klass] = anchor
    return records

def to_ground(self):
    # TODO: should AlgebraicField be a Composite domain?
    if self.domain.is_Composite or hasattr(self.domain, 'domain'):
        return self.clone(domain=self.domain.domain)
    else:
        raise ValueError("%s is not a composite domain" % self.domain)

def write(self, pretty=True, encoding="UTF-8", xml_declaration=True):
    self.root.attrib["format"] = ".".join(str(i) for i in self.effectiveFormatTuple)

    if (
        self.documentObject.axes
        or self.documentObject.axisMappings
        or self.documentObject.elidedFallbackName is not None
    ):
        axesElement = ET.Element("axes")
        if self.documentObject.elidedFallbackName is not None:
            axesElement.attrib["elidedfallbackname"] = (
                self.documentObject.elidedFallbackName
            )
        self.root.append(axesElement)
    for axisObject in self.documentObject.axes:
        self._addAxis(axisObject)

    if self.documentObject.axisMappings:
        mappingsElement = None
        lastGroup = object()
        for mappingObject in self.documentObject.axisMappings:
            if getattr(mappingObject, "groupDescription", None) != lastGroup:
                if mappingsElement is not None:
                    self.root.findall(".axes")[0].append(mappingsElement)
                lastGroup = getattr(mappingObject, "groupDescription", None)
                mappingsElement = ET.Element("mappings")
                if lastGroup is not None:
                    mappingsElement.attrib["description"] = lastGroup
            self._addAxisMapping(mappingsElement, mappingObject)
        if mappingsElement is not None:
            self.root.findall(".axes")[0].append(mappingsElement)

    if self.documentObject.locationLabels:
        labelsElement = ET.Element("labels")
        for labelObject in self.documentObject.locationLabels:
            self._addLocationLabel(labelsElement, labelObject)
        self.root.append(labelsElement)

    if self.documentObject.rules:
        if getattr(self.documentObject, "rulesProcessingLast", False):
            attributes = {"processing": "last"}
        else:
            attributes = {}
        self.root.append(ET.Element("rules", attributes))
    for ruleObject in self.documentObject.rules:
        self._addRule(ruleObject)

    if self.documentObject.sources:
        self.root.append(ET.Element("sources"))
    for sourceObject in self.documentObject.sources:
        self._addSource(sourceObject)

    if self.documentObject.variableFonts:
        variableFontsElement = ET.Element("variable-fonts")
        for variableFont in self.documentObject.variableFonts:
            self._addVariableFont(variableFontsElement, variableFont)
        self.root.append(variableFontsElement)

    if self.documentObject.instances:
        self.root.append(ET.Element("instances"))
    for instanceObject in self.documentObject.instances:
        self._addInstance(instanceObject)

    if self.documentObject.lib:
        self._addLib(self.root, self.documentObject.lib, 2)

    tree = ET.ElementTree(self.root)
    tree.write(
        self.path,
        encoding=encoding,
        method="xml",
        xml_declaration=xml_declaration,
        pretty_print=pretty,
    )

def _parse_headers(
    self, headers: dict[bytes, bytes]
) -> tuple[str, int, tuple[str | int, ...]]:
    prefix = b""
    decoder_name = "raw"
    offset = 0
    if (
        headers.get(b"XTENSION") == b"'BINTABLE'"
        and headers.get(b"ZIMAGE") == b"T"
        and headers[b"ZCMPTYPE"] == b"'GZIP_1  '"
    ):
        no_prefix_size = self._get_size(headers, prefix) or (0, 0)
        number_of_bits = int(headers[b"BITPIX"])
        offset = no_prefix_size[0] * no_prefix_size[1] * (number_of_bits // 8)

        prefix = b"Z"
        decoder_name = "fits_gzip"

    size = self._get_size(headers, prefix)
    if not size:
        return "", 0, ()

    self._size = size

    number_of_bits = int(headers[prefix + b"BITPIX"])
    if number_of_bits == 8:
        self._mode = "L"
    elif number_of_bits == 16:
        self._mode = "I;16"
    elif number_of_bits == 32:
        self._mode = "I"
    elif number_of_bits in (-32, -64):
        self._mode = "F"

    args: tuple[str | int, ...]
    if decoder_name == "raw":
        args = (self.mode, 0, -1)
    else:
        args = (number_of_bits,)
    return decoder_name, offset, args

def _normal_ordered_form_factor(product, independent=False, recursive_limit=10,
                                _recursive_depth=0):
    """
    Helper function for normal_ordered_form_factor: Write multiplication
    expression with bosonic or fermionic operators on normally ordered form,
    using the bosonic and fermionic commutation relations. The resulting
    operator expression is equivalent to the argument, but will in general be
    a sum of operator products instead of a simple product.
    """

    factors = _expand_powers(product)

    new_factors = []
    n = 0
    while n < len(factors) - 1:
        current, next = factors[n], factors[n + 1]
        if any(not isinstance(f, (FermionOp, BosonOp)) for f in (current, next)):
            new_factors.append(current)
            n += 1
            continue

        key_1 = (current.is_annihilation, str(current.name))
        key_2 = (next.is_annihilation, str(next.name))

        if key_1 <= key_2:
            new_factors.append(current)
            n += 1
            continue

        n += 2
        if current.is_annihilation and not next.is_annihilation:
            if isinstance(current, BosonOp) and isinstance(next, BosonOp):
                if current.args[0] != next.args[0]:
                    if independent:
                        c = 0
                    else:
                        c = Commutator(current, next)
                    new_factors.append(next * current + c)
                else:
                    new_factors.append(next * current + 1)
            elif isinstance(current, FermionOp) and isinstance(next, FermionOp):
                if current.args[0] != next.args[0]:
                    if independent:
                        c = 0
                    else:
                        c = AntiCommutator(current, next)
                    new_factors.append(-next * current + c)
                else:
                    new_factors.append(-next * current + 1)
        elif (current.is_annihilation == next.is_annihilation and
            isinstance(current, FermionOp) and isinstance(next, FermionOp)):
            new_factors.append(-next * current)
        else:
            new_factors.append(next * current)

    if n == len(factors) - 1:
        new_factors.append(factors[-1])

    if new_factors == factors:
        return product
    else:
        expr = Mul(*new_factors).expand()
        return normal_ordered_form(expr,
                                   recursive_limit=recursive_limit,
                                   _recursive_depth=_recursive_depth + 1,
                                   independent=independent)

def __eq__(self, other: object) -> bool:
    if not isinstance(other, Attribute):
        return NotImplemented

    return (
        self.oid == other.oid
        and self.value == other.value
        and self._type == other._type
    )

def _extract_differential_symbol(self, s: str):
    differential_symbols = {"d", r"\text{d}", r"\mathrm{d}"}

    differential_symbol = next((symbol for symbol in differential_symbols if symbol in s), None)

    return differential_symbol

def prune_features(self, feature_index_map):
    self.ensureDecompiled()
    self.SubstitutionRecord = [
        r for r in self.SubstitutionRecord if r.FeatureIndex in feature_index_map.keys()
    ]
    # remap feature indices
    for r in self.SubstitutionRecord:
        r.FeatureIndex = feature_index_map[r.FeatureIndex]
    self.SubstitutionCount = len(self.SubstitutionRecord)
    return bool(self.SubstitutionCount)

def wrap_bio(self, incoming, outgoing, server_side=False,
             server_hostname=None, session=None):
    # Need to encode server_hostname here because _wrap_bio() can only
    # handle ASCII str.
    return self.sslobject_class._create(
        incoming, outgoing, server_side=server_side,
        server_hostname=self._encode_hostname(server_hostname),
        session=session, context=self,
    )

def _repr_png_(self):
    with self.convert('png') as cloned:
        return cloned.make_blob()

def analyse_text(text):
    if re.search(r'^\s*(#If|Module|Namespace)', text, re.MULTILINE):
        return 0.5

def qsize(self):
    '''Return the approximate size of the queue (not reliable!).'''
    with self.mutex:
        return self._qsize()

def _parse_labeled_statement(self) -> c_ast.Node:
    tok_type = self._peek_type()
    match tok_type:
        case "ID":
            name_tok = self._advance()
            self._expect("COLON")
            if self._starts_statement():
                stmt = self._parse_pragmacomp_or_statement()
            else:
                stmt = c_ast.EmptyStatement(self._tok_coord(name_tok))
            return c_ast.Label(name_tok.value, stmt, self._tok_coord(name_tok))
        case "CASE":
            case_tok = self._advance()
            expr = self._parse_constant_expression()
            self._expect("COLON")
            if self._starts_statement():
                stmt = self._parse_pragmacomp_or_statement()
            else:
                stmt = c_ast.EmptyStatement(self._tok_coord(case_tok))
            return c_ast.Case(expr, [stmt], self._tok_coord(case_tok))
        case "DEFAULT":
            def_tok = self._advance()
            self._expect("COLON")
            if self._starts_statement():
                stmt = self._parse_pragmacomp_or_statement()
            else:
                stmt = c_ast.EmptyStatement(self._tok_coord(def_tok))
            return c_ast.Default([stmt], self._tok_coord(def_tok))
        case _:
            self._parse_error("Invalid labeled statement", self.clex.filename)

def coerce_to_array(
    values, mask=None, copy: bool = False
) -> tuple[np.ndarray, np.ndarray]:
    """
    Coerce the input values array to numpy arrays with a mask.

    Parameters
    ----------
    values : 1D list-like
    mask : bool 1D array, optional
    copy : bool, default False
        if True, copy the input

    Returns
    -------
    tuple of (values, mask)
    """
    if isinstance(values, BooleanArray):
        if mask is not None:
            raise ValueError("cannot pass mask for BooleanArray input")
        values, mask = values._data, values._mask
        if copy:
            values = values.copy()
            mask = mask.copy()
        return values, mask

    mask_values = None
    if isinstance(values, np.ndarray) and values.dtype == np.bool_:
        if copy:
            values = values.copy()
    elif isinstance(values, np.ndarray) and values.dtype.kind in "iufcb":
        mask_values = isna(values)

        values_bool = np.zeros(len(values), dtype=bool)
        values_bool[~mask_values] = values[~mask_values].astype(bool)

        if not np.all(
            values_bool[~mask_values].astype(values.dtype) == values[~mask_values]
        ):
            raise TypeError("Need to pass bool-like values")

        values = values_bool
    else:
        values_object = np.asarray(values, dtype=object)

        inferred_dtype = lib.infer_dtype(values_object, skipna=True)
        integer_like = ("floating", "integer", "mixed-integer-float")
        if inferred_dtype not in ("boolean", "empty", *integer_like):
            raise TypeError("Need to pass bool-like values")

        # mypy does not narrow the type of mask_values to npt.NDArray[np.bool_]
        # within this branch, it assumes it can also be None
        mask_values = cast("npt.NDArray[np.bool_]", isna(values_object))
        values = np.zeros(len(values), dtype=bool)
        values[~mask_values] = values_object[~mask_values].astype(bool)

        # if the values were integer-like, validate it were actually 0/1's
        if (inferred_dtype in integer_like) and not (
            np.all(
                values[~mask_values].astype(float)
                == values_object[~mask_values].astype(float)
            )
        ):
            raise TypeError("Need to pass bool-like values")

    if mask is None and mask_values is None:
        mask = np.zeros(values.shape, dtype=bool)
    elif mask is None:
        mask = mask_values
    elif isinstance(mask, np.ndarray) and mask.dtype == np.bool_:
        if mask_values is not None:
            mask = mask | mask_values
        elif copy:
            mask = mask.copy()
    else:
        mask = np.array(mask, dtype=bool)
        if mask_values is not None:
            mask = mask | mask_values

    if values.shape != mask.shape:
        raise ValueError("values.shape and mask.shape must match")

    return values, mask

def get_num_heads_and_hidden_size(self, reshape_q: NodeProto) -> tuple[int, int]:
    """Detect num_heads and hidden_size from a reshape node.

    Args:
        reshape_q (NodeProto): reshape node for Q

    Returns:
        Tuple[int, int]: num_heads and hidden_size
    """
    # we assume that reshape fusion has done, so the shape is a tensor like [0, 0, num_heads, head_size]
    q_shape_value = self.model.get_constant_value(reshape_q.input[1])
    if q_shape_value is None:
        concat = self.model.get_parent(reshape_q, 1)
        if concat is not None and concat.op_type == "Concat":
            return self.get_num_heads_and_hidden_size_from_concat(concat)
        logger.debug("%s is not initializer.", reshape_q.input[1])
        return self.num_heads, self.hidden_size  # Fall back to user specified value

    if (
        (not isinstance(q_shape_value, np.ndarray))
        or len(q_shape_value) != 4
        or (q_shape_value[2] <= 0 or q_shape_value[3] <= 0)
    ):
        logger.debug("q_shape_value=%s. Expected value are like [0, 0, num_heads, head_size].", q_shape_value)
        return self.num_heads, self.hidden_size  # Fall back to user specified value

    num_heads = q_shape_value[2]
    head_size = q_shape_value[3]
    hidden_size = num_heads * head_size

    if self.num_heads > 0 and num_heads != self.num_heads:
        if self.num_heads_warning:
            logger.warning(
                "--num_heads is %d. Detected value is %d. Using detected value.", self.num_heads, num_heads
            )
            self.num_heads_warning = False  # Do not show the warning more than once

    if self.hidden_size > 0 and hidden_size != self.hidden_size:
        if self.hidden_size_warning:
            logger.warning(
                "--hidden_size is %d. Detected value is %d. Using detected value.", self.hidden_size, hidden_size
            )
            self.hidden_size_warning = False  # Do not show the warning more than once

    return num_heads, hidden_size

def _parse_compound_statement(self) -> c_ast.Node:
    lbrace_tok = self._expect("LBRACE")
    if self._accept("RBRACE"):
        return c_ast.Compound(block_items=None, coord=self._tok_coord(lbrace_tok))
    block_items = self._parse_block_item_list()
    self._expect("RBRACE")
    return c_ast.Compound(
        block_items=block_items, coord=self._tok_coord(lbrace_tok)
    )

def valid_contextj(label: str, pos: int) -> bool:
    cp_value = ord(label[pos])

    if cp_value == 0x200c:

        if pos > 0:
            if _combining_class(ord(label[pos - 1])) == _virama_combining_class:
                return True

        ok = False
        for i in range(pos-1, -1, -1):
            joining_type = idnadata.joining_types.get(ord(label[i]))
            if joining_type == ord('T'):
                continue
            elif joining_type in [ord('L'), ord('D')]:
                ok = True
                break
            else:
                break

        if not ok:
            return False

        ok = False
        for i in range(pos+1, len(label)):
            joining_type = idnadata.joining_types.get(ord(label[i]))
            if joining_type == ord('T'):
                continue
            elif joining_type in [ord('R'), ord('D')]:
                ok = True
                break
            else:
                break
        return ok

    if cp_value == 0x200d:

        if pos > 0:
            if _combining_class(ord(label[pos - 1])) == _virama_combining_class:
                return True
        return False

    else:

        return False

def getpath(self, testfile):
    folder = os.path.dirname(sys.modules[self.__module__].__file__)
    return os.path.join(folder, "data", testfile)

def query(self) -> "MultiMapping[str]":
    """A multidict with all the variables in the query string."""
    return self._rel_url.query

def content_type(self):
    """String held in the ``ContentType`` attribute of this ``<Default>``
    element."""
    return self.get("ContentType")

def set_batch_size(feature: FeatureType) -> None:
    nonlocal batch_size
    if isinstance(feature, Image) and config.ARROW_RECORD_BATCH_SIZE_FOR_IMAGE_DATASETS is not None:
        batch_size = min(batch_size, config.ARROW_RECORD_BATCH_SIZE_FOR_IMAGE_DATASETS)
    elif isinstance(feature, Audio) and config.ARROW_RECORD_BATCH_SIZE_FOR_AUDIO_DATASETS is not None:
        batch_size = min(batch_size, config.ARROW_RECORD_BATCH_SIZE_FOR_AUDIO_DATASETS)
    elif isinstance(feature, Video) and config.ARROW_RECORD_BATCH_SIZE_FOR_VIDEO_DATASETS is not None:
        batch_size = min(batch_size, config.ARROW_RECORD_BATCH_SIZE_FOR_VIDEO_DATASETS)
    elif (
        isinstance(feature, Value)
        and feature.dtype == "binary"
        and config.ARROW_RECORD_BATCH_SIZE_FOR_BINARY_DATASETS is not None
    ):
        batch_size = min(batch_size, config.ARROW_RECORD_BATCH_SIZE_FOR_BINARY_DATASETS)

def _eval_is_irrational(self):
    for t in self.args:
        a = t.is_irrational
        if a:
            others = list(self.args)
            others.remove(t)
            if all((x.is_rational and fuzzy_not(x.is_zero)) is True for x in others):
                return True
            return
        if a is None:
            return
    if all(x.is_real for x in self.args):
        return False

def parse_opts(self, argv, ignore_unknown=[]):
    posargs = []
    passthru_options = []
    for a in argv:
        orig_a = a
        if not a.startswith("--"):
            posargs.append(a)
            continue
        a = a[2:]
        i = a.find("=")
        op = "="
        if i == -1:
            if a.startswith("no-"):
                k = a[3:]
                if k == "canonical-order":
                    # reorderTables=None is faster than False (the latter
                    # still reorders to "keep" the original table order)
                    v = None
                else:
                    v = False
            else:
                k = a
                v = True
            if k.endswith("?"):
                k = k[:-1]
                v = "?"
        else:
            k = a[:i]
            if k[-1] in "-+":
                op = k[-1] + "="  # Op is '-=' or '+=' now.
                k = k[:-1]
            v = a[i + 1 :]
        ok = k
        k = k.replace("-", "_")
        if not hasattr(self, k):
            if ignore_unknown is True or ok in ignore_unknown:
                passthru_options.append(orig_a)
                continue
            else:
                raise self.UnknownOptionError("Unknown option '%s'" % a)

        ov = getattr(self, k)
        if v == "?":
            print("Current setting for '%s' is: %s" % (ok, ov))
            continue
        if isinstance(ov, bool):
            v = bool(v)
        elif isinstance(ov, int):
            v = int(v)
        elif isinstance(ov, str):
            v = str(v)  # redundant
        elif isinstance(ov, list):
            if isinstance(v, bool):
                raise self.OptionError(
                    "Option '%s' requires values to be specified using '='" % a
                )
            vv = v.replace(",", " ").split()
            if vv == [""]:
                vv = []
            vv = [int(x, 0) if len(x) and x[0] in "0123456789" else x for x in vv]
            if op == "=":
                v = vv
            elif op == "+=":
                v = ov
                v.extend(vv)
            elif op == "-=":
                v = ov
                for x in vv:
                    if x in v:
                        v.remove(x)
            else:
                assert False

        setattr(self, k, v)

    return posargs + passthru_options

def __lt__(self, other):
    'True if all counts in self are a proper subset of those in other.'
    if not isinstance(other, Counter):
        return NotImplemented
    return self <= other and self != other

def readLocationElement(self, locationElement):
    """Read a ``<location>`` element.

    .. versionchanged:: 5.0
       Return a tuple of (designLocation, userLocation)
    """
    if self._strictAxisNames and not self.documentObject.axes:
        raise DesignSpaceDocumentError("No axes defined")
    userLoc = {}
    designLoc = {}
    for dimensionElement in locationElement.findall(".dimension"):
        dimName = dimensionElement.attrib.get("name")
        if self._strictAxisNames and dimName not in self.axisDefaults:
            # In case the document contains no axis definitions,
            self.log.warning('Location with undefined axis: "%s".', dimName)
            continue
        userValue = xValue = yValue = None
        try:
            userValue = dimensionElement.attrib.get("uservalue")
            if userValue is not None:
                userValue = float(userValue)
        except ValueError:
            self.log.warning(
                "ValueError in readLocation userValue %3.3f", userValue
            )
        try:
            xValue = dimensionElement.attrib.get("xvalue")
            if xValue is not None:
                xValue = float(xValue)
        except ValueError:
            self.log.warning("ValueError in readLocation xValue %3.3f", xValue)
        try:
            yValue = dimensionElement.attrib.get("yvalue")
            if yValue is not None:
                yValue = float(yValue)
        except ValueError:
            self.log.warning("ValueError in readLocation yValue %3.3f", yValue)
        if userValue is None == xValue is None:
            raise DesignSpaceDocumentError(
                f'Exactly one of uservalue="" or xvalue="" must be provided for location dimension "{dimName}"'
            )
        if yValue is not None:
            if xValue is None:
                raise DesignSpaceDocumentError(
                    f'Missing xvalue="" for the location dimension "{dimName}"" with yvalue="{yValue}"'
                )
            designLoc[dimName] = (xValue, yValue)
        elif xValue is not None:
            designLoc[dimName] = xValue
        else:
            userLoc[dimName] = userValue
    return designLoc, userLoc

def _pattern_permute(
    self, basic_pattern: str, options: str, basic_result: int
) -> list[tuple[str, int]]:
    """Takes a basic pattern and its result and clones
    the pattern according to the modifications described in the $options
    parameter. It returns a list of all cloned patterns."""
    patterns = [(basic_pattern, basic_result)]

    # rotations
    if "4" in options:
        res = patterns[-1][1]
        for i in range(4):
            patterns.append(
                (self._string_permute(patterns[-1][0], ROTATION_MATRIX), res)
            )
    # mirror
    if "M" in options:
        n = len(patterns)
        for pattern, res in patterns[:n]:
            patterns.append((self._string_permute(pattern, MIRROR_MATRIX), res))

    # negate
    if "N" in options:
        n = len(patterns)
        for pattern, res in patterns[:n]:
            # Swap 0 and 1
            pattern = pattern.replace("0", "Z").replace("1", "0").replace("Z", "1")
            res = 1 - int(res)
            patterns.append((pattern, res))

    return patterns

def __add__(p1, p2):
    """Add two polynomials.

    Examples
    ========

    >>> from sympy.polys.domains import ZZ
    >>> from sympy.polys.rings import ring

    >>> _, x, y = ring('x, y', ZZ)
    >>> (x + y)**2 + (x - y)**2
    2*x**2 + 2*y**2

    """
    if not p2:
        return p1.copy()
    ring = p1.ring
    if ring.is_element(p2):
        p = p1.copy()
        get = p.get
        zero = ring.domain.zero
        for k, v in p2.items():
            v = get(k, zero) + v
            if v:
                p[k] = v
            else:
                del p[k]
        return p
    elif isinstance(p2, PolyElement):
        if isinstance(ring.domain, PolynomialRing) and ring.domain.ring == p2.ring:
            pass
        elif isinstance(p2.ring.domain, PolynomialRing) and p2.ring.domain.ring == ring:
            return p2.__radd__(p1)
        else:
            return NotImplemented

    try:
        cp2 = ring.domain_new(p2)
    except CoercionFailed:
        return NotImplemented
    else:
        p = p1.copy()
        if not cp2:
            return p
        zm = ring.zero_monom
        if zm not in p1.keys():
            p[zm] = cp2
        else:
            if p2 == -p[zm]:
                del p[zm]
            else:
                p[zm] += cp2
        return p

def _parse_content_type(self) -> None:
    if not hasattr(self, "_parsed_content_type"):
        self._parsed_content_type = http.parse_options_header(self.content_type)

def __init__(
    self,
    frame: "Frame",
    selector: str,
    has_text: Union[str, Pattern[str]] = None,
    has_not_text: Union[str, Pattern[str]] = None,
    has: "Locator" = None,
    has_not: "Locator" = None,
    visible: bool = None,
) -> None:
    self._frame = frame
    self._selector = selector
    self._loop = frame._loop
    self._dispatcher_fiber = frame._connection._dispatcher_fiber

    if has_text:
        self._selector += f" >> internal:has-text={escape_for_text_selector(has_text, exact=False)}"

    if has:
        if has._frame != frame:
            raise Error('Inner "has" locator must belong to the same frame.')
        self._selector += " >> internal:has=" + json.dumps(
            has._selector, ensure_ascii=False
        )

    if has_not_text:
        self._selector += f" >> internal:has-not-text={escape_for_text_selector(has_not_text, exact=False)}"

    if has_not:
        locator = has_not
        if locator._frame != frame:
            raise Error('Inner "has_not" locator must belong to the same frame.')
        self._selector += " >> internal:has-not=" + json.dumps(locator._selector)

    if visible is not None:
        self._selector += f" >> visible={bool_to_js_bool(visible)}"

def request_chunked(self, method, url, body=None, headers=None):
    """
    Alternative to the common request method, which sends the
    body with chunked encoding and not as one block
    """
    headers = headers or {}
    header_keys = set([six.ensure_str(k.lower()) for k in headers])
    skip_accept_encoding = "accept-encoding" in header_keys
    skip_host = "host" in header_keys
    self.putrequest(
        method, url, skip_accept_encoding=skip_accept_encoding, skip_host=skip_host
    )
    if "user-agent" not in header_keys:
        self.putheader("User-Agent", _get_default_user_agent())
    for header, value in headers.items():
        self.putheader(header, value)
    if "transfer-encoding" not in header_keys:
        self.putheader("Transfer-Encoding", "chunked")
    self.endheaders()

    if body is not None:
        stringish_types = six.string_types + (bytes,)
        if isinstance(body, stringish_types):
            body = (body,)
        for chunk in body:
            if not chunk:
                continue
            if not isinstance(chunk, bytes):
                chunk = chunk.encode("utf8")
            len_str = hex(len(chunk))[2:]
            to_send = bytearray(len_str.encode())
            to_send += b"\r\n"
            to_send += chunk
            to_send += b"\r\n"
            self.send(to_send)

    # After the if clause, to always have a closed body
    self.send(b"0\r\n\r\n")

def _push_indices_up(cls, diagonal_indices, indices, rank):
    positions, shape = cls._get_positions_shape(range(rank), diagonal_indices)

    def transform(x):
        for i, e in enumerate(positions):
            if (isinstance(e, int) and x == e) or (isinstance(e, (tuple, Tuple)) and (x in e)):
                return i

    return _apply_recursively_over_nested_lists(transform, indices)

def parseImpl(self, instring, loc, doActions=True):
    if col(loc, instring) == 1:
        return loc, []
    raise ParseException(instring, loc, self.errmsg, self)

def _prune_post_subset(self, font):
    tableTags = font.keys()
    # Prune the name table last because when we're pruning the name table,
    # we visit each table in the font to see what name table records are
    # still in use.
    if "name" in tableTags:
        tableTags.remove("name")
        tableTags.append("name")
    for tag in tableTags:
        if tag == "GlyphOrder":
            continue
        if tag == "OS/2":
            if self.options.prune_unicode_ranges:
                old_uniranges = font[tag].getUnicodeRanges()
                new_uniranges = font[tag].recalcUnicodeRanges(font, pruneOnly=True)
                if old_uniranges != new_uniranges:
                    log.info(
                        "%s Unicode ranges pruned: %s", tag, sorted(new_uniranges)
                    )
            if self.options.prune_codepage_ranges and font[tag].version >= 1:
                # codepage range fields were added with OS/2 format 1
                # https://learn.microsoft.com/en-us/typography/opentype/spec/os2#version-1
                old_codepages = font[tag].getCodePageRanges()
                new_codepages = font[tag].recalcCodePageRanges(font, pruneOnly=True)
                if old_codepages != new_codepages:
                    log.info(
                        "%s CodePage ranges pruned: %s",
                        tag,
                        sorted(new_codepages),
                    )
            if self.options.recalc_average_width:
                old_avg_width = font[tag].xAvgCharWidth
                new_avg_width = font[tag].recalcAvgCharWidth(font)
                if old_avg_width != new_avg_width:
                    log.info("%s xAvgCharWidth updated: %d", tag, new_avg_width)
            if self.options.recalc_max_context:
                max_context = maxCtxFont(font)
                if max_context != font[tag].usMaxContext:
                    font[tag].usMaxContext = max_context
                    log.info("%s usMaxContext updated: %d", tag, max_context)
        clazz = ttLib.getTableClass(tag)
        if hasattr(clazz, "prune_post_subset"):
            with timer("prune '%s'" % tag):
                table = font[tag]
                retain = table.prune_post_subset(font, self.options)
            if not retain:
                log.info("%s pruned to empty; dropped", tag)
                del font[tag]
            else:
                log.info("%s pruned", tag)

def _together(expr):
    if isinstance(expr, Basic):
        if expr.is_Atom or (expr.is_Function and not deep):
            return expr
        elif expr.is_Add:
            return gcd_terms(list(map(_together, Add.make_args(expr))), fraction=fraction)
        elif expr.is_Pow:
            base = _together(expr.base)

            if deep:
                exp = _together(expr.exp)
            else:
                exp = expr.exp

            return expr.func(base, exp)
        else:
            return expr.func(*[ _together(arg) for arg in expr.args ])
    elif iterable(expr):
        return expr.__class__([ _together(ex) for ex in expr ])

    return expr

def _validate_color_or_linecolor(s):
    if cbook._str_equal(s, 'linecolor'):
        return s
    elif cbook._str_equal(s, 'mfc') or cbook._str_equal(s, 'markerfacecolor'):
        return 'markerfacecolor'
    elif cbook._str_equal(s, 'mec') or cbook._str_equal(s, 'markeredgecolor'):
        return 'markeredgecolor'
    elif s is None:
        return None
    elif isinstance(s, str) and len(s) == 6 or len(s) == 8:
        stmp = '#' + s
        if is_color_like(stmp):
            return stmp
        if s.lower() == 'none':
            return None
    elif is_color_like(s):
        return s

    raise ValueError(f'{s!r} does not look like a color arg')

def __init__(self, *args, **kwargs):
    raise TypeError(
        f"{self.__class__.__name__} does not have a public "
        f"constructor. Instances are returned by SSLContext.wrap_bio()."
    )

def postParse(self, instring, loc, tokenlist):
    for i, tok in enumerate(tokenlist):
        if len(tok) == 0:
            continue

        ikey = tok[0]
        if isinstance(ikey, int):
            ikey = str(ikey).strip()

        if len(tok) == 1:
            tokenlist[ikey] = _ParseResultsWithOffset("", i)

        elif len(tok) == 2 and not isinstance(tok[1], ParseResults):
            tokenlist[ikey] = _ParseResultsWithOffset(tok[1], i)

        else:
            try:
                dictvalue = tok.copy()  # ParseResults(i)
            except Exception:
                exc = TypeError(
                    "could not extract dict values from parsed results"
                    " - Dict expression must contain Grouped expressions"
                )
                raise exc from None

            del dictvalue[0]

            if len(dictvalue) != 1 or (
                isinstance(dictvalue, ParseResults) and dictvalue.haskeys()
            ):
                tokenlist[ikey] = _ParseResultsWithOffset(dictvalue, i)
            else:
                tokenlist[ikey] = _ParseResultsWithOffset(dictvalue[0], i)

    if self._asPythonDict:
        return [tokenlist.as_dict()] if self.resultsName else tokenlist.as_dict()
    else:
        return [tokenlist] if self.resultsName else tokenlist

def get_editor(self) -> str:
    if self.editor is not None:
        return self.editor
    for key in "VISUAL", "EDITOR":
        rv = os.environ.get(key)
        if rv:
            return rv
    if WIN:
        return "notepad"
    for editor in "sensible-editor", "vim", "nano":
        if os.system(f"which {editor} >/dev/null 2>&1") == 0:
            return editor
    return "vi"

def asdict(self):
    d = {}
    for attr, value in self.__dict__.items():
        if attr.startswith("_"):
            continue
        if hasattr(value, "asdict"):
            value = value.asdict()
        elif isinstance(value, list):
            value = [v.asdict() if hasattr(v, "asdict") else v for v in value]
        d[attr] = value
    return d

def _convert_expr_from_c(self, tp, var, context):
    if isinstance(tp, model.BasePrimitiveType):
        if tp.is_integer_type() and tp.name != '_Bool':
            return '_cffi_from_c_int(%s, %s)' % (var, tp.name)
        elif isinstance(tp, model.UnknownFloatType):
            return '_cffi_from_c_double(%s)' % (var,)
        elif tp.name != 'long double' and not tp.is_complex_type():
            cname = tp.name.replace(' ', '_')
            if cname in ('char16_t', 'char32_t'):
                self.needs_version(VERSION_CHAR16CHAR32)
            return '_cffi_from_c_%s(%s)' % (cname, var)
        else:
            return '_cffi_from_c_deref((char *)&%s, _cffi_type(%d))' % (
                var, self._gettypenum(tp))
    elif isinstance(tp, (model.PointerType, model.FunctionPtrType)):
        return '_cffi_from_c_pointer((char *)%s, _cffi_type(%d))' % (
            var, self._gettypenum(tp))
    elif isinstance(tp, model.ArrayType):
        return '_cffi_from_c_pointer((char *)%s, _cffi_type(%d))' % (
            var, self._gettypenum(model.PointerType(tp.item)))
    elif isinstance(tp, model.StructOrUnion):
        if tp.fldnames is None:
            raise TypeError("'%s' is used as %s, but is opaque" % (
                tp._get_c_name(), context))
        return '_cffi_from_c_struct((char *)&%s, _cffi_type(%d))' % (
            var, self._gettypenum(tp))
    elif isinstance(tp, model.EnumType):
        return '_cffi_from_c_deref((char *)&%s, _cffi_type(%d))' % (
            var, self._gettypenum(tp))
    else:
        raise NotImplementedError(tp)

def wrapper(*args):
    nonlocal found_arity, limit
    while 1:
        try:
            ret = func(*args[limit:])
            found_arity = True
            return ret
        except TypeError as te:
            # re-raise TypeErrors if they did not come from our arity testing
            if found_arity:
                raise
            else:
                tb = te.__traceback__
                frames = traceback.extract_tb(tb, limit=2)
                frame_summary = frames[-1]
                trim_arity_type_error = (
                    [frame_summary[:2]][-1][:2] == pa_call_line_synth
                )
                del tb

                if trim_arity_type_error:
                    if limit < max_limit:
                        limit += 1
                        continue

                raise

def get_all_fig_managers(cls):
    """Return a list of figure managers."""
    return list(cls.figs.values())

def equals(self, other, failing_expression=False):
    """Return True if the sides of the relationship are mathematically
    identical and the type of relationship is the same.
    If failing_expression is True, return the expression whose truth value
    was unknown."""
    if isinstance(other, Relational):
        if other in (self, self.reversed):
            return True
        a, b = self, other
        if a.func in (Eq, Ne) or b.func in (Eq, Ne):
            if a.func != b.func:
                return False
            left, right = [i.equals(j,
                                    failing_expression=failing_expression)
                           for i, j in zip(a.args, b.args)]
            if left is True:
                return right
            if right is True:
                return left
            lr, rl = [i.equals(j, failing_expression=failing_expression)
                      for i, j in zip(a.args, b.reversed.args)]
            if lr is True:
                return rl
            if rl is True:
                return lr
            e = (left, right, lr, rl)
            if all(i is False for i in e):
                return False
            for i in e:
                if i not in (True, False):
                    return i
        else:
            if b.func != a.func:
                b = b.reversed
            if a.func != b.func:
                return False
            left = a.lhs.equals(b.lhs,
                                failing_expression=failing_expression)
            if left is False:
                return False
            right = a.rhs.equals(b.rhs,
                                 failing_expression=failing_expression)
            if right is False:
                return False
            if left is True:
                return right
            return left

def unescape_byte_(match, encoding):
    n = match.group(0)[1:]
    return bytechr(int(n, 16)).decode(encoding)

def subset_glyphs(self, s):
    table = self.table

    used = set()
    advIdxes_ = set()
    retainAdvMap = False

    if table.AdvWidthMap:
        table.AdvWidthMap.mapping = _dict_subset(table.AdvWidthMap.mapping, s.glyphs)
        used.update(table.AdvWidthMap.mapping.values())
    else:
        used.update(s.reverseOrigGlyphMap.values())
        advIdxes_ = used.copy()
        retainAdvMap = s.options.retain_gids

    if table.LsbMap:
        table.LsbMap.mapping = _dict_subset(table.LsbMap.mapping, s.glyphs)
        used.update(table.LsbMap.mapping.values())
    if table.RsbMap:
        table.RsbMap.mapping = _dict_subset(table.RsbMap.mapping, s.glyphs)
        used.update(table.RsbMap.mapping.values())

    varidx_map = table.VarStore.subset_varidxes(
        used, retainFirstMap=retainAdvMap, advIdxes=advIdxes_
    )

    if table.AdvWidthMap:
        table.AdvWidthMap.mapping = _remap_index_map(s, varidx_map, table.AdvWidthMap)
    if table.LsbMap:
        table.LsbMap.mapping = _remap_index_map(s, varidx_map, table.LsbMap)
    if table.RsbMap:
        table.RsbMap.mapping = _remap_index_map(s, varidx_map, table.RsbMap)

    # TODO Return emptiness...
    return True

def alt_screen(cls, enable: bool) -> "Control":
    """Enable or disable alt screen."""
    if enable:
        return cls(ControlType.ENABLE_ALT_SCREEN, ControlType.HOME)
    else:
        return cls(ControlType.DISABLE_ALT_SCREEN)

def parse_table_hhea_(self, table):
    statements = table.statements
    fields = ("CaretOffset", "Ascender", "Descender", "LineGap")
    while self.next_token_ != "}" or self.cur_comments_:
        self.advance_lexer_(comments=True)
        if self.cur_token_type_ is Lexer.COMMENT:
            statements.append(
                self.ast.Comment(self.cur_token_, location=self.cur_token_location_)
            )
        elif self.cur_token_type_ is Lexer.NAME and self.cur_token_ in fields:
            key = self.cur_token_.lower()
            value = self.expect_number_()
            statements.append(
                self.ast.HheaField(key, value, location=self.cur_token_location_)
            )
            if self.next_token_ != ";":
                raise FeatureLibError(
                    "Incomplete statement", self.next_token_location_
                )
        elif self.cur_token_ == ";":
            continue
        else:
            raise FeatureLibError(
                "Expected CaretOffset, Ascender, " "Descender or LineGap",
                self.cur_token_location_,
            )

def format_ticks(self, values):
    # docstring inherited
    r_mapping = {v: self._text(k) for k, v in self._units.items()}
    return [r_mapping.get(round(val), '') for val in values]

def conjugates(self, R):
    R_c = list(chain.from_iterable((rel.cyclic_conjugates(), \
            (rel**-1).cyclic_conjugates()) for rel in R))
    R_set = set()
    for conjugate in R_c:
        R_set = R_set.union(conjugate)
    R_c_list = []
    for x in self.A:
        r = {word for word in R_set if word[0] == x}
        R_c_list.append(r)
        R_set.difference_update(r)
    return R_c_list

def _reject_duplicate_attribute(
    oid: ObjectIdentifier,
    attributes: typing.List[
        typing.Tuple[ObjectIdentifier, bytes, typing.Optional[int]]
    ],
) -> None:
    # This is quadratic in the number of attributes
    for attr_oid, _, _ in attributes:
        if attr_oid == oid:
            raise ValueError("This attribute has already been set.")

def parseImpl(self, instring, loc, doActions=True):
    if instring[loc] not in self.initChars:
        raise ParseException(instring, loc, self.errmsg, self)

    start = loc
    loc += 1
    instrlen = len(instring)
    bodychars = self.bodyChars
    maxloc = start + self.maxLen
    maxloc = min(maxloc, instrlen)
    while loc < maxloc and instring[loc] in bodychars:
        loc += 1

    throwException = False
    if loc - start < self.minLen:
        throwException = True
    elif self.maxSpecified and loc < instrlen and instring[loc] in bodychars:
        throwException = True
    elif self.asKeyword:
        if (
            start > 0
            and instring[start - 1] in bodychars
            or loc < instrlen
            and instring[loc] in bodychars
        ):
            throwException = True

    if throwException:
        raise ParseException(instring, loc, self.errmsg, self)

    return loc, instring[start:loc]

def __init__(
    self,
    app: WSGIApplication,
    exports: (
        cabc.Mapping[str, str | tuple[str, str]]
        | t.Iterable[tuple[str, str | tuple[str, str]]]
    ),
    disallow: None = None,
    cache: bool = True,
    cache_timeout: int = 60 * 60 * 12,
    fallback_mimetype: str = "application/octet-stream",
) -> None:
    self.app = app
    self.exports: list[tuple[str, _TLoader]] = []
    self.cache = cache
    self.cache_timeout = cache_timeout

    if isinstance(exports, cabc.Mapping):
        exports = exports.items()

    for key, value in exports:
        if isinstance(value, tuple):
            loader = self.get_package_loader(*value)
        elif isinstance(value, str):
            if os.path.isfile(value):
                loader = self.get_file_loader(value)
            else:
                loader = self.get_directory_loader(value)
        else:
            raise TypeError(f"unknown def {value!r}")

        self.exports.append((key, loader))

    if disallow is not None:
        from fnmatch import fnmatch

        self.is_allowed = lambda x: not fnmatch(x, disallow)

    self.fallback_mimetype = fallback_mimetype

def _write_c_min(self, min_val) -> None:
    # Write the <c:min> element.

    if min_val is None:
        return

    attributes = [("val", min_val)]

    self._xml_empty_tag("c:min", attributes)

def _cdist_callable(XA, XB, *, out, metric, **kwargs):
    mA = XA.shape[0]
    mB = XB.shape[0]
    dm = _prepare_out_argument(out, np.float64, (mA, mB))
    for i in range(mA):
        for j in range(mB):
            dm[i, j] = metric(XA[i], XB[j], **kwargs)
    return dm

def index(self, gen):
    """Compute index of ``gen`` in ``self.gens``. """
    if gen is None:
        if self.ngens:
            i = 0
        else:
            i = -1  # indicate impossible choice
    elif isinstance(gen, int):
        i = gen

        if 0 <= i and i < self.ngens:
            pass
        elif -self.ngens <= i and i <= -1:
            i = -i - 1
        else:
            raise ValueError("invalid generator index: %s" % gen)
    elif self.is_element(gen):
        try:
            i = self.gens.index(gen)
        except ValueError:
            raise ValueError("invalid generator: %s" % gen)
    elif isinstance(gen, str):
        try:
            i = self.symbols.index(gen)
        except ValueError:
            raise ValueError("invalid generator: %s" % gen)
    else:
        raise ValueError("expected a polynomial generator, an integer, a string or None, got %s" % gen)

    return i

def _parse_direct_abstract_declarator(self) -> c_ast.Node:
    lparen_tok = self._accept("LPAREN")
    if lparen_tok:
        if self._starts_declaration() or self._peek_type() == "RPAREN":
            params = self._parse_parameter_type_list_opt()
            self._expect("RPAREN")
            decl = c_ast.FuncDecl(
                args=params,
                type=c_ast.TypeDecl(None, None, None, None),
                coord=self._tok_coord(lparen_tok),
            )
        else:
            decl = self._parse_abstract_declarator_opt()
            self._expect("RPAREN")
            assert decl is not None
    elif self._peek_type() == "LBRACKET":
        decl = self._parse_abstract_array_base()
    else:
        self._parse_error("Invalid abstract declarator", self.clex.filename)

    return self._parse_decl_suffixes(decl)

def __del__(self):
    if self._state == futures._PENDING and self._log_destroy_pending:
        context = {
            'task': self,
            'message': 'Task was destroyed but it is pending!',
        }
        if self._source_traceback:
            context['source_traceback'] = self._source_traceback
        self._loop.call_exception_handler(context)
    super().__del__()

def argmax(self, axis: AxisInt = 0, skipna: bool = True):  # type: ignore[override]
    # override base class by adding axis keyword
    validate_bool_kwarg(skipna, "skipna")
    if not skipna and self._hasna:
        raise ValueError("Encountered an NA value with skipna=False")
    return nargminmax(self, "argmax", axis=axis)

def _interpolate_some(self, parser, option, accum, rest, section, map,
                      depth):
    rawval = parser.get(section, option, raw=True, fallback=rest)
    if depth > MAX_INTERPOLATION_DEPTH:
        raise InterpolationDepthError(option, section, rawval)
    while rest:
        p = rest.find("%")
        if p < 0:
            accum.append(rest)
            return
        if p > 0:
            accum.append(rest[:p])
            rest = rest[p:]
        # p is no longer used
        c = rest[1:2]
        if c == "%":
            accum.append("%")
            rest = rest[2:]
        elif c == "(":
            m = self._KEYCRE.match(rest)
            if m is None:
                raise InterpolationSyntaxError(option, section,
                    "bad interpolation variable reference %r" % rest)
            var = parser.optionxform(m.group(1))
            rest = rest[m.end():]
            try:
                v = map[var]
            except KeyError:
                raise InterpolationMissingOptionError(
                    option, section, rawval, var) from None
            if "%" in v:
                self._interpolate_some(parser, option, accum, v,
                                       section, map, depth + 1)
            else:
                accum.append(v)
        else:
            raise InterpolationSyntaxError(
                option, section,
                "'%%' must be followed by '%%' or '(', "
                "found: %r" % (rest,))

def _scan_declarator_name_info(self) -> Tuple[Optional[str], bool]:
    saw_paren = False
    while self._accept("TIMES"):
        while self._peek_type() in _TYPE_QUALIFIER:
            self._advance()

    tok = self._peek()
    if tok is None:
        return None, saw_paren
    if tok.type in {"ID", "TYPEID"}:
        self._advance()
        return tok.type, saw_paren
    if tok.type == "LPAREN":
        saw_paren = True
        self._advance()
        tok_type, nested_paren = self._scan_declarator_name_info()
        if nested_paren:
            saw_paren = True
        depth = 1
        while True:
            tok = self._peek()
            if tok is None:
                return None, saw_paren
            if tok.type == "LPAREN":
                depth += 1
            elif tok.type == "RPAREN":
                depth -= 1
                self._advance()
                if depth == 0:
                    break
                continue
            self._advance()
        return tok_type, saw_paren
    return None, saw_paren

def parse(self, vstring):
    # I've given up on thinking I can reconstruct the version string
    # from the parsed tuple -- so I just store the string here for
    # use by __str__
    self.vstring = vstring
    components = [x for x in self.component_re.split(vstring) if x and x != "."]
    for i, obj in enumerate(components):
        try:
            components[i] = int(obj)
        except ValueError:
            pass

    self.version = components

def parse_table_head_(self, table):
    statements = table.statements
    while self.next_token_ != "}" or self.cur_comments_:
        self.advance_lexer_(comments=True)
        if self.cur_token_type_ is Lexer.COMMENT:
            statements.append(
                self.ast.Comment(self.cur_token_, location=self.cur_token_location_)
            )
        elif self.is_cur_keyword_("FontRevision"):
            statements.append(self.parse_FontRevision_())
        elif self.cur_token_ == ";":
            continue
        else:
            raise FeatureLibError("Expected FontRevision", self.cur_token_location_)

def get_or_load_model(self, pipeline, model_name, model_obj, framework_model_dir):
    if model_name in ["clip", "clip2", "unet", "unetxl"] and pipeline:
        if model_name == "clip":
            model = pipeline.text_encoder
            pipeline.text_encoder = None
        elif model_name == "clip2":
            model = pipeline.text_encoder_2
            pipeline.text_encoder_2 = None
        else:
            model = pipeline.unet
            pipeline.unet = None
    else:
        model = model_obj.load_model(framework_model_dir)

    return model.to(self.torch_device)

def _genops(data, yield_end_pos=False):
    if isinstance(data, bytes_types):
        data = io.BytesIO(data)

    if hasattr(data, "tell"):
        getpos = data.tell
    else:
        getpos = lambda: None

    while True:
        pos = getpos()
        code = data.read(1)
        opcode = code2op.get(code.decode("latin-1"))
        if opcode is None:
            if code == b"":
                raise ValueError("pickle exhausted before seeing STOP")
            else:
                raise ValueError("at position %s, opcode %r unknown" % (
                                 "<unknown>" if pos is None else pos,
                                 code))
        if opcode.arg is None:
            arg = None
        else:
            arg = opcode.arg.reader(data)
        if yield_end_pos:
            yield opcode, arg, pos, getpos()
        else:
            yield opcode, arg, pos
        if code == b'.':
            assert opcode.name == 'STOP'
            break

def _check_axes(axes, ndim):
    if axes is None:
        return tuple(range(ndim))
    elif np.isscalar(axes):
        axes = (operator.index(axes),)
    elif isinstance(axes, Iterable):
        for ax in axes:
            axes = tuple(operator.index(ax) for ax in axes)
            if ax < -ndim or ax > ndim - 1:
                raise ValueError(f"specified axis: {ax} is out of range")
        axes = tuple(ax % ndim if ax < 0 else ax for ax in axes)
    else:
        message = "axes must be an integer, iterable of integers, or None"
        raise ValueError(message)
    if len(tuple(set(axes))) != len(axes):
        raise ValueError("axes must be unique")
    return axes

def makeInnerLines(self):
    # inner grid lines
    group = Group()

    w, h = self.width, self.height

    if self.useLines == 1:
        if self.orientation == 'vertical':
            r = self.makeLinePosList(self.x, isX=1)
            for x in r:
                line = Line(x, self.y, x, self.y + h)
                line.strokeColor = self.strokeColor
                line.strokeWidth = self.strokeWidth
                group.add(line)
        elif self.orientation == 'horizontal':
            r = self.makeLinePosList(self.y, isX=0)
            for y in r:
                line = Line(self.x, y, self.x + w, y)
                line.strokeColor = self.strokeColor
                line.strokeWidth = self.strokeWidth
                group.add(line)

    return group

def __init__(self, profile: str | SupportsRead[bytes] | core.CmsProfile) -> None:
    """
    :param profile: Either a string representing a filename,
        a file like object containing a profile or a
        low-level profile object

    """
    self.filename: str | None = None

    if isinstance(profile, str):
        if sys.platform == "win32":
            profile_bytes_path = profile.encode()
            try:
                profile_bytes_path.decode("ascii")
            except UnicodeDecodeError:
                with open(profile, "rb") as f:
                    self.profile = core.profile_frombytes(f.read())
                return
        self.filename = profile
        self.profile = core.profile_open(profile)
    elif hasattr(profile, "read"):
        self.profile = core.profile_frombytes(profile.read())
    elif isinstance(profile, core.CmsProfile):
        self.profile = profile
    else:
        msg = "Invalid type for Profile"  # type: ignore[unreachable]
        raise TypeError(msg)

def _save(im: Image.Image, fp: IO[bytes], filename: str | bytes) -> None:
    if im.mode == "1":
        rawmode, head = "1;I", b"P4"
    elif im.mode == "L":
        rawmode, head = "L", b"P5"
    elif im.mode in ("I", "I;16"):
        rawmode, head = "I;16B", b"P5"
    elif im.mode in ("RGB", "RGBA"):
        rawmode, head = "RGB", b"P6"
    elif im.mode == "F":
        rawmode, head = "F;32F", b"Pf"
    else:
        msg = f"cannot write mode {im.mode} as PPM"
        raise OSError(msg)
    fp.write(head + b"\n%d %d\n" % im.size)
    if head == b"P6":
        fp.write(b"255\n")
    elif head == b"P5":
        if rawmode == "L":
            fp.write(b"255\n")
        else:
            fp.write(b"65535\n")
    elif head == b"Pf":
        fp.write(b"-1.0\n")
    row_order = -1 if im.mode == "F" else 1
    ImageFile._save(
        im, fp, [ImageFile._Tile("raw", (0, 0) + im.size, 0, (rawmode, 0, row_order))]
    )

def __init__(self):
    self.byName = {}
    self.byAlias = {}

def value(self):
    quote = False
    if self.defects:
        quote = True
    else:
        for x in self:
            if x.token_type == 'quoted-string':
                quote = True
    if len(self) != 0 and quote:
        pre = post = ''
        if self[0].token_type=='cfws' or self[0][0].token_type=='cfws':
            pre = ' '
        if self[-1].token_type=='cfws' or self[-1][-1].token_type=='cfws':
            post = ' '
        return pre+quote_string(self.display_name)+post
    else:
        return super().value

def find_cookie(line):
    try:
        # Decode as UTF-8. Either the line is an encoding
        # declaration, in which case it should be pure ASCII, or it
        # must be UTF-8 per default encoding.
        line_string = line.decode('utf-8')
    except UnicodeDecodeError:
        msg = 'invalid or missing encoding declaration'
        if filename is not None:
            msg = '{} for {!r}'.format(msg, filename)
        raise SyntaxError(msg)

    match = cookie_re.match(line_string)
    if not match:
        return None
    encoding = _get_normal_name(match.group(1))
    try:
        lookup(encoding)
    except LookupError:
        # This behaviour mimics the Python interpreter
        if filename is None:
            msg = 'unknown encoding: ' + encoding
        else:
            msg = 'unknown encoding for {!r}: ' '{}'.format(
                filename, encoding
            )
        raise SyntaxError(msg)

    if bom_found:
        if encoding != 'utf-8':
            # This behaviour mimics the Python interpreter
            if filename is None:
                msg = 'encoding problem: utf-8'
            else:
                msg = 'encoding problem for ' '{!r}: utf-8'.format(
                    filename
                )
            raise SyntaxError(msg)
        encoding += '-sig'
    return encoding

def get_local_part(value):
    """ local-part = dot-atom / quoted-string / obs-local-part

    """
    local_part = LocalPart()
    leader = None
    if value[0] in CFWS_LEADER:
        leader, value = get_cfws(value)
    if not value:
        raise errors.HeaderParseError(
            "expected local-part but found '{}'".format(value))
    try:
        token, value = get_dot_atom(value)
    except errors.HeaderParseError:
        try:
            token, value = get_word(value)
        except errors.HeaderParseError:
            if value[0] != '\\' and value[0] in PHRASE_ENDS:
                raise
            token = TokenList()
    if leader is not None:
        token[:0] = [leader]
    local_part.append(token)
    if value and (value[0]=='\\' or value[0] not in PHRASE_ENDS):
        obs_local_part, value = get_obs_local_part(str(local_part) + value)
        if obs_local_part.token_type == 'invalid-obs-local-part':
            local_part.defects.append(errors.InvalidHeaderDefect(
                "local-part is not dot-atom, quoted-string, or obs-local-part"))
        else:
            local_part.defects.append(errors.ObsoleteHeaderDefect(
                "local-part is not a dot-atom (contains CFWS)"))
        local_part[0] = obs_local_part
    try:
        local_part.value.encode('ascii')
    except UnicodeEncodeError:
        local_part.defects.append(errors.NonASCIILocalPartDefect(
                "local-part contains non-ASCII characters)"))
    return local_part, value

def expn(self, address):
    """SMTP 'expn' command -- expands a mailing list."""
    self.putcmd("expn", _addr_only(address))
    return self.getreply()

def parseImpl(self, instring, loc, doActions=True):
    maxExcLoc = -1
    maxException = None

    for e in self.exprs:
        try:
            return e._parse(
                instring,
                loc,
                doActions,
            )
        except ParseFatalException as pfe:
            pfe.__traceback__ = None
            pfe.parser_element = e
            raise
        except ParseException as err:
            if err.loc > maxExcLoc:
                maxException = err
                maxExcLoc = err.loc
        except IndexError:
            if len(instring) > maxExcLoc:
                maxException = ParseException(
                    instring, len(instring), e.errmsg, self
                )
                maxExcLoc = len(instring)

    if maxException is not None:
        # infer from this check that all alternatives failed at the current position
        # so emit this collective error message instead of any individual error message
        if maxExcLoc == loc:
            maxException.msg = self.errmsg
        raise maxException
    else:
        raise ParseException(
            instring, loc, "no defined alternatives to match", self
        )

def headers(self) -> CIMultiDictProxy[str]:
    """A case-insensitive multidict proxy with all headers."""
    return self._headers

def _load_data(cls, name: str) -> type[Any]:
    name = name.replace("\0", "")
    log.debug("loading: %r", name)
    cmap_paths = (
        os.environ.get("CMAP_PATH", "/usr/share/pdfminer/"),
        os.path.join(os.path.dirname(__file__), "cmap"),
    )

    for directory in cmap_paths:
        # Load JSON format (secure)
        json_filename = f"{name}.json.gz"
        json_path = os.path.join(directory, json_filename)
        resolved_json_path = os.path.realpath(json_path)
        resolved_directory = os.path.realpath(directory)

        # Check if resolved path is within the intended directory
        if resolved_json_path.startswith(
            resolved_directory + os.sep
        ) and os.path.exists(resolved_json_path):
            log.debug("loading JSON: %r", json_path)
            with gzip.open(resolved_json_path, "rt", encoding="utf-8") as gzfile:
                data: dict[str, Any] = json.load(gzfile)
                # Convert string keys to integers for CID mappings
                if "CID2UNICHR_H" in data:
                    data["CID2UNICHR_H"] = {
                        int(k): v for k, v in data["CID2UNICHR_H"].items()
                    }
                if "CID2UNICHR_V" in data:
                    data["CID2UNICHR_V"] = {
                        int(k): v for k, v in data["CID2UNICHR_V"].items()
                    }
                # CODE2CID may also have numeric keys that need conversion
                if data.get("CODE2CID"):
                    data["CODE2CID"] = cls._convert_code2cid_keys(data["CODE2CID"])
                return type(str(name), (), data)

    raise CMapDB.CMapNotFound(name)

def __repr__(self):
    info = ['StreamReader']
    if self._buffer:
        info.append(f'{len(self._buffer)} bytes')
    if self._eof:
        info.append('eof')
    if self._limit != _DEFAULT_LIMIT:
        info.append(f'limit={self._limit}')
    if self._waiter:
        info.append(f'waiter={self._waiter!r}')
    if self._exception:
        info.append(f'exception={self._exception!r}')
    if self._transport:
        info.append(f'transport={self._transport!r}')
    if self._paused:
        info.append('paused')
    return '<{}>'.format(' '.join(info))

def open_url(url: str, wait: bool = False, locate: bool = False) -> int:
    import subprocess

    def _unquote_file(url: str) -> str:
        from urllib.parse import unquote

        if url.startswith("file://"):
            url = unquote(url[7:])

        return url

    if sys.platform == "darwin":
        args = ["open"]
        if wait:
            args.append("-W")
        if locate:
            args.append("-R")
        args.append(_unquote_file(url))
        null = open("/dev/null", "w")
        try:
            return subprocess.Popen(args, stderr=null).wait()
        finally:
            null.close()
    elif WIN:
        if locate:
            url = _unquote_file(url.replace('"', ""))
            args = f'explorer /select,"{url}"'
        else:
            url = url.replace('"', "")
            wait_str = "/WAIT" if wait else ""
            args = f'start {wait_str} "" "{url}"'
        return os.system(args)
    elif CYGWIN:
        if locate:
            url = os.path.dirname(_unquote_file(url).replace('"', ""))
            args = f'cygstart "{url}"'
        else:
            url = url.replace('"', "")
            wait_str = "-w" if wait else ""
            args = f'cygstart {wait_str} "{url}"'
        return os.system(args)

    try:
        if locate:
            url = os.path.dirname(_unquote_file(url)) or "."
        else:
            url = _unquote_file(url)
        c = subprocess.Popen(["xdg-open", url])
        if wait:
            return c.wait()
        return 0
    except OSError:
        if url.startswith(("http://", "https://")) and not locate and not wait:
            import webbrowser

            webbrowser.open(url)
            return 0
        return 1

def closure_glyphs(self, s):
    glyphSet = self.glyphs
    decompose = s.glyphs
    while decompose:
        components = set()
        for g in decompose:
            if g not in glyphSet:
                continue
            gl = glyphSet[g]
            for c in gl.getComponentNames(self):
                components.add(c)
        components -= s.glyphs
        s.glyphs.update(components)
        decompose = components

def _ConvertScalarFieldValue(value, field, path, require_str=False):
  """Convert a single scalar field value.

  Args:
    value: A scalar value to convert the scalar field value.
    field: The descriptor of the field to convert.
    path: parent path to log parse error info.
    require_str: If True, the field value must be a str.

  Returns:
    The converted scalar field value

  Raises:
    ParseError: In case of convert problems.
    EnumStringValueParseError: In case of unknown enum string value.
  """
  try:
    if field.cpp_type in _INT_TYPES:
      return _ConvertInteger(value)
    elif field.cpp_type in _FLOAT_TYPES:
      return _ConvertFloat(value, field)
    elif field.cpp_type == descriptor.FieldDescriptor.CPPTYPE_BOOL:
      return _ConvertBool(value, require_str)
    elif field.cpp_type == descriptor.FieldDescriptor.CPPTYPE_STRING:
      if field.type == descriptor.FieldDescriptor.TYPE_BYTES:
        if isinstance(value, str):
          encoded = value.encode('utf-8')
        else:
          encoded = value
        # Add extra padding '='
        padded_value = encoded + b'=' * (4 - len(encoded) % 4)
        return base64.urlsafe_b64decode(padded_value)
      else:
        # Checking for unpaired surrogates appears to be unreliable,
        # depending on the specific Python version, so we check manually.
        if _UNPAIRED_SURROGATE_PATTERN.search(value):
          raise ParseError('Unpaired surrogate')
        return value
    elif field.cpp_type == descriptor.FieldDescriptor.CPPTYPE_ENUM:
      # Convert an enum value.
      enum_value = field.enum_type.values_by_name.get(value, None)
      if enum_value is None:
        try:
          number = int(value)
          enum_value = field.enum_type.values_by_number.get(number, None)
        except ValueError as e:
          # Since parsing to integer failed and lookup in values_by_name didn't
          # find this name, we have an enum string value which is unknown.
          raise EnumStringValueParseError(
              'Invalid enum value {0} for enum type {1}'.format(
                  value, field.enum_type.full_name
              )
          ) from e
        if enum_value is None:
          if field.enum_type.is_closed:
            raise ParseError(
                'Invalid enum value {0} for enum type {1}'.format(
                    value, field.enum_type.full_name
                )
            )
          else:
            return number
      return enum_value.number
  except EnumStringValueParseError as e:
    raise EnumStringValueParseError('{0} at {1}'.format(e, path)) from e
  except ParseError as e:
    raise ParseError('{0} at {1}'.format(e, path)) from e

def before_get(self, parser, section, option, value, defaults):
    L = []
    self._interpolate_some(parser, option, L, value, section, defaults, 1)
    return ''.join(L)

def is_le(lhs, rhs, assumptions=None):
    """Fuzzy bool for lhs is less than or equal to rhs.

    See the docstring for :func:`~.is_ge` for more.
    """
    return is_ge(rhs, lhs, assumptions)

def __repr__(self):
    try:
        if self._semlock._is_mine():
            name = process.current_process().name
            if threading.current_thread().name != "MainThread":
                name = f"{name}|{threading.current_thread().name}"
        elif self._semlock._get_value() == 1:
            name = "None"
        elif self._semlock._count() > 0:
            name = "SomeOtherThread"
        else:
            name = "SomeOtherProcess"
    except Exception:
        name = "unknown"
    return f"<{self.__class__.__name__}(owner={name})>"

def _get_xy_transform(self, renderer, coords):

    if isinstance(coords, tuple):
        xcoord, ycoord = coords
        from matplotlib.transforms import blended_transform_factory
        tr1 = self._get_xy_transform(renderer, xcoord)
        tr2 = self._get_xy_transform(renderer, ycoord)
        return blended_transform_factory(tr1, tr2)
    elif callable(coords):
        tr = coords(renderer)
        if isinstance(tr, BboxBase):
            return BboxTransformTo(tr)
        elif isinstance(tr, Transform):
            return tr
        else:
            raise TypeError(
                f"xycoords callable must return a BboxBase or Transform, not a "
                f"{type(tr).__name__}")
    elif isinstance(coords, Artist):
        bbox = coords.get_window_extent(renderer)
        return BboxTransformTo(bbox)
    elif isinstance(coords, BboxBase):
        return BboxTransformTo(coords)
    elif isinstance(coords, Transform):
        return coords
    elif not isinstance(coords, str):
        raise TypeError(
            f"'xycoords' must be an instance of str, tuple[str, str], Artist, "
            f"Transform, or Callable, not a {type(coords).__name__}")

    if coords == 'data':
        return self.axes.transData
    elif coords == 'polar':
        from matplotlib.projections import PolarAxes
        tr = PolarAxes.PolarTransform(apply_theta_transforms=False)
        trans = tr + self.axes.transData
        return trans

    try:
        bbox_name, unit = coords.split()
    except ValueError:  # i.e. len(coords.split()) != 2.
        raise ValueError(f"{coords!r} is not a valid coordinate") from None

    bbox0, xy0 = None, None

    # if unit is offset-like
    if bbox_name == "figure":
        bbox0 = self.get_figure(root=False).figbbox
    elif bbox_name == "subfigure":
        bbox0 = self.get_figure(root=False).bbox
    elif bbox_name == "axes":
        bbox0 = self.axes.bbox

    # reference x, y in display coordinate
    if bbox0 is not None:
        xy0 = bbox0.p0
    elif bbox_name == "offset":
        xy0 = self._get_position_xy(renderer)
    else:
        raise ValueError(f"{coords!r} is not a valid coordinate")

    if unit == "points":
        tr = Affine2D().scale(
            self.get_figure(root=True).dpi / 72)  # dpi/72 dots per point
    elif unit == "pixels":
        tr = Affine2D()
    elif unit == "fontsize":
        tr = Affine2D().scale(
            self.get_size() * self.get_figure(root=True).dpi / 72)
    elif unit == "fraction":
        tr = Affine2D().scale(*bbox0.size)
    else:
        raise ValueError(f"{unit!r} is not a recognized unit")

    return tr.translate(*xy0)

def unique_colors(self):
    """Discards all duplicate pixels, and rebuilds the image
    as a single row.

    .. versionadded:: 0.5.0
    """
    return library.MagickUniqueImageColors(self.wand)

def save(self, obj, save_persistent_id=True):
    obj_type = type(obj)
    if obj_type not in self.dispatch:
        if "regex" in sys.modules:
            import regex  # type: ignore

            if obj_type is regex.Pattern:
                pklregister(obj_type)(_save_regexPattern)
        if "spacy" in sys.modules:
            import spacy  # type: ignore

            if issubclass(obj_type, spacy.Language):
                pklregister(obj_type)(_save_spacyLanguage)
        if "tiktoken" in sys.modules:
            import tiktoken  # type: ignore

            if obj_type is tiktoken.Encoding:
                pklregister(obj_type)(_save_tiktokenEncoding)
        if "torch" in sys.modules:
            import torch  # type: ignore

            if issubclass(obj_type, torch.Tensor):
                pklregister(obj_type)(_save_torchTensor)

            if obj_type is torch.Generator:
                pklregister(obj_type)(_save_torchGenerator)

            # Unwrap `torch.compile`-ed modules
            if issubclass(obj_type, torch.nn.Module):
                obj = getattr(obj, "_orig_mod", obj)
        if "transformers" in sys.modules:
            import transformers  # type: ignore

            if issubclass(obj_type, transformers.PreTrainedTokenizerBase):
                pklregister(obj_type)(_save_transformersPreTrainedTokenizerBase)

    # Unwrap `torch.compile`-ed functions
    if obj_type is FunctionType:
        obj = getattr(obj, "_torchdynamo_orig_callable", obj)
    dill.Pickler.save(self, obj, save_persistent_id=save_persistent_id)

def parseImpl(self, instring, loc, doActions=True):
    errmsg = self.errmsg
    errloc = loc
    if self.caseless:
        if instring[loc : loc + self.matchLen].upper() == self.caselessmatch:
            if loc == 0 or instring[loc - 1].upper() not in self.identChars:
                if (
                    loc >= len(instring) - self.matchLen
                    or instring[loc + self.matchLen].upper() not in self.identChars
                ):
                    return loc + self.matchLen, self.match
                else:
                    # followed by keyword char
                    errmsg += ", was immediately followed by keyword character"
                    errloc = loc + self.matchLen
            else:
                # preceded by keyword char
                errmsg += ", keyword was immediately preceded by keyword character"
                errloc = loc - 1
        # else no match just raise plain exception

    else:
        if (
            instring[loc] == self.firstMatchChar
            and self.matchLen == 1
            or instring.startswith(self.match, loc)
        ):
            if loc == 0 or instring[loc - 1] not in self.identChars:
                if (
                    loc >= len(instring) - self.matchLen
                    or instring[loc + self.matchLen] not in self.identChars
                ):
                    return loc + self.matchLen, self.match
                else:
                    # followed by keyword char
                    errmsg += (
                        ", keyword was immediately followed by keyword character"
                    )
                    errloc = loc + self.matchLen
            else:
                # preceded by keyword char
                errmsg += ", keyword was immediately preceded by keyword character"
                errloc = loc - 1
        # else no match just raise plain exception

    raise ParseException(instring, errloc, errmsg, self)

def sign(
    self,
    private_key: CertificateIssuerPrivateKeyTypes,
    algorithm: typing.Optional[_AllowedHashTypes],
    backend: typing.Any = None,
    *,
    rsa_padding: typing.Optional[
        typing.Union[padding.PSS, padding.PKCS1v15]
    ] = None,
) -> Certificate:
    """
    Signs the certificate using the CA's private key.
    """
    if self._subject_name is None:
        raise ValueError("A certificate must have a subject name")

    if self._issuer_name is None:
        raise ValueError("A certificate must have an issuer name")

    if self._serial_number is None:
        raise ValueError("A certificate must have a serial number")

    if self._not_valid_before is None:
        raise ValueError("A certificate must have a not valid before time")

    if self._not_valid_after is None:
        raise ValueError("A certificate must have a not valid after time")

    if self._public_key is None:
        raise ValueError("A certificate must have a public key")

    if rsa_padding is not None:
        if not isinstance(rsa_padding, (padding.PSS, padding.PKCS1v15)):
            raise TypeError("Padding must be PSS or PKCS1v15")
        if not isinstance(private_key, rsa.RSAPrivateKey):
            raise TypeError("Padding is only supported for RSA keys")

    return rust_x509.create_x509_certificate(
        self, private_key, algorithm, rsa_padding
    )

def _get_permutation_from_arguments(cls, permutation, index_order_old, index_order_new, dim):
    if permutation is None:
        if index_order_new is None or index_order_old is None:
            raise ValueError("Permutation not defined")
        return PermuteDims._get_permutation_from_index_orders(index_order_old, index_order_new, dim)
    else:
        if index_order_new is not None:
            raise ValueError("index_order_new cannot be defined with permutation")
        if index_order_old is not None:
            raise ValueError("index_order_old cannot be defined with permutation")
        return permutation

def readAxisSubset(self, element: ET.Element):
    if "uservalue" in element.attrib:
        xml_attrs = {"name", "uservalue"}
        unknown_attrs = set(element.attrib) - xml_attrs
        if unknown_attrs:
            raise DesignSpaceDocumentError(
                f"axis-subset element contains unknown attributes: {', '.join(unknown_attrs)}"
            )

        name = element.get("name")
        if name is None:
            raise DesignSpaceDocumentError(
                "axis-subset element must have a name attribute."
            )
        userValueStr = element.get("uservalue")
        if userValueStr is None:
            raise DesignSpaceDocumentError(
                "The axis-subset element for a discrete subset must have a uservalue attribute."
            )
        userValue = float(userValueStr)

        return self.valueAxisSubsetDescriptorClass(name=name, userValue=userValue)
    else:
        xml_attrs = {"name", "userminimum", "userdefault", "usermaximum"}
        unknown_attrs = set(element.attrib) - xml_attrs
        if unknown_attrs:
            raise DesignSpaceDocumentError(
                f"axis-subset element contains unknown attributes: {', '.join(unknown_attrs)}"
            )

        name = element.get("name")
        if name is None:
            raise DesignSpaceDocumentError(
                "axis-subset element must have a name attribute."
            )

        userMinimum = element.get("userminimum")
        userDefault = element.get("userdefault")
        userMaximum = element.get("usermaximum")
        if (
            userMinimum is not None
            and userDefault is not None
            and userMaximum is not None
        ):
            return self.rangeAxisSubsetDescriptorClass(
                name=name,
                userMinimum=float(userMinimum),
                userDefault=float(userDefault),
                userMaximum=float(userMaximum),
            )
        if all(v is None for v in (userMinimum, userDefault, userMaximum)):
            return self.rangeAxisSubsetDescriptorClass(name=name)

        raise DesignSpaceDocumentError(
            "axis-subset element must have min/max/default values or none at all."
        )

def do(rv, first=True):
    # args which can be expressed as A*(cos(a)*cos(b)+/-sin(a)*sin(b))
    # or B*(cos(a)*sin(b)+/-cos(b)*sin(a)) can be combined into
    # A*f(a+/-b) where f is either sin or cos.
    #
    # If there are more than two args, the pairs which "work" will have
    # a gcd extractable and the remaining two terms will have the above
    # structure -- all pairs must be checked to find the ones that
    # work.

    if not rv.is_Add:
        return rv

    args = list(ordered(rv.args))
    if len(args) != 2:
        hit = False
        for i in range(len(args)):
            ai = args[i]
            if ai is None:
                continue
            for j in range(i + 1, len(args)):
                aj = args[j]
                if aj is None:
                    continue
                was = ai + aj
                new = do(was)
                if new != was:
                    args[i] = new  # update in place
                    args[j] = None
                    hit = True
                    break  # go to next i
        if hit:
            rv = Add(*[_f for _f in args if _f])
            if rv.is_Add:
                rv = do(rv)

        return rv

    # two-arg Add
    split = trig_split(*args, two=True)
    if not split:
        return rv
    gcd, n1, n2, a, b, same = split

    # identify and get c1 to be cos then apply rule if possible
    if same:  # coscos, sinsin
        gcd = n1*gcd
        if n1 == n2:
            return gcd*cos(a - b)
        return gcd*cos(a + b)
    else:  #cossin, cossin
        gcd = n1*gcd
        if n1 == n2:
            return gcd*sin(a + b)
        return gcd*sin(b - a)

def parseImpl(self, instring, loc, doActions=True):
    self_expr = self.expr
    try:
        loc, tokens = self_expr._parse(instring, loc, doActions, callPreParse=False)
    except (ParseException, IndexError):
        default_value = self.defaultValue
        if default_value is not self.__optionalNotMatched:
            if self_expr.resultsName:
                tokens = ParseResults([default_value])
                tokens[self_expr.resultsName] = default_value
            else:
                tokens = [default_value]
        else:
            tokens = []
    return loc, tokens

def _replace_guids_with_channels(self, payload: Any) -> Any:
    if payload is None:
        return payload
    if isinstance(payload, list):
        return list(map(self._replace_guids_with_channels, payload))
    if isinstance(payload, dict):
        if payload.get("guid") in self._objects:
            return self._objects[payload["guid"]]._channel
        result = {}
        for key, value in payload.items():
            result[key] = self._replace_guids_with_channels(value)
        return result
    return payload

def _can_close(self) -> bool:
    if self.content[0] == "*":
        return self.is_right_flanking()
    return self.is_right_flanking() and (
        not self.is_left_flanking() or self.followed_by_punc()
    )

def do(rv, first=True):
    # cos(a)+/-cos(b) can be combined into a product of cosines and
    # sin(a)+/-sin(b) can be combined into a product of cosine and
    # sine.
    #
    # If there are more than two args, the pairs which "work" will
    # have a gcd extractable and the remaining two terms will have
    # the above structure -- all pairs must be checked to find the
    # ones that work. args that don't have a common set of symbols
    # are skipped since this doesn't lead to a simpler formula and
    # also has the arbitrariness of combining, for example, the x
    # and y term instead of the y and z term in something like
    # cos(x) + cos(y) + cos(z).

    if not rv.is_Add:
        return rv

    args = list(ordered(rv.args))
    if len(args) != 2:
        hit = False
        for i in range(len(args)):
            ai = args[i]
            if ai is None:
                continue
            for j in range(i + 1, len(args)):
                aj = args[j]
                if aj is None:
                    continue
                was = ai + aj
                new = do(was)
                if new != was:
                    args[i] = new  # update in place
                    args[j] = None
                    hit = True
                    break  # go to next i
        if hit:
            rv = Add(*[_f for _f in args if _f])
            if rv.is_Add:
                rv = do(rv)

        return rv

    # two-arg Add
    split = trig_split(*args)
    if not split:
        return rv
    gcd, n1, n2, a, b, iscos = split

    # application of rule if possible
    if iscos:
        if n1 == n2:
            return gcd*n1*2*cos((a + b)/2)*cos((a - b)/2)
        if n1 < 0:
            a, b = b, a
        return -2*gcd*sin((a + b)/2)*sin((a - b)/2)
    else:
        if n1 == n2:
            return gcd*n1*2*sin((a + b)/2)*cos((a - b)/2)
        if n1 < 0:
            a, b = b, a
        return 2*gcd*cos((a + b)/2)*sin((a - b)/2)

def _canonicalize(self):
    args = self.args
    args = self._flatten(args)

    ranks = [get_rank(arg) for arg in args]

    # Check if there are nested permutation and lift them up:
    permutation_cycles = []
    for i, arg in enumerate(args):
        if not isinstance(arg, PermuteDims):
            continue
        permutation_cycles.extend([[k + sum(ranks[:i]) for k in j] for j in arg.permutation.cyclic_form])
        args[i] = arg.expr
    if permutation_cycles:
        return _permute_dims(_array_tensor_product(*args), Permutation(sum(ranks)-1)*Permutation(permutation_cycles))

    if len(args) == 1:
        return args[0]

    # If any object is a ZeroArray, return a ZeroArray:
    if any(isinstance(arg, (ZeroArray, ZeroMatrix)) for arg in args):
        shapes = reduce(operator.add, [get_shape(i) for i in args], ())
        return ZeroArray(*shapes)

    # If there are contraction objects inside, transform the whole
    # expression into `ArrayContraction`:
    contractions = {i: arg for i, arg in enumerate(args) if isinstance(arg, ArrayContraction)}
    if contractions:
        ranks = [_get_subrank(arg) if isinstance(arg, ArrayContraction) else get_rank(arg) for arg in args]
        cumulative_ranks = list(accumulate([0] + ranks))[:-1]
        tp = _array_tensor_product(*[arg.expr if isinstance(arg, ArrayContraction) else arg for arg in args])
        contraction_indices = [tuple(cumulative_ranks[i] + k for k in j) for i, arg in contractions.items() for j in arg.contraction_indices]
        return _array_contraction(tp, *contraction_indices)

    diagonals = {i: arg for i, arg in enumerate(args) if isinstance(arg, ArrayDiagonal)}
    if diagonals:
        inverse_permutation = []
        last_perm = []
        ranks = [get_rank(arg) for arg in args]
        cumulative_ranks = list(accumulate([0] + ranks))[:-1]
        for i, arg in enumerate(args):
            if isinstance(arg, ArrayDiagonal):
                i1 = get_rank(arg) - len(arg.diagonal_indices)
                i2 = len(arg.diagonal_indices)
                inverse_permutation.extend([cumulative_ranks[i] + j for j in range(i1)])
                last_perm.extend([cumulative_ranks[i] + j for j in range(i1, i1 + i2)])
            else:
                inverse_permutation.extend([cumulative_ranks[i] + j for j in range(get_rank(arg))])
        inverse_permutation.extend(last_perm)
        tp = _array_tensor_product(*[arg.expr if isinstance(arg, ArrayDiagonal) else arg for arg in args])
        ranks2 = [_get_subrank(arg) if isinstance(arg, ArrayDiagonal) else get_rank(arg) for arg in args]
        cumulative_ranks2 = list(accumulate([0] + ranks2))[:-1]
        diagonal_indices = [tuple(cumulative_ranks2[i] + k for k in j) for i, arg in diagonals.items() for j in arg.diagonal_indices]
        return _permute_dims(_array_diagonal(tp, *diagonal_indices), _af_invert(inverse_permutation))

    return self.func(*args, canonicalize=False)

def parse_position_(self, enumerated, vertical):
    assert self.cur_token_ in {"position", "pos"}
    if self.next_token_ == "cursive":  # GPOS type 3
        return self.parse_position_cursive_(enumerated, vertical)
    elif self.next_token_ == "base":  # GPOS type 4
        return self.parse_position_base_(enumerated, vertical)
    elif self.next_token_ == "ligature":  # GPOS type 5
        return self.parse_position_ligature_(enumerated, vertical)
    elif self.next_token_ == "mark":  # GPOS type 6
        return self.parse_position_mark_(enumerated, vertical)

    location = self.cur_token_location_
    prefix, glyphs, lookups, values, suffix, hasMarks = self.parse_glyph_pattern_(
        vertical
    )
    self.expect_symbol_(";")

    if any(lookups):
        # GPOS type 8: Chaining contextual positioning; explicit lookups
        if any(values):
            raise FeatureLibError(
                'If "lookup" is present, no values must be specified', location
            )
        return self.ast.ChainContextPosStatement(
            prefix, glyphs, suffix, lookups, location=location
        )

    # Pair positioning, format A: "pos V 10 A -10;"
    # Pair positioning, format B: "pos V A -20;"
    if not prefix and not suffix and len(glyphs) == 2 and not hasMarks:
        if values[0] is None:  # Format B: "pos V A -20;"
            values.reverse()
        return self.ast.PairPosStatement(
            glyphs[0],
            values[0],
            glyphs[1],
            values[1],
            enumerated=enumerated,
            location=location,
        )

    if enumerated:
        raise FeatureLibError(
            '"enumerate" is only allowed with pair positionings', location
        )
    return self.ast.SinglePosStatement(
        list(zip(glyphs, values)),
        prefix,
        suffix,
        forceChain=hasMarks,
        location=location,
    )

def SetRuleData(r, d):
    (r.Class,) = d
    (r.GlyphCount,) = (len(x) + 1 for x in d)

def notify_all(self):
    assert self._lock._semlock._is_mine(), "lock is not owned"
    assert not self._wait_semaphore.acquire(False)

    # to take account of timeouts since last notify*() we subtract
    # woken_count from sleeping_count and rezero woken_count
    while self._woken_count.acquire(False):
        res = self._sleeping_count.acquire(False)
        assert res

    sleepers = 0
    while self._sleeping_count.acquire(False):
        self._wait_semaphore.release()  # wake up one sleeper
        sleepers += 1

    if sleepers:
        for _ in range(sleepers):
            self._woken_count.acquire()  # wait for a sleeper to wake

        # rezero wait_semaphore in case some timeouts just happened
        while self._wait_semaphore.acquire(False):
            pass

def __init__(self, safe):
    """safe: bytes object."""
    self.safe = _ALWAYS_SAFE.union(safe)

def subset_features(self, feature_indices, keepEmptyDefaultLangSys=False):
    if (
        self.DefaultLangSys
        and not self.DefaultLangSys.subset_features(feature_indices)
        and not keepEmptyDefaultLangSys
    ):
        self.DefaultLangSys = None
    self.LangSysRecord = [
        l for l in self.LangSysRecord if l.LangSys.subset_features(feature_indices)
    ]
    self.LangSysCount = len(self.LangSysRecord)
    return bool(self.LangSysCount or self.DefaultLangSys)

def __getattribute__(self, attr):
    try:
        return object.__getattribute__(self, attr)
    except AttributeError:
        # attr must be a fieldname
        pass
    fielddict = np.ndarray.__getattribute__(self, 'dtype').fields
    try:
        res = fielddict[attr][:2]
    except (TypeError, KeyError) as e:
        raise AttributeError(
            f'record array has no attribute {attr}') from e
    # So far, so good
    _localdict = np.ndarray.__getattribute__(self, '__dict__')
    _data = np.ndarray.view(self, _localdict['_baseclass'])
    obj = _data.getfield(*res)
    if obj.dtype.names is not None:
        raise NotImplementedError("MaskedRecords is currently limited to"
                                  "simple records.")
    # Get some special attributes
    # Reset the object's mask
    hasmasked = False
    _mask = _localdict.get('_mask', None)
    if _mask is not None:
        try:
            _mask = _mask[attr]
        except IndexError:
            # Couldn't find a mask: use the default (nomask)
            pass
        tp_len = len(_mask.dtype)
        hasmasked = _mask.view((bool, ((tp_len,) if tp_len else ()))).any()
    if (obj.shape or hasmasked):
        obj = obj.view(ma.MaskedArray)
        obj._baseclass = np.ndarray
        obj._isfield = True
        obj._mask = _mask
        # Reset the field values
        _fill_value = _localdict.get('_fill_value', None)
        if _fill_value is not None:
            try:
                obj._fill_value = _fill_value[attr]
            except ValueError:
                obj._fill_value = None
    else:
        obj = obj.item()
    return obj

def on(
    self,
    event: str,
    f: typing.Callable[..., typing.Union[typing.Awaitable[None], None]],
) -> None:
    return super().on(event=event, f=f)

def _get_coeffs_from_subs_expression(expr):
    if isinstance(expr, Subs):
        free_symbol = expr.args[1][0]
        term = expr.args[0]
        return {ode_order(term, free_symbol): 1}

    if isinstance(expr, Mul):
        coeff = expr.args[0]
        order = list(_get_coeffs_from_subs_expression(expr.args[1]).keys())[0]
        return {order: coeff}

    if isinstance(expr, Add):
        coeffs = {}
        for arg in expr.args:

            if isinstance(arg, Mul):
                coeffs.update(_get_coeffs_from_subs_expression(arg))

            else:
                order = list(_get_coeffs_from_subs_expression(arg).keys())[0]
                coeffs[order] = 1

        return coeffs

def before_get(self, parser, section, option, value, vars):
    rawval = value
    depth = MAX_INTERPOLATION_DEPTH
    while depth:                    # Loop through this until it's done
        depth -= 1
        if value and "%(" in value:
            replace = functools.partial(self._interpolation_replace,
                                        parser=parser)
            value = self._KEYCRE.sub(replace, value)
            try:
                value = value % vars
            except KeyError as e:
                raise InterpolationMissingOptionError(
                    option, section, rawval, e.args[0]) from None
        else:
            break
    if value and "%(" in value:
        raise InterpolationDepthError(option, section, rawval)
    return value

def ulabel(label: Union[str, bytes, bytearray]) -> str:
    if not isinstance(label, (bytes, bytearray)):
        try:
            label_bytes = label.encode('ascii')
        except UnicodeEncodeError:
            check_label(label)
            return label
    else:
        label_bytes = label

    label_bytes = label_bytes.lower()
    if label_bytes.startswith(_alabel_prefix):
        label_bytes = label_bytes[len(_alabel_prefix):]
        if not label_bytes:
            raise IDNAError('Malformed A-label, no Punycode eligible content found')
        if label_bytes.decode('ascii')[-1] == '-':
            raise IDNAError('A-label must not end with a hyphen')
    else:
        check_label(label_bytes)
        return label_bytes.decode('ascii')

    try:
        label = label_bytes.decode('punycode')
    except UnicodeError:
        raise IDNAError('Invalid A-label')
    check_label(label)
    return label

def expect(self, name: str, *, expected: str) -> Token:
    """Expect a certain token name next, failing with a syntax error otherwise.

    The token is *not* read.
    """
    if not self.check(name):
        raise self.raise_syntax_error(f"Expected {expected}")
    return self.read()

def sendfile(self, file, offset=0, count=None):
    """Send a file, possibly by using os.sendfile() if this is a
    clear-text socket.  Return the total number of bytes sent.
    """
    if self._sslobj is not None:
        return self._sendfile_use_send(file, offset, count)
    else:
        # os.sendfile() works with plain sockets only
        return super().sendfile(file, offset, count)

def _addLib(self, parentElement: ET.Element, data: Any, indent_level: int) -> None:
    if not data:
        return
    libElement = ET.Element("lib")
    libElement.append(plistlib.totree(data, indent_level=indent_level))
    parentElement.append(libElement)

def getpydocsign(a, var):
    global lcb_map
    if isfunction(var):
        if 'result' in var:
            af = var['result']
        else:
            af = var['name']
        if af in var['vars']:
            return getpydocsign(af, var['vars'][af])
        else:
            errmess(f'getctype: function {af} has no return value?!\n')
        return '', ''
    sig, sigout = a, a
    opt = ''
    if isintent_in(var):
        opt = 'input'
    elif isintent_inout(var):
        opt = 'in/output'
    out_a = a
    if isintent_out(var):
        for k in var['intent']:
            if k[:4] == 'out=':
                out_a = k[4:]
                break
    init = ''
    ctype = getctype(var)

    if hasinitvalue(var):
        init, showinit = getinit(a, var)
        init = f', optional\\n    Default: {showinit}'
    if isscalar(var):
        if isintent_inout(var):
            sig = '%s : %s rank-0 array(%s,\'%s\')%s' % (a, opt, c2py_map[ctype],
                                                         c2pycode_map[ctype], init)
        else:
            sig = f'{a} : {opt} {c2py_map[ctype]}{init}'
        sigout = f'{out_a} : {c2py_map[ctype]}'
    elif isstring(var):
        if isintent_inout(var):
            sig = '%s : %s rank-0 array(string(len=%s),\'c\')%s' % (
                a, opt, getstrlength(var), init)
        else:
            sig = f'{a} : {opt} string(len={getstrlength(var)}){init}'
        sigout = f'{out_a} : string(len={getstrlength(var)})'
    elif isarray(var):
        dim = var['dimension']
        rank = repr(len(dim))
        sig = '%s : %s rank-%s array(\'%s\') with bounds (%s)%s' % (a, opt, rank,
                                                                    c2pycode_map[
                                                                        ctype],
                                                                    ','.join(dim), init)
        if a == out_a:
            sigout = '%s : rank-%s array(\'%s\') with bounds (%s)'\
                % (a, rank, c2pycode_map[ctype], ','.join(dim))
        else:
            sigout = '%s : rank-%s array(\'%s\') with bounds (%s) and %s storage'\
                % (out_a, rank, c2pycode_map[ctype], ','.join(dim), a)
    elif isexternal(var):
        ua = ''
        if a in lcb_map and lcb_map[a] in lcb2_map and 'argname' in lcb2_map[lcb_map[a]]:
            ua = lcb2_map[lcb_map[a]]['argname']
            if not ua == a:
                ua = f' => {ua}'
            else:
                ua = ''
        sig = f'{a} : call-back function{ua}'
        sigout = sig
    else:
        errmess(
            f'getpydocsign: Could not resolve docsignature for "{a}".\n')
    return sig, sigout

def get_representation_definition(self, media_type=None):
    """Return the appropriate representation definition."""
    for representation in self.representations:
        if media_type is None or representation.media_type == media_type:
            return representation
    return None

def _setResultsName(self, name, listAllMatches=False):
    if (
        __diag__.warn_multiple_tokens_in_named_alternation
        and Diagnostics.warn_multiple_tokens_in_named_alternation
        not in self.suppress_warnings_
    ):
        if any(
            isinstance(e, And)
            and Diagnostics.warn_multiple_tokens_in_named_alternation
            not in e.suppress_warnings_
            for e in self.exprs
        ):
            warnings.warn(
                "{}: setting results name {!r} on {} expression "
                "will return a list of all parsed tokens in an And alternative, "
                "in prior versions only the first token was returned; enclose "
                "contained argument in Group".format(
                    "warn_multiple_tokens_in_named_alternation",
                    name,
                    type(self).__name__,
                ),
                stacklevel=3,
            )

    return super()._setResultsName(name, listAllMatches)

def pr(left, right):
    """create and return a new specialized BinOp from myself"""
    if left is None:
        return right
    elif right is None:
        return left

    k = klass
    if isinstance(left, ConditionBinOp):
        if isinstance(right, ConditionBinOp):
            k = JointConditionBinOp
        elif isinstance(left, k):
            return left
        elif isinstance(right, k):
            return right

    elif isinstance(left, FilterBinOp):
        if isinstance(right, FilterBinOp):
            k = JointFilterBinOp
        elif isinstance(left, k):
            return left
        elif isinstance(right, k):
            return right

    return k(
        self.op, left, right, queryables=self.queryables, encoding=self.encoding
    ).evaluate()

def _default_start_debug_action(
    instring: str, loc: int, expr: "ParserElement", cache_hit: bool = False
):
    cache_hit_str = "*" if cache_hit else ""
    print(
        (
            f"{cache_hit_str}Match {expr} at loc {loc}({lineno(loc, instring)},{col(loc, instring)})\n"
            f"  {line(loc, instring)}\n"
            f"  {' ' * (col(loc, instring) - 1)}^"
        )
    )

def _divmod(a, b):
    """(a // b, a % b)"""
    da, db = a.denominator, b.denominator
    div, n_mod = divmod(a.numerator * db, da * b.numerator)
    return div, Fraction(n_mod, da * db)

def resize_object(obj: T_obj, key: str, value: T_num) -> T_obj:
    assert key in ("x0", "x1", "top", "bottom")
    old_value = obj[key]
    diff = value - old_value
    new_items = [
        (key, value),
    ]
    if key == "x0":
        assert value <= obj["x1"]
        new_items.append(("width", obj["x1"] - value))
    elif key == "x1":
        assert value >= obj["x0"]
        new_items.append(("width", value - obj["x0"]))
    elif key == "top":
        assert value <= obj["bottom"]
        new_items.append(("doctop", obj["doctop"] + diff))
        new_items.append(("height", obj["height"] - diff))
        if "y1" in obj:
            new_items.append(("y1", obj["y1"] - diff))
    elif key == "bottom":
        assert value >= obj["top"]
        new_items.append(("height", obj["height"] + diff))
        if "y0" in obj:
            new_items.append(("y0", obj["y0"] - diff))
    return obj.__class__(tuple(obj.items()) + tuple(new_items))

def closure_glyphs(self, s, cur_glyphs):
    if self.Format == 1:
        indices = self.Coverage.intersect(cur_glyphs)
        if not indices or not all(
            c.intersect(s.glyphs)
            for c in self.LookAheadCoverage + self.BacktrackCoverage
        ):
            return
        s.glyphs.update(self.Substitute[i] for i in indices)
    else:
        assert 0, "unknown format: %s" % self.Format

def test(e: T_obj) -> bool:
    dim = "height" if e["orientation"] == "v" else "width"
    et_correct = e["object_type"] == edge_type if edge_type is not None else True
    orient_correct = orientation is None or e["orientation"] == orientation
    return bool(et_correct and orient_correct and (e[dim] >= min_length))

def _setResultsName(self, name, listAllMatches=False):
    if (
        __diag__.warn_ungrouped_named_tokens_in_collection
        and Diagnostics.warn_ungrouped_named_tokens_in_collection
        not in self.suppress_warnings_
    ):
        for e in self.exprs:
            if (
                isinstance(e, ParserElement)
                and e.resultsName
                and Diagnostics.warn_ungrouped_named_tokens_in_collection
                not in e.suppress_warnings_
            ):
                warnings.warn(
                    "{}: setting results name {!r} on {} expression "
                    "collides with {!r} on contained expression".format(
                        "warn_ungrouped_named_tokens_in_collection",
                        name,
                        type(self).__name__,
                        e.resultsName,
                    ),
                    stacklevel=3,
                )

    return super()._setResultsName(name, listAllMatches)

def prune_post_subset(self, font, options):
    table = self.table
    # XXX check these against OTS
    if table.LigCaretList and not table.LigCaretList.LigGlyphCount:
        table.LigCaretList = None
    if table.MarkAttachClassDef and not table.MarkAttachClassDef.classDefs:
        table.MarkAttachClassDef = None
    if table.GlyphClassDef and not table.GlyphClassDef.classDefs:
        table.GlyphClassDef = None
    if table.AttachList and not table.AttachList.GlyphCount:
        table.AttachList = None
    if hasattr(table, "VarStore"):
        _pruneGDEF(font)
        if table.VarStore.VarDataCount == 0:
            if table.Version == 0x00010003:
                table.Version = 0x00010002
    if (
        not hasattr(table, "MarkGlyphSetsDef")
        or not table.MarkGlyphSetsDef
        or not table.MarkGlyphSetsDef.Coverage
    ):
        table.MarkGlyphSetsDef = None
        if table.Version == 0x00010002:
            table.Version = 0x00010000
    return bool(
        table.LigCaretList
        or table.MarkAttachClassDef
        or table.GlyphClassDef
        or table.AttachList
        or (table.Version >= 0x00010002 and table.MarkGlyphSetsDef)
        or (table.Version >= 0x00010003 and table.VarStore)
    )

def __call__(self, r, g, b):
    c = self._interpolate_axis
    return c(0, r), c(1, g), c(2, b)

def _eval_expand_mul(self, **hints):
    from sympy.simplify.radsimp import fraction

    # Handle things like 1/(x*(x + 1)), which are automatically converted
    # to 1/x*1/(x + 1)
    expr = self
    # default matches fraction's default
    n, d = fraction(expr, hints.get('exact', False))
    if d.is_Mul:
        n, d = [i._eval_expand_mul(**hints) if i.is_Mul else i
            for i in (n, d)]
    expr = n/d
    if not expr.is_Mul:
        return expr

    plain, sums, rewrite = [], [], False
    for factor in expr.args:
        if factor.is_Add:
            sums.append(factor)
            rewrite = True
        else:
            if factor.is_commutative:
                plain.append(factor)
            else:
                sums.append(Basic(factor))  # Wrapper

    if not rewrite:
        return expr
    else:
        plain = self.func(*plain)
        if sums:
            deep = hints.get("deep", False)
            terms = self.func._expandsums(sums)
            args = []
            for term in terms:
                t = self.func(plain, term)
                if t.is_Mul and any(a.is_Add for a in t.args) and deep:
                    t = t._eval_expand_mul()
                args.append(t)
            return Add(*args)
        else:
            return plain

def _get_tagged_response(self, tag, expect_bye=False):

    while 1:
        result = self.tagged_commands[tag]
        if result is not None:
            del self.tagged_commands[tag]
            return result

        if expect_bye:
            typ = 'BYE'
            bye = self.untagged_responses.pop(typ, None)
            if bye is not None:
                # Server replies to the "LOGOUT" command with "BYE"
                return (typ, bye)

        # If we've seen a BYE at this point, the socket will be
        # closed, so report the BYE now.
        self._check_bye()

        # Some have reported "unexpected response" exceptions.
        # Note that ignoring them here causes loops.
        # Instead, send me details of the unexpected response and
        # I'll update the code in `_get_response()'.

        try:
            self._get_response()
        except self.abort as val:
            if __debug__:
                if self.debug >= 1:
                    self.print_log()
            raise

def build(self, serve: bool = False, dirty: bool = False):
    self.pool = ProcessPoolExecutor(
        self.root.plugin.concurrency,
        mp_context = multiprocessing.get_context("spawn")
    )

    # Determine projects in topological order and prepare for building
    built: list[str] = []
    queue = [*self.root.jobs()]
    for job in queue:
        _setup(job.project, self.root, serve)
        if serve:
            self._link(job.project)

    # Schedule projects for building
    for job in reversed(queue):
        if self._schedule(job, serve, dirty):
            queue.remove(job)

    # Build loop - iteratively build more projects while there are still
    # projects to be built, sticking to the topological order.
    while len(built) < len(self.pool_jobs):
        for future in as_completed(self.pool_jobs.values()):
            slug, errors, warnings = future.result()
            if slug in built:
                continue

            # Mark project as built
            built.append(slug)

            # Schedule projects for building
            for job in reversed(queue):
                if self._schedule(job, serve, dirty):
                    queue.remove(job)

            # Print errors and warnings
            for project in self.projects:
                if project.slug == slug:
                    _print(get_log_for(project), errors, warnings)
                    break

    # Shutdown process pool
    self.pool.shutdown()
    if self.watcher:

        # Update watched paths
        for project in self.projects:
            if project.slug not in built:
                self.pool_jobs.pop(project.slug, None)
                self.watcher.unwatch(project)
            else:
                self.watcher.watch(project, self.taint)

def _TR56(rv, f, g, h, max, pow):
    """Helper for TR5 and TR6 to replace f**2 with h(g**2)

    Options
    =======

    max :   controls size of exponent that can appear on f
            e.g. if max=4 then f**4 will be changed to h(g**2)**2.
    pow :   controls whether the exponent must be a perfect power of 2
            e.g. if pow=True (and max >= 6) then f**6 will not be changed
            but f**8 will be changed to h(g**2)**4

    >>> from sympy.simplify.fu import _TR56 as T
    >>> from sympy.abc import x
    >>> from sympy import sin, cos
    >>> h = lambda x: 1 - x
    >>> T(sin(x)**3, sin, cos, h, 4, False)
    (1 - cos(x)**2)*sin(x)
    >>> T(sin(x)**6, sin, cos, h, 6, False)
    (1 - cos(x)**2)**3
    >>> T(sin(x)**6, sin, cos, h, 6, True)
    sin(x)**6
    >>> T(sin(x)**8, sin, cos, h, 10, True)
    (1 - cos(x)**2)**4
    """

    def _f(rv):
        # I'm not sure if this transformation should target all even powers
        # or only those expressible as powers of 2. Also, should it only
        # make the changes in powers that appear in sums -- making an isolated
        # change is not going to allow a simplification as far as I can tell.
        if not (rv.is_Pow and rv.base.func == f):
            return rv
        if not rv.exp.is_real:
            return rv

        if (rv.exp < 0) == True:
            return rv
        if (rv.exp > max) == True:
            return rv
        if rv.exp == 1:
            return rv
        if rv.exp == 2:
            return h(g(rv.base.args[0])**2)
        else:
            if rv.exp % 2 == 1:
                e = rv.exp//2
                return f(rv.base.args[0])*h(g(rv.base.args[0])**2)**e
            elif rv.exp == 4:
                e = 2
            elif not pow:
                if rv.exp % 2:
                    return rv
                e = rv.exp//2
            else:
                p = perfect_power(rv.exp)
                if not p:
                    return rv
                e = rv.exp//2
            return h(g(rv.base.args[0])**2)**e

    return bottom_up(rv, _f)

def _parse_declarator_kind(self, kind: str, allow_paren: bool) -> c_ast.Node:
    ptr = None
    if self._peek_type() == "TIMES":
        ptr = self._parse_pointer()
    direct = self._parse_direct_declarator(kind, allow_paren=allow_paren)
    if ptr is not None:
        return self._type_modify_decl(direct, ptr)
    return direct

def _parseCache(
    self, instring, loc, doActions=True, callPreParse=True
) -> Tuple[int, ParseResults]:
    HIT, MISS = 0, 1
    TRY, MATCH, FAIL = 0, 1, 2
    lookup = (self, instring, loc, callPreParse, doActions)
    with ParserElement.packrat_cache_lock:
        cache = ParserElement.packrat_cache
        value = cache.get(lookup)
        if value is cache.not_in_cache:
            ParserElement.packrat_cache_stats[MISS] += 1
            try:
                value = self._parseNoCache(instring, loc, doActions, callPreParse)
            except ParseBaseException as pe:
                # cache a copy of the exception, without the traceback
                cache.set(lookup, pe.__class__(*pe.args))
                raise
            else:
                cache.set(lookup, (value[0], value[1].copy(), loc))
                return value
        else:
            ParserElement.packrat_cache_stats[HIT] += 1
            if self.debug and self.debugActions.debug_try:
                try:
                    self.debugActions.debug_try(instring, loc, self, cache_hit=True)  # type: ignore [call-arg]
                except TypeError:
                    pass
            if isinstance(value, Exception):
                if self.debug and self.debugActions.debug_fail:
                    try:
                        self.debugActions.debug_fail(
                            instring, loc, self, value, cache_hit=True  # type: ignore [call-arg]
                        )
                    except TypeError:
                        pass
                raise value

            value = cast(Tuple[int, ParseResults, int], value)
            loc_, result, endloc = value[0], value[1].copy(), value[2]
            if self.debug and self.debugActions.debug_match:
                try:
                    self.debugActions.debug_match(
                        instring, loc_, endloc, self, result, cache_hit=True  # type: ignore [call-arg]
                    )
                except TypeError:
                    pass

            return loc_, result

def _get_text_metrics_with_cache(renderer, text, fontprop, ismath, dpi):
    """Call ``renderer.get_text_width_height_descent``, caching the results."""
    # Cached based on a copy of fontprop so that later in-place mutations of
    # the passed-in argument do not mess up the cache.
    return _get_text_metrics_with_cache_impl(
        weakref.ref(renderer), text, fontprop.copy(), ismath, dpi)

def get_tokens_unprocessed(self, text, stack=('root',)):
    for index, token, value in CppLexer.get_tokens_unprocessed(self, text, stack):
        if value in self.structure:
            yield index, Name.Builtin, value
        elif value in self.operators:
            yield index, Operator, value
        elif value in self.variables:
            yield index, Keyword.Reserved, value
        elif value in self.suppress_highlight:
            yield index, Name, value
        elif value in self.functions:
            yield index, Name.Function, value
        else:
            yield index, token, value

def __call__(
    self, environ: WSGIEnvironment, start_response: StartResponse
) -> t.Iterable[bytes]:
    path = get_path_info(environ)
    file_loader = None

    for search_path, loader in self.exports:
        if search_path == path:
            real_filename, file_loader = loader(None)

            if file_loader is not None:
                break

        if not search_path.endswith("/"):
            search_path += "/"

        if path.startswith(search_path):
            real_filename, file_loader = loader(path[len(search_path) :])

            if file_loader is not None:
                break

    if file_loader is None or not self.is_allowed(real_filename):  # type: ignore
        return self.app(environ, start_response)

    guessed_type = mimetypes.guess_type(real_filename)  # type: ignore
    mime_type = get_content_type(guessed_type[0] or self.fallback_mimetype, "utf-8")
    f, mtime, file_size = file_loader()

    headers = [("Date", http_date())]

    if self.cache:
        timeout = self.cache_timeout
        etag = self.generate_etag(mtime, file_size, real_filename)  # type: ignore
        headers += [
            ("Etag", f'"{etag}"'),
            ("Cache-Control", f"max-age={timeout}, public"),
        ]

        if not is_resource_modified(environ, etag, last_modified=mtime):
            f.close()
            start_response("304 Not Modified", headers)
            return []

        headers.append(("Expires", http_date(time() + timeout)))
    else:
        headers.append(("Cache-Control", "public"))

    headers.extend(
        (
            ("Content-Type", mime_type),
            ("Content-Length", str(file_size)),
            ("Last-Modified", http_date(mtime)),
        )
    )
    start_response("200 OK", headers)
    return wrap_file(environ, f)

def validate_color_for_prop_cycle(s):
    # N-th color cycle syntax can't go into the color cycle.
    if isinstance(s, str) and re.match("^C[0-9]$", s):
        raise ValueError(f"Cannot put cycle reference ({s!r}) in prop_cycler")
    return validate_color(s)

def _print_Derivative(self, der_expr):
    from sympy.physics.vector.functions import dynamicsymbols
    # make sure it is in the right form
    der_expr = der_expr.doit()
    if not isinstance(der_expr, Derivative):
        return r"\left(%s\right)" % self.doprint(der_expr)

    # check if expr is a dynamicsymbol
    t = dynamicsymbols._t
    expr = der_expr.expr
    red = expr.atoms(AppliedUndef)
    syms = der_expr.variables
    test1 = not all(True for i in red if i.free_symbols == {t})
    test2 = not all(t == i for i in syms)
    if test1 or test2:
        return super()._print_Derivative(der_expr)

    # done checking
    dots = len(syms)
    base = self._print_Function(expr)
    base_split = base.split('_', 1)
    base = base_split[0]
    if dots == 1:
        base = r"\dot{%s}" % base
    elif dots == 2:
        base = r"\ddot{%s}" % base
    elif dots == 3:
        base = r"\dddot{%s}" % base
    elif dots == 4:
        base = r"\ddddot{%s}" % base
    else:  # Fallback to standard printing
        return super()._print_Derivative(der_expr)
    if len(base_split) != 1:
        base += '_' + base_split[1]
    return base

def parse_qsl(qs, keep_blank_values=False, strict_parsing=False,
              encoding='utf-8', errors='replace', max_num_fields=None, separator='&'):
    """Parse a query given as a string argument.

        Arguments:

        qs: percent-encoded query string to be parsed

        keep_blank_values: flag indicating whether blank values in
            percent-encoded queries should be treated as blank strings.
            A true value indicates that blanks should be retained as blank
            strings.  The default false value indicates that blank values
            are to be ignored and treated as if they were  not included.

        strict_parsing: flag indicating what to do with parsing errors. If
            false (the default), errors are silently ignored. If true,
            errors raise a ValueError exception.

        encoding and errors: specify how to decode percent-encoded sequences
            into Unicode characters, as accepted by the bytes.decode() method.

        max_num_fields: int. If set, then throws a ValueError
            if there are more than n fields read by parse_qsl().

        separator: str. The symbol to use for separating the query arguments.
            Defaults to &.

        Returns a list, as G-d intended.
    """

    if not separator or not isinstance(separator, (str, bytes)):
        raise ValueError("Separator must be of type string or bytes.")
    if isinstance(qs, str):
        if not isinstance(separator, str):
            separator = str(separator, 'ascii')
        eq = '='
        def _unquote(s):
            return unquote_plus(s, encoding=encoding, errors=errors)
    else:
        if not qs:
            return []
        # Use memoryview() to reject integers and iterables,
        # acceptable by the bytes constructor.
        qs = bytes(memoryview(qs))
        if isinstance(separator, str):
            separator = bytes(separator, 'ascii')
        eq = b'='
        def _unquote(s):
            return unquote_to_bytes(s.replace(b'+', b' '))

    if not qs:
        return []

    # If max_num_fields is defined then check that the number of fields
    # is less than max_num_fields. This prevents a memory exhaustion DOS
    # attack via post bodies with many fields.
    if max_num_fields is not None:
        num_fields = 1 + qs.count(separator)
        if max_num_fields < num_fields:
            raise ValueError('Max number of fields exceeded')

    r = []
    for name_value in qs.split(separator):
        if name_value or strict_parsing:
            name, has_eq, value = name_value.partition(eq)
            if not has_eq and strict_parsing:
                raise ValueError("bad query field: %r" % (name_value,))
            if value or keep_blank_values:
                name = _unquote(name)
                value = _unquote(value)
                r.append((name, value))
    return r

def _setResultsName(self, name, listAllMatches=False):
    if (
        __diag__.warn_ungrouped_named_tokens_in_collection
        and Diagnostics.warn_ungrouped_named_tokens_in_collection
        not in self.suppress_warnings_
    ):
        for e in [self.expr] + self.expr.recurse():
            if (
                isinstance(e, ParserElement)
                and e.resultsName
                and Diagnostics.warn_ungrouped_named_tokens_in_collection
                not in e.suppress_warnings_
            ):
                warnings.warn(
                    "{}: setting results name {!r} on {} expression "
                    "collides with {!r} on contained expression".format(
                        "warn_ungrouped_named_tokens_in_collection",
                        name,
                        type(self).__name__,
                        e.resultsName,
                    ),
                    stacklevel=3,
                )

    return super()._setResultsName(name, listAllMatches)

def __init__(self,
             smartTagType=(),
            ):
    self.smartTagType = smartTagType

def decorator(f: _AnyCallable) -> CmdType:
    if isinstance(f, Command):
        raise TypeError("Attempted to convert a callback into a command twice.")

    attr_params = attrs.pop("params", None)
    params = attr_params if attr_params is not None else []

    try:
        decorator_params = f.__click_params__  # type: ignore
    except AttributeError:
        pass
    else:
        del f.__click_params__  # type: ignore
        params.extend(reversed(decorator_params))

    if attrs.get("help") is None:
        attrs["help"] = f.__doc__

    if t.TYPE_CHECKING:
        assert cls is not None
        assert not callable(name)

    if name is not None:
        cmd_name = name
    else:
        cmd_name = f.__name__.lower().replace("_", "-")
        cmd_left, sep, suffix = cmd_name.rpartition("-")

        if sep and suffix in {"command", "cmd", "group", "grp"}:
            cmd_name = cmd_left

    cmd = cls(name=cmd_name, callback=f, params=params, **attrs)
    cmd.__doc__ = f.__doc__
    return cmd

def null_safe_rl(expr: _T) -> _T:
    result = rule(expr)
    if result is None:
        return expr
    return result

def getinit(a, var):
    if isstring(var):
        init, showinit = '""', "''"
    else:
        init, showinit = '', ''
    if hasinitvalue(var):
        init = var['=']
        showinit = init
        if iscomplex(var) or iscomplexarray(var):
            ret = {}

            try:
                v = var["="]
                if ',' in v:
                    ret['init.r'], ret['init.i'] = markoutercomma(
                        v[1:-1]).split('@,@')
                else:
                    v = eval(v, {}, {})
                    ret['init.r'], ret['init.i'] = str(v.real), str(v.imag)
            except Exception:
                raise ValueError(
                    f'getinit: expected complex number `(r,i)\' but got `{init}\' as initial value of {a!r}.')
            if isarray(var):
                init = f"(capi_c.r={ret['init.r']},capi_c.i={ret['init.i']},capi_c)"
        elif isstring(var):
            if not init:
                init, showinit = '""', "''"
            if init[0] == "'":
                init = '"%s"' % (init[1:-1].replace('"', '\\"'))
            if init[0] == '"':
                showinit = f"'{init[1:-1]}'"
    return init, showinit

def __init__(self, env, engine, parser, **kwargs) -> None:
