def save(self, file=None, filename=None, adjoin=True):
    """Saves the image into the ``file`` or ``filename``. It takes
    only one argument at a time.

    :param file: a file object to write to
    :type file: file object
    :param filename: a filename string to write to
    :type filename: :class:`str`
    :param adjoin: write all images to a single multi-image file. Only
                   available if file format supports frames, layers, & etc.
    :type adjoin: :class:`bool`

    .. versionadded:: 0.1.1

    .. versionchanged:: 0.1.5
       The ``file`` parameter was added.

    .. versionchanged:: 6.0.0
       The ``adjoin`` parameter was added.

    """
    if file is None and filename is None:
        raise TypeError('expected an argument')
    elif file is not None and filename is not None:
        raise TypeError('expected only one argument; but two passed')
    elif file is not None:
        is_fd = (isinstance(file, IOBase),
                 hasattr(libc, 'fdopen'),
                 callable(getattr(file, 'fileno', None)),
                 hasattr(file, 'mode'))
        if isinstance(file, str):
            raise TypeError('file must be a writable file object, '
                            'but {0!r} is a string; did you want '
                            '.save(filename={0!r})?'.format(file))
        elif all(is_fd):
            fd = libc.fdopen(file.fileno(), binary(file.mode))
            if library.MagickGetNumberImages(self.wand) > 1:
                r = library.MagickWriteImagesFile(self.wand, fd)
            else:
                r = library.MagickWriteImageFile(self.wand, fd)
            libc.fflush(fd)
            if not r:
                self.raise_exception()
        elif not callable(getattr(file, 'write', None)):
            raise TypeError('file must be a writable file object, '
                            'but it does not have write() method: ' +
                            repr(file))
        else:
            file.write(self.make_blob())
    else:
        if not isinstance(filename, str):
            if not hasattr(filename, '__fspath__'):
                raise TypeError('filename must be a string, not ' +
                                repr(filename))
        filename = encode_filename(filename)
        if library.MagickGetNumberImages(self.wand) > 1:
            r = library.MagickWriteImages(self.wand, filename, adjoin)
        else:
            r = library.MagickWriteImage(self.wand, filename)
        if not r:
            self.raise_exception()

def _keep_positive(self):
    '''Internal method to strip elements with a negative or zero count'''
    nonpositive = [elem for elem, count in self.items() if not count > 0]
    for elem in nonpositive:
        del self[elem]
    return self

def symmetric_poly(self, n):
    """
    Return the elementary symmetric polynomial of degree *n* over
    this ring's generators.
    """
    if n < 0 or n > self.ngens:
        raise ValueError("Cannot generate symmetric polynomial of order %s for %s" % (n, self.gens))
    elif not n:
        return self.one
    else:
        poly = self.zero
        for s in subsets(range(self.ngens), int(n)):
            monom = tuple(int(i in s) for i in range(self.ngens))
            poly += self.term_new(monom, self.domain.one)
        return poly

def apply_to_surface(self, verts, u_set, v_set, set_len=None, inc_pos=None):
    """
    Apply this color scheme to a
    set of vertices over two
    independent variables u and v.
    """
    bounds = create_bounds()
    cverts = []
    if callable(set_len):
        set_len(len(u_set)*len(v_set)*2)
    # calculate f() = r,g,b for each vert
    # and find the min and max for r,g,b
    for _u in range(len(u_set)):
        column = []
        for _v in range(len(v_set)):
            if verts[_u][_v] is None:
                column.append(None)
            else:
                x, y, z = verts[_u][_v]
                u, v = u_set[_u], v_set[_v]
                c = self(x, y, z, u, v)
                if c is not None:
                    c = list(c)
                    update_bounds(bounds, c)
                column.append(c)
            if callable(inc_pos):
                inc_pos()
        cverts.append(column)
    # scale and apply gradient
    for _u in range(len(u_set)):
        for _v in range(len(v_set)):
            if cverts[_u][_v] is not None:
                # scale from [f_min, f_max] to [0,1]
                for _c in range(3):
                    cverts[_u][_v][_c] = rinterpolate(bounds[_c][0],
                                         bounds[_c][1], cverts[_u][_v][_c])
                # apply gradient
                cverts[_u][_v] = self.gradient(*cverts[_u][_v])
            if callable(inc_pos):
                inc_pos()
    return cverts

def _update_wrapper(wrapper, wrapped,
                    assigned=functools.WRAPPER_ASSIGNMENTS,
                    updated=functools.WRAPPER_UPDATES):
    for attr in assigned:
        try:
            value = getattr(wrapped, attr)
        except AttributeError:
            continue
        else:
            setattr(wrapper, attr, value)
    for attr in updated:
        getattr(wrapper, attr).update(getattr(wrapped, attr, {}))
    wrapper.__wrapped__ = wrapped
    return wrapper

def before_get(self, parser, section, option, value, defaults):
    L = []
    self._interpolate_some(parser, option, L, value, section, defaults, 1)
    return ''.join(L)

def _handle_ndarray_creation_inputs(cls, iterable=None, shape=None, **kwargs):
    from sympy.matrices.matrixbase import MatrixBase
    from sympy.tensor.array import SparseNDimArray

    if shape is None:
        if iterable is None:
            shape = ()
            iterable = ()
        # Construction of a sparse array from a sparse array
        elif isinstance(iterable, SparseNDimArray):
            return iterable._shape, iterable._sparse_array

        # Construct N-dim array from another N-dim array:
        elif isinstance(iterable, NDimArray):
            shape = iterable.shape

        # Construct N-dim array from an iterable (numpy arrays included):
        elif isinstance(iterable, Iterable):
            iterable, shape = cls._scan_iterable_shape(iterable)

        # Construct N-dim array from a Matrix:
        elif isinstance(iterable, MatrixBase):
            shape = iterable.shape

        else:
            shape = ()
            iterable = (iterable,)

    if isinstance(iterable, (Dict, dict)) and shape is not None:
        new_dict = iterable.copy()
        for k in new_dict:
            if isinstance(k, (tuple, Tuple)):
                new_key = 0
                for i, idx in enumerate(k):
                    new_key = new_key * shape[i] + idx
                iterable[new_key] = iterable[k]
                del iterable[k]

    if isinstance(shape, (SYMPY_INTS, Integer)):
        shape = (shape,)

    if not all(isinstance(dim, (SYMPY_INTS, Integer)) for dim in shape):
        raise TypeError("Shape should contain integers only.")

    return tuple(shape), iterable

def parseImpl(self, instring, loc, doActions=True):
    # check first character of opening quote to see if that is a match
    # before doing the more complicated regex match
    result = (
        instring[loc] == self.first_quote_char
        and self.re_match(instring, loc)
        or None
    )
    if not result:
        raise ParseException(instring, loc, self.errmsg, self)

    # get ending loc and matched string from regex matching result
    loc = result.end()
    ret = result.group()

    if self.unquote_results:
        # strip off quotes
        ret = ret[self.quote_char_len : -self.end_quote_char_len]

        if isinstance(ret, str_type):
            # fmt: off
            if self.convert_whitespace_escapes:
                # as we iterate over matches in the input string,
                # collect from whichever match group of the unquote_scan_re
                # regex matches (only 1 group will match at any given time)
                ret = "".join(
                    # match group 1 matches \t, \n, etc.
                    self.ws_map[match.group(1)] if match.group(1)
                    # match group 2 matches escaped characters
                    else match.group(2)[-1] if match.group(2)
                    # match group 3 matches any character
                    else match.group(3)
                    for match in self.unquote_scan_re.finditer(ret)
                )
            else:
                ret = "".join(
                    # match group 1 matches escaped characters
                    match.group(1)[-1] if match.group(1)
                    # match group 2 matches any character
                    else match.group(2)
                    for match in self.unquote_scan_re.finditer(ret)
                )
            # fmt: on

            # replace escaped quotes
            if self.esc_quote:
                ret = ret.replace(self.esc_quote, self.end_quote_char)

    return loc, ret

def _galois_group_degree_6_lookup(T, max_tries=30, randomize=False):
    r"""
    Compute the Galois group of a polynomial of degree 6.

    Explanation
    ===========

    Based on Alg 6.3.10 of [1], but uses resolvent coeff lookup.

    """
    from sympy.combinatorics.galois import S6TransitiveSubgroups

    # First resolvent:

    history = set()
    for i in range(max_tries):
        R_dup = get_resolvent_by_lookup(T, 1)
        if dup_sqf_p(R_dup, ZZ):
            break
        _, T = tschirnhausen_transformation(T, max_tries=max_tries,
                                            history=history,
                                            fixed_order=not randomize)
    else:
        raise MaxTriesException

    fl = dup_factor_list(R_dup, ZZ)

    # Group the factors by degree.
    factors_by_deg = defaultdict(list)
    for r, _ in fl[1]:
        factors_by_deg[len(r) - 1].append(r)

    L = sorted(sum([
        [d] * len(ff) for d, ff in factors_by_deg.items()
    ], []))

    T_has_sq_disc = has_square_disc(T)

    if L == [1, 2, 3]:
        f1 = factors_by_deg[3][0]
        return ((S6TransitiveSubgroups.C6, False) if has_square_disc(f1)
                else (S6TransitiveSubgroups.D6, False))

    elif L == [3, 3]:
        f1, f2 = factors_by_deg[3]
        any_square = has_square_disc(f1) or has_square_disc(f2)
        return ((S6TransitiveSubgroups.G18, False) if any_square
                else (S6TransitiveSubgroups.G36m, False))

    elif L == [2, 4]:
        if T_has_sq_disc:
            return (S6TransitiveSubgroups.S4p, True)
        else:
            f1 = factors_by_deg[4][0]
            return ((S6TransitiveSubgroups.A4xC2, False) if has_square_disc(f1)
                    else (S6TransitiveSubgroups.S4xC2, False))

    elif L == [1, 1, 4]:
        return ((S6TransitiveSubgroups.A4, True) if T_has_sq_disc
                else (S6TransitiveSubgroups.S4m, False))

    elif L == [1, 5]:
        return ((S6TransitiveSubgroups.PSL2F5, True) if T_has_sq_disc
                else (S6TransitiveSubgroups.PGL2F5, False))

    elif L == [1, 1, 1, 3]:
        return (S6TransitiveSubgroups.S3, False)

    assert L == [6]

    # Second resolvent:

    history = set()
    for i in range(max_tries):
        R_dup = get_resolvent_by_lookup(T, 2)
        if dup_sqf_p(R_dup, ZZ):
            break
        _, T = tschirnhausen_transformation(T, max_tries=max_tries,
                                            history=history,
                                            fixed_order=not randomize)
    else:
        raise MaxTriesException

    T_has_sq_disc = has_square_disc(T)

    if dup_irreducible_p(R_dup, ZZ):
        return ((S6TransitiveSubgroups.A6, True) if T_has_sq_disc
                else (S6TransitiveSubgroups.S6, False))
    else:
        return ((S6TransitiveSubgroups.G36p, True) if T_has_sq_disc
                else (S6TransitiveSubgroups.G72, False))

def _validate_linestyle(ls):
    """
    A validator for all possible line styles, the named ones *and*
    the on-off ink sequences.
    """
    if isinstance(ls, str):
        try:  # Look first for a valid named line style, like '--' or 'solid'.
            return _validate_named_linestyle(ls)
        except ValueError:
            pass
        try:
            ls = ast.literal_eval(ls)  # Parsing matplotlibrc.
        except (SyntaxError, ValueError):
            pass  # Will error with the ValueError at the end.

    def _is_iterable_not_string_like(x):
        # Explicitly exclude bytes/bytearrays so that they are not
        # nonsensically interpreted as sequences of numbers (codepoints).
        return np.iterable(x) and not isinstance(x, (str, bytes, bytearray))

    if _is_iterable_not_string_like(ls):
        if len(ls) == 2 and _is_iterable_not_string_like(ls[1]):
            # (offset, (on, off, on, off, ...))
            offset, onoff = ls
        else:
            # For backcompat: (on, off, on, off, ...); the offset is implicit.
            offset = 0
            onoff = ls

        if (isinstance(offset, Real)
                and len(onoff) % 2 == 0
                and all(isinstance(elem, Real) for elem in onoff)):
            return (offset, onoff)

    raise ValueError(f"linestyle {ls!r} is not a valid on-off ink sequence.")

def _sparse_fit(self, X, strategy, missing_values, fill_value):
    """Fit the transformer on sparse data."""
    missing_mask = _get_mask(X, missing_values)
    mask_data = missing_mask.data
    n_implicit_zeros = X.shape[0] - np.diff(X.indptr)

    statistics = np.empty(X.shape[1])

    if strategy == "constant":
        # for constant strategy, self.statistics_ is used to store
        # fill_value in each column, or np.nan for columns to drop
        statistics.fill(fill_value)

        if not self.keep_empty_features:
            for i in range(missing_mask.shape[1]):
                if all(missing_mask[:, i].data):
                    statistics[i] = np.nan

    else:
        for i in range(X.shape[1]):
            column = X.data[X.indptr[i] : X.indptr[i + 1]]
            mask_column = mask_data[X.indptr[i] : X.indptr[i + 1]]
            column = column[~mask_column]

            # combine explicit and implicit zeros
            mask_zeros = _get_mask(column, 0)
            column = column[~mask_zeros]
            n_explicit_zeros = mask_zeros.sum()
            n_zeros = n_implicit_zeros[i] + n_explicit_zeros

            if len(column) == 0 and self.keep_empty_features:
                # in case we want to keep columns with only missing values.
                statistics[i] = 0
            else:
                if strategy == "mean":
                    s = column.size + n_zeros
                    statistics[i] = np.nan if s == 0 else column.sum() / s

                elif strategy == "median":
                    statistics[i] = _get_median(column, n_zeros)

                elif strategy == "most_frequent":
                    statistics[i] = _most_frequent(column, 0, n_zeros)

                elif isinstance(strategy, Callable):
                    statistics[i] = self.strategy(column)

    super()._fit_indicator(missing_mask)

    return statistics

def _open(self) -> None:
    if not SUPPORTED:
        msg = "image file could not be opened because AVIF support not installed"
        raise SyntaxError(msg)

    if DECODE_CODEC_CHOICE != "auto" and not _avif.decoder_codec_available(
        DECODE_CODEC_CHOICE
    ):
        msg = "Invalid opening codec"
        raise ValueError(msg)

    assert self.fp is not None
    self._decoder = _avif.AvifDecoder(
        self.fp.read(),
        DECODE_CODEC_CHOICE,
        _get_default_max_threads(),
    )

    # Get info from decoder
    self._size, self.n_frames, self._mode, icc, exif, exif_orientation, xmp = (
        self._decoder.get_info()
    )
    self.is_animated = self.n_frames > 1

    if icc:
        self.info["icc_profile"] = icc
    if xmp:
        self.info["xmp"] = xmp

    if exif_orientation != 1 or exif:
        exif_data = Image.Exif()
        if exif:
            exif_data.load(exif)
            original_orientation = exif_data.get(ExifTags.Base.Orientation, 1)
        else:
            original_orientation = 1
        if exif_orientation != original_orientation:
            exif_data[ExifTags.Base.Orientation] = exif_orientation
            exif = exif_data.tobytes()
    if exif:
        self.info["exif"] = exif
    self.seek(0)

def getstrlength(var):
    if isstringfunction(var):
        if 'result' in var:
            a = var['result']
        else:
            a = var['name']
        if a in var['vars']:
            return getstrlength(var['vars'][a])
        else:
            errmess(f'getstrlength: function {a} has no return value?!\n')
    if not isstring(var):
        errmess(
            f'getstrlength: expected a signature of a string but got: {repr(var)}\n')
    len = '1'
    if 'charselector' in var:
        a = var['charselector']
        if '*' in a:
            len = a['*']
        elif 'len' in a:
            len = f2cexpr(a['len'])
    if re.match(r'\(\s*(\*|:)\s*\)', len) or re.match(r'(\*|:)', len):
        if isintent_hide(var):
            errmess('getstrlength:intent(hide): expected a string with defined length but got: %s\n' % (
                repr(var)))
        len = '-1'
    return len

def _untagged_response(self, typ, dat, name):
    if typ == 'NO':
        return typ, dat
    if not name in self.untagged_responses:
        return typ, [None]
    data = self.untagged_responses.pop(name)
    if __debug__:
        if self.debug >= 5:
            self._mesg('untagged_responses[%s] => %s' % (name, data))
    return typ, data

def edit_file(self, filename: str) -> None:
    import subprocess

    editor = self.get_editor()
    environ: t.Optional[t.Dict[str, str]] = None

    if self.env:
        environ = os.environ.copy()
        environ.update(self.env)

    try:
        c = subprocess.Popen(f'{editor} "{filename}"', env=environ, shell=True)
        exit_code = c.wait()
        if exit_code != 0:
            raise ClickException(
                _("{editor}: Editing failed").format(editor=editor)
            )
    except OSError as e:
        raise ClickException(
            _("{editor}: Editing failed: {e}").format(editor=editor, e=e)
        ) from e

def _handle_target_dir(
    self, target_dir: str, target_temp_dir: TempDirectory, upgrade: bool
) -> None:
    ensure_dir(target_dir)

    # Checking both purelib and platlib directories for installed
    # packages to be moved to target directory
    lib_dir_list = []

    # Checking both purelib and platlib directories for installed
    # packages to be moved to target directory
    scheme = get_scheme("", home=target_temp_dir.path)
    purelib_dir = scheme.purelib
    platlib_dir = scheme.platlib
    data_dir = scheme.data

    if os.path.exists(purelib_dir):
        lib_dir_list.append(purelib_dir)
    if os.path.exists(platlib_dir) and platlib_dir != purelib_dir:
        lib_dir_list.append(platlib_dir)
    if os.path.exists(data_dir):
        lib_dir_list.append(data_dir)

    for lib_dir in lib_dir_list:
        for item in os.listdir(lib_dir):
            if lib_dir == data_dir:
                ddir = os.path.join(data_dir, item)
                if any(s.startswith(ddir) for s in lib_dir_list[:-1]):
                    continue
            target_item_dir = os.path.join(target_dir, item)
            if os.path.exists(target_item_dir):
                if not upgrade:
                    logger.warning(
                        "Target directory %s already exists. Specify "
                        "--upgrade to force replacement.",
                        target_item_dir,
                    )
                    continue
                if os.path.islink(target_item_dir):
                    logger.warning(
                        "Target directory %s already exists and is "
                        "a link. pip will not automatically replace "
                        "links, please remove if replacement is "
                        "desired.",
                        target_item_dir,
                    )
                    continue
                if os.path.isdir(target_item_dir):
                    shutil.rmtree(target_item_dir)
                else:
                    os.remove(target_item_dir)

            shutil.move(os.path.join(lib_dir, item), target_item_dir)

def __init__(self, seq):
    if isinstance(seq, str):
        self.data = seq
    elif isinstance(seq, UserString):
        self.data = seq.data[:]
    else:
        self.data = str(seq)

def validate_axisbelow(s):
    try:
        return validate_bool(s)
    except ValueError:
        if isinstance(s, str):
            if s == 'line':
                return 'line'
    raise ValueError(f'{s!r} cannot be interpreted as'
                     ' True, False, or "line"')

def updateFilenameFromPath(self, masters=True, instances=True, force=False):
    """Set a descriptor filename attr from the path and this document path.

    If the filename attribute is not None: skip it.
    """
    if masters:
        for descriptor in self.sources:
            if descriptor.filename is not None and not force:
                continue
            if self.path is not None:
                descriptor.filename = self._posixRelativePath(descriptor.path)
    if instances:
        for descriptor in self.instances:
            if descriptor.filename is not None and not force:
                continue
            if self.path is not None:
                descriptor.filename = self._posixRelativePath(descriptor.path)

def update_interface(self) -> None:
    """Update the interface."""
    try:
        line = self.status_stream.readline()
    except OSError as err:
        # resource temporarly unavailable is ignored
        if err.errno != errno.EAGAIN and err.errno != errno.EWOULDBLOCK:
            print(err.strerror)
        return

    pkgname = status = status_str = percent = base = ""

    if line.startswith("pm"):
        try:
            (status, pkgname, percent, status_str) = line.split(":", 3)
        except ValueError:
            # silently ignore lines that can't be parsed
            return
    elif line.startswith("status"):
        try:
            (base, pkgname, status, status_str) = line.split(":", 3)
        except ValueError:
            (base, pkgname, status) = line.split(":", 2)
    elif line.startswith("processing"):
        (status, status_str, pkgname) = line.split(":", 2)
        self.processing(pkgname.strip(), status_str.strip())

    # Always strip the status message
    pkgname = pkgname.strip()
    status_str = status_str.strip()
    status = status.strip()

    if status == "pmerror" or status == "error":
        self.error(pkgname, status_str)
    elif status == "conffile-prompt" or status == "pmconffile":
        match = re.match("\\s*'(.*)'\\s*'(.*)'.*", status_str)
        if match:
            self.conffile(match.group(1), match.group(2))
    elif status == "pmstatus":
        # FIXME: Float comparison
        if float(percent) != self.percent or status_str != self.status:
            self.status_change(pkgname, float(percent), status_str.strip())
            self.percent = float(percent)
            self.status = status_str.strip()
    elif base == "status":
        self.dpkg_status_change(pkgname, status)

def _parse_specifier(package_spec: str) -> ParsedPackage:
    """Parse package_spec as would be given to pipx"""
    # If package_spec is valid pypi name, pip will always treat it as a
    #       pypi package, not checking for local path.
    #       We replicate pypi precedence here (only non-valid-pypi names
    #       initiate check for local path, e.g. './package-name')
    valid_pep508 = None
    valid_url = None
    valid_local_path = None

    try:
        package_req = Requirement(package_spec)
    except InvalidRequirement:
        # not a valid PEP508 package specification
        pass
    else:
        # valid PEP508 package specification
        valid_pep508 = package_req

    if valid_pep508 and package_req.name.endswith(ARCHIVE_EXTENSIONS):
        # It might be a local archive
        (package_path, package_path_exists) = _check_package_path(package_req.name)

        if package_path_exists:
            valid_local_path = str(package_path.resolve())
        else:
            raise PipxError(f"{package_path} does not exist")

    # If this looks like a URL, treat it as such.
    if not valid_pep508:
        parsed_url = urllib.parse.urlsplit(package_spec)
        if parsed_url.scheme and parsed_url.netloc:
            valid_url = package_spec

    # Treat the input as a local path if it does not look like a PEP 508
    # specifier nor a URL. In this case we want to split out the extra part.
    if not valid_pep508 and not valid_url:
        (package_path_str, package_extras_str) = _split_path_extras(package_spec)
        (package_path, package_path_exists) = _check_package_path(package_path_str)
        if package_path_exists:
            valid_local_path = str(package_path.resolve()) + package_extras_str

    if not valid_pep508 and not valid_url and not valid_local_path:
        raise PipxError(f"Unable to parse package spec: {package_spec}")

    if valid_pep508 and valid_local_path:
        # It is a valid local path without "./"
        # Use valid_local_path
        valid_pep508 = None

    return ParsedPackage(
        valid_pep508=valid_pep508,
        valid_url=valid_url,
        valid_local_path=valid_local_path,
    )

def cb_routsign2map(rout, um):
    """
    name,begintitle,endtitle,argname
    ctype,rctype,maxnofargs,nofoptargs,returncptr
    """
    ret = {'name': f"cb_{rout['name']}_in_{um}",
           'returncptr': ''}
    if isintent_callback(rout):
        if '_' in rout['name']:
            F_FUNC = 'F_FUNC_US'
        else:
            F_FUNC = 'F_FUNC'
        ret['callbackname'] = f"{F_FUNC}({rout['name'].lower()},{rout['name'].upper()})"
        ret['static'] = 'extern'
    else:
        ret['callbackname'] = ret['name']
        ret['static'] = 'static'
    ret['argname'] = rout['name']
    ret['begintitle'] = gentitle(ret['name'])
    ret['endtitle'] = gentitle(f"end of {ret['name']}")
    ret['ctype'] = getctype(rout)
    ret['rctype'] = 'void'
    if ret['ctype'] == 'string':
        ret['rctype'] = 'void'
    else:
        ret['rctype'] = ret['ctype']
    if ret['rctype'] != 'void':
        if iscomplexfunction(rout):
            ret['returncptr'] = """
#ifdef F2PY_CB_RETURNCOMPLEX
return_value=
#endif
"""
        else:
            ret['returncptr'] = 'return_value='
    if ret['ctype'] in cformat_map:
        ret['showvalueformat'] = f"{cformat_map[ret['ctype']]}"
    if isstringfunction(rout):
        ret['strlength'] = getstrlength(rout)
    if isfunction(rout):
        if 'result' in rout:
            a = rout['result']
        else:
            a = rout['name']
        if hasnote(rout['vars'][a]):
            ret['note'] = rout['vars'][a]['note']
            rout['vars'][a]['note'] = ['See elsewhere.']
        ret['rname'] = a
        ret['pydocsign'], ret['pydocsignout'] = getpydocsign(a, rout)
        if iscomplexfunction(rout):
            ret['rctype'] = """
#ifdef F2PY_CB_RETURNCOMPLEX
#ctype#
#else
void
#endif
"""
    elif hasnote(rout):
        ret['note'] = rout['note']
        rout['note'] = ['See elsewhere.']
    nofargs = 0
    nofoptargs = 0
    if 'args' in rout and 'vars' in rout:
        for a in rout['args']:
            var = rout['vars'][a]
            if l_or(isintent_in, isintent_inout)(var):
                nofargs = nofargs + 1
                if isoptional(var):
                    nofoptargs = nofoptargs + 1
    ret['maxnofargs'] = repr(nofargs)
    ret['nofoptargs'] = repr(nofoptargs)
    if hasnote(rout) and isfunction(rout) and 'result' in rout:
        ret['routnote'] = rout['note']
        rout['note'] = ['See elsewhere.']
    return ret

def _parse_struct_declarator(self) -> "_DeclInfo":
    if self._accept("COLON"):
        bitsize = self._parse_constant_expression()
        return {
            "decl": c_ast.TypeDecl(None, None, None, None),
            "init": None,
            "bitsize": bitsize,
        }

    decl = self._parse_declarator()
    if self._accept("COLON"):
        bitsize = self._parse_constant_expression()
        return {"decl": decl, "init": None, "bitsize": bitsize}

    return {"decl": decl, "init": None, "bitsize": None}

def _f(rv):
    # I'm not sure if this transformation should target all even powers
    # or only those expressible as powers of 2. Also, should it only
    # make the changes in powers that appear in sums -- making an isolated
    # change is not going to allow a simplification as far as I can tell.
    if not (rv.is_Pow and rv.base.func == f):
        return rv
    if not rv.exp.is_real:
        return rv

    if (rv.exp < 0) == True:
        return rv
    if (rv.exp > max) == True:
        return rv
    if rv.exp == 1:
        return rv
    if rv.exp == 2:
        return h(g(rv.base.args[0])**2)
    else:
        if rv.exp % 2 == 1:
            e = rv.exp//2
            return f(rv.base.args[0])*h(g(rv.base.args[0])**2)**e
        elif rv.exp == 4:
            e = 2
        elif not pow:
            if rv.exp % 2:
                return rv
            e = rv.exp//2
        else:
            p = perfect_power(rv.exp)
            if not p:
                return rv
            e = rv.exp//2
        return h(g(rv.base.args[0])**2)**e

def connection_made(self, transport):
    if self._reject_connection:
        context = {
            'message': ('An open stream was garbage collected prior to '
                        'establishing network connection; '
                        'call "stream.close()" explicitly.')
        }
        if self._source_traceback:
            context['source_traceback'] = self._source_traceback
        self._loop.call_exception_handler(context)
        transport.abort()
        return
    self._transport = transport
    reader = self._stream_reader
    if reader is not None:
        reader.set_transport(transport)
    self._over_ssl = transport.get_extra_info('sslcontext') is not None
    if self._client_connected_cb is not None:
        self._stream_writer = StreamWriter(transport, self,
                                           reader,
                                           self._loop)
        res = self._client_connected_cb(reader,
                                        self._stream_writer)
        if coroutines.iscoroutine(res):
            def callback(task):
                if task.cancelled():
                    transport.close()
                    return
                exc = task.exception()
                if exc is not None:
                    self._loop.call_exception_handler({
                        'message': 'Unhandled exception in client_connected_cb',
                        'exception': exc,
                        'transport': transport,
                    })
                    transport.close()

            self._task = self._loop.create_task(res)
            self._task.add_done_callback(callback)

        self._strong_reader = None

def _expect_reference_link(
    text: str, start: int, link_text: str, link_ref_defs: dict[str, tuple[str, str]]
) -> tuple[Group, Group, int] | None:
    link_label = _parse_link_label(text, start)
    label = link_text
    if link_label is not None:
        assert link_label.text is not None
        label = link_label.text[1:-1] or link_text
    elif text[start : start + 2] == "[]":
        link_label = Group(start, start + 2, "[]")
    result = _get_reference_link(label, link_ref_defs)
    if not result:
        return None
    link_dest = Group(start, start, result[0])
    link_title = Group(start, start, result[1])
    return (link_dest, link_title, link_label.end if link_label else start)

def is_left_flanking(self) -> bool:
    return (
        self.end < len(self.text)
        and self.whitespace_re.match(self.text, self.end) is None
    ) and (
        not self.followed_by_punc()
        or self.start == 0
        or self.preceded_by_punc()
        or self.whitespace_re.match(self.text, self.start - 1) is not None
    )

def _to_py(self, x):
    if isinstance(x, str):
        return "b'%s'" % (x,)
    if isinstance(x, (list, tuple)):
        rep = [self._to_py(item) for item in x]
        if len(rep) == 1:
            rep.append('')
        return "(%s)" % (','.join(rep),)
    return x.as_python_expr()  # Py2: unicode unexpected; Py3: bytes unexp.

def _resize_state(self):
    """Add additional ``n_estimators`` entries to all attributes."""
    # self.n_estimators is the number of additional est to fit
    total_n_estimators = self.n_estimators
    if total_n_estimators < self.estimators_.shape[0]:
        raise ValueError(
            "resize with smaller n_estimators %d < %d"
            % (total_n_estimators, self.estimators_[0])
        )

    self.estimators_ = np.resize(
        self.estimators_, (total_n_estimators, self.n_trees_per_iteration_)
    )
    self.train_score_ = np.resize(self.train_score_, total_n_estimators)
    if self.subsample < 1 or hasattr(self, "oob_improvement_"):
        # if do oob resize arrays or create new if not available
        if hasattr(self, "oob_improvement_"):
            self.oob_improvement_ = np.resize(
                self.oob_improvement_, total_n_estimators
            )
            self.oob_scores_ = np.resize(self.oob_scores_, total_n_estimators)
            self.oob_score_ = np.nan
        else:
            self.oob_improvement_ = np.zeros(
                (total_n_estimators,), dtype=np.float64
            )
            self.oob_scores_ = np.zeros((total_n_estimators,), dtype=np.float64)
            self.oob_score_ = np.nan

def _command(self, name, *args):

    if self.state not in Commands[name]:
        self.literal = None
        raise self.error("command %s illegal in state %s, "
                         "only allowed in states %s" %
                         (name, self.state,
                          ', '.join(Commands[name])))

    for typ in ('OK', 'NO', 'BAD'):
        if typ in self.untagged_responses:
            del self.untagged_responses[typ]

    if 'READ-ONLY' in self.untagged_responses \
    and not self.is_readonly:
        raise self.readonly('mailbox status changed to READ-ONLY')

    tag = self._new_tag()
    name = bytes(name, self._encoding)
    data = tag + b' ' + name
    for arg in args:
        if arg is None: continue
        if isinstance(arg, str):
            arg = bytes(arg, self._encoding)
        data = data + b' ' + arg

    literal = self.literal
    if literal is not None:
        self.literal = None
        if type(literal) is type(self._command):
            literator = literal
        else:
            literator = None
            data = data + bytes(' {%s}' % len(literal), self._encoding)

    if __debug__:
        if self.debug >= 4:
            self._mesg('> %r' % data)
        else:
            self._log('> %r' % data)

    try:
        self.send(data + CRLF)
    except OSError as val:
        raise self.abort('socket error: %s' % val)

    if literal is None:
        return tag

    while 1:
        # Wait for continuation response

        while self._get_response():
            if self.tagged_commands[tag]:   # BAD/NO?
                return tag

        # Send literal

        if literator:
            literal = literator(self.continuation_response)

        if __debug__:
            if self.debug >= 4:
                self._mesg('write literal size %s' % len(literal))

        try:
            self.send(literal)
            self.send(CRLF)
        except OSError as val:
            raise self.abort('socket error: %s' % val)

        if not literator:
            break

    return tag

def _do_collect_type(self, tp):
    if not isinstance(tp, model.BaseTypeByIdentity):
        if isinstance(tp, tuple):
            for x in tp:
                self._do_collect_type(x)
        return
    if tp not in self._typesdict:
        self._typesdict[tp] = None
        if isinstance(tp, model.FunctionPtrType):
            self._do_collect_type(tp.as_raw_function())
        elif isinstance(tp, model.StructOrUnion):
            if tp.fldtypes is not None and (
                    tp not in self.ffi._parser._included_declarations):
                for name1, tp1, _, _ in self._enum_fields(tp):
                    self._do_collect_type(self._field_type(tp, name1, tp1))
        else:
            for _, x in tp._get_items():
                self._do_collect_type(x)

def _pop_symbol_list(self, lists):
    symbol_lists = []
    for l in lists:
        mark = True
        for s in l:
            if s is not None and not isinstance(s, Symbol):
                mark = False
                break
        if mark:
            lists.remove(l)
            symbol_lists.append(l)
    if len(symbol_lists) == 1:
        return symbol_lists[0]
    elif len(symbol_lists) == 0:
        return []
    else:
        raise ValueError("Only one list of Symbols "
                         "can be given for a color scheme.")

def _clip(a, min=None, max=None, out=None, **kwargs):
    if a.dtype.kind in "iu":
        # If min/max is a Python integer, deal with out-of-bound values here.
        # (This enforces NEP 50 rules as no value based promotion is done.)
        if type(min) is int and min <= np.iinfo(a.dtype).min:
            min = None
        if type(max) is int and max >= np.iinfo(a.dtype).max:
            max = None

    if min is None and max is None:
        # return identity
        return um.positive(a, out=out, **kwargs)
    elif min is None:
        return um.minimum(a, max, out=out, **kwargs)
    elif max is None:
        return um.maximum(a, min, out=out, **kwargs)
    else:
        return um.clip(a, min, max, out=out, **kwargs)

def feed(self, byte_str: Union[bytes, bytearray]) -> ProbingState:
    assert self.coding_sm is not None
    assert self.distribution_analyzer is not None

    for i, byte in enumerate(byte_str):
        coding_state = self.coding_sm.next_state(byte)
        if coding_state == MachineState.ERROR:
            self.logger.debug(
                "%s %s prober hit error at byte %s",
                self.charset_name,
                self.language,
                i,
            )
            self._state = ProbingState.NOT_ME
            break
        if coding_state == MachineState.ITS_ME:
            self._state = ProbingState.FOUND_IT
            break
        if coding_state == MachineState.START:
            char_len = self.coding_sm.get_current_charlen()
            if i == 0:
                self._last_char[1] = byte
                self.context_analyzer.feed(
                    self._last_char[2 - char_len :], char_len
                )
                self.distribution_analyzer.feed(self._last_char, char_len)
            else:
                self.context_analyzer.feed(
                    byte_str[i + 1 - char_len : i + 3 - char_len], char_len
                )
                self.distribution_analyzer.feed(byte_str[i - 1 : i + 1], char_len)

    self._last_char[0] = byte_str[-1]

    if self.state == ProbingState.DETECTING:
        if self.context_analyzer.got_enough_data() and (
            self.get_confidence() > self.SHORTCUT_THRESHOLD
        ):
            self._state = ProbingState.FOUND_IT

    return self.state

def get_extras(package_spec: str) -> Set[str]:
    parsed_package = _parse_specifier(package_spec)
    if parsed_package.valid_pep508 and parsed_package.valid_pep508.extras is not None:
        return parsed_package.valid_pep508.extras
    elif parsed_package.valid_local_path:
        (_, package_extras_str) = _split_path_extras(parsed_package.valid_local_path)
        return Requirement("notapackage" + package_extras_str).extras

    return set()

def denom(self, a):
    """Returns denominator of `a`. """
    return a.denominator

def _eval_is_integer(self):
    is_rational = self._eval_is_rational()
    if is_rational is False:
        return False

    numerators = []
    denominators = []
    unknown = False
    for a in self.args:
        hit = False
        if a.is_integer:
            if abs(a) is not S.One:
                numerators.append(a)
        elif a.is_Rational:
            n, d = a.as_numer_denom()
            if abs(n) is not S.One:
                numerators.append(n)
            if d is not S.One:
                denominators.append(d)
        elif a.is_Pow:
            b, e = a.as_base_exp()
            if not b.is_integer or not e.is_integer:
                hit = unknown = True
            if e.is_negative:
                denominators.append(2 if a is S.Half else
                    Pow(a, S.NegativeOne))
            elif not hit:
                # int b and pos int e: a = b**e is integer
                assert not e.is_positive
                # for rational self and e equal to zero: a = b**e is 1
                assert not e.is_zero
                return # sign of e unknown -> self.is_integer unknown
            else:
                # x**2, 2**x, or x**y with x and y int-unknown -> unknown
                return
        else:
            return

    if not denominators and not unknown:
        return True

    allodd = lambda x: all(i.is_odd for i in x)
    alleven = lambda x: all(i.is_even for i in x)
    anyeven = lambda x: any(i.is_even for i in x)

    from .relational import is_gt
    if not numerators and denominators and all(
            is_gt(_, S.One) for _ in denominators):
        return False
    elif unknown:
        return
    elif allodd(numerators) and anyeven(denominators):
        return False
    elif anyeven(numerators) and denominators == [2]:
        return True
    elif alleven(numerators) and allodd(denominators
            ) and (Mul(*denominators, evaluate=False) - 1
            ).is_positive:
        return False
    if len(denominators) == 1:
        d = denominators[0]
        if d.is_Integer and d.is_even:
            # if minimal power of 2 in num vs den is not
            # negative then we have an integer
            if (Add(*[i.as_base_exp()[1] for i in
                    numerators if i.is_even]) - trailing(d.p)
                    ).is_nonnegative:
                return True
    if len(numerators) == 1:
        n = numerators[0]
        if n.is_Integer and n.is_even:
            # if minimal power of 2 in den vs num is positive
            # then we have have a non-integer
            if (Add(*[i.as_base_exp()[1] for i in
                    denominators if i.is_even]) - trailing(n.p)
                    ).is_positive:
                return False

def _save_transformersPreTrainedTokenizerBase(pickler, obj):
    log(pickler, f"Tok: {obj}")
    # Ignore the `cache` attribute and make hashing stable.
    #
    # Some tokenizers backed by the `tokenizers` library mutate their internal `_tokenizer` state when called
    # (e.g. by enabling truncation/padding). This can change the serialized bytes across runs and make dataset
    # fingerprints unstable, which prevents `.map(load_from_cache_file=True)` from reusing cache files.
    #
    # For hashing/fingerprinting, we temporarily disable backend truncation/padding to avoid these runtime settings
    # affecting the fingerprint, then restore the original settings.
    state = obj.__dict__.copy()
    if "cache" in state and isinstance(state["cache"], dict):
        state["cache"] = {}
    if "deprecation_warnings" in state and isinstance(state["deprecation_warnings"], dict):
        state["deprecation_warnings"] = {}

    backend_tokenizer = obj.__dict__.get("_tokenizer")
    truncation = padding = None
    if (
        backend_tokenizer is not None
        and hasattr(backend_tokenizer, "truncation")
        and hasattr(backend_tokenizer, "padding")
    ):
        truncation = backend_tokenizer.truncation
        padding = backend_tokenizer.padding
        try:
            if truncation is not None and hasattr(backend_tokenizer, "no_truncation"):
                backend_tokenizer.no_truncation()
            if padding is not None and hasattr(backend_tokenizer, "no_padding"):
                backend_tokenizer.no_padding()
        except Exception:
            truncation = padding = None

    try:
        pickler.save_reduce(type(obj), (), state=state, obj=obj)
    finally:
        try:
            if backend_tokenizer is not None:
                if truncation is not None and hasattr(backend_tokenizer, "enable_truncation"):
                    backend_tokenizer.enable_truncation(**truncation)
                if padding is not None and hasattr(backend_tokenizer, "enable_padding"):
                    backend_tokenizer.enable_padding(**padding)
        except Exception:
            pass
    log(pickler, "# Tok")

def visit_Assign(self, node, **kwargs):
    cmpr = ast.Compare(
        ops=[ast.Eq()], left=node.targets[0], comparators=[node.value]
    )
    return self.visit(cmpr)

def subset_glyphs(self, s):
    if self.Format == 1:
        return self.ExtSubTable.subset_glyphs(s)
    else:
        assert 0, "unknown format: %s" % self.Format

def path_qs(self) -> str:
    """The URL including PATH_INFO and the query string.

    E.g, /app/blog?id=10
    """
    return str(self._rel_url)

def get_tokens_unprocessed(self, text, stack=('root',)):
    for index, token, value in CLexer.get_tokens_unprocessed(self, text, stack):
        if token is Name:
            if value in self.variable_qualifiers:
                token = Keyword.Type
            elif value in self.vector_types:
                token = Keyword.Type
            elif value in self.variables:
                token = Name.Builtin
            elif value in self.execution_confs:
                token = Keyword.Pseudo
            elif value in self.function_qualifiers:
                token = Keyword.Reserved
            elif value in self.functions:
                token = Name.Function
        yield index, token, value

def test_test(env: "Environment", value: str) -> bool:
    """Check if a test exists by name. Useful if a test may be
    optionally available.

    .. code-block:: jinja

        {% if 'loud' is test %}
            {% if value is loud %}
                {{ value|upper }}
            {% else %}
                {{ value|lower }}
            {% endif %}
        {% else %}
            {{ value }}
        {% endif %}

    .. versionadded:: 3.0
    """
    return value in env.tests

