def selected_alpn_protocol(self):
    self._checkClosed()
    if self._sslobj is None or not _ssl.HAS_ALPN:
        return None
    else:
        return self._sslobj.selected_alpn_protocol()

def print_log(self):
    self._mesg('last %d IMAP4 interactions:' % len(self._cmd_log))
    i, n = self._cmd_log_idx, self._cmd_log_len
    while n:
        try:
            self._mesg(*self._cmd_log[i])
        except:
            pass
        i += 1
        if i >= self._cmd_log_len:
            i = 0
        n -= 1

def get_bsdf_serializer(options):
    from . import _bsdf as bsdf

    class NDArrayExtension(bsdf.Extension):
        """Copy of BSDF's NDArrayExtension but deal with lazy blobs."""

        name = "ndarray"
        cls = np.ndarray

        def encode(self, s, v):
            return dict(shape=v.shape, dtype=str(v.dtype), data=v.tobytes())

        def decode(self, s, v):
            return v  # return as dict, because of lazy blobs, decode in Image

    class ImageExtension(bsdf.Extension):
        """We implement two extensions that trigger on the Image classes."""

        def encode(self, s, v):
            return dict(array=v.array, meta=v.meta)

        def decode(self, s, v):
            return Image(v["array"], v["meta"])

    class Image2DExtension(ImageExtension):
        name = "image2d"
        cls = Image2D

    class Image3DExtension(ImageExtension):
        name = "image3d"
        cls = Image3D

    exts = [NDArrayExtension, Image2DExtension, Image3DExtension]
    serializer = bsdf.BsdfSerializer(exts, **options)

    return bsdf, serializer

def parseImpl(self, instring, loc, doActions=True):
    if loc < len(instring):
        if instring[loc] == "\n":
            return loc + 1, "\n"
        else:
            raise ParseException(instring, loc, self.errmsg, self)
    elif loc == len(instring):
        return loc + 1, []
    else:
        raise ParseException(instring, loc, self.errmsg, self)

def length(self):
    """Length of the series expansion"""
    raise NotImplementedError("(%s).length" % self)

def doRollover(self):
    """
    Do a rollover, as described in __init__().
    """
    if self.stream:
        self.stream.close()
        self.stream = None
    if self.backupCount > 0:
        for i in range(self.backupCount - 1, 0, -1):
            sfn = self.rotation_filename("%s.%d" % (self.baseFilename, i))
            dfn = self.rotation_filename("%s.%d" % (self.baseFilename,
                                                    i + 1))
            if os.path.exists(sfn):
                if os.path.exists(dfn):
                    os.remove(dfn)
                os.rename(sfn, dfn)
        dfn = self.rotation_filename(self.baseFilename + ".1")
        if os.path.exists(dfn):
            os.remove(dfn)
        self.rotate(self.baseFilename, dfn)
    if not self.delay:
        self.stream = self._open()

def try_parse(
    self,
    instring: str,
    loc: int,
    *,
    raise_fatal: bool = False,
    do_actions: bool = False,
) -> int:
    try:
        return self._parse(instring, loc, doActions=do_actions)[0]
    except ParseFatalException:
        if raise_fatal:
            raise
        raise ParseException(instring, loc, self.errmsg, self)

def unquote_to_bytes(string):
    """unquote_to_bytes('abc%20def') -> b'abc def'."""
    return bytes(_unquote_impl(string))

def parse_table_STAT_(self, table):
    statements = table.statements
    design_axes = []
    while self.next_token_ != "}" or self.cur_comments_:
        self.advance_lexer_(comments=True)
        if self.cur_token_type_ is Lexer.COMMENT:
            statements.append(
                self.ast.Comment(self.cur_token_, location=self.cur_token_location_)
            )
        elif self.cur_token_type_ is Lexer.NAME:
            if self.is_cur_keyword_("ElidedFallbackName"):
                names = self.parse_STAT_ElidedFallbackName()
                statements.append(self.ast.ElidedFallbackName(names))
            elif self.is_cur_keyword_("ElidedFallbackNameID"):
                value = self.expect_number_()
                statements.append(self.ast.ElidedFallbackNameID(value))
                self.expect_symbol_(";")
            elif self.is_cur_keyword_("DesignAxis"):
                designAxis = self.parse_STAT_design_axis()
                design_axes.append(designAxis.tag)
                statements.append(designAxis)
                self.expect_symbol_(";")
            elif self.is_cur_keyword_("AxisValue"):
                axisValueRecord = self.parse_STAT_axis_value_()
                for location in axisValueRecord.locations:
                    if location.tag not in design_axes:
                        # Tag must be defined in a DesignAxis before it
                        # can be referenced
                        raise FeatureLibError(
                            "DesignAxis not defined for " f"{location.tag}.",
                            self.cur_token_location_,
                        )
                statements.append(axisValueRecord)
                self.expect_symbol_(";")
            else:
                raise FeatureLibError(
                    f"Unexpected token {self.cur_token_}", self.cur_token_location_
                )
        elif self.cur_token_ == ";":
            continue

def decode(self, inp):
    if not inp:
        return b''
    return binascii.a2b_base64(inp)

def _parseCache(
    self, instring, loc, doActions=True, callPreParse=True
) -> Tuple[int, ParseResults]:
    HIT, MISS = 0, 1
    TRY, MATCH, FAIL = 0, 1, 2
    lookup = (self, instring, loc, callPreParse, doActions)
    with ParserElement.packrat_cache_lock:
        cache = ParserElement.packrat_cache
        value = cache.get(lookup)
        if value is cache.not_in_cache:
            ParserElement.packrat_cache_stats[MISS] += 1
            try:
                value = self._parseNoCache(instring, loc, doActions, callPreParse)
            except ParseBaseException as pe:
                # cache a copy of the exception, without the traceback
                cache.set(lookup, pe.__class__(*pe.args))
                raise
            else:
                cache.set(lookup, (value[0], value[1].copy(), loc))
                return value
        else:
            ParserElement.packrat_cache_stats[HIT] += 1
            if self.debug and self.debugActions.debug_try:
                try:
                    self.debugActions.debug_try(instring, loc, self, cache_hit=True)  # type: ignore [call-arg]
                except TypeError:
                    pass
            if isinstance(value, Exception):
                if self.debug and self.debugActions.debug_fail:
                    try:
                        self.debugActions.debug_fail(
                            instring, loc, self, value, cache_hit=True  # type: ignore [call-arg]
                        )
                    except TypeError:
                        pass
                raise value

            value = cast(Tuple[int, ParseResults, int], value)
            loc_, result, endloc = value[0], value[1].copy(), value[2]
            if self.debug and self.debugActions.debug_match:
                try:
                    self.debugActions.debug_match(
                        instring, loc_, endloc, self, result, cache_hit=True  # type: ignore [call-arg]
                    )
                except TypeError:
                    pass

            return loc_, result

def postParse(self, instring, loc, tokenlist):
    for i, tok in enumerate(tokenlist):
        if len(tok) == 0:
            continue

        ikey = tok[0]
        if isinstance(ikey, int):
            ikey = str(ikey).strip()

        if len(tok) == 1:
            tokenlist[ikey] = _ParseResultsWithOffset("", i)

        elif len(tok) == 2 and not isinstance(tok[1], ParseResults):
            tokenlist[ikey] = _ParseResultsWithOffset(tok[1], i)

        else:
            try:
                dictvalue = tok.copy()  # ParseResults(i)
            except Exception:
                exc = TypeError(
                    "could not extract dict values from parsed results"
                    " - Dict expression must contain Grouped expressions"
                )
                raise exc from None

            del dictvalue[0]

            if len(dictvalue) != 1 or (
                isinstance(dictvalue, ParseResults) and dictvalue.haskeys()
            ):
                tokenlist[ikey] = _ParseResultsWithOffset(dictvalue, i)
            else:
                tokenlist[ikey] = _ParseResultsWithOffset(dictvalue[0], i)

    if self._asPythonDict:
        return [tokenlist.as_dict()] if self.resultsName else tokenlist.as_dict()
    else:
        return [tokenlist] if self.resultsName else tokenlist

def _get_error_bars_props(self, options):
    # Convert user error bars properties to structure required internally.
    if not options:
        return {}

    # Default values.
    error_bars = {"type": "fixedVal", "value": 1, "endcap": 1, "direction": "both"}

    types = {
        "fixed": "fixedVal",
        "percentage": "percentage",
        "standard_deviation": "stdDev",
        "standard_error": "stdErr",
        "custom": "cust",
    }

    # Check the error bars type.
    error_type = options["type"]

    if error_type in types:
        error_bars["type"] = types[error_type]
    else:
        warn(f"Unknown error bars type '{error_type}")
        return {}

    # Set the value for error types that require it.
    if "value" in options:
        error_bars["value"] = options["value"]

    # Set the end-cap style.
    if "end_style" in options:
        error_bars["endcap"] = options["end_style"]

    # Set the error bar direction.
    if "direction" in options:
        if options["direction"] == "minus":
            error_bars["direction"] = "minus"
        elif options["direction"] == "plus":
            error_bars["direction"] = "plus"
        else:
            # Default to 'both'.
            pass

    # Set any custom values.
    error_bars["plus_values"] = options.get("plus_values")
    error_bars["minus_values"] = options.get("minus_values")
    error_bars["plus_data"] = options.get("plus_data")
    error_bars["minus_data"] = options.get("minus_data")

    # Set the line properties for the error bars.
    error_bars["line"] = Shape._get_line_properties(options)

    return error_bars

def _setResultsName(self, name, listAllMatches=False):
    if (
        __diag__.warn_ungrouped_named_tokens_in_collection
        and Diagnostics.warn_ungrouped_named_tokens_in_collection
        not in self.suppress_warnings_
    ):
        for e in self.exprs:
            if (
                isinstance(e, ParserElement)
                and e.resultsName
                and Diagnostics.warn_ungrouped_named_tokens_in_collection
                not in e.suppress_warnings_
            ):
                warnings.warn(
                    "{}: setting results name {!r} on {} expression "
                    "collides with {!r} on contained expression".format(
                        "warn_ungrouped_named_tokens_in_collection",
                        name,
                        type(self).__name__,
                        e.resultsName,
                    ),
                    stacklevel=3,
                )

    return super()._setResultsName(name, listAllMatches)

def _galois_group_degree_5_lookup_ext_factor(T, max_tries=30, randomize=False):
    r"""
    Compute the Galois group of a polynomial of degree 5.

    Explanation
    ===========

    Based on Alg 6.3.9 of [1], but uses resolvent coeff lookup, plus
    factorization over an algebraic extension.

    """
    from sympy.combinatorics.galois import S5TransitiveSubgroups

    _T = T

    history = set()
    for i in range(max_tries):
        R_dup = get_resolvent_by_lookup(T, 1)
        if dup_sqf_p(R_dup, ZZ):
            break
        _, T = tschirnhausen_transformation(T, max_tries=max_tries,
                                            history=history,
                                            fixed_order=not randomize)
    else:
        raise MaxTriesException

    sq_disc = has_square_disc(T)

    if dup_irreducible_p(R_dup, ZZ):
        return ((S5TransitiveSubgroups.A5, True) if sq_disc
                else (S5TransitiveSubgroups.S5, False))

    if not sq_disc:
        return (S5TransitiveSubgroups.M20, False)

    # If we get this far, Gal(T) can only be D5 or C5.
    # But for Gal(T) to have order 5, T must already split completely in
    # the extension field obtained by adjoining a single one of its roots.
    fl = Poly(_T, domain=ZZ.alg_field_from_poly(_T)).factor_list()[1]
    if len(fl) == 5:
        return (S5TransitiveSubgroups.C5, True)
    else:
        return (S5TransitiveSubgroups.D5, True)

def map_style(self, markers=None, dashes=None, order=None):
    mapping = StyleMapping(self, markers, dashes, order)
    self._style_map = mapping

def __or__(self, other) -> "ParserElement":
    """
    Implementation of ``|`` operator - returns :class:`MatchFirst`
    """
    if other is Ellipsis:
        return _PendingSkip(self, must_skip=True)

    if isinstance(other, str_type):
        # `expr | ""` is equivalent to `Opt(expr)`
        if other == "":
            return Opt(self)
        other = self._literalStringClass(other)
    if not isinstance(other, ParserElement):
        return NotImplemented
    return MatchFirst([self, other])

def parseOptions(args):
    rawOptions, files = getopt.gnu_getopt(
        args,
        "ld:o:fvqht:x:sgim:z:baey:",
        [
            "unicodedata=",
            "recalc-timestamp",
            "no-recalc-timestamp",
            "flavor=",
            "version",
            "with-zopfli",
            "newline=",
            "optimize-font-speed",
        ],
    )

    options = Options(rawOptions, len(files))
    jobs = []

    if not files:
        raise getopt.GetoptError("Must specify at least one input file")

    for input in files:
        if input != "-" and not os.path.isfile(input):
            raise getopt.GetoptError('File not found: "%s"' % input)
        tp = guessFileType(input)
        if tp in ("OTF", "TTF", "TTC", "WOFF", "WOFF2"):
            extension = ".ttx"
            if options.listTables:
                action = ttList
            else:
                action = ttDump
        elif tp == "TTX":
            extension = "." + options.flavor if options.flavor else ".ttf"
            action = ttCompile
        elif tp == "OTX":
            extension = "." + options.flavor if options.flavor else ".otf"
            action = ttCompile
        else:
            raise getopt.GetoptError('Unknown file type: "%s"' % input)

        if options.outputFile:
            output = options.outputFile
        else:
            if input == "-":
                raise getopt.GetoptError("Must provide -o when reading from stdin")
            output = makeOutputFileName(
                input, options.outputDir, extension, options.overWrite
            )
            # 'touch' output file to avoid race condition in choosing file names
            if action != ttList:
                open(output, "a").close()
        jobs.append((action, input, output))
    return jobs, options

def _is_python_file(filename):
    '''Check if a file is a Python source file.'''
    if (
        filename == '-'
        or filename.endswith('.py')
        or (SUPPORTS_IPYNB and filename.endswith('.ipynb'))
    ):
        return True
    try:
        with open(filename) as fobj:
            first_line = fobj.readline()
            if first_line.startswith('#!') and 'python' in first_line:
                return True
    except Exception:
        return False
    return False

def parseImpl(self, instring, loc, doActions=True):
    if instring[loc] == self.firstMatchChar and instring.startswith(
        self.match, loc
    ):
        return loc + self.matchLen, self.match
    raise ParseException(instring, loc, self.errmsg, self)

def __sub__(p1, p2):
    """Subtract polynomial p2 from p1.

    Examples
    ========

    >>> from sympy.polys.domains import ZZ
    >>> from sympy.polys.rings import ring

    >>> _, x, y = ring('x, y', ZZ)
    >>> p1 = x + y**2
    >>> p2 = x*y + y**2
    >>> p1 - p2
    -x*y + x

    """
    if not p2:
        return p1.copy()
    ring = p1.ring
    if ring.is_element(p2):
        p = p1.copy()
        get = p.get
        zero = ring.domain.zero
        for k, v in p2.items():
            v = get(k, zero) - v
            if v:
                p[k] = v
            else:
                del p[k]
        return p
    elif isinstance(p2, PolyElement):
        if isinstance(ring.domain, PolynomialRing) and ring.domain.ring == p2.ring:
            pass
        elif isinstance(p2.ring.domain, PolynomialRing) and p2.ring.domain.ring == ring:
            return p2.__rsub__(p1)
        else:
            return NotImplemented

    try:
        p2 = ring.domain_new(p2)
    except CoercionFailed:
        return NotImplemented
    else:
        p = p1.copy()
        zm = ring.zero_monom
        if zm not in p1.keys():
            p[zm] = -p2
        else:
            if p2 == p[zm]:
                del p[zm]
            else:
                p[zm] -= p2
        return p

