        test_writable_dir(d)
        for d in set(get_lib_location_guesses(root=root, isolated=isolated))
    )

def generate(cls) -> Ed448PrivateKey:
    from cryptography.hazmat.backends.openssl.backend import backend

    if not backend.ed448_supported():
        raise UnsupportedAlgorithm(
            "ed448 is not supported by this version of OpenSSL.",
            _Reasons.UNSUPPORTED_PUBLIC_KEY_ALGORITHM,
        )

    return rust_openssl.ed448.generate_key()

def searchsorted(
    self,
    value: NumpyValueArrayLike | ExtensionArray,
    side: Literal["left", "right"] = "left",
    sorter: NumpySorter | None = None,
) -> npt.NDArray[np.intp] | np.intp:
    npvalue = self._validate_setitem_value(value)
    return self._ndarray.searchsorted(npvalue, side=side, sorter=sorter)

def readRules(self):
    # we also need to read any conditions that are outside of a condition set.
    rules = []
    rulesElement = self.root.find(".rules")
    if rulesElement is not None:
        processingValue = rulesElement.attrib.get("processing", "first")
        if processingValue not in {"first", "last"}:
            raise DesignSpaceDocumentError(
                "<rules> processing attribute value is not valid: %r, "
                "expected 'first' or 'last'" % processingValue
            )
        self.documentObject.rulesProcessingLast = processingValue == "last"
    for ruleElement in self.root.findall(".rules/rule"):
        ruleObject = self.ruleDescriptorClass()
        ruleName = ruleObject.name = ruleElement.attrib.get("name")
        # read any stray conditions outside a condition set
        externalConditions = self._readConditionElements(
            ruleElement,
            ruleName,
        )
        if externalConditions:
            ruleObject.conditionSets.append(externalConditions)
            self.log.info(
                "Found stray rule conditions outside a conditionset. "
                "Wrapped them in a new conditionset."
            )
        # read the conditionsets
        for conditionSetElement in ruleElement.findall(".conditionset"):
            conditionSet = self._readConditionElements(
                conditionSetElement,
                ruleName,
            )
            if conditionSet is not None:
                ruleObject.conditionSets.append(conditionSet)
        for subElement in ruleElement.findall(".sub"):
            a = subElement.attrib["name"]
            b = subElement.attrib["with"]
            ruleObject.subs.append((a, b))
        rules.append(ruleObject)
    self.documentObject.rules = rules

def get_phrase(value):
    """ phrase = 1*word / obs-phrase
        obs-phrase = word *(word / "." / CFWS)

    This means a phrase can be a sequence of words, periods, and CFWS in any
    order as long as it starts with at least one word.  If anything other than
    words is detected, an ObsoleteHeaderDefect is added to the token's defect
    list.  We also accept a phrase that starts with CFWS followed by a dot;
    this is registered as an InvalidHeaderDefect, since it is not supported by
    even the obsolete grammar.

    """
    phrase = Phrase()
    try:
        token, value = get_word(value)
        phrase.append(token)
    except errors.HeaderParseError:
        phrase.defects.append(errors.InvalidHeaderDefect(
            "phrase does not start with word"))
    while value and value[0] not in PHRASE_ENDS:
        if value[0]=='.':
            phrase.append(DOT)
            phrase.defects.append(errors.ObsoleteHeaderDefect(
                "period in 'phrase'"))
            value = value[1:]
        else:
            try:
                token, value = get_word(value)
            except errors.HeaderParseError:
                if value[0] in CFWS_LEADER:
                    token, value = get_cfws(value)
                    phrase.defects.append(errors.ObsoleteHeaderDefect(
                        "comment found without atom"))
                else:
                    raise
            phrase.append(token)
    return phrase, value

def reset_translation(
    self, reader: Union[None, PdfReader, IndirectObject] = None
) -> None:
    """
    Reset the translation table between reader and the writer object.

    Late cloning will create new independent objects.

    Args:
        reader: PdfReader or IndirectObject referencing a PdfReader object.
            if set to None or omitted, all tables will be reset.

    """
    if reader is None:
        self._id_translated = {}
    elif isinstance(reader, PdfReader):
        try:
            del self._id_translated[id(reader)]
        except Exception:
            pass
    elif isinstance(reader, IndirectObject):
        try:
            del self._id_translated[id(reader.pdf)]
        except Exception:
            pass
    else:
        raise Exception("invalid parameter {reader}")

def _parse_expression_opt(self) -> Optional[c_ast.Node]:
    if self._starts_expression():
        return self._parse_expression()
    return None

def replace_in_obj(
    obj: PdfObject, crossref: Dict[IndirectObject, IndirectObject]
) -> None:
    if isinstance(obj, DictionaryObject):
        key_val = obj.items()
    elif isinstance(obj, ArrayObject):
        key_val = enumerate(obj)  # type: ignore
    else:
        return
    assert isinstance(obj, (DictionaryObject, ArrayObject))
    for k, v in key_val:
        if isinstance(v, IndirectObject):
            orphans[v.idnum - 1] = False
            if v in crossref:
                obj[k] = crossref[v]
        else:
            """the filtering on DictionaryObject and ArrayObject only
            will be performed within replace_in_obj"""
            replace_in_obj(v, crossref)

def getusersitepackages():
    """Returns the user-specific site-packages directory path.

    If the global variable ``USER_SITE`` is not initialized yet, this
    function will also set it.
    """
    global USER_SITE, ENABLE_USER_SITE
    userbase = getuserbase() # this will also set USER_BASE

    if USER_SITE is None:
        if userbase is None:
            ENABLE_USER_SITE = False # disable user site and return None
        else:
            USER_SITE = _get_path(userbase)

    return USER_SITE

def last_update(
    self, last_update: datetime.datetime
) -> CertificateRevocationListBuilder:
    if not isinstance(last_update, datetime.datetime):
        raise TypeError("Expecting datetime object.")
    if self._last_update is not None:
        raise ValueError("Last update may only be set once.")
    last_update = _convert_to_naive_utc_time(last_update)
    if last_update < _EARLIEST_UTC_TIME:
        raise ValueError(
            "The last update date must be on or after" " 1950 January 1."
        )
    if self._next_update is not None and last_update > self._next_update:
        raise ValueError(
            "The last update date must be before the next update date."
        )
    return CertificateRevocationListBuilder(
        self._issuer_name,
        last_update,
        self._next_update,
        self._extensions,
        self._revoked_certificates,
    )

def is_cur_keyword_(self, k):
    if self.cur_token_type_ is Lexer.NAME:
        if isinstance(k, type("")):  # basestring is gone in Python3
            return self.cur_token_ == k
        else:
            return self.cur_token_ in k
    return False

def a(self):
    a, b = self._mpi_
    return self.ctx.make_mpf((a, a))

def parseImpl(self, instring, loc, doActions=True):
    errmsg = self.errmsg
    errloc = loc
    if self.caseless:
        if instring[loc : loc + self.matchLen].upper() == self.caselessmatch:
            if loc == 0 or instring[loc - 1].upper() not in self.identChars:
                if (
                    loc >= len(instring) - self.matchLen
                    or instring[loc + self.matchLen].upper() not in self.identChars
                ):
                    return loc + self.matchLen, self.match
                else:
                    # followed by keyword char
                    errmsg += ", was immediately followed by keyword character"
                    errloc = loc + self.matchLen
            else:
                # preceded by keyword char
                errmsg += ", keyword was immediately preceded by keyword character"
                errloc = loc - 1
        # else no match just raise plain exception

    else:
        if (
            instring[loc] == self.firstMatchChar
            and self.matchLen == 1
            or instring.startswith(self.match, loc)
        ):
            if loc == 0 or instring[loc - 1] not in self.identChars:
                if (
                    loc >= len(instring) - self.matchLen
                    or instring[loc + self.matchLen] not in self.identChars
                ):
                    return loc + self.matchLen, self.match
                else:
                    # followed by keyword char
                    errmsg += (
                        ", keyword was immediately followed by keyword character"
                    )
                    errloc = loc + self.matchLen
            else:
                # preceded by keyword char
                errmsg += ", keyword was immediately preceded by keyword character"
                errloc = loc - 1
        # else no match just raise plain exception

    raise ParseException(instring, errloc, errmsg, self)

def emit(self, record):
    """
    Emit a record.

    Writes the LogRecord to the queue, preparing it for pickling first.
    """
    try:
        self.enqueue(self.prepare(record))
    except Exception:
        self.handleError(record)

def subset_lookups(self, lookup_indices):
    c = self.__subset_classify_context()

    if self.Format in [1, 2]:
        for rs in getattr(self, c.RuleSet):
            if not rs:
                continue
            for r in getattr(rs, c.Rule):
                if not r:
                    continue
                setattr(
                    r,
                    c.LookupRecord,
                    [
                        ll
                        for ll in getattr(r, c.LookupRecord)
                        if ll and ll.LookupListIndex in lookup_indices
                    ],
                )
                for ll in getattr(r, c.LookupRecord):
                    if not ll:
                        continue
                    ll.LookupListIndex = lookup_indices.index(ll.LookupListIndex)
    elif self.Format == 3:
        setattr(
            self,
            c.LookupRecord,
            [
                ll
                for ll in getattr(self, c.LookupRecord)
                if ll and ll.LookupListIndex in lookup_indices
            ],
        )
        for ll in getattr(self, c.LookupRecord):
            if not ll:
                continue
            ll.LookupListIndex = lookup_indices.index(ll.LookupListIndex)
    else:
        assert 0, "unknown format: %s" % self.Format

def _parse_any_declarator(
    self, allow_abstract: bool = False, typeid_paren_as_abstract: bool = False
) -> Tuple[Optional[c_ast.Node], bool]:
    # C declarators are ambiguous without lookahead. For example:
    #   int foo(int (aa));   -> aa is a name (ID)
    #   typedef char TT;
    #   int bar(int (TT));   -> TT is a type (TYPEID) in parens
    name_type, saw_paren = self._peek_declarator_name_info()
    if name_type is None or (
        typeid_paren_as_abstract and name_type == "TYPEID" and saw_paren
    ):
        if not allow_abstract:
            tok = self._peek()
            coord = self._tok_coord(tok) if tok is not None else self.clex.filename
            self._parse_error("Invalid declarator", coord)
        decl = self._parse_abstract_declarator_opt()
        return decl, False

    if name_type == "TYPEID":
        if typeid_paren_as_abstract:
            decl = self._parse_typeid_noparen_declarator()
        else:
            decl = self._parse_typeid_declarator()
    else:
        decl = self._parse_id_declarator()
    return decl, True

def _parse_assignment_expression(self) -> c_ast.Node:
    if self._peek_type() == "LPAREN" and self._peek_type(2) == "LBRACE":
        self._advance()
        comp = self._parse_compound_statement()
        self._expect("RPAREN")
        return comp

    expr = self._parse_conditional_expression()
    if self._is_assignment_op():
        op = self._advance().value
        rhs = self._parse_assignment_expression()
        return c_ast.Assignment(op, expr, rhs, expr.coord)
    return expr

def subset_glyphs(self, s):
    if self.Format == 1:
        mark1_indices = self.Mark1Coverage.subset(s.glyphs)
        self.Mark1Array.MarkRecord = _list_subset(
            self.Mark1Array.MarkRecord, mark1_indices
        )
        self.Mark1Array.MarkCount = len(self.Mark1Array.MarkRecord)
        class_indices = _uniq_sort(v.Class for v in self.Mark1Array.MarkRecord)

        intersect_mark2_indices = self.Mark2Coverage.intersect(s.glyphs)
        mark2_records = self.Mark2Array.Mark2Record
        num_mark2_records = len(mark2_records)
        mark2_indices = [
            i
            for i in intersect_mark2_indices
            if i < num_mark2_records
            and any(mark2_records[i].Mark2Anchor[j] is not None for j in class_indices)
        ]
        if not mark2_indices:
            return False

        self.Mark2Coverage.remap(mark2_indices)
        self.Mark2Array.Mark2Record = _list_subset(
            self.Mark2Array.Mark2Record, mark2_indices
        )
        self.Mark2Array.MarkCount = len(self.Mark2Array.Mark2Record)
        # Prune empty classes
        self.ClassCount = len(class_indices)
        for m in self.Mark1Array.MarkRecord:
            m.Class = class_indices.index(m.Class)
        for b in self.Mark2Array.Mark2Record:
            b.Mark2Anchor = _list_subset(b.Mark2Anchor, class_indices)
        return bool(
            self.ClassCount and self.Mark1Array.MarkCount and self.Mark2Array.MarkCount
        )
    else:
        assert 0, "unknown format: %s" % self.Format

def __init__(
    self,
    local: ContextVar[T] | Local | LocalStack[T] | t.Callable[[], T],
    name: str | None = None,
    *,
    unbound_message: str | None = None,
) -> None:
    if name is None:
        get_name = _identity
    else:
        get_name = attrgetter(name)  # type: ignore[assignment]

    if unbound_message is None:
        unbound_message = "object is not bound"

    if isinstance(local, Local):
        if name is None:
            raise TypeError("'name' is required when proxying a 'Local' object.")

        def _get_current_object() -> T:
            try:
                return get_name(local)  # type: ignore[return-value]
            except AttributeError:
                raise RuntimeError(unbound_message) from None

    elif isinstance(local, LocalStack):

        def _get_current_object() -> T:
            obj = local.top

            if obj is None:
                raise RuntimeError(unbound_message)

            return get_name(obj)

    elif isinstance(local, ContextVar):

        def _get_current_object() -> T:
            try:
                obj = local.get()
            except LookupError:
                raise RuntimeError(unbound_message) from None

            return get_name(obj)

    elif callable(local):

        def _get_current_object() -> T:
            return get_name(local())

    else:
        raise TypeError(f"Don't know how to proxy '{type(local)}'.")

    object.__setattr__(self, "_LocalProxy__wrapped", local)
    object.__setattr__(self, "_get_current_object", _get_current_object)

def prune_post_subset(self, font, options):
    # Keep whole "CPAL" if "SVG " is present as it may be referenced by the latter
    # via 'var(--color{palette_entry_index}, ...)' CSS color variables.
    # For now we just assume this is the case by the mere presence of "SVG " table,
    # for parsing SVG to collect all the used indices is too much work...
    # TODO(anthrotype): Do The Right Thing (TM).
    if "SVG " in font:
        return True

    colr = font.get("COLR")
    if not colr:  # drop CPAL if COLR was subsetted to empty
        return False

    colors_by_index = defaultdict(list)

    def collect_colors_by_index(paint):
        if hasattr(paint, "PaletteIndex"):  # either solid colors...
            colors_by_index[paint.PaletteIndex].append(paint)
        elif hasattr(paint, "ColorLine"):  # ... or gradient color stops
            for stop in paint.ColorLine.ColorStop:
                colors_by_index[stop.PaletteIndex].append(stop)

    if colr.version == 0:
        for layers in colr.ColorLayers.values():
            for layer in layers:
                colors_by_index[layer.colorID].append(layer)
    else:
        if colr.table.LayerRecordArray:
            for layer in colr.table.LayerRecordArray.LayerRecord:
                colors_by_index[layer.PaletteIndex].append(layer)
        for record in colr.table.BaseGlyphList.BaseGlyphPaintRecord:
            record.Paint.traverse(colr.table, collect_colors_by_index)

    # don't remap palette entry index 0xFFFF, this is always the foreground color
    # https://github.com/fonttools/fonttools/issues/2257
    retained_palette_indices = set(colors_by_index.keys()) - {0xFFFF}
    for palette in self.palettes:
        palette[:] = [c for i, c in enumerate(palette) if i in retained_palette_indices]
        assert len(palette) == len(retained_palette_indices)

    for new_index, old_index in enumerate(sorted(retained_palette_indices)):
        for record in colors_by_index[old_index]:
            if hasattr(record, "colorID"):  # v0
                record.colorID = new_index
            elif hasattr(record, "PaletteIndex"):  # v1
                record.PaletteIndex = new_index
            else:
                raise AssertionError(record)

    self.numPaletteEntries = len(self.palettes[0])

    if self.version == 1:
        kept_labels = []
        for i, label in enumerate(self.paletteEntryLabels):
            if i in retained_palette_indices:
                kept_labels.append(label)
        self.paletteEntryLabels = kept_labels
    return bool(self.numPaletteEntries)

def _generateDefaultName(self) -> str:
    def charsAsStr(s):
        max_repr_len = 16
        s = _collapse_string_to_ranges(s, re_escape=False)
        if len(s) > max_repr_len:
            return s[: max_repr_len - 3] + "..."
        else:
            return s

    if self.initChars != self.bodyChars:
        base = f"W:({charsAsStr(self.initChars)}, {charsAsStr(self.bodyChars)})"
    else:
        base = f"W:({charsAsStr(self.initChars)})"

    # add length specification
    if self.minLen > 1 or self.maxLen != _MAX_INT:
        if self.minLen == self.maxLen:
            if self.minLen == 1:
                return base[2:]
            else:
                return base + f"{{{self.minLen}}}"
        elif self.maxLen == _MAX_INT:
            return base + f"{{{self.minLen},...}}"
        else:
            return base + f"{{{self.minLen},{self.maxLen}}}"
    return base

def update(partial_products, indices):
    if partial_products:
        pprod = partial_products[-1]
    else:
        pprod = ctx.one
    for k in indices:
        pprod = pprod * f(a + ctx.mpf(k))
        partial_products.append(pprod)

def _eval_herm_antiherm(self, herm):
    for t in self.args:
        if t.is_hermitian is None or t.is_antihermitian is None:
            return
        if t.is_hermitian:
            continue
        elif t.is_antihermitian:
            herm = not herm
        else:
            return

    if herm is not False:
        return herm

    is_zero = self._eval_is_zero()
    if is_zero:
        return True
    elif is_zero is False:
        return herm

def connect(self, host='localhost', port=0, source_address=None):
    """Connect to a host on a given port.

    If the hostname ends with a colon (`:') followed by a number, and
    there is no port specified, that suffix will be stripped off and the
    number interpreted as the port number to use.

    Note: This method is automatically invoked by __init__, if a host is
    specified during instantiation.

    """

    if source_address:
        self.source_address = source_address

    if not port and (host.find(':') == host.rfind(':')):
        i = host.rfind(':')
        if i >= 0:
            host, port = host[:i], host[i + 1:]
            try:
                port = int(port)
            except ValueError:
                raise OSError("nonnumeric port")
    if not port:
        port = self.default_port
    sys.audit("smtplib.connect", self, host, port)
    self.sock = self._get_socket(host, port, self.timeout)
    self.file = None
    (code, msg) = self.getreply()
    if self.debuglevel > 0:
        self._print_debug('connect:', repr(msg))
    return (code, msg)

def assert_array_almost_equal(x, y, decimal=6, err_msg='', verbose=True):
    """
    Checks the equality of two masked arrays, up to given number odecimals.

    The equality is checked elementwise.

    """
    def compare(x, y):
        "Returns the result of the loose comparison between x and y)."
        return almost(x, y, decimal)
    assert_array_compare(compare, x, y, err_msg=err_msg, verbose=verbose,
                         header='Arrays are not almost equal')

def is_right_flanking(self) -> bool:
    return (
        self.start > 0
        and self.whitespace_re.match(self.text, self.start - 1) is None
    ) and (
        not self.preceded_by_punc()
        or self.end == len(self.text)
        or self.followed_by_punc()
        or self.whitespace_re.match(self.text, self.end) is not None
    )

def remapComponentsFast(self, glyphidmap):
    if not self.data or struct.unpack(">h", self.data[:2])[0] >= 0:
        return  # Not composite
    data = self.data = bytearray(self.data)
    i = 10
    more = 1
    while more:
        flags = (data[i] << 8) | data[i + 1]
        glyphID = (data[i + 2] << 8) | data[i + 3]
        # Remap
        glyphID = glyphidmap[glyphID]
        data[i + 2] = glyphID >> 8
        data[i + 3] = glyphID & 0xFF
        i += 4
        flags = int(flags)

        if flags & 0x0001:
            i += 4  # ARG_1_AND_2_ARE_WORDS
        else:
            i += 2
        if flags & 0x0008:
            i += 2  # WE_HAVE_A_SCALE
        elif flags & 0x0040:
            i += 4  # WE_HAVE_AN_X_AND_Y_SCALE
        elif flags & 0x0080:
            i += 8  # WE_HAVE_A_TWO_BY_TWO
        more = flags & 0x0020  # MORE_COMPONENTS

def __new__(cls, arg1, arg2):
    arg1, arg2 = _sympify((arg1, arg2))

    if not arg1.is_Matrix:
        raise TypeError("Argument 1 of DotProduct is not a matrix")
    if not arg2.is_Matrix:
        raise TypeError("Argument 2 of DotProduct is not a matrix")
    if not (1 in arg1.shape):
        raise TypeError("Argument 1 of DotProduct is not a vector")
    if not (1 in arg2.shape):
        raise TypeError("Argument 2 of DotProduct is not a vector")

    if set(arg1.shape) != set(arg2.shape):
        raise TypeError("DotProduct arguments are not the same length")

    return Basic.__new__(cls, arg1, arg2)

def get_by_label(
    self, text: Union[str, Pattern[str]], exact: bool = None
) -> "Locator":
    return self.locator(get_by_label_selector(text, exact=exact))

def subparse(
    self, end_tokens: t.Optional[t.Tuple[str, ...]] = None
) -> t.List[nodes.Node]:
    body: t.List[nodes.Node] = []
    data_buffer: t.List[nodes.Node] = []
    add_data = data_buffer.append

    if end_tokens is not None:
        self._end_token_stack.append(end_tokens)

    def flush_data() -> None:
        if data_buffer:
            lineno = data_buffer[0].lineno
            body.append(nodes.Output(data_buffer[:], lineno=lineno))
            del data_buffer[:]

    try:
        while self.stream:
            token = self.stream.current
            if token.type == "data":
                if token.value:
                    add_data(nodes.TemplateData(token.value, lineno=token.lineno))
                next(self.stream)
            elif token.type == "variable_begin":
                next(self.stream)
                add_data(self.parse_tuple(with_condexpr=True))
                self.stream.expect("variable_end")
            elif token.type == "block_begin":
                flush_data()
                next(self.stream)
                if end_tokens is not None and self.stream.current.test_any(
                    *end_tokens
                ):
                    return body
                rv = self.parse_statement()
                if isinstance(rv, list):
                    body.extend(rv)
                else:
                    body.append(rv)
                self.stream.expect("block_end")
            else:
                raise AssertionError("internal parsing error")

        flush_data()
    finally:
        if end_tokens is not None:
            self._end_token_stack.pop()
    return body

def get_param_completion(
    callback: Callable[..., Any] | None = None,
) -> Callable[..., Any] | None:
    if not callback:
        return None
    parameters = get_params_from_function(callback)
    ctx_name = None
    args_name = None
    incomplete_name = None
    unassigned_params = list(parameters.values())
    for param_sig in unassigned_params[:]:
        origin = get_origin(param_sig.annotation)
        if lenient_issubclass(param_sig.annotation, click.Context):
            ctx_name = param_sig.name
            unassigned_params.remove(param_sig)
        elif lenient_issubclass(origin, list):
            args_name = param_sig.name
            unassigned_params.remove(param_sig)
        elif lenient_issubclass(param_sig.annotation, str):
            incomplete_name = param_sig.name
            unassigned_params.remove(param_sig)
    # If there are still unassigned parameters (not typed), extract by name
    for param_sig in unassigned_params[:]:
        if ctx_name is None and param_sig.name == "ctx":
            ctx_name = param_sig.name
            unassigned_params.remove(param_sig)
        elif args_name is None and param_sig.name == "args":
            args_name = param_sig.name
            unassigned_params.remove(param_sig)
        elif incomplete_name is None and param_sig.name == "incomplete":
            incomplete_name = param_sig.name
            unassigned_params.remove(param_sig)
    # Extract value param name first
    if unassigned_params:
        show_params = " ".join([param.name for param in unassigned_params])
        raise click.ClickException(
            f"Invalid autocompletion callback parameters: {show_params}"
        )

    def wrapper(ctx: click.Context, args: list[str], incomplete: str | None) -> Any:
        use_params: dict[str, Any] = {}
        if ctx_name:
            use_params[ctx_name] = ctx
        if args_name:
            use_params[args_name] = args
        if incomplete_name:
            use_params[incomplete_name] = incomplete
        return callback(**use_params)

    update_wrapper(wrapper, callback)
    return wrapper

def get_params_convertors_ctx_param_name_from_function(
    callback: Callable[..., Any] | None,
) -> tuple[list[click.Argument | click.Option], dict[str, Any], str | None]:
    params = []
    convertors = {}
    context_param_name = None
    if callback:
        parameters = get_params_from_function(callback)
        for param_name, param in parameters.items():
            if lenient_issubclass(param.annotation, click.Context):
                context_param_name = param_name
                continue
            click_param, convertor = get_click_param(param)
            if convertor:
                convertors[param_name] = convertor
            params.append(click_param)
    return params, convertors, context_param_name

def to_tree(self, tagname=None, value=None, namespace=None):
    namespace = getattr(self, "namespace", namespace)
    if value is not None:
        if namespace is not None:
            tagname = "{%s}%s" % (namespace, tagname)
        value = safe_string(value)
        return Element(tagname, {self.attribute:value})

def get_parse_math(self):
    """Return whether mathtext parsing is considered for this `Text`."""
    return self._parse_math

def _done_callback(future: asyncio.Future) -> None:
    exc = future.exception()
    if exc:
        self._on_event_listener_error(exc)

def __eq__(self, other):
    if self is other:
        return True
    elif isinstance(other, str_type):
        return self.matches(other, parse_all=True)
    elif isinstance(other, ParserElement):
        return vars(self) == vars(other)
    return False

def get_param_callback(
    *,
    callback: Callable[..., Any] | None = None,
    convertor: Callable[..., Any] | None = None,
) -> Callable[..., Any] | None:
    if not callback:
        return None
    parameters = get_params_from_function(callback)
    ctx_name = None
    click_param_name = None
    value_name = None
    untyped_names: list[str] = []
    for param_name, param_sig in parameters.items():
        if lenient_issubclass(param_sig.annotation, click.Context):
            ctx_name = param_name
        elif lenient_issubclass(param_sig.annotation, click.Parameter):
            click_param_name = param_name
        else:
            untyped_names.append(param_name)
    # Extract value param name first
    if untyped_names:
        value_name = untyped_names.pop()
    # If context and Click param were not typed (old/Click callback style) extract them
    if untyped_names:
        if ctx_name is None:
            ctx_name = untyped_names.pop(0)
        if click_param_name is None:
            if untyped_names:
                click_param_name = untyped_names.pop(0)
        if untyped_names:
            raise click.ClickException(
                "Too many CLI parameter callback function parameters"
            )

    def wrapper(ctx: click.Context, param: click.Parameter, value: Any) -> Any:
        use_params: dict[str, Any] = {}
        if ctx_name:
            use_params[ctx_name] = ctx
        if click_param_name:
            use_params[click_param_name] = param
        if value_name:
            if convertor:
                use_value = convertor(value)
            else:
                use_value = value
            use_params[value_name] = use_value
        return callback(**use_params)

    update_wrapper(wrapper, callback)
    return wrapper

def validate_int(cls, value):
    if not isinstance(value, numbers.Integral):
        raise TypeError("value must be an integral type, got %s" % type(value))

def add_attribute(
    self,
    oid: ObjectIdentifier,
    value: bytes,
    *,
    _tag: typing.Optional[_ASN1Type] = None,
) -> CertificateSigningRequestBuilder:
    """
    Adds an X.509 attribute with an OID and associated value.
    """
    if not isinstance(oid, ObjectIdentifier):
        raise TypeError("oid must be an ObjectIdentifier")

    if not isinstance(value, bytes):
        raise TypeError("value must be bytes")

    if _tag is not None and not isinstance(_tag, _ASN1Type):
        raise TypeError("tag must be _ASN1Type")

    _reject_duplicate_attribute(oid, self._attributes)

    if _tag is not None:
        tag = _tag.value
    else:
        tag = None

    return CertificateSigningRequestBuilder(
        self._subject_name,
        self._extensions,
        self._attributes + [(oid, value, tag)],
    )

def _skipIgnorables(self, instring: str, loc: int) -> int:
    if not self.ignoreExprs:
        return loc
    exprsFound = True
    ignore_expr_fns = [e._parse for e in self.ignoreExprs]
    last_loc = loc
    while exprsFound:
        exprsFound = False
        for ignore_fn in ignore_expr_fns:
            try:
                while 1:
                    loc, dummy = ignore_fn(instring, loc)
                    exprsFound = True
            except ParseException:
                pass
        # check if all ignore exprs matched but didn't actually advance the parse location
        if loc == last_loc:
            break
        last_loc = loc
    return loc

def _parse_constant(self) -> c_ast.Node:
    tok = self._advance()
    if tok.type in _INT_CONST:
        u_count = 0
        l_count = 0
        for ch in tok.value[-3:]:
            if ch in ("l", "L"):
                l_count += 1
            elif ch in ("u", "U"):
                u_count += 1
        if u_count > 1:
            raise ValueError("Constant cannot have more than one u/U suffix.")
        if l_count > 2:
            raise ValueError("Constant cannot have more than two l/L suffix.")
        prefix = "unsigned " * u_count + "long " * l_count
        return c_ast.Constant(prefix + "int", tok.value, self._tok_coord(tok))

    if tok.type in _FLOAT_CONST:
        if tok.value[-1] in ("f", "F"):
            t = "float"
        elif tok.value[-1] in ("l", "L"):
            t = "long double"
        else:
            t = "double"
        return c_ast.Constant(t, tok.value, self._tok_coord(tok))

    if tok.type in _CHAR_CONST:
        return c_ast.Constant("char", tok.value, self._tok_coord(tok))

    self._parse_error("Invalid constant", self._tok_coord(tok))

def taufrom(ctx, q=None, m=None, k=None, tau=None, qbar=None):
    r"""
    Returns the elliptic half-period ratio `\tau`, given any of
    `q, m, k, \tau, \bar{q}`::

        >>> from mpmath import *
        >>> mp.dps = 25; mp.pretty = True
        >>> taufrom(tau=0.5j)
        (0.0 + 0.5j)
        >>> taufrom(q=qfrom(tau=0.5j))
        (0.0 + 0.5j)
        >>> taufrom(m=mfrom(tau=0.5j))
        (0.0 + 0.5j)
        >>> taufrom(k=kfrom(tau=0.5j))
        (0.0 + 0.5j)
        >>> taufrom(qbar=qbarfrom(tau=0.5j))
        (0.0 + 0.5j)

    """
    if tau is not None:
        return ctx.convert(tau)
    if m is not None:
        m = ctx.convert(m)
        return ctx.j*ctx.ellipk(1-m)/ctx.ellipk(m)
    if k is not None:
        k = ctx.convert(k)
        return ctx.j*ctx.ellipk(1-k**2)/ctx.ellipk(k**2)
    if q is not None:
        return ctx.log(q) / (ctx.pi*ctx.j)
    if qbar is not None:
        qbar = ctx.convert(qbar)
        return ctx.log(qbar) / (2*ctx.pi*ctx.j)

def relation(self, other: Token) -> int:
    if self.end <= other.start:
        return Token.PRECEDE
    if self.end >= other.end:
        if (
            self.etype.parse_children
            and other.start >= self.inner_start
            and other.end <= self.inner_end
        ):
            return Token.CONTAIN
        if self.etype.parse_children and self.inner_end <= other.start:
            return Token.SHADE
    return Token.INTERSECT

def _open(self) -> None:
    assert self.fp is not None

    magic_number = self._read_magic()
    try:
        mode = MODES[magic_number]
    except KeyError:
        msg = "not a PPM file"
        raise SyntaxError(msg)
    self._mode = mode

    if magic_number in (b"P1", b"P4"):
        self.custom_mimetype = "image/x-portable-bitmap"
    elif magic_number in (b"P2", b"P5"):
        self.custom_mimetype = "image/x-portable-graymap"
    elif magic_number in (b"P3", b"P6"):
        self.custom_mimetype = "image/x-portable-pixmap"

    self._size = int(self._read_token()), int(self._read_token())

    decoder_name = "raw"
    if magic_number in (b"P1", b"P2", b"P3"):
        decoder_name = "ppm_plain"

    args: str | tuple[str | int, ...]
    if mode == "1":
        args = "1;I"
    elif mode == "F":
        scale = float(self._read_token())
        if scale == 0.0 or not math.isfinite(scale):
            msg = "scale must be finite and non-zero"
            raise ValueError(msg)
        self.info["scale"] = abs(scale)

        rawmode = "F;32F" if scale < 0 else "F;32BF"
        args = (rawmode, 0, -1)
    else:
        maxval = int(self._read_token())
        if not 0 < maxval < 65536:
            msg = "maxval must be greater than 0 and less than 65536"
            raise ValueError(msg)
        if maxval > 255 and mode == "L":
            self._mode = "I"

        rawmode = mode
        if decoder_name != "ppm_plain":
            # If maxval matches a bit depth, use the raw decoder directly
            if maxval == 65535 and mode == "L":
                rawmode = "I;16B"
            elif maxval != 255:
                decoder_name = "ppm"

        args = rawmode if decoder_name == "raw" else (rawmode, maxval)
    self.tile = [
        ImageFile._Tile(decoder_name, (0, 0) + self.size, self.fp.tell(), args)
    ]

def _shift_index(
    table: Any, r_idx: int, c_idx: int, direction: str
) -> tuple[int, int]:
    """
    Shift the index based on the specified direction.

    Parameters
    ----------
    table : camelot.core.Table
        The table structure containing rows and columns.
    r_idx : int
        Row index of the cell.
    c_idx : int
        Column index of the cell.
    direction : str
        Direction in which to shift the index ('l', 'r', 't', 'b').

    Returns
    -------
    tuple
        New row and column indices after the shift.
    """
    if direction == "l":
        while c_idx > 0 and not table.cells[r_idx][c_idx].left:
            c_idx -= 1
    elif direction == "r":
        while (
            c_idx < len(table.cells[r_idx]) - 1
            and not table.cells[r_idx][c_idx].right
        ):
            c_idx += 1
    elif direction == "t":
        while r_idx > 0 and not table.cells[r_idx][c_idx].top:
            r_idx -= 1
    elif direction == "b":
        while r_idx < len(table.cells) - 1 and not table.cells[r_idx][c_idx].bottom:
            r_idx += 1

    return r_idx, c_idx

def validate_int_in_range(cls, value, min_inclusive, max_inclusive):
    cls.validate_int(value)
    if value < min_inclusive or value > max_inclusive:
        raise ValueError(
            "value must be in range %d to %d inclusive, got %d"
            % (min_inclusive, max_inclusive, value)
        )

def stroke_color(self):
    stroke = self.options['stroke']
    return Color(stroke) if stroke else None

def get_unichr(self, cid: int) -> str:
    """Interpret character id as unicode codepoint"""
    log.debug("get_unichr: %r, %r", self, cid)
    return chr(cid)

def _should_enable_warnings(
    cmd_line_warn_options: typing.Iterable[str], warn_env_var: typing.Optional[str]
) -> bool:
    enable = bool(warn_env_var)
    for warn_opt in cmd_line_warn_options:
        w_action, w_message, w_category, w_module, w_line = (warn_opt + "::::").split(
            ":"
        )[:5]
        if not w_action.lower().startswith("i") and (
            not (w_message or w_category or w_module) or w_module == "pyparsing"
        ):
            enable = True
        elif w_action.lower().startswith("i") and w_module in ("pyparsing", ""):
            enable = False
    return enable

def test_iterable(value: t.Any) -> bool:
    """Check if it's possible to iterate over an object."""
    try:
        iter(value)
    except TypeError:
        return False

    return True

def _draw_supports(self):
    support_markers = []

    xmax = self._right_support[0]
    xmin = self._left_support[0]
    ymin = min(self._left_support[1],self._right_support[1])
    ymax = self._crown_y

    if abs(1.1*xmax-0.8*xmin)>abs(1.1*ymax-0.8*ymin):
        max_diff = 1.1*xmax-0.8*xmin
    else:
        max_diff = 1.1*ymax-0.8*ymin

    if self._supports['left']=='roller':
        support_markers.append(
            {
                'args':[
                    [self._left_support[0]],
                    [self._left_support[1]-0.02*max_diff]
                ],
                'marker':'o',
                'markersize':11,
                'color':'black',
                'markerfacecolor':'none'
            }
        )
    else:
        support_markers.append(
            {
                'args':[
                    [self._left_support[0]],
                    [self._left_support[1]-0.007*max_diff]
                ],
                'marker':6,
                'markersize':15,
                'color':'black',
                'markerfacecolor':'none'
            }
        )

    if self._supports['right']=='roller':
        support_markers.append(
            {
                'args':[
                    [self._right_support[0]],
                    [self._right_support[1]-0.02*max_diff]
                ],
                'marker':'o',
                'markersize':11,
                'color':'black',
                'markerfacecolor':'none'
            }
        )
    else:
        support_markers.append(
            {
                'args':[
                    [self._right_support[0]],
                    [self._right_support[1]-0.007*max_diff]
                ],
                'marker':6,
                'markersize':15,
                'color':'black',
                'markerfacecolor':'none'
            }
        )

    support_markers.append(
        {
            'args':[
                [self._right_support[0]],
                [self._right_support[1]-0.036*max_diff]
            ],
            'marker':'_',
            'markersize':15,
            'color':'black',
            'markerfacecolor':'none'
        }
    )

    support_markers.append(
        {
            'args':[
                [self._left_support[0]],
                [self._left_support[1]-0.036*max_diff]
            ],
            'marker':'_',
            'markersize':15,
            'color':'black',
            'markerfacecolor':'none'
        }
    )

    return support_markers

def recompile(ffi, module_name, preamble, tmpdir='.', call_c_compiler=True,
              c_file=None, source_extension='.c', extradir=None,
              compiler_verbose=1, target=None, debug=None,
              uses_ffiplatform=True, **kwds):
    if not isinstance(module_name, str):
        module_name = module_name.encode('ascii')
    if ffi._windows_unicode:
        ffi._apply_windows_unicode(kwds)
    if preamble is not None:
        if call_c_compiler and _is_file_like(c_file):
            raise TypeError("Writing to file-like objects is not supported "
                            "with call_c_compiler=True")
        embedding = (ffi._embedding is not None)
        if embedding:
            ffi._apply_embedding_fix(kwds)
        if c_file is None:
            c_file, parts = _modname_to_file(tmpdir, module_name,
                                             source_extension)
            if extradir:
                parts = [extradir] + parts
            ext_c_file = os.path.join(*parts)
        else:
            ext_c_file = c_file
        #
        if target is None:
            if embedding:
                target = '%s.*' % module_name
            else:
                target = '*'
        #
        if uses_ffiplatform:
            ext = ffiplatform.get_extension(ext_c_file, module_name, **kwds)
        else:
            ext = None
        updated = make_c_source(ffi, module_name, preamble, c_file,
                                verbose=compiler_verbose)
        if call_c_compiler:
            patchlist = []
            cwd = os.getcwd()
            try:
                if embedding:
                    _patch_for_embedding(patchlist)
                if target != '*':
                    _patch_for_target(patchlist, target)
                if compiler_verbose:
                    if tmpdir == '.':
                        msg = 'the current directory is'
                    else:
                        msg = 'setting the current directory to'
                    print('%s %r' % (msg, os.path.abspath(tmpdir)))
                os.chdir(tmpdir)
                outputfilename = ffiplatform.compile('.', ext,
                                                     compiler_verbose, debug)
            finally:
                os.chdir(cwd)
                _unpatch_meths(patchlist)
            return outputfilename
        else:
            return ext, updated
    else:
        if c_file is None:
            c_file, _ = _modname_to_file(tmpdir, module_name, '.py')
        updated = make_py_source(ffi, module_name, c_file,
                                 verbose=compiler_verbose)
        if call_c_compiler:
            return c_file
        else:
            return None, updated

def _get_output(output, input, shape=None, complex_output=False):
    if shape is None:
        shape = input.shape
    if output is None:
        if not complex_output:
            output = np.zeros(shape, dtype=input.dtype.name)
        else:
            complex_type = np.promote_types(input.dtype, np.complex64)
            output = np.zeros(shape, dtype=complex_type)
    elif isinstance(output, type | np.dtype):
        # Classes (like `np.float32`) and dtypes are interpreted as dtype
        if complex_output and np.dtype(output).kind != 'c':
            warnings.warn("promoting specified output dtype to complex", stacklevel=3)
            output = np.promote_types(output, np.complex64)
        output = np.zeros(shape, dtype=output)
    elif isinstance(output, str):
        output = np.dtype(output)
        if complex_output and output.kind != 'c':
            raise RuntimeError("output must have complex dtype")
        elif not issubclass(output.type, np.number):
            raise RuntimeError("output must have numeric dtype")
        output = np.zeros(shape, dtype=output)
    else:
        # output was supplied as an array
        output = np.asarray(output)
        if output.shape != shape:
            raise RuntimeError("output shape not correct")
        elif complex_output and output.dtype.kind != 'c':
            raise RuntimeError("output must have complex dtype")
    return output

def parseURI(self, uri):
    if self.entityResolver:
        input = self.entityResolver.resolveEntity(None, uri)
    else:
        input = DOMEntityResolver().resolveEntity(None, uri)
    return self.parse(input)

def parse_subscript(
    self, node: nodes.Expr
) -> t.Union[nodes.Getattr, nodes.Getitem]:
    token = next(self.stream)
    arg: nodes.Expr

    if token.type == "dot":
        attr_token = self.stream.current
        next(self.stream)
        if attr_token.type == "name":
            return nodes.Getattr(
                node, attr_token.value, "load", lineno=token.lineno
            )
        elif attr_token.type != "integer":
            self.fail("expected name or number", attr_token.lineno)
        arg = nodes.Const(attr_token.value, lineno=attr_token.lineno)
        return nodes.Getitem(node, arg, "load", lineno=token.lineno)
    if token.type == "lbracket":
        args: t.List[nodes.Expr] = []
        while self.stream.current.type != "rbracket":
            if args:
                self.stream.expect("comma")
            args.append(self.parse_subscribed())
        self.stream.expect("rbracket")
        if len(args) == 1:
            arg = args[0]
        else:
            arg = nodes.Tuple(args, "load", lineno=token.lineno)
        return nodes.Getitem(node, arg, "load", lineno=token.lineno)
    self.fail("expected subscript expression", token.lineno)

def subset_glyphs(self, s):
    if self.Format == 1:
        mark_indices = self.MarkCoverage.subset(s.glyphs)
        self.MarkArray.MarkRecord = _list_subset(
            self.MarkArray.MarkRecord, mark_indices
        )
        self.MarkArray.MarkCount = len(self.MarkArray.MarkRecord)
        class_indices = _uniq_sort(v.Class for v in self.MarkArray.MarkRecord)

        intersect_ligature_indices = self.LigatureCoverage.intersect(s.glyphs)
        ligature_array = self.LigatureArray.LigatureAttach
        num_ligatures = self.LigatureArray.LigatureCount

        ligature_indices = [
            i
            for i in intersect_ligature_indices
            if i < num_ligatures
            and any(
                any(component.LigatureAnchor[j] is not None for j in class_indices)
                for component in ligature_array[i].ComponentRecord
            )
        ]

        if not ligature_indices:
            return False

        self.LigatureCoverage.remap(ligature_indices)
        self.LigatureArray.LigatureAttach = _list_subset(
            self.LigatureArray.LigatureAttach, ligature_indices
        )
        self.LigatureArray.LigatureCount = len(self.LigatureArray.LigatureAttach)
        # Prune empty classes
        self.ClassCount = len(class_indices)
        for m in self.MarkArray.MarkRecord:
            m.Class = class_indices.index(m.Class)
        for l in self.LigatureArray.LigatureAttach:
            if l is None:
                continue
            for c in l.ComponentRecord:
                c.LigatureAnchor = _list_subset(c.LigatureAnchor, class_indices)
        return bool(
            self.ClassCount
            and self.MarkArray.MarkCount
            and self.LigatureArray.LigatureCount
        )
    else:
        assert 0, "unknown format: %s" % self.Format

def base64_decode(input, errors='strict'):
    assert errors == 'strict'
    return (base64.decodebytes(input), len(input))

def encode(s: Union[str, bytes, bytearray], strict: bool = False, uts46: bool = False, std3_rules: bool = False, transitional: bool = False) -> bytes:
    if isinstance(s, (bytes, bytearray)):
        try:
            s = s.decode('ascii')
        except UnicodeDecodeError:
            raise IDNAError('should pass a unicode string to the function rather than a byte string.')
    if uts46:
        s = uts46_remap(s, std3_rules, transitional)
    trailing_dot = False
    result = []
    if strict:
        labels = s.split('.')
    else:
        labels = _unicode_dots_re.split(s)
    if not labels or labels == ['']:
        raise IDNAError('Empty domain')
    if labels[-1] == '':
        del labels[-1]
        trailing_dot = True
    for label in labels:
        s = alabel(label)
        if s:
            result.append(s)
        else:
            raise IDNAError('Empty label')
    if trailing_dot:
        result.append(b'')
    s = b'.'.join(result)
    if not valid_string_length(s, trailing_dot):
        raise IDNAError('Domain too long')
    return s

def _open(self) -> None:
    assert self.fp is not None

    headers: dict[bytes, bytes] = {}
    header_in_progress = False
    decoder_name = ""
    while True:
        header = self.fp.read(80)
        if not header:
            msg = "Truncated FITS file"
            raise OSError(msg)
        keyword = header[:8].strip()
        if keyword in (b"SIMPLE", b"XTENSION"):
            header_in_progress = True
        elif headers and not header_in_progress:
            # This is now a data unit
            break
        elif keyword == b"END":
            # Seek to the end of the header unit
            self.fp.seek(math.ceil(self.fp.tell() / 2880) * 2880)
            if not decoder_name:
                decoder_name, offset, args = self._parse_headers(headers)

            header_in_progress = False
            continue

        if decoder_name:
            # Keep going to read past the headers
            continue

        value = header[8:].split(b"/")[0].strip()
        if value.startswith(b"="):
            value = value[1:].strip()
        if not headers and (not _accept(keyword) or value != b"T"):
            msg = "Not a FITS file"
            raise SyntaxError(msg)
        headers[keyword] = value

    if not decoder_name:
        msg = "No image data"
        raise ValueError(msg)

    offset += self.fp.tell() - 80
    self.tile = [ImageFile._Tile(decoder_name, (0, 0) + self.size, offset, args)]

def doit(self, *args, **kwargs):
    if kwargs.get("deep", True):
        expr = self.expr.doit(*args, **kwargs)
    else:
        expr = self.expr
    if isinstance(expr, (MatrixBase, NDimArray)):
        return expr.reshape(*self.shape)
    return Reshape(expr, self.shape)

def determine_type_convertor(type_: Any) -> Callable[[Any], Any] | None:
    convertor: Callable[[Any], Any] | None = None
    if lenient_issubclass(type_, Path):
        convertor = param_path_convertor
    if lenient_issubclass(type_, Enum):
        convertor = generate_enum_convertor(type_)
    return convertor

def _parse_musl_version(output: str) -> Optional[_MuslVersion]:
    lines = [n for n in (n.strip() for n in output.splitlines()) if n]
    if len(lines) < 2 or lines[0][:4] != "musl":
        return None
    m = re.match(r"Version (\d+)\.(\d+)", lines[1])
    if not m:
        return None
    return _MuslVersion(major=int(m.group(1)), minor=int(m.group(2)))

def local(self) -> Optional[str]:
    """The local version segment of the version.

    >>> print(Version("1.2.3").local)
    None
    >>> Version("1.2.3+abc").local
    'abc'
    """
    if self._version.local:
        return ".".join(str(x) for x in self._version.local)
    else:
        return None

def postParse(self, instring, loc, tokenlist):
    retToks = tokenlist.copy()
    del retToks[:]
    retToks += ParseResults(
        ["".join(tokenlist._asStringList(self.joinString))], modal=self.modalResults
    )

    if self.resultsName and retToks.haskeys():
        return [retToks]
    else:
        return retToks

def as_coeff_Mul(self, rational=False):
    """
    Efficiently extract the coefficient of a product.
    """
    coeff, args = self.args[0], self.args[1:]

    if coeff.is_Number:
        if not rational or coeff.is_Rational:
            if len(args) == 1:
                return coeff, args[0]
            else:
                return coeff, self._new_rawargs(*args)
        elif coeff.is_extended_negative:
            return S.NegativeOne, self._new_rawargs(*((-coeff,) + args))
    return S.One, self

def fromnid(cls, nid):
    """Create _ASN1Object from OpenSSL numeric ID
    """
    return super().__new__(cls, *_nid2obj(nid))

def _write_gap_width(self, val) -> None:
    # Write the <c:gapWidth> element.

    if val is None:
        return

    attributes = [("val", val)]

    self._xml_empty_tag("c:gapWidth", attributes)

def SeriesFactory(values, xvalues=None, zvalues=None, title=None, title_from_data=False):
    """
    Convenience Factory for creating chart data series.
    """

    if not isinstance(values, Reference):
        values = Reference(range_string=values)

    if title_from_data:
        cell = values.pop()
        title = u"{0}!{1}".format(values.sheetname, cell)
        title = SeriesLabel(strRef=StrRef(title))
    elif title is not None:
        title = SeriesLabel(v=title)

    source = NumDataSource(numRef=NumRef(f=values))
    if xvalues is not None:
        if not isinstance(xvalues, Reference):
            xvalues = Reference(range_string=xvalues)
        series = XYSeries()
        series.yVal = source
        series.xVal = AxDataSource(numRef=NumRef(f=xvalues))
        if zvalues is not None:
            if not isinstance(zvalues, Reference):
                zvalues = Reference(range_string=zvalues)
            series.zVal = NumDataSource(NumRef(f=zvalues))
    else:
        series = Series()
        series.val = source

    if title is not None:
        series.title = title
    return series

def filter_edges(
    edges: Iterable[T_obj],
    orientation: Optional[str] = None,
    edge_type: Optional[str] = None,
    min_length: T_num = 1,
) -> T_obj_list:
    if orientation not in ("v", "h", None):
        raise ValueError("Orientation must be 'v' or 'h'")

    def test(e: T_obj) -> bool:
        dim = "height" if e["orientation"] == "v" else "width"
        et_correct = e["object_type"] == edge_type if edge_type is not None else True
        orient_correct = orientation is None or e["orientation"] == orientation
        return bool(et_correct and orient_correct and (e[dim] >= min_length))

    return list(filter(test, edges))

def unquote(str):
    """Remove quotes from a string."""
    if len(str) > 1:
        if str.startswith('"') and str.endswith('"'):
            return str[1:-1].replace('\\\\', '\\').replace('\\"', '"')
        if str.startswith('<') and str.endswith('>'):
            return str[1:-1]
    return str

def __iter__(self):
    # XXX does it break when underlying container state changed?
    return itertools.chain((self.default_section,), self._sections.keys())

def __call__(self, x, pos=None):
    # docstring inherited
    return self.format_ticks([x])[0]

def print_args(args):
    for arg in vars(args):
        logger.info(f"{arg}: {getattr(args, arg)}")

def _keep_coeff(coeff, factors, clear=True, sign=False):
    """Return ``coeff*factors`` unevaluated if necessary.

    If ``clear`` is False, do not keep the coefficient as a factor
    if it can be distributed on a single factor such that one or
    more terms will still have integer coefficients.

    If ``sign`` is True, allow a coefficient of -1 to remain factored out.

    Examples
    ========

    >>> from sympy.core.mul import _keep_coeff
    >>> from sympy.abc import x, y
    >>> from sympy import S

    >>> _keep_coeff(S.Half, x + 2)
    (x + 2)/2
    >>> _keep_coeff(S.Half, x + 2, clear=False)
    x/2 + 1
    >>> _keep_coeff(S.Half, (x + 2)*y, clear=False)
    y*(x + 2)/2
    >>> _keep_coeff(S(-1), x + y)
    -x - y
    >>> _keep_coeff(S(-1), x + y, sign=True)
    -(x + y)
    """
    if not coeff.is_Number:
        if factors.is_Number:
            factors, coeff = coeff, factors
        else:
            return coeff*factors
    if factors is S.One:
        return coeff
    if coeff is S.One:
        return factors
    elif coeff is S.NegativeOne and not sign:
        return -factors
    elif factors.is_Add:
        if not clear and coeff.is_Rational and coeff.q != 1:
            args = [i.as_coeff_Mul() for i in factors.args]
            args = [(_keep_coeff(c, coeff), m) for c, m in args]
            if any(c.is_Integer for c, _ in args):
                return Add._from_args([Mul._from_args(
                    i[1:] if i[0] == 1 else i) for i in args])
        return Mul(coeff, factors, evaluate=False)
    elif factors.is_Mul:
        margs = list(factors.args)
        if margs[0].is_Number:
            margs[0] *= coeff
            if margs[0] == 1:
                margs.pop(0)
        else:
            margs.insert(0, coeff)
        return Mul._from_args(margs)
    else:
        m = coeff*factors
        if m.is_Number and not factors.is_Number:
            m = Mul._from_args((coeff, factors))
        return m

def parseImpl(self, instring, loc, doActions=True):
    start = loc
    instrlen = len(instring)
    maxloc = start + len(self.match_string)

    if maxloc <= instrlen:
        match_string = self.match_string
        match_stringloc = 0
        mismatches = []
        maxMismatches = self.maxMismatches

        for match_stringloc, s_m in enumerate(
            zip(instring[loc:maxloc], match_string)
        ):
            src, mat = s_m
            if self.caseless:
                src, mat = src.lower(), mat.lower()

            if src != mat:
                mismatches.append(match_stringloc)
                if len(mismatches) > maxMismatches:
                    break
        else:
            loc = start + match_stringloc + 1
            results = ParseResults([instring[start:loc]])
            results["original"] = match_string
            results["mismatches"] = mismatches
            return loc, results

    raise ParseException(instring, loc, self.errmsg, self)

def _hits_python(G, max_iter=100, tol=1.0e-8, nstart=None, normalized=True):
    if isinstance(G, nx.MultiGraph | nx.MultiDiGraph):
        raise Exception("hits() not defined for graphs with multiedges.")
    if len(G) == 0:
        return {}, {}
    # choose fixed starting vector if not given
    if nstart is None:
        h = dict.fromkeys(G, 1.0 / G.number_of_nodes())
    else:
        h = nstart
        # normalize starting vector
        s = 1.0 / sum(h.values())
        for k in h:
            h[k] *= s
    for _ in range(max_iter):  # power iteration: make up to max_iter iterations
        hlast = h
        h = dict.fromkeys(hlast.keys(), 0)
        a = dict.fromkeys(hlast.keys(), 0)
        # this "matrix multiply" looks odd because it is
        # doing a left multiply a^T=hlast^T*G
        for n in h:
            for nbr in G[n]:
                a[nbr] += hlast[n] * G[n][nbr].get("weight", 1)
        # now multiply h=Ga
        for n in h:
            for nbr in G[n]:
                h[n] += a[nbr] * G[n][nbr].get("weight", 1)
        # normalize vector
        s = 1.0 / max(h.values())
        for n in h:
            h[n] *= s
        # normalize vector
        s = 1.0 / max(a.values())
        for n in a:
            a[n] *= s
        # check convergence, l1 norm
        err = sum(abs(h[n] - hlast[n]) for n in h)
        if err < tol:
            break
    else:
        raise nx.PowerIterationFailedConvergence(max_iter)
    if normalized:
        s = 1.0 / sum(a.values())
        for n in a:
            a[n] *= s
        s = 1.0 / sum(h.values())
        for n in h:
            h[n] *= s
    return h, a

def __getitem__(
    self, idx: typing.Union[int, slice]
) -> typing.Union[RevokedCertificate, typing.List[RevokedCertificate]]:
    """
    Returns a revoked certificate (or slice of revoked certificates).
    """

def _union(cls, kinds) -> 'ArrayKind':
    elem_kinds = {e.kind for e in kinds}
    if len(elem_kinds) == 1:
        elemkind, = elem_kinds
    else:
        elemkind = UndefinedKind
    return ArrayKind(elemkind)

def superscript(self, tokens):
    def isprime(x):
        return isinstance(x, Token) and x.type == "PRIMES"

    def iscmdprime(x):
        return isinstance(x, Token) and (x.type == "PRIMES_VIA_CMD"
                                         or x.type == "CMD_PRIME")

    def isstar(x):
        return isinstance(x, Token) and x.type == "STARS"

    def iscmdstar(x):
        return isinstance(x, Token) and (x.type == "STARS_VIA_CMD"
                                         or x.type == "CMD_ASTERISK")

    base = tokens[0]
    if len(tokens) == 3: # a^b OR a^\prime OR a^\ast
        sup = tokens[2]
    if len(tokens) == 5:
        # a^{'}, a^{''}, ... OR
        # a^{*}, a^{**}, ... OR
        # a^{\prime}, a^{\prime\prime}, ... OR
        # a^{\ast}, a^{\ast\ast}, ...
        sup = tokens[3]

    if self._obj_is_sympy_Matrix(base):
        if sup == sympy.Symbol("T"):
            return sympy.Transpose(base)
        if sup == sympy.Symbol("H"):
            return sympy.adjoint(base)
        if isprime(sup):
            sup = sup.value
            if len(sup) % 2 == 0:
                return base
            return sympy.Transpose(base)
        if iscmdprime(sup):
            sup = sup.value
            if (len(sup)/len(r"\prime")) % 2 == 0:
                return base
            return sympy.Transpose(base)
        if isstar(sup):
            sup = sup.value
            # need .doit() in order to be consistent with
            # sympy.adjoint() which returns the evaluated adjoint
            # of a matrix
            if len(sup) % 2 == 0:
                return base.doit()
            return sympy.adjoint(base)
        if iscmdstar(sup):
            sup = sup.value
            # need .doit() for same reason as above
            if (len(sup)/len(r"\ast")) % 2 == 0:
                return base.doit()
            return sympy.adjoint(base)

    if isprime(sup) or iscmdprime(sup) or isstar(sup) or iscmdstar(sup):
        raise LaTeXParsingError(f"{base} with superscript {sup} is not understood.")

    return sympy.Pow(base, sup)

def _np_pdist(X, out, w, V, VI, metric='euclidean', **kwargs):

    X = _asarray_validated(X, sparse_ok=False, objects_ok=True, mask_ok=True,
                           check_finite=False)
    m, n = X.shape

    if w is not None:
        kwargs["w"] = w
    if V is not None:
        kwargs["V"] = V
    if VI is not None:
        kwargs["VI"] = VI

    if callable(metric):
        mstr = getattr(metric, '__name__', 'UnknownCustomMetric')
        metric_info = _METRIC_ALIAS.get(mstr, None)

        if metric_info is not None:
            X, typ, kwargs = _validate_pdist_input(
                X, m, n, metric_info, **kwargs)

        return _pdist_callable(X, metric=metric, out=out, **kwargs)
    elif isinstance(metric, str):
        mstr = metric.lower()
        metric_info = _METRIC_ALIAS.get(mstr, None)

        if metric_info is not None:
            pdist_fn = metric_info.pdist_func
            return pdist_fn(X, out=out, **kwargs)
        elif mstr.startswith("test_"):
            metric_info = _TEST_METRICS.get(mstr, None)
            if metric_info is None:
                raise ValueError(f'Unknown "Test" Distance Metric: {mstr[5:]}')
            X, typ, kwargs = _validate_pdist_input(
                X, m, n, metric_info, **kwargs)
            return _pdist_callable(
                X, metric=metric_info.dist_func, out=out, **kwargs)
        else:
            raise ValueError(f'Unknown Distance Metric: {mstr}')
    else:
        raise TypeError('2nd argument metric must be a string identifier '
                        'or a function.')

def toXML(self, writer, ttFont):
    names = sorted(self.yPels.keys())
    for name in names:
        writer.simpletag("yPel", name=name, value=self.yPels[name])
        writer.newline()

def __init__(self, requirement_string: str) -> None:
    try:
        parsed = _parse_requirement(requirement_string)
    except ParserSyntaxError as e:
        raise InvalidRequirement(str(e)) from e

    self.name: str = parsed.name
    if parsed.url:
        parsed_url = urllib.parse.urlparse(parsed.url)
        if parsed_url.scheme == "file":
            if urllib.parse.urlunparse(parsed_url) != parsed.url:
                raise InvalidRequirement("Invalid URL given")
        elif not (parsed_url.scheme and parsed_url.netloc) or (
            not parsed_url.scheme and not parsed_url.netloc
        ):
            raise InvalidRequirement(f"Invalid URL: {parsed.url}")
        self.url: Optional[str] = parsed.url
    else:
        self.url = None
    self.extras: Set[str] = set(parsed.extras if parsed.extras else [])
    self.specifier: SpecifierSet = SpecifierSet(parsed.specifier)
    self.marker: Optional[Marker] = None
    if parsed.marker is not None:
        self.marker = Marker.__new__(Marker)
        self.marker._markers = _normalize_extra_values(parsed.marker)

def parseImpl(self, instring, loc, doActions=True):
    self_expr = self.expr
    try:
        loc, tokens = self_expr._parse(instring, loc, doActions, callPreParse=False)
    except (ParseException, IndexError):
        default_value = self.defaultValue
        if default_value is not self.__optionalNotMatched:
            if self_expr.resultsName:
                tokens = ParseResults([default_value])
                tokens[self_expr.resultsName] = default_value
            else:
                tokens = [default_value]
        else:
            tokens = []
    return loc, tokens

def get_alpha(self):
    try:
        return super().get_alpha()
    except AttributeError:
        return 1

def detect_all(
    byte_str: Union[bytes, bytearray],
    ignore_threshold: bool = False,
    should_rename_legacy: bool = False,
) -> List[ResultDict]:
    """
    Detect all the possible encodings of the given byte string.

    :param byte_str:          The byte sequence to examine.
    :type byte_str:           ``bytes`` or ``bytearray``
    :param ignore_threshold:  Include encodings that are below
                              ``UniversalDetector.MINIMUM_THRESHOLD``
                              in results.
    :type ignore_threshold:   ``bool``
    :param should_rename_legacy:  Should we rename legacy encodings
                                  to their more modern equivalents?
    :type should_rename_legacy:   ``bool``
    """
    if not isinstance(byte_str, bytearray):
        if not isinstance(byte_str, bytes):
            raise TypeError(
                f"Expected object of type bytes or bytearray, got: {type(byte_str)}"
            )
        byte_str = bytearray(byte_str)

    detector = UniversalDetector(should_rename_legacy=should_rename_legacy)
    detector.feed(byte_str)
    detector.close()

    if detector.input_state == InputState.HIGH_BYTE:
        results: List[ResultDict] = []
        probers: List[CharSetProber] = []
        for prober in detector.charset_probers:
            if isinstance(prober, CharSetGroupProber):
                probers.extend(p for p in prober.probers)
            else:
                probers.append(prober)
        for prober in probers:
            if ignore_threshold or prober.get_confidence() > detector.MINIMUM_THRESHOLD:
                charset_name = prober.charset_name or ""
                lower_charset_name = charset_name.lower()
                # Use Windows encoding name instead of ISO-8859 if we saw any
                # extra Windows-specific bytes
                if lower_charset_name.startswith("iso-8859") and detector.has_win_bytes:
                    charset_name = detector.ISO_WIN_MAP.get(
                        lower_charset_name, charset_name
                    )
                # Rename legacy encodings with superset encodings if asked
                if should_rename_legacy:
                    charset_name = detector.LEGACY_MAP.get(
                        charset_name.lower(), charset_name
                    )
                results.append(
                    {
                        "encoding": charset_name,
                        "confidence": prober.get_confidence(),
                        "language": prober.language,
                    }
                )
        if len(results) > 0:
            return sorted(results, key=lambda result: -result["confidence"])

    return [detector.result]

def _fix_decl_name_type(
    self,
    decl: c_ast.Decl | c_ast.Typedef | c_ast.Typename,
    typename: List[Any],
) -> c_ast.Decl | c_ast.Typedef | c_ast.Typename:
    """Fixes a declaration. Modifies decl."""
    # Reach the underlying basic type
    typ = decl
    while not isinstance(typ, c_ast.TypeDecl):
        typ = typ.type

    decl.name = typ.declname
    typ.quals = decl.quals[:]

    # The typename is a list of types. If any type in this
    # list isn't an IdentifierType, it must be the only
    # type in the list (it's illegal to declare "int enum ..")
    # If all the types are basic, they're collected in the
    # IdentifierType holder.
    for tn in typename:
        if not isinstance(tn, c_ast.IdentifierType):
            if len(typename) > 1:
                self._parse_error("Invalid multiple types specified", tn.coord)
            else:
                typ.type = tn
                return decl

    if not typename:
        # Functions default to returning int
        if not isinstance(decl.type, c_ast.FuncDecl):
            self._parse_error("Missing type in declaration", decl.coord)
        typ.type = c_ast.IdentifierType(["int"], coord=decl.coord)
    else:
        # At this point, we know that typename is a list of IdentifierType
        # nodes. Concatenate all the names into a single list.
        typ.type = c_ast.IdentifierType(
            [name for id in typename for name in id.names], coord=typename[0].coord
        )
    return decl

def subset_glyphs(self, s):
    s.glyphs = None  # We use s.glyphs_requested and s.unicodes_requested only

    tables_format12_bmp = []
    table_plat0_enc3 = {}  # Unicode platform, Unicode BMP only, keyed by language
    table_plat3_enc1 = {}  # Windows platform, Unicode BMP, keyed by language

    for t in self.tables:
        if t.platformID == 0 and t.platEncID == 3:
            table_plat0_enc3[t.language] = t
        if t.platformID == 3 and t.platEncID == 1:
            table_plat3_enc1[t.language] = t

        if t.format == 14:
            # TODO(behdad) We drop all the default-UVS mappings
            # for glyphs_requested.  So it's the caller's responsibility to make
            # sure those are included.
            t.uvsDict = {
                v: [
                    (u, g)
                    for u, g in l
                    if g in s.glyphs_requested or u in s.unicodes_requested
                ]
                for v, l in t.uvsDict.items()
                if v in s.unicodes_requested
            }
            t.uvsDict = {v: l for v, l in t.uvsDict.items() if l}
        elif t.isUnicode():
            t.cmap = {
                u: g
                for u, g in t.cmap.items()
                if g in s.glyphs_requested or u in s.unicodes_requested
            }
            # Collect format 12 tables that hold only basic multilingual plane
            # codepoints.
            if t.format == 12 and t.cmap and max(t.cmap.keys()) < 0x10000:
                tables_format12_bmp.append(t)
        else:
            t.cmap = {u: g for u, g in t.cmap.items() if g in s.glyphs_requested}

    # Fomat 12 tables are redundant if they contain just the same BMP codepoints
    # their little BMP-only encoding siblings contain.
    for t in tables_format12_bmp:
        if (
            t.platformID == 0  # Unicode platform
            and t.platEncID == 4  # Unicode full repertoire
            and t.language in table_plat0_enc3  # Have a BMP-only sibling?
            and table_plat0_enc3[t.language].cmap == t.cmap
        ):
            t.cmap.clear()
        elif (
            t.platformID == 3  # Windows platform
            and t.platEncID == 10  # Unicode full repertoire
            and t.language in table_plat3_enc1  # Have a BMP-only sibling?
            and table_plat3_enc1[t.language].cmap == t.cmap
        ):
            t.cmap.clear()

    self.tables = [t for t in self.tables if (t.cmap if t.format != 14 else t.uvsDict)]
    self.numSubTables = len(self.tables)
    # TODO(behdad) Convert formats when needed.
    # In particular, if we have a format=12 without non-BMP
    # characters, convert it to format=4 if there's not one.
    return True  # Required table

def str(self, printer, precedence, exp_pattern, mul_symbol):
    if not self:
        return printer._print(self.ring.domain.zero)
    prec_mul = precedence["Mul"]
    prec_atom = precedence["Atom"]
    ring = self.ring
    symbols = ring.symbols
    ngens = ring.ngens
    zm = ring.zero_monom
    sexpvs = []
    for expv, coeff in self.terms():
        negative = ring.domain.is_negative(coeff)
        sign = " - " if negative else " + "
        sexpvs.append(sign)
        if expv == zm:
            scoeff = printer._print(coeff)
            if negative and scoeff.startswith("-"):
                scoeff = scoeff[1:]
        else:
            if negative:
                coeff = -coeff
            if coeff != self.ring.domain.one:
                scoeff = printer.parenthesize(coeff, prec_mul, strict=True)
            else:
                scoeff = ''
        sexpv = []
        for i in range(ngens):
            exp = expv[i]
            if not exp:
                continue
            symbol = printer.parenthesize(symbols[i], prec_atom, strict=True)
            if exp != 1:
                if exp != int(exp) or exp < 0:
                    sexp = printer.parenthesize(exp, prec_atom, strict=False)
                else:
                    sexp = exp
                sexpv.append(exp_pattern % (symbol, sexp))
            else:
                sexpv.append('%s' % symbol)
        if scoeff:
            sexpv = [scoeff] + sexpv
        sexpvs.append(mul_symbol.join(sexpv))
    if sexpvs[0] in [" + ", " - "]:
        head = sexpvs.pop(0)
        if head == " - ":
            sexpvs.insert(0, "-")
    return "".join(sexpvs)

def _prepare_payload_as_dict(
    self, inputs: Any, parameters: dict, provider_mapping_info: InferenceProviderMapping
) -> dict | None:
    payload = super()._prepare_payload_as_dict(inputs, parameters, provider_mapping_info)
    response_format = parameters.get("response_format")
    if isinstance(response_format, dict) and response_format.get("type") == "json_schema":
        json_schema_details = response_format.get("json_schema")
        if isinstance(json_schema_details, dict) and "schema" in json_schema_details:
            payload["response_format"] = {  # type: ignore
                "type": "json_object",
                "schema": json_schema_details["schema"],
            }

    return payload

def filterContour(self, contour):
    quadratics = []
    currentPt = None
    newContour = []
    for op, args in contour:
        if op == "qCurveTo" and (
            self.all_cubic or (len(args) > 2 and args[-1] is not None)
        ):
            if args[-1] is None:
                raise NotImplementedError(
                    "oncurve-less contours with all_cubic not implemented"
                )
            quadratics.append((currentPt,) + args)
        else:
            if quadratics:
                newContour.extend(self._quadratics_to_curve(quadratics))
                quadratics = []
            newContour.append((op, args))
        currentPt = args[-1] if args else None
    if quadratics:
        newContour.extend(self._quadratics_to_curve(quadratics))

    if not self.all_cubic:
        # Add back implicit oncurve points
        contour = newContour
        newContour = []
        for op, args in contour:
            if op == "qCurveTo" and newContour and newContour[-1][0] == "qCurveTo":
                pt0 = newContour[-1][1][-2]
                pt1 = newContour[-1][1][-1]
                pt2 = args[0]
                if (
                    pt1 is not None
                    and math.isclose(pt2[0] - pt1[0], pt1[0] - pt0[0])
                    and math.isclose(pt2[1] - pt1[1], pt1[1] - pt0[1])
                ):
                    newArgs = newContour[-1][1][:-1] + args
                    newContour[-1] = (op, newArgs)
                    continue

            newContour.append((op, args))

    return newContour

def write_examples_on_file(self):
    """Write stored examples from the write-pool of examples. It makes a table out of the examples and write it."""
    if not self.current_examples:
        return
    # preserve the order the columns
    if self.schema:
        schema_cols = set(self.schema.names)
        examples_cols = self.current_examples[0][0].keys()  # .keys() preserves the order (unlike set)
        common_cols = [col for col in self.schema.names if col in examples_cols]
        extra_cols = [col for col in examples_cols if col not in schema_cols]
        cols = common_cols + extra_cols
    else:
        cols = list(self.current_examples[0][0])
    batch_examples = {}
    for col in cols:
        # We use row[0][col] since current_examples contains (example, key) tuples.
        # Moreover, examples could be Arrow arrays of 1 element.
        # This can happen in `.map()` when we want to re-write the same Arrow data
        if all(isinstance(row[0][col], (pa.Array, pa.ChunkedArray)) for row in self.current_examples):
            arrays = [row[0][col] for row in self.current_examples]
            arrays = [
                chunk
                for array in arrays
                for chunk in (array.chunks if isinstance(array, pa.ChunkedArray) else [array])
            ]
            batch_examples[col] = pa.concat_arrays(arrays)
        else:
            batch_examples[col] = [
                row[0][col].to_pylist()[0] if isinstance(row[0][col], (pa.Array, pa.ChunkedArray)) else row[0][col]
                for row in self.current_examples
            ]
    self.write_batch(batch_examples=batch_examples)
    self.current_examples = []

def from_RealField(K1, a, K0):
    """Convert a mpmath `mpf` object to `dtype`. """
    p, q = K0.to_rational(a)
    return PythonRational(int(p), int(q))

def _RegularMessageToJsonObject(self, message, js):
  """Converts normal message according to ProtoJSON Specification."""
  fields = message.ListFields()

  try:
    for field, value in fields:
      if field.is_extension:
        name = '[%s]' % field.full_name
      elif self.preserving_proto_field_name:
        name = field.name
      else:
        name = field.json_name

      if _IsMapEntry(field):
        # Convert a map field.
        v_field = field.message_type.fields_by_name['value']
        js_map = {}
        for key in value:
          if isinstance(key, bool):
            if key:
              recorded_key = 'true'
            else:
              recorded_key = 'false'
          else:
            recorded_key = str(key)
          js_map[recorded_key] = self._FieldToJsonObject(v_field, value[key])
        js[name] = js_map
      elif field.is_repeated:
        # Convert a repeated field.
        js[name] = [self._FieldToJsonObject(field, k) for k in value]
      else:
        js[name] = self._FieldToJsonObject(field, value)

    # Serialize default value if including_default_value_fields is True.
    if (
        self.always_print_fields_with_no_presence
    ):
      message_descriptor = message.DESCRIPTOR
      for field in message_descriptor.fields:

        # always_print_fields_with_no_presence doesn't apply to
        # any field which supports presence.
        if self.always_print_fields_with_no_presence and field.has_presence:
          continue

        if self.preserving_proto_field_name:
          name = field.name
        else:
          name = field.json_name
        if name in js:
          # Skip the field which has been serialized already.
          continue
        if _IsMapEntry(field):
          js[name] = {}
        elif field.is_repeated:
          js[name] = []
        else:
          js[name] = self._FieldToJsonObject(field, field.default_value)

  except ValueError as e:
    raise SerializeToJsonError(
        'Failed to serialize {0} field: {1}.'.format(field.name, e)
    ) from e

  return js

def stop(self) -> None:
    """Stop live rendering display."""
    with self._lock:
        if not self._started:
            return
        self.console.clear_live()
        self._started = False

        if self.auto_refresh and self._refresh_thread is not None:
            self._refresh_thread.stop()
            self._refresh_thread = None
        # allow it to fully render on the last even if overflow
        self.vertical_overflow = "visible"
        with self.console:
            try:
                if not self._alt_screen and not self.console.is_jupyter:
                    self.refresh()
            finally:
                self._disable_redirect_io()
                self.console.pop_render_hook()
                if not self._alt_screen and self.console.is_terminal:
                    self.console.line()
                self.console.show_cursor(True)
                if self._alt_screen:
                    self.console.set_alt_screen(False)

                if self.transient and not self._alt_screen:
                    self.console.control(self._live_render.restore_cursor())
                if self.ipy_widget is not None and self.transient:
                    self.ipy_widget.close()  # pragma: no cover

def get_skip_index(self, add, is_channel_last: bool):
    """Add has two inputs. This classifies which input is skip based on shape info (skip allows broadcast)."""
    skip = -1
    broadcast = False

    assert self.shape_infer_helper is not None
    shape_a = self.shape_infer_helper.get_edge_shape(add.input[0])
    shape_b = self.shape_infer_helper.get_edge_shape(add.input[1])
    assert shape_a is not None and shape_b is not None

    if len(shape_a) == 4 and len(shape_b) == 4:
        if shape_a == shape_b:
            skip = 1
        else:
            c = 3 if is_channel_last else 1
            h = 1 if is_channel_last else 2
            w = 2 if is_channel_last else 3
            if shape_a[0] == shape_b[0] and shape_a[c] == shape_b[c]:
                if shape_b[h] == 1 and shape_b[w] == 1:
                    skip = 1
                    broadcast = True
                elif shape_a[h] == 1 and shape_a[w] == 1:
                    skip = 0
                    broadcast = True

    if skip < 0:
        logger.debug(
            "skip SkipGroupNorm fusion since shape of Add inputs (%s, %s) are not expected",
            add.input[0],
            add.input[1],
        )
    return skip, broadcast

def to_tree(self, tagname=None, idx=None, namespace=None):

    if tagname is None:
        tagname = self.tagname

    # keywords have to be masked
    if tagname.startswith("_"):
        tagname = tagname[1:]

    tagname = namespaced(self, tagname, namespace)
    namespace = getattr(self, "namespace", namespace)

    attrs = dict(self)
    for key, ns in self.__namespaced__:
        if key in attrs:
            attrs[ns] = attrs[key]
            del attrs[key]

    el = Element(tagname, attrs)
    if "attr_text" in self.__attrs__:
        el.text = safe_string(getattr(self, "attr_text"))

    for child_tag in self.__elements__:
        desc = getattr(self.__class__, child_tag, None)
        obj = getattr(self, child_tag)
        if hasattr(desc, "namespace") and hasattr(obj, 'namespace'):
            obj.namespace = desc.namespace

        if isinstance(obj, seq_types):
            if isinstance(desc, NestedSequence):
                # wrap sequence in container
                if not obj:
                    continue
                nodes = [desc.to_tree(child_tag, obj, namespace)]
            elif isinstance(desc, Sequence):
                # sequence
                desc.idx_base = self.idx_base
                nodes = (desc.to_tree(child_tag, obj, namespace))
            else: # property
                nodes = (v.to_tree(child_tag, namespace) for v in obj)
            for node in nodes:
                el.append(node)
        else:
            if child_tag in self.__nested__:
                node = desc.to_tree(child_tag, obj, namespace)
            elif obj is None:
                continue
            else:
                node = obj.to_tree(child_tag)
            if node is not None:
                el.append(node)
    return el

def all_numeric(x):
    for x_i in x:
        if not isinstance(x_i, Number):
            return False
    return True

def _normalize_mode(im: Image.Image) -> Image.Image:
    """
    Takes an image (or frame), returns an image in a mode that is appropriate
    for saving in a Gif.

    It may return the original image, or it may return an image converted to
    palette or 'L' mode.

    :param im: Image object
    :returns: Image object
    """
    if im.mode in RAWMODE:
        im.load()
        return im
    if Image.getmodebase(im.mode) == "RGB":
        im = im.convert("P", palette=Image.Palette.ADAPTIVE)
        assert im.palette is not None
        if im.palette.mode == "RGBA":
            for rgba in im.palette.colors:
                if rgba[3] == 0:
                    im.info["transparency"] = im.palette.colors[rgba]
                    break
        return im
    return im.convert("L")

def _checknames(descr, names=None):
    """
    Checks that field names ``descr`` are not reserved keywords.

    If this is the case, a default 'f%i' is substituted.  If the argument
    `names` is not None, updates the field names to valid names.

    """
    ndescr = len(descr)
    default_names = [f'f{i}' for i in range(ndescr)]
    if names is None:
        new_names = default_names
    else:
        if isinstance(names, (tuple, list)):
            new_names = names
        elif isinstance(names, str):
            new_names = names.split(',')
        else:
            raise NameError(f'illegal input names {names!r}')
        nnames = len(new_names)
        if nnames < ndescr:
            new_names += default_names[nnames:]
    ndescr = []
    for (n, d, t) in zip(new_names, default_names, descr.descr):
        if n in reserved_fields:
            if t[0] in reserved_fields:
                ndescr.append((d, t[1]))
            else:
                ndescr.append(t)
        else:
            ndescr.append((n, t[1]))
    return np.dtype(ndescr)

def parse_cvNameIDs_(self, tag, block_name):
    assert self.cur_token_ == block_name, self.cur_token_
    block = self.ast.NestedBlock(tag, block_name, location=self.cur_token_location_)
    self.expect_symbol_("{")
    for symtab in self.symbol_tables_:
        symtab.enter_scope()
    while self.next_token_ != "}" or self.cur_comments_:
        self.advance_lexer_(comments=True)
        if self.cur_token_type_ is Lexer.COMMENT:
            block.statements.append(
                self.ast.Comment(self.cur_token_, location=self.cur_token_location_)
            )
        elif self.is_cur_keyword_("name"):
            location = self.cur_token_location_
            platformID, platEncID, langID, string = self.parse_name_()
            block.statements.append(
                self.ast.CVParametersNameStatement(
                    tag,
                    platformID,
                    platEncID,
                    langID,
                    string,
                    block_name,
                    location=location,
                )
            )
        elif self.cur_token_ == ";":
            continue
        else:
            raise FeatureLibError('Expected "name"', self.cur_token_location_)
    self.expect_symbol_("}")
    for symtab in self.symbol_tables_:
        symtab.exit_scope()
    self.expect_symbol_(";")
    return block

def get_tokens_unprocessed(self, text):
    # 'in' is either a keyword or an operator.
    # If the token two tokens after 'in' is ')', 'in' is a keyword:
    #   objectloop(a in b)
    # Otherwise, it is an operator:
    #   objectloop(a in b && true)
    objectloop_queue = []
    objectloop_token_count = -1
    previous_token = None
    for index, token, value in RegexLexer.get_tokens_unprocessed(self,
                                                                 text):
        if previous_token is Name.Variable and value == 'in':
            objectloop_queue = [[index, token, value]]
            objectloop_token_count = 2
        elif objectloop_token_count > 0:
            if token not in Comment and token not in Text:
                objectloop_token_count -= 1
            objectloop_queue.append((index, token, value))
        else:
            if objectloop_token_count == 0:
                if objectloop_queue[-1][2] == ')':
                    objectloop_queue[0][1] = Keyword
                while objectloop_queue:
                    yield objectloop_queue.pop(0)
                objectloop_token_count = -1
            yield index, token, value
        if token not in Comment and token not in Text:
            previous_token = token
    while objectloop_queue:
        yield objectloop_queue.pop(0)

def __init__(self, hatch, density):
    self.num_lines = int((hatch.count('|') + hatch.count('+')) * density)
    self.num_vertices = self.num_lines * 2

def column(self) -> int:
    """
    Return the 1-based column on the line of text where the exception occurred.
    """
    return col(self.loc, self.pstr)

def rFonts_hAnsi(self) -> str | None:
    """The value of `w:rFonts/@w:hAnsi` or |None| if not present."""
    rFonts = self.rFonts
    if rFonts is None:
        return None
    return rFonts.hAnsi

def __setitem__(self, key, value):
    try:
        k = 'get' + key
    except TypeError:
        raise ValueError('Incompatible key: {} (type: {})'
                         ''.format(key, type(key)))
    if k == 'get':
        raise ValueError('Incompatible key: cannot use "" as a name')
    self._data[key] = value
    func = functools.partial(self._parser._get_conv, conv=value)
    func.converter = value
    setattr(self._parser, k, func)
    for proxy in self._parser.values():
        getter = functools.partial(proxy.get, _impl=func)
        setattr(proxy, k, getter)

def pl_true(expr, model=None, deep=False):
    """
    Returns whether the given assignment is a model or not.

    If the assignment does not specify the value for every proposition,
    this may return None to indicate 'not obvious'.

    Parameters
    ==========

    model : dict, optional, default: {}
        Mapping of symbols to boolean values to indicate assignment.
    deep: boolean, optional, default: False
        Gives the value of the expression under partial assignments
        correctly. May still return None to indicate 'not obvious'.


    Examples
    ========

    >>> from sympy.abc import A, B
    >>> from sympy.logic.inference import pl_true
    >>> pl_true( A & B, {A: True, B: True})
    True
    >>> pl_true(A & B, {A: False})
    False
    >>> pl_true(A & B, {A: True})
    >>> pl_true(A & B, {A: True}, deep=True)
    >>> pl_true(A >> (B >> A))
    >>> pl_true(A >> (B >> A), deep=True)
    True
    >>> pl_true(A & ~A)
    >>> pl_true(A & ~A, deep=True)
    False
    >>> pl_true(A & B & (~A | ~B), {A: True})
    >>> pl_true(A & B & (~A | ~B), {A: True}, deep=True)
    False

    """

    from sympy.core.symbol import Symbol

    boolean = (True, False)

    def _validate(expr):
        if isinstance(expr, Symbol) or expr in boolean:
            return True
        if not isinstance(expr, BooleanFunction):
            return False
        return all(_validate(arg) for arg in expr.args)

    if expr in boolean:
        return expr
    expr = sympify(expr)
    if not _validate(expr):
        raise ValueError("%s is not a valid boolean expression" % expr)
    if not model:
        model = {}
    model = {k: v for k, v in model.items() if v in boolean}
    result = expr.subs(model)
    if result in boolean:
        return bool(result)
    if deep:
        model = dict.fromkeys(result.atoms(), True)
        if pl_true(result, model):
            if valid(result):
                return True
        else:
            if not satisfiable(result):
                return False
    return None

def run(self) -> None:
    while not self.done.wait(1 / self.refresh_per_second):
        with self.live._lock:
            if not self.done.is_set():
                self.live.refresh()

def _parse_parameter_declaration(self) -> c_ast.Node:
    spec, _, spec_coord = self._parse_declaration_specifiers(allow_no_type=True)

    if not spec["type"]:
        spec["type"] = [c_ast.IdentifierType(["int"], coord=spec_coord)]

    if self._starts_declarator():
        decl, is_named = self._parse_any_declarator(
            allow_abstract=True, typeid_paren_as_abstract=True
        )
        if is_named:
            return self._build_declarations(
                spec=spec, decls=[dict(decl=decl, init=None, bitsize=None)]
            )[0]
        return self._build_parameter_declaration(spec, decl, spec_coord)

    decl = self._parse_abstract_declarator_opt()
    return self._build_parameter_declaration(spec, decl, spec_coord)

def __init__(self, gs):
    super(_GradientStop, self).__init__(gs)
    self._gs = gs

def getarrdims(a, var, verbose=0):
    ret = {}
    if isstring(var) and not isarray(var):
        ret['size'] = getstrlength(var)
        ret['rank'] = '0'
        ret['dims'] = ''
    elif isscalar(var):
        ret['size'] = '1'
        ret['rank'] = '0'
        ret['dims'] = ''
    elif isarray(var):
        dim = copy.copy(var['dimension'])
        ret['size'] = '*'.join(dim)
        try:
            ret['size'] = repr(eval(ret['size']))
        except Exception:
            pass
        ret['dims'] = ','.join(dim)
        ret['rank'] = repr(len(dim))
        ret['rank*[-1]'] = repr(len(dim) * [-1])[1:-1]
        for i in range(len(dim)):  # solve dim for dependencies
            v = []
            if dim[i] in depargs:
                v = [dim[i]]
            else:
                for va in depargs:
                    if re.match(r'.*?\b%s\b.*' % va, dim[i]):
                        v.append(va)
            for va in v:
                if depargs.index(va) > depargs.index(a):
                    dim[i] = '*'
                    break
        ret['setdims'], i = '', -1
        for d in dim:
            i = i + 1
            if d not in ['*', ':', '(*)', '(:)']:
                ret['setdims'] = '%s#varname#_Dims[%d]=%s,' % (
                    ret['setdims'], i, d)
        if ret['setdims']:
            ret['setdims'] = ret['setdims'][:-1]
        ret['cbsetdims'], i = '', -1
        for d in var['dimension']:
            i = i + 1
            if d not in ['*', ':', '(*)', '(:)']:
                ret['cbsetdims'] = '%s#varname#_Dims[%d]=%s,' % (
                    ret['cbsetdims'], i, d)
            elif isintent_in(var):
                outmess('getarrdims:warning: assumed shape array, using 0 instead of %r\n'
                        % (d))
                ret['cbsetdims'] = '%s#varname#_Dims[%d]=%s,' % (
                    ret['cbsetdims'], i, 0)
            elif verbose:
                errmess(
                    f'getarrdims: If in call-back function: array argument {repr(a)} must have bounded dimensions: got {repr(d)}\n')
        if ret['cbsetdims']:
            ret['cbsetdims'] = ret['cbsetdims'][:-1]
#         if not isintent_c(var):
#             var['dimension'].reverse()
    return ret

def add_legend_data(
    self, ax, func, common_kws=None, attrs=None, semantic_kws=None,
):
    """Add labeled artists to represent the different plot semantics."""
    verbosity = self.legend
    if isinstance(verbosity, str) and verbosity not in ["auto", "brief", "full"]:
        err = "`legend` must be 'auto', 'brief', 'full', or a boolean."
        raise ValueError(err)
    elif verbosity is True:
        verbosity = "auto"

    keys = []
    legend_kws = {}
    common_kws = {} if common_kws is None else common_kws.copy()
    semantic_kws = {} if semantic_kws is None else semantic_kws.copy()

    # Assign a legend title if there is only going to be one sub-legend,
    # otherwise, subtitles will be inserted into the texts list with an
    # invisible handle (which is a hack)
    titles = {
        title for title in
        (self.variables.get(v, None) for v in ["hue", "size", "style"])
        if title is not None
    }
    title = "" if len(titles) != 1 else titles.pop()
    title_kws = dict(
        visible=False, color="w", s=0, linewidth=0, marker="", dashes=""
    )

    def update(var_name, val_name, **kws):

        key = var_name, val_name
        if key in legend_kws:
            legend_kws[key].update(**kws)
        else:
            keys.append(key)
            legend_kws[key] = dict(**kws)

    if attrs is None:
        attrs = {"hue": "color", "size": ["linewidth", "s"], "style": None}
    for var, names in attrs.items():
        self._update_legend_data(
            update, var, verbosity, title, title_kws, names, semantic_kws.get(var),
        )

    legend_data = {}
    legend_order = []

    # Don't allow color=None so we can set a neutral color for size/style legends
    if common_kws.get("color", False) is None:
        common_kws.pop("color")

    for key in keys:

        _, label = key
        kws = legend_kws[key]
        level_kws = {}
        use_attrs = [
            *self._legend_attributes,
            *common_kws,
            *[attr for var_attrs in semantic_kws.values() for attr in var_attrs],
        ]
        for attr in use_attrs:
            if attr in kws:
                level_kws[attr] = kws[attr]
        artist = func(label=label, **{"color": ".2", **common_kws, **level_kws})
        if _version_predates(mpl, "3.5.0"):
            if isinstance(artist, mpl.lines.Line2D):
                ax.add_line(artist)
            elif isinstance(artist, mpl.patches.Patch):
                ax.add_patch(artist)
            elif isinstance(artist, mpl.collections.Collection):
                ax.add_collection(artist)
        else:
            ax.add_artist(artist)
        legend_data[key] = artist
        legend_order.append(key)

    self.legend_title = title
    self.legend_data = legend_data
    self.legend_order = legend_order

def _write_xref_table(
    self, stream: StreamType, object_positions: List[int], free_objects: List[int]
) -> int:
    xref_location = stream.tell()
    stream.write(b"xref\n")
    stream.write(f"0 {len(self._objects) + 1}\n".encode())
    stream.write(f"{free_objects[0]:0>10} {65535:0>5} f \n".encode())
    free_idx = 1
    for offset in object_positions:
        if offset > 0:
            stream.write(f"{offset:0>10} {0:0>5} n \n".encode())
        else:
            stream.write(f"{free_objects[free_idx]:0>10} {1:0>5} f \n".encode())
            free_idx += 1
    return xref_location

def parse_table_OS_2_(self, table):
    statements = table.statements
    numbers = (
        "FSType",
        "TypoAscender",
        "TypoDescender",
        "TypoLineGap",
        "winAscent",
        "winDescent",
        "XHeight",
        "CapHeight",
        "WeightClass",
        "WidthClass",
        "LowerOpSize",
        "UpperOpSize",
    )
    ranges = ("UnicodeRange", "CodePageRange")
    while self.next_token_ != "}" or self.cur_comments_:
        self.advance_lexer_(comments=True)
        if self.cur_token_type_ is Lexer.COMMENT:
            statements.append(
                self.ast.Comment(self.cur_token_, location=self.cur_token_location_)
            )
        elif self.cur_token_type_ is Lexer.NAME:
            key = self.cur_token_.lower()
            value = None
            if self.cur_token_ in numbers:
                value = self.expect_number_()
            elif self.is_cur_keyword_("Panose"):
                value = []
                for i in range(10):
                    value.append(self.expect_number_())
            elif self.cur_token_ in ranges:
                value = []
                while self.next_token_ != ";":
                    value.append(self.expect_number_())
            elif self.is_cur_keyword_("Vendor"):
                value = self.expect_string_()
            statements.append(
                self.ast.OS2Field(key, value, location=self.cur_token_location_)
            )
        elif self.cur_token_ == ";":
            continue

def simp_coeff_dep(expr, wrt1, wrt2=None):
    """Split rhs into terms, split terms into dep and coeff and collect on dep"""
    add_dep_terms = lambda e: e.is_Add and e.has(*wrt1)
    expandable = lambda e: e.is_Mul and any(map(add_dep_terms, e.args))
    expand_func = lambda e: expand_mul(e, deep=False)
    expand_mul_mod = lambda e: e.replace(expandable, expand_func)
    terms = Add.make_args(expand_mul_mod(expr))
    dc = {}
    for term in terms:
        coeff, dep = term.as_independent(*wrt1, as_Add=False)
        # Collect together the coefficients for terms that have the same
        # dependence on wrt1 (after dep is normalised using simpdep).
        dep = simpdep(dep, wrt1)

        # See if the dependence on t cancels out...
        if dep is not S.One:
            dep2 = factor_terms(dep)
            if not dep2.has(*wrt1):
                coeff *= dep2
                dep = S.One

        if dep not in dc:
            dc[dep] = coeff
        else:
            dc[dep] += coeff
    # Apply the method recursively to the coefficients but this time
    # collecting on wrt2 rather than wrt2.
    termpairs = ((simpcoeff(c, wrt2), d) for d, c in dc.items())
    if wrt2 is not None:
        termpairs = ((simp_coeff_dep(c, wrt2), d) for c, d in termpairs)
    return Add(*(c * d for c, d in termpairs))

def _write_name(self, data) -> None:
    # Write the <c:name> element.

    if data is None:
        return

    self._xml_data_element("c:name", data)

def f(rv):
    if not (
        isinstance(rv, Pow) and
        (rv.base.is_positive or rv.exp.is_integer and rv.exp.is_negative)):
        return rv

    if isinstance(rv.base, tan):
        return cot(rv.base.args[0])**-rv.exp
    elif isinstance(rv.base, sin):
        return csc(rv.base.args[0])**-rv.exp
    elif isinstance(rv.base, cos):
        return sec(rv.base.args[0])**-rv.exp
    return rv

def _set_dps(ctx, n):
    ctx._prec[0] = dps_to_prec(n)
    ctx._dps = max(1, int(n))

def _eval_is_odd(self):
    is_integer = self._eval_is_integer()
    if is_integer is not True:
        return is_integer

    from sympy.simplify.radsimp import fraction
    n, d = fraction(self)
    if d.is_Integer and d.is_even:
        # if minimal power of 2 in num vs den is
        # positive then we have an even number
        if (Add(*[i.as_base_exp()[1] for i in
                Mul.make_args(n) if i.is_even]) - trailing(d.p)
                ).is_positive:
            return False
        return
    r, acc = True, 1
    for t in self.args:
        if abs(t) is S.One:
            continue
        if t.is_even:
            return False
        if r is False:
            pass
        elif acc != 1 and (acc + t).is_odd:
            r = False
        elif t.is_even is None:
            r = None
        acc = t
    return r

def __str__(self) -> str:
    if not self.fit_args:
        return f"Fit({self.fit_type})"
    return f"Fit({self.fit_type}, {self.fit_args})"

def __gt__(self, other):
    'True if all counts in self are a proper superset of those in other.'
    if not isinstance(other, Counter):
        return NotImplemented
    return self >= other and self != other

def __mul__(self, other) -> "ParserElement":
    """
    Implementation of ``*`` operator, allows use of ``expr * 3`` in place of
    ``expr + expr + expr``.  Expressions may also be multiplied by a 2-integer
    tuple, similar to ``{min, max}`` multipliers in regular expressions.  Tuples
    may also include ``None`` as in:

    - ``expr*(n, None)`` or ``expr*(n, )`` is equivalent
      to ``expr*n + ZeroOrMore(expr)``
      (read as "at least n instances of ``expr``")
    - ``expr*(None, n)`` is equivalent to ``expr*(0, n)``
      (read as "0 to n instances of ``expr``")
    - ``expr*(None, None)`` is equivalent to ``ZeroOrMore(expr)``
    - ``expr*(1, None)`` is equivalent to ``OneOrMore(expr)``

    Note that ``expr*(None, n)`` does not raise an exception if
    more than n exprs exist in the input stream; that is,
    ``expr*(None, n)`` does not enforce a maximum number of expr
    occurrences.  If this behavior is desired, then write
    ``expr*(None, n) + ~expr``
    """
    if other is Ellipsis:
        other = (0, None)
    elif isinstance(other, tuple) and other[:1] == (Ellipsis,):
        other = ((0,) + other[1:] + (None,))[:2]

    if isinstance(other, int):
        minElements, optElements = other, 0
    elif isinstance(other, tuple):
        other = tuple(o if o is not Ellipsis else None for o in other)
        other = (other + (None, None))[:2]
        if other[0] is None:
            other = (0, other[1])
        if isinstance(other[0], int) and other[1] is None:
            if other[0] == 0:
                return ZeroOrMore(self)
            if other[0] == 1:
                return OneOrMore(self)
            else:
                return self * other[0] + ZeroOrMore(self)
        elif isinstance(other[0], int) and isinstance(other[1], int):
            minElements, optElements = other
            optElements -= minElements
        else:
            return NotImplemented
    else:
        return NotImplemented

    if minElements < 0:
        raise ValueError("cannot multiply ParserElement by negative value")
    if optElements < 0:
        raise ValueError(
            "second tuple value must be greater or equal to first tuple value"
        )
    if minElements == optElements == 0:
        return And([])

    if optElements:

        def makeOptionalList(n):
            if n > 1:
                return Opt(self + makeOptionalList(n - 1))
            else:
                return Opt(self)

        if minElements:
            if minElements == 1:
                ret = self + makeOptionalList(optElements)
            else:
                ret = And([self] * minElements) + makeOptionalList(optElements)
        else:
            ret = makeOptionalList(optElements)
    else:
        if minElements == 1:
            ret = self
        else:
            ret = And([self] * minElements)
    return ret

def _get_background(
    im: Image.Image,
    info_background: int | tuple[int, int, int] | tuple[int, int, int, int] | None,
) -> int:
    background = 0
    if info_background:
        if isinstance(info_background, tuple):
            # WebPImagePlugin stores an RGBA value in info["background"]
            # So it must be converted to the same format as GifImagePlugin's
            # info["background"] - a global color table index
            assert im.palette is not None
            try:
                background = im.palette.getcolor(info_background, im)
            except ValueError as e:
                if str(e) not in (
                    # If all 256 colors are in use,
                    # then there is no need for the background color
                    "cannot allocate more than 256 colors",
                    # Ignore non-opaque WebP background
                    "cannot add non-opaque RGBA color to RGB palette",
                ):
                    raise
        else:
            background = info_background
    return background

def display_name(self):
    res = TokenList(self)
    if len(res) == 0:
        return res.value
    if res[0].token_type == 'cfws':
        res.pop(0)
    else:
        if res[0][0].token_type == 'cfws':
            res[0] = TokenList(res[0][1:])
    if res[-1].token_type == 'cfws':
        res.pop()
    else:
        if res[-1][-1].token_type == 'cfws':
            res[-1] = TokenList(res[-1][:-1])
    return res.value

def load_from_docinfo(
    self, docinfo, delete_missing: bool = False, raise_failure: bool = False
) -> None:
    """Populate the XMP metadata object with DocumentInfo.

    Arguments:
        docinfo: a DocumentInfo, e.g pdf.docinfo
        delete_missing: if the entry is not DocumentInfo, delete the equivalent
            from XMP
        raise_failure: if True, raise any failure to convert docinfo;
            otherwise warn and continue

    A few entries in the deprecated DocumentInfo dictionary are considered
    approximately equivalent to certain XMP records. This method copies
    those entries into the XMP metadata.
    """
    from lxml.etree import QName

    def warn_or_raise(msg, e=None):
        if raise_failure:
            raise ValueError(msg) from e
        warn(msg)

    for uri, shortkey, docinfo_name, converter in self.DOCINFO_MAPPING:
        qname = QName(uri, shortkey)
        # docinfo might be a dict or pikepdf.Dictionary, so lookup keys
        # by str(Name)
        val = docinfo.get(str(docinfo_name))
        if val is None:
            if delete_missing and qname in self:
                del self[qname]
            continue
        try:
            val = str(val)
            if converter:
                val = converter.xmp_from_docinfo(val)
            if not val:
                continue
            self._setitem(qname, val, True)
        except (ValueError, AttributeError, NotImplementedError) as e:
            warn_or_raise(
                f"The metadata field {docinfo_name} could not be copied to XMP", e
            )
    valid_docinfo_names = {
        str(docinfo_name) for _, _, docinfo_name, _ in self.DOCINFO_MAPPING
    }
    extra_docinfo_names = {str(k) for k in docinfo.keys()} - valid_docinfo_names
    for extra in extra_docinfo_names:
        warn_or_raise(
            f"The metadata field {extra} with value '{repr(docinfo.get(extra))}' "
            "has no XMP equivalent, so it was discarded",
        )

def assert_equal(actual, desired, err_msg=''):
    """
    Asserts that two items are equal.

    """
    # Case #1: dictionary .....
    if isinstance(desired, dict):
        if not isinstance(actual, dict):
            raise AssertionError(repr(type(actual)))
        assert_equal(len(actual), len(desired), err_msg)
        for k in desired:
            if k not in actual:
                raise AssertionError(f"{k} not in {actual}")
            assert_equal(actual[k], desired[k], f'key={k!r}\n{err_msg}')
        return
    # Case #2: lists .....
    if isinstance(desired, (list, tuple)) and isinstance(actual, (list, tuple)):
        return _assert_equal_on_sequences(actual, desired, err_msg='')
    if not (isinstance(actual, ndarray) or isinstance(desired, ndarray)):
        msg = build_err_msg([actual, desired], err_msg,)
        if not desired == actual:
            raise AssertionError(msg)
        return
    # Case #4. arrays or equivalent
    if ((actual is masked) and not (desired is masked)) or \
            ((desired is masked) and not (actual is masked)):
        msg = build_err_msg([actual, desired],
                            err_msg, header='', names=('x', 'y'))
        raise ValueError(msg)
    actual = np.asanyarray(actual)
    desired = np.asanyarray(desired)
    (actual_dtype, desired_dtype) = (actual.dtype, desired.dtype)
    if actual_dtype.char == "S" and desired_dtype.char == "S":
        return _assert_equal_on_sequences(actual.tolist(),
                                          desired.tolist(),
                                          err_msg='')
    return assert_array_equal(actual, desired, err_msg)

def __exit__(self, type: object, value: object, traceback: object) -> None:
    self.write_stream.close()
    self.status_stream.close()

def sizes(self) -> RequestSizes:
    """Request.sizes

    Returns resource size information for given request.

    Returns
    -------
    {requestBodySize: int, requestHeadersSize: int, responseBodySize: int, responseHeadersSize: int}
    """

    return mapping.from_impl(self._sync(self._impl_obj.sizes()))

def __new__(cls, match_string: str = "", *, matchString: str = ""):
    # Performance tuning: select a subclass with optimized parseImpl
    if cls is Literal:
        match_string = matchString or match_string
        if not match_string:
            return super().__new__(Empty)
        if len(match_string) == 1:
            return super().__new__(_SingleCharLiteral)

    # Default behavior
    return super().__new__(cls)

def f(rv):
    if not (isinstance(rv, Pow) and isinstance(rv.base, (sin, cos))):
        return rv
    b, n = rv.as_base_exp()
    x = b.args[0]
    if n.is_Integer and n.is_positive:
        if n.is_odd and isinstance(b, cos):
            rv = 2**(1-n)*Add(*[binomial(n, k)*cos((n - 2*k)*x)
                for k in range((n + 1)/2)])
        elif n.is_odd and isinstance(b, sin):
            rv = 2**(1-n)*S.NegativeOne**((n-1)/2)*Add(*[binomial(n, k)*
                S.NegativeOne**k*sin((n - 2*k)*x) for k in range((n + 1)/2)])
        elif n.is_even and isinstance(b, cos):
            rv = 2**(1-n)*Add(*[binomial(n, k)*cos((n - 2*k)*x)
                for k in range(n/2)])
        elif n.is_even and isinstance(b, sin):
            rv = 2**(1-n)*S.NegativeOne**(n/2)*Add(*[binomial(n, k)*
                S.NegativeOne**k*cos((n - 2*k)*x) for k in range(n/2)])
        if n.is_even:
            rv += 2**(-n)*binomial(n, n/2)
    return rv

def addr_spec(self):
    for x in self:
        if x.token_type == 'addr-spec':
            if x.local_part:
                return x.addr_spec
            else:
                return quote_string(x.local_part) + x.addr_spec
    else:
        return '<>'

def _relpath(self, path):
    if isinstance(path, str):
        if not self.path:
            return path
        # We need to account for S3FileSystem returning paths that do not
        # start with a '/'
        if path == self.path or (
            self.path.startswith(self.fs.sep) and path == self.path[1:]
        ):
            return ""
        prefix = self.path + self.fs.sep
        if self.path.startswith(self.fs.sep) and not path.startswith(self.fs.sep):
            prefix = prefix[1:]
        assert path.startswith(prefix)
        return path[len(prefix) :]
    return [self._relpath(_path) for _path in path]

def _emit_bytecode_StructType(self, tp, index):
    struct_index = self._struct_unions[tp]
    self.cffi_types[index] = CffiOp(OP_STRUCT_UNION, struct_index)

def subset_glyphs(self, s):
    glyphs = s.glyphs_gsubed
    for t in self.kernTables:
        t.kernTable = {
            (a, b): v
            for (a, b), v in t.kernTable.items()
            if a in glyphs and b in glyphs
        }
    self.kernTables = [t for t in self.kernTables if t.kernTable]
    return bool(self.kernTables)

def _score_with_raw_predictions(self, X, y, sample_weight, raw_predictions=None):
    if raw_predictions is None:
        patcher_raw_predict = nullcontext()
    else:
        patcher_raw_predict = _patch_raw_predict(self, raw_predictions)

    with patcher_raw_predict:
        if sample_weight is None:
            return self._scorer(self, X, y)
        else:
            return self._scorer(self, X, y, sample_weight=sample_weight)

def _canonicalize(self):
    expr = self.expr
    diagonal_indices = self.diagonal_indices
    trivial_diags = [i for i in diagonal_indices if len(i) == 1]
    if len(trivial_diags) > 0:
        trivial_pos = {e[0]: i for i, e in enumerate(diagonal_indices) if len(e) == 1}
        diag_pos = {e: i for i, e in enumerate(diagonal_indices) if len(e) > 1}
        diagonal_indices_short = [i for i in diagonal_indices if len(i) > 1]
        rank1 = get_rank(self)
        rank2 = len(diagonal_indices)
        rank3 = rank1 - rank2
        inv_permutation = []
        counter1 = 0
        indices_down = ArrayDiagonal._push_indices_down(diagonal_indices_short, list(range(rank1)), get_rank(expr))
        for i in indices_down:
            if i in trivial_pos:
                inv_permutation.append(rank3 + trivial_pos[i])
            elif isinstance(i, (Integer, int)):
                inv_permutation.append(counter1)
                counter1 += 1
            else:
                inv_permutation.append(rank3 + diag_pos[i])
        permutation = _af_invert(inv_permutation)
        if len(diagonal_indices_short) > 0:
            return _permute_dims(_array_diagonal(expr, *diagonal_indices_short), permutation)
        else:
            return _permute_dims(expr, permutation)
    if isinstance(expr, ArrayAdd):
        return self._ArrayDiagonal_denest_ArrayAdd(expr, *diagonal_indices)
    if isinstance(expr, ArrayDiagonal):
        return self._ArrayDiagonal_denest_ArrayDiagonal(expr, *diagonal_indices)
    if isinstance(expr, PermuteDims):
        return self._ArrayDiagonal_denest_PermuteDims(expr, *diagonal_indices)
    if isinstance(expr, (ZeroArray, ZeroMatrix)):
        positions, shape = self._get_positions_shape(expr.shape, diagonal_indices)
        return ZeroArray(*shape)
    return self.func(expr, *diagonal_indices, canonicalize=False)

def add_outline_item(
    self,
    title: str,
    page_number: Union[None, PageObject, IndirectObject, int],
    parent: Union[None, TreeObject, IndirectObject] = None,
    before: Union[None, TreeObject, IndirectObject] = None,
    color: Optional[Union[Tuple[float, float, float], str]] = None,
    bold: bool = False,
    italic: bool = False,
    fit: Fit = PAGE_FIT,
    is_open: bool = True,
) -> IndirectObject:
    """
    Add an outline item (commonly referred to as a "Bookmark") to the PDF file.

    Args:
        title: Title to use for this outline item.
        page_number: Page number this outline item will point to.
        parent: A reference to a parent outline item to create nested
            outline items.
        before:
        color: Color of the outline item's font as a red, green, blue tuple
            from 0.0 to 1.0 or as a Hex String (#RRGGBB)
        bold: Outline item font is bold
        italic: Outline item font is italic
        fit: The fit of the destination page.

    Returns:
        The added outline item as an indirect object.

    """
    page_ref: Union[None, NullObject, IndirectObject, NumberObject]
    if isinstance(italic, Fit):  # it means that we are on the old params
        if fit is not None and page_number is None:
            page_number = fit
        return self.add_outline_item(
            title, page_number, parent, None, before, color, bold, italic, is_open=is_open
        )
    if page_number is None:
        action_ref = None
    else:
        if isinstance(page_number, IndirectObject):
            page_ref = page_number
        elif isinstance(page_number, PageObject):
            page_ref = page_number.indirect_reference
        elif isinstance(page_number, int):
            try:
                page_ref = self.pages[page_number].indirect_reference
            except IndexError:
                page_ref = NumberObject(page_number)
        if page_ref is None:
            logger_warning(
                f"can not find reference of page {page_number}",
                __name__,
            )
            page_ref = NullObject()
        dest = Destination(
            NameObject("/" + title + " outline item"),
            page_ref,
            fit,
        )

        action_ref = self._add_object(
            DictionaryObject(
                {
                    NameObject(GoToActionArguments.D): dest.dest_array,
                    NameObject(GoToActionArguments.S): NameObject("/GoTo"),
                }
            )
        )
    outline_item = self._add_object(
        _create_outline_item(action_ref, title, color, italic, bold)
    )

    if parent is None:
        parent = self.get_outline_root()
    return self.add_outline_item_destination(outline_item, parent, before, is_open)

def isdtype(
    dtype: DType, 
    kind: DType | str | tuple[DType | str, ...],
    *,
    _tuple: bool = True, # Disallow nested tuples
) -> bool:
    """
    Returns a boolean indicating whether a provided dtype is of a specified data type ``kind``.

    Note that outside of this function, this compat library does not yet fully
    support complex numbers.

    See
    https://data-apis.org/array-api/latest/API_specification/generated/array_api.isdtype.html
    for more details
    """
    if isinstance(kind, tuple) and _tuple:
        return _builtin_any(isdtype(dtype, k, _tuple=False) for k in kind)
    elif isinstance(kind, str):
        if kind == 'bool':
            return dtype == torch.bool
        elif kind == 'signed integer':
            return dtype in _int_dtypes and dtype.is_signed
        elif kind == 'unsigned integer':
            return dtype in _int_dtypes and not dtype.is_signed
        elif kind == 'integral':
            return dtype in _int_dtypes
        elif kind == 'real floating':
            return dtype.is_floating_point
        elif kind == 'complex floating':
            return dtype.is_complex
        elif kind == 'numeric':
            return isdtype(dtype, ('integral', 'real floating', 'complex floating'))
        else:
            raise ValueError(f"Unrecognized data type kind: {kind!r}")
    else:
        return dtype == kind

def parse_table_BASE_(self, table):
    statements = table.statements
    while self.next_token_ != "}" or self.cur_comments_:
        self.advance_lexer_(comments=True)
        if self.cur_token_type_ is Lexer.COMMENT:
            statements.append(
                self.ast.Comment(self.cur_token_, location=self.cur_token_location_)
            )
        elif self.is_cur_keyword_("HorizAxis.BaseTagList"):
            horiz_bases = self.parse_base_tag_list_()
        elif self.is_cur_keyword_("HorizAxis.BaseScriptList"):
            horiz_scripts = self.parse_base_script_list_(len(horiz_bases))
            statements.append(
                self.ast.BaseAxis(
                    horiz_bases,
                    horiz_scripts,
                    False,
                    location=self.cur_token_location_,
                )
            )
        elif self.is_cur_keyword_("HorizAxis.MinMax"):
            base_script_list = self.find_previous(statements, ast.BaseAxis)
            if base_script_list is None:
                raise FeatureLibError(
                    "MinMax must be preceded by BaseScriptList",
                    self.cur_token_location_,
                )
            if base_script_list.vertical:
                raise FeatureLibError(
                    "HorizAxis.MinMax must be preceded by HorizAxis statements",
                    self.cur_token_location_,
                )
            base_script_list.minmax.append(self.parse_base_minmax_())
        elif self.is_cur_keyword_("VertAxis.BaseTagList"):
            vert_bases = self.parse_base_tag_list_()
        elif self.is_cur_keyword_("VertAxis.BaseScriptList"):
            vert_scripts = self.parse_base_script_list_(len(vert_bases))
            statements.append(
                self.ast.BaseAxis(
                    vert_bases,
                    vert_scripts,
                    True,
                    location=self.cur_token_location_,
                )
            )
        elif self.is_cur_keyword_("VertAxis.MinMax"):
            base_script_list = self.find_previous(statements, ast.BaseAxis)
            if base_script_list is None:
                raise FeatureLibError(
                    "MinMax must be preceded by BaseScriptList",
                    self.cur_token_location_,
                )
            if not base_script_list.vertical:
                raise FeatureLibError(
                    "VertAxis.MinMax must be preceded by VertAxis statements",
                    self.cur_token_location_,
                )
            base_script_list.minmax.append(self.parse_base_minmax_())
        elif self.cur_token_ == ";":
            continue

def _prod(a, axis=None, dtype=None, out=None, keepdims=False,
          initial=_NoValue, where=True):
    return umr_prod(a, axis, dtype, out, keepdims, initial, where)

def as_real_imag(self, deep=True, **hints):
    from sympy.functions.elementary.complexes import Abs, im, re
    other = []
    coeffr = []
    coeffi = []
    addterms = S.One
    for a in self.args:
        r, i = a.as_real_imag()
        if i.is_zero:
            coeffr.append(r)
        elif r.is_zero:
            coeffi.append(i*S.ImaginaryUnit)
        elif a.is_commutative:
            aconj = a.conjugate() if other else None
            # search for complex conjugate pairs:
            for i, x in enumerate(other):
                if x == aconj:
                    coeffr.append(Abs(x)**2)
                    del other[i]
                    break
            else:
                if a.is_Add:
                    addterms *= a
                else:
                    other.append(a)
        else:
            other.append(a)
    m = self.func(*other)
    if hints.get('ignore') == m:
        return
    if len(coeffi) % 2:
        imco = im(coeffi.pop(0))
        # all other pairs make a real factor; they will be
        # put into reco below
    else:
        imco = S.Zero
    reco = self.func(*(coeffr + coeffi))
    r, i = (reco*re(m), reco*im(m))
    if addterms == 1:
        if m == 1:
            if imco.is_zero:
                return (reco, S.Zero)
            else:
                return (S.Zero, reco*imco)
        if imco is S.Zero:
            return (r, i)
        return (-imco*i, imco*r)
    from .function import expand_mul
    addre, addim = expand_mul(addterms, deep=False).as_real_imag()
    if imco is S.Zero:
        return (r*addre - i*addim, i*addre + r*addim)
    else:
        r, i = -imco*i, imco*r
        return (r*addre - i*addim, r*addim + i*addre)

def _eval_pos_neg(self, sign):
    saw_NON = saw_NOT = False
    for t in self.args:
        if t.is_extended_positive:
            continue
        elif t.is_extended_negative:
            sign = -sign
        elif t.is_zero:
            if all(a.is_finite for a in self.args):
                return False
            return
        elif t.is_extended_nonpositive:
            sign = -sign
            saw_NON = True
        elif t.is_extended_nonnegative:
            saw_NON = True
        # FIXME: is_positive/is_negative is False doesn't take account of
        # Symbol('x', infinite=True, extended_real=True) which has
        # e.g. is_positive is False but has uncertain sign.
        elif t.is_positive is False:
            sign = -sign
            if saw_NOT:
                return
            saw_NOT = True
        elif t.is_negative is False:
            if saw_NOT:
                return
            saw_NOT = True
        else:
            return
    if sign == 1 and saw_NON is False and saw_NOT is False:
        return True
    if sign < 0:
        return False

def _parse_function_decl(self, base_decl: c_ast.Node) -> c_ast.Node:
    self._expect("LPAREN")
    if self._accept("RPAREN"):
        args = None
    else:
        args = (
            self._parse_parameter_type_list()
            if self._starts_declaration()
            else self._parse_identifier_list_opt()
        )
        self._expect("RPAREN")

    func = c_ast.FuncDecl(args=args, type=None, coord=base_decl.coord)

    if self._peek_type() == "LBRACE":
        if func.args is not None:
            for param in func.args.params:
                if isinstance(param, c_ast.EllipsisParam):
                    break
                name = getattr(param, "name", None)
                if name:
                    self._add_identifier(name, param.coord)

    return func

def get_ring(self):
    """Returns ring associated with ``self``. """
    from sympy.polys.domains import PythonIntegerRing
    return PythonIntegerRing()

def _interpolate_some(self, parser, option, accum, rest, section, map,
                      depth):
    rawval = parser.get(section, option, raw=True, fallback=rest)
    if depth > MAX_INTERPOLATION_DEPTH:
        raise InterpolationDepthError(option, section, rawval)
    while rest:
        p = rest.find("$")
        if p < 0:
            accum.append(rest)
            return
        if p > 0:
            accum.append(rest[:p])
            rest = rest[p:]
        # p is no longer used
        c = rest[1:2]
        if c == "$":
            accum.append("$")
            rest = rest[2:]
        elif c == "{":
            m = self._KEYCRE.match(rest)
            if m is None:
                raise InterpolationSyntaxError(option, section,
                    "bad interpolation variable reference %r" % rest)
            path = m.group(1).split(':')
            rest = rest[m.end():]
            sect = section
            opt = option
            try:
                if len(path) == 1:
                    opt = parser.optionxform(path[0])
                    v = map[opt]
                elif len(path) == 2:
                    sect = path[0]
                    opt = parser.optionxform(path[1])
                    v = parser.get(sect, opt, raw=True)
                else:
                    raise InterpolationSyntaxError(
                        option, section,
                        "More than one ':' found: %r" % (rest,))
            except (KeyError, NoSectionError, NoOptionError):
                raise InterpolationMissingOptionError(
                    option, section, rawval, ":".join(path)) from None
            if "$" in v:
                self._interpolate_some(parser, opt, accum, v, sect,
                                       dict(parser.items(sect, raw=True)),
                                       depth + 1)
            else:
                accum.append(v)
        else:
            raise InterpolationSyntaxError(
                option, section,
                "'$' must be followed by '$' or '{', "
                "found: %r" % (rest,))

def shim_cb(sslobj, servername, sslctx):
    servername = self._encode_hostname(servername)
    return server_name_callback(sslobj, servername, sslctx)

def f(pointer):
    if not isinstance(pointer, Iterable):
        return [pointer], ()

    if len(pointer) == 0:
        return [], (0,)

    result = []
    elems, shapes = zip(*[f(i) for i in pointer])
    if len(set(shapes)) != 1:
        raise ValueError("could not determine shape unambiguously")
    for i in elems:
        result.extend(i)
    return result, (len(shapes),)+shapes[0]

def map_forward(self, v):
    """Maps value from axis mapping's input (user) to output (design)."""
    from fontTools.varLib.models import piecewiseLinearMap

    if not self.map:
        return v
    return piecewiseLinearMap(v, {k: v for k, v in self.map})

def _eval_power(self, expt):

    # don't break up NC terms: (A*B)**3 != A**3*B**3, it is A*B*A*B*A*B
    cargs, nc = self.args_cnc(split_1=False)

    if expt.is_Integer:
        return Mul(*[Pow(b, expt, evaluate=False) for b in cargs]) * \
            Pow(Mul._from_args(nc), expt, evaluate=False)
    if expt.is_Rational and expt.q == 2:
        if self.is_imaginary:
            a = self.as_real_imag()[1]
            if a.is_Rational:
                n, d = abs(a/2).as_numer_denom()
                n, t = integer_nthroot(n, 2)
                if t:
                    d, t = integer_nthroot(d, 2)
                    if t:
                        from sympy.functions.elementary.complexes import sign
                        r = sympify(n)/d
                        return _unevaluated_Mul(r**expt.p, (1 + sign(a)*S.ImaginaryUnit)**expt.p)

    p = Pow(self, expt, evaluate=False)

    if expt.is_Rational or expt.is_Float:
        return p._eval_expand_power_base()

    return p

def parse_feature_reference_(self):
    assert self.cur_token_ == "feature", self.cur_token_
    location = self.cur_token_location_
    featureName = self.expect_tag_()
    self.expect_symbol_(";")
    return self.ast.FeatureReferenceStatement(featureName, location=location)

def _generateDefaultName(self) -> str:
    def charsAsStr(s):
        max_repr_len = 16
        s = _collapse_string_to_ranges(s, re_escape=False)
        if len(s) > max_repr_len:
            return s[: max_repr_len - 3] + "..."
        else:
            return s

    if self.initChars != self.bodyChars:
        base = f"W:({charsAsStr(self.initChars)}, {charsAsStr(self.bodyChars)})"
    else:
        base = f"W:({charsAsStr(self.initChars)})"

    # add length specification
    if self.minLen > 1 or self.maxLen != _MAX_INT:
        if self.minLen == self.maxLen:
            if self.minLen == 1:
                return base[2:]
            else:
                return base + f"{{{self.minLen}}}"
        elif self.maxLen == _MAX_INT:
            return base + f"{{{self.minLen},...}}"
        else:
            return base + f"{{{self.minLen},{self.maxLen}}}"
    return base

def wait_for(self, predicate, timeout=None):
    result = predicate()
    if result:
        return result
    if timeout is not None:
        endtime = _time() + timeout
    else:
        endtime = None
        waittime = None
    while not result:
        if endtime is not None:
            waittime = endtime - _time()
            if waittime <= 0:
                break
        self.wait(waittime)
        result = predicate()
    return result

def parseImpl(self, instring, loc, doActions=True):
    startloc = loc
    instrlen = len(instring)
    self_expr_parse = self.expr._parse
    self_failOn_canParseNext = (
        self.failOn.canParseNext if self.failOn is not None else None
    )
    ignorer_try_parse = self.ignorer.try_parse if self.ignorer.ignoreExprs else None

    tmploc = loc
    while tmploc <= instrlen:
        if self_failOn_canParseNext is not None:
            # break if failOn expression matches
            if self_failOn_canParseNext(instring, tmploc):
                break

        if ignorer_try_parse is not None:
            # advance past ignore expressions
            prev_tmploc = tmploc
            while 1:
                try:
                    tmploc = ignorer_try_parse(instring, tmploc)
                except ParseBaseException:
                    break
                # see if all ignorers matched, but didn't actually ignore anything
                if tmploc == prev_tmploc:
                    break
                prev_tmploc = tmploc

        try:
            self_expr_parse(instring, tmploc, doActions=False, callPreParse=False)
        except (ParseException, IndexError):
            # no match, advance loc in string
            tmploc += 1
        else:
            # matched skipto expr, done
            break

    else:
        # ran off the end of the input string without matching skipto expr, fail
        raise ParseException(instring, loc, self.errmsg, self)

    # build up return values
    loc = tmploc
    skiptext = instring[startloc:loc]
    skipresult = ParseResults(skiptext)

    if self.includeMatch:
        loc, mat = self_expr_parse(instring, loc, doActions, callPreParse=False)
        skipresult += mat

    return loc, skipresult

def find_spec(self, fullname, path, target=None):
    if fullname in self.known_modules:
        return spec_from_loader(fullname, self)
    return None

def ellipfun(ctx, kind, u=None, m=None, q=None, k=None, tau=None):
    try:
        S = jacobi_spec[kind]
    except KeyError:
        raise ValueError("First argument must be a two-character string "
            "containing 's', 'c', 'd' or 'n', e.g.: 'sn'")
    if u is None:
        def f(*args, **kwargs):
            return ctx.ellipfun(kind, *args, **kwargs)
        f.__name__ = kind
        return f
    prec = ctx.prec
    try:
        ctx.prec += 10
        u = ctx.convert(u)
        q = ctx.qfrom(m=m, q=q, k=k, tau=tau)
        if S is None:
            v = ctx.one + 0*q*u
        elif q == ctx.zero:
            if S[4] == '1': v = ctx.one
            else:           v = getattr(ctx, S[4])(u)
            v += 0*q*u
        elif q == ctx.one:
            if S[5] == '1': v = ctx.one
            else:           v = getattr(ctx, S[5])(u)
            v += 0*q*u
        else:
            t = u / ctx.jtheta(3, 0, q)**2
            v = ctx.one
            for a in S[0]: v *= ctx.jtheta(a, 0, q)
            for b in S[1]: v /= ctx.jtheta(b, 0, q)
            for c in S[2]: v *= ctx.jtheta(c, t, q)
            for d in S[3]: v /= ctx.jtheta(d, t, q)
    finally:
        ctx.prec = prec
    return +v

def parseImpl(self, instring, loc, doActions=True):
    if loc != 0:
        raise ParseException(instring, loc, "not found at string start")
    return super().parseImpl(instring, loc, doActions)

def run_validation(self, value: object):
    if isinstance(value, str):
        value = [value]
    if not isinstance(value, list):
        raise c.ValidationError('Expected a list of language codes.')
    for lang in value[:]:
        if lang != 'en':
            lang_detected = self.get_lunr_supported_lang(lang)
            if not lang_detected:
                log.info(f"Option search.lang '{lang}' is not supported, falling back to 'en'")
                value.remove(lang)
                if 'en' not in value:
                    value.append('en')
            elif lang_detected != lang:
                value.remove(lang)
                value.append(lang_detected)
                log.info(f"Option search.lang '{lang}' switched to '{lang_detected}'")
    return value

def check_bidi(label: str, check_ltr: bool = False) -> bool:
    # Bidi rules should only be applied if string contains RTL characters
    bidi_label = False
    for (idx, cp) in enumerate(label, 1):
        direction = unicodedata.bidirectional(cp)
        if direction == '':
            # String likely comes from a newer version of Unicode
            raise IDNABidiError('Unknown directionality in label {} at position {}'.format(repr(label), idx))
        if direction in ['R', 'AL', 'AN']:
            bidi_label = True
    if not bidi_label and not check_ltr:
        return True

    # Bidi rule 1
    direction = unicodedata.bidirectional(label[0])
    if direction in ['R', 'AL']:
        rtl = True
    elif direction == 'L':
        rtl = False
    else:
        raise IDNABidiError('First codepoint in label {} must be directionality L, R or AL'.format(repr(label)))

    valid_ending = False
    number_type = None  # type: Optional[str]
    for (idx, cp) in enumerate(label, 1):
        direction = unicodedata.bidirectional(cp)

        if rtl:
            # Bidi rule 2
            if not direction in ['R', 'AL', 'AN', 'EN', 'ES', 'CS', 'ET', 'ON', 'BN', 'NSM']:
                raise IDNABidiError('Invalid direction for codepoint at position {} in a right-to-left label'.format(idx))
            # Bidi rule 3
            if direction in ['R', 'AL', 'EN', 'AN']:
                valid_ending = True
            elif direction != 'NSM':
                valid_ending = False
            # Bidi rule 4
            if direction in ['AN', 'EN']:
                if not number_type:
                    number_type = direction
                else:
                    if number_type != direction:
                        raise IDNABidiError('Can not mix numeral types in a right-to-left label')
        else:
            # Bidi rule 5
            if not direction in ['L', 'EN', 'ES', 'CS', 'ET', 'ON', 'BN', 'NSM']:
                raise IDNABidiError('Invalid direction for codepoint at position {} in a left-to-right label'.format(idx))
            # Bidi rule 6
            if direction in ['L', 'EN']:
                valid_ending = True
            elif direction != 'NSM':
                valid_ending = False

    if not valid_ending:
        raise IDNABidiError('Label ends with illegal codepoint directionality')

    return True

def remove_redundant_langsys(self):
    table = self.table
    if not table.ScriptList or not table.FeatureList:
        return

    features = table.FeatureList.FeatureRecord

    for s in table.ScriptList.ScriptRecord:
        d = s.Script.DefaultLangSys
        if not d:
            continue
        for lr in s.Script.LangSysRecord[:]:
            l = lr.LangSys
            # Compare d and l
            if len(d.FeatureIndex) != len(l.FeatureIndex):
                continue
            if (d.ReqFeatureIndex == 65535) != (l.ReqFeatureIndex == 65535):
                continue

            if d.ReqFeatureIndex != 65535:
                if features[d.ReqFeatureIndex] != features[l.ReqFeatureIndex]:
                    continue

            for i in range(len(d.FeatureIndex)):
                if features[d.FeatureIndex[i]] != features[l.FeatureIndex[i]]:
                    break
            else:
                # LangSys and default are equal; delete LangSys
                s.Script.LangSysRecord.remove(lr)

def _writeGlyphElement(self, instanceElement, instanceObject, glyphName, data):
    glyphElement = ET.Element("glyph")
    if data.get("mute"):
        glyphElement.attrib["mute"] = "1"
    if data.get("unicodes") is not None:
        glyphElement.attrib["unicode"] = " ".join(
            [hex(u) for u in data.get("unicodes")]
        )
    if data.get("instanceLocation") is not None:
        locationElement, data["instanceLocation"] = self._makeLocationElement(
            data.get("instanceLocation")
        )
        glyphElement.append(locationElement)
    if glyphName is not None:
        glyphElement.attrib["name"] = glyphName
    if data.get("note") is not None:
        noteElement = ET.Element("note")
        noteElement.text = data.get("note")
        glyphElement.append(noteElement)
    if data.get("masters") is not None:
        mastersElement = ET.Element("masters")
        for m in data.get("masters"):
            masterElement = ET.Element("master")
            if m.get("glyphName") is not None:
                masterElement.attrib["glyphname"] = m.get("glyphName")
            if m.get("font") is not None:
                masterElement.attrib["source"] = m.get("font")
            if m.get("location") is not None:
                locationElement, m["location"] = self._makeLocationElement(
                    m.get("location")
                )
                masterElement.append(locationElement)
            mastersElement.append(masterElement)
        glyphElement.append(mastersElement)
    return glyphElement

def _build_path_iterator(path, namespaces, with_prefixes=True):
    """compile selector pattern"""
    if path[-1:] == "/":
        path += "*"  # implicit all (FIXME: keep this?)

    cache_key = (path,)
    if namespaces:
        # lxml originally used None for the default namespace but ElementTree uses the
        # more convenient (all-strings-dict) empty string, so we support both here,
        # preferring the more convenient '', as long as they aren't ambiguous.
        if None in namespaces:
            if '' in namespaces and namespaces[None] != namespaces['']:
                raise ValueError("Ambiguous default namespace provided: %r versus %r" % (
                    namespaces[None], namespaces['']))
            cache_key += (namespaces[None],) + tuple(sorted(
                item for item in namespaces.items() if item[0] is not None))
        else:
            cache_key += tuple(sorted(namespaces.items()))

    try:
        return _cache[cache_key]
    except KeyError:
        pass
    if len(_cache) > 100:
        _cache.clear()

    if path[:1] == "/":
        raise SyntaxError("cannot use absolute path on element")
    stream = iter(xpath_tokenizer(path, namespaces, with_prefixes=with_prefixes))
    try:
        _next = stream.next
    except AttributeError:
        # Python 3
        _next = stream.__next__
    try:
        token = _next()
    except StopIteration:
        raise SyntaxError("empty path expression")
    selector = []
    while 1:
        try:
            selector.append(ops[token[0]](_next, token))
        except StopIteration:
            raise SyntaxError("invalid path")
        try:
            token = _next()
            if token[0] == "/":
                token = _next()
        except StopIteration:
            break
    _cache[cache_key] = selector
    return selector

def param_value(self):
    # This is part of the "handle quoted extended parameters" hack.
    for token in self:
        if token.token_type == 'value':
            return token.stripped_value
        if token.token_type == 'quoted-string':
            for token in token:
                if token.token_type == 'bare-quoted-string':
                    for token in token:
                        if token.token_type == 'value':
                            return token.stripped_value
    return ''

def query_params(self):
    """Return the query parameters for this method."""
    return self.params(['query'])

def _construct_simple(coeffs, opt):
    """Handle simple domains, e.g.: ZZ, QQ, RR and algebraic domains. """
    rationals = floats = complexes = algebraics = False
    float_numbers = []

    if opt.extension is True:
        is_algebraic = lambda coeff: coeff.is_number and coeff.is_algebraic
    else:
        is_algebraic = lambda coeff: False

    for coeff in coeffs:
        if coeff.is_Rational:
            if not coeff.is_Integer:
                rationals = True
        elif coeff.is_Float:
            if algebraics:
                # there are both reals and algebraics -> EX
                return False
            else:
                floats = True
                float_numbers.append(coeff)
        else:
            is_complex = pure_complex(coeff)
            if is_complex:
                complexes = True
                x, y = is_complex
                if x.is_Rational and y.is_Rational:
                    if not (x.is_Integer and y.is_Integer):
                        rationals = True
                    continue
                else:
                    floats = True
                    if x.is_Float:
                        float_numbers.append(x)
                    if y.is_Float:
                        float_numbers.append(y)
            elif is_algebraic(coeff):
                if floats:
                    # there are both algebraics and reals -> EX
                    return False
                algebraics = True
            else:
                # this is a composite domain, e.g. ZZ[X], EX
                return None

    # Use the maximum precision of all coefficients for the RR or CC
    # precision
    max_prec = max(c._prec for c in float_numbers) if float_numbers else 53

    if algebraics:
        domain, result = _construct_algebraic(coeffs, opt)
    else:
        if floats and complexes:
            domain = ComplexField(prec=max_prec)
        elif floats:
            domain = RealField(prec=max_prec)
        elif rationals or opt.field:
            domain = QQ_I if complexes else QQ
        else:
            domain = ZZ_I if complexes else ZZ

        result = [domain.from_sympy(coeff) for coeff in coeffs]

    return domain, result

def __init__(
    self, exprs_arg: typing.Iterable[ParserElement], savelist: bool = True
):
    exprs: List[ParserElement] = list(exprs_arg)
    if exprs and Ellipsis in exprs:
        tmp = []
        for i, expr in enumerate(exprs):
            if expr is Ellipsis:
                if i < len(exprs) - 1:
                    skipto_arg: ParserElement = typing.cast(
                        ParseExpression, (Empty() + exprs[i + 1])
                    ).exprs[-1]
                    tmp.append(SkipTo(skipto_arg)("_skipped*"))
                else:
                    raise Exception(
                        "cannot construct And with sequence ending in ..."
                    )
            else:
                tmp.append(expr)
        exprs[:] = tmp
    super().__init__(exprs, savelist)
    if self.exprs:
        self.mayReturnEmpty = all(e.mayReturnEmpty for e in self.exprs)
        if not isinstance(self.exprs[0], White):
            self.set_whitespace_chars(
                self.exprs[0].whiteChars,
                copy_defaults=self.exprs[0].copyDefaultWhiteChars,
            )
            self.skipWhitespace = self.exprs[0].skipWhitespace
        else:
            self.skipWhitespace = False
    else:
        self.mayReturnEmpty = True
    self.callPreparse = True

def scan_flow_scalar_non_spaces(self, double, start_mark):
    # See the specification for details.
    chunks = []
    while True:
        length = 0
        while self.peek(length) not in '\'\"\\\0 \t\r\n\x85\u2028\u2029':
            length += 1
        if length:
            chunks.append(self.prefix(length))
            self.forward(length)
        ch = self.peek()
        if not double and ch == '\'' and self.peek(1) == '\'':
            chunks.append('\'')
            self.forward(2)
        elif (double and ch == '\'') or (not double and ch in '\"\\'):
            chunks.append(ch)
            self.forward()
        elif double and ch == '\\':
            self.forward()
            ch = self.peek()
            if ch in self.ESCAPE_REPLACEMENTS:
                chunks.append(self.ESCAPE_REPLACEMENTS[ch])
                self.forward()
            elif ch in self.ESCAPE_CODES:
                length = self.ESCAPE_CODES[ch]
                self.forward()
                for k in range(length):
                    if self.peek(k) not in '0123456789ABCDEFabcdef':
                        raise ScannerError("while scanning a double-quoted scalar", start_mark,
                                "expected escape sequence of %d hexadecimal numbers, but found %r" %
                                    (length, self.peek(k)), self.get_mark())
                code = int(self.prefix(length), 16)
                chunks.append(chr(code))
                self.forward(length)
            elif ch in '\r\n\x85\u2028\u2029':
                self.scan_line_break()
                chunks.extend(self.scan_flow_scalar_breaks(double, start_mark))
            else:
                raise ScannerError("while scanning a double-quoted scalar", start_mark,
                        "found unknown escape character %r" % ch, self.get_mark())
        else:
            return chunks

def f(rv):
    if not (rv.is_Add or rv.is_Mul or rv.is_Pow):
        return rv

    n, d = rv.as_numer_denom()
    if not d.args or not n.args:
        return rv

    dok = {}

    def ok(di):
        m = as_f_sign_1(di)
        if m:
            g, f, s = m
            if s is S.NegativeOne and f.is_Mul and len(f.args) == 2 and \
                    all(isinstance(fi, tan) for fi in f.args):
                return g, f

    d_args = list(Mul.make_args(d))
    for i, di in enumerate(d_args):
        m = ok(di)
        if m:
            g, t = m
            s = Add(*[_.args[0] for _ in t.args])
            dok[s] = S.One
            d_args[i] = g
            continue
        if di.is_Add:
            di = factor(di)
            if di.is_Mul:
                d_args.extend(di.args)
                d_args[i] = S.One
        elif di.is_Pow and (di.exp.is_integer or di.base.is_positive):
            m = ok(di.base)
            if m:
                g, t = m
                s = Add(*[_.args[0] for _ in t.args])
                dok[s] = di.exp
                d_args[i] = g**di.exp
            else:
                di = factor(di)
                if di.is_Mul:
                    d_args.extend(di.args)
                    d_args[i] = S.One
    if not dok:
        return rv

    def ok(ni):
        if ni.is_Add and len(ni.args) == 2:
            a, b = ni.args
            if isinstance(a, tan) and isinstance(b, tan):
                return a, b
    n_args = list(Mul.make_args(factor_terms(n)))
    hit = False
    for i, ni in enumerate(n_args):
        m = ok(ni)
        if not m:
            m = ok(-ni)
            if m:
                n_args[i] = S.NegativeOne
            else:
                if ni.is_Add:
                    ni = factor(ni)
                    if ni.is_Mul:
                        n_args.extend(ni.args)
                        n_args[i] = S.One
                    continue
                elif ni.is_Pow and (
                        ni.exp.is_integer or ni.base.is_positive):
                    m = ok(ni.base)
                    if m:
                        n_args[i] = S.One
                    else:
                        ni = factor(ni)
                        if ni.is_Mul:
                            n_args.extend(ni.args)
                            n_args[i] = S.One
                        continue
                else:
                    continue
        else:
            n_args[i] = S.One
        hit = True
        s = Add(*[_.args[0] for _ in m])
        ed = dok[s]
        newed = ed.extract_additively(S.One)
        if newed is not None:
            if newed:
                dok[s] = newed
            else:
                dok.pop(s)
        n_args[i] *= -tan(s)

    if hit:
        rv = Mul(*n_args)/Mul(*d_args)/Mul(*[(Add(*[
            tan(a) for a in i.args]) - 1)**e for i, e in dok.items()])

    return rv

def _simpsol(soleq):
    lhs = soleq.lhs
    sol = soleq.rhs
    sol = powsimp(sol)
    gens = list(sol.atoms(exp))
    p = Poly(sol, *gens, expand=False)
    gens = [factor_terms(g) for g in gens]
    if not gens:
        gens = p.gens
    syms = [Symbol('C1'), Symbol('C2')]
    terms = []
    for coeff, monom in zip(p.coeffs(), p.monoms()):
        coeff = piecewise_fold(coeff)
        if isinstance(coeff, Piecewise):
            coeff = Piecewise(*((ratsimp(coef).collect(syms), cond) for coef, cond in coeff.args))
        else:
            coeff = ratsimp(coeff).collect(syms)
        monom = Mul(*(g ** i for g, i in zip(gens, monom)))
        terms.append(coeff * monom)
    return Eq(lhs, Add(*terms))

def check_directive(self):

    # DIRECTIVE:        ^ '%' ...
    # The '%' indicator is already checked.
    if self.column == 0:
        return True

def ensure_str(s, encoding='utf-8', errors='strict'):
    """Coerce *s* to `str`.

    For Python 2:
      - `unicode` -> encoded to `str`
      - `str` -> `str`

    For Python 3:
      - `str` -> `str`
      - `bytes` -> decoded to `str`
    """
    # Optimization: Fast return for the common case.
    if type(s) is str:
        return s
    if PY2 and isinstance(s, text_type):
        return s.encode(encoding, errors)
    elif PY3 and isinstance(s, binary_type):
        return s.decode(encoding, errors)
    elif not isinstance(s, (text_type, binary_type)):
        raise TypeError("not expecting type '%s'" % type(s))
    return s

def _options(self):
    if self._name != self._parser.default_section:
        return self._parser.options(self._name)
    else:
        return self._parser.defaults()

def parseImpl(self, instring, loc, doActions=True):
    notchars = self.notCharsSet
    if instring[loc] in notchars:
        raise ParseException(instring, loc, self.errmsg, self)

    start = loc
    loc += 1
    maxlen = min(start + self.maxLen, len(instring))
    while loc < maxlen and instring[loc] not in notchars:
        loc += 1

    if loc - start < self.minLen:
        raise ParseException(instring, loc, self.errmsg, self)

    return loc, instring[start:loc]

def __mul__(p1, p2):
    """Multiply two polynomials.

    Examples
    ========

    >>> from sympy.polys.domains import QQ
    >>> from sympy.polys.rings import ring

    >>> _, x, y = ring('x, y', QQ)
    >>> p1 = x + y
    >>> p2 = x - y
    >>> p1*p2
    x**2 - y**2

    """
    ring = p1.ring
    p = ring.zero
    if not p1 or not p2:
        return p
    elif ring.is_element(p2):
        get = p.get
        zero = ring.domain.zero
        monomial_mul = ring.monomial_mul
        p2it = list(p2.items())
        for exp1, v1 in p1.items():
            for exp2, v2 in p2it:
                exp = monomial_mul(exp1, exp2)
                p[exp] = get(exp, zero) + v1*v2
        p.strip_zero()
        # p._check()
        return p
    elif isinstance(p2, PolyElement):
        if isinstance(ring.domain, PolynomialRing) and ring.domain.ring == p2.ring:
            pass
        elif isinstance(p2.ring.domain, PolynomialRing) and p2.ring.domain.ring == ring:
            return p2.__rmul__(p1)
        else:
            return NotImplemented

    try:
        p2 = ring.domain_new(p2)
    except CoercionFailed:
        return NotImplemented
    else:
        for exp1, v1 in p1.items():
            v = v1*p2
            if v:
                p[exp1] = v
        # p._check()
        return p

def __mul__(self, other) -> "ParserElement":
    """
    Implementation of ``*`` operator, allows use of ``expr * 3`` in place of
    ``expr + expr + expr``.  Expressions may also be multiplied by a 2-integer
    tuple, similar to ``{min, max}`` multipliers in regular expressions.  Tuples
    may also include ``None`` as in:

    - ``expr*(n, None)`` or ``expr*(n, )`` is equivalent
      to ``expr*n + ZeroOrMore(expr)``
      (read as "at least n instances of ``expr``")
    - ``expr*(None, n)`` is equivalent to ``expr*(0, n)``
      (read as "0 to n instances of ``expr``")
    - ``expr*(None, None)`` is equivalent to ``ZeroOrMore(expr)``
    - ``expr*(1, None)`` is equivalent to ``OneOrMore(expr)``

    Note that ``expr*(None, n)`` does not raise an exception if
    more than n exprs exist in the input stream; that is,
    ``expr*(None, n)`` does not enforce a maximum number of expr
    occurrences.  If this behavior is desired, then write
    ``expr*(None, n) + ~expr``
    """
    if other is Ellipsis:
        other = (0, None)
    elif isinstance(other, tuple) and other[:1] == (Ellipsis,):
        other = ((0,) + other[1:] + (None,))[:2]

    if isinstance(other, int):
        minElements, optElements = other, 0
    elif isinstance(other, tuple):
        other = tuple(o if o is not Ellipsis else None for o in other)
        other = (other + (None, None))[:2]
        if other[0] is None:
            other = (0, other[1])
        if isinstance(other[0], int) and other[1] is None:
            if other[0] == 0:
                return ZeroOrMore(self)
            if other[0] == 1:
                return OneOrMore(self)
            else:
                return self * other[0] + ZeroOrMore(self)
        elif isinstance(other[0], int) and isinstance(other[1], int):
            minElements, optElements = other
            optElements -= minElements
        else:
            return NotImplemented
    else:
        return NotImplemented

    if minElements < 0:
        raise ValueError("cannot multiply ParserElement by negative value")
    if optElements < 0:
        raise ValueError(
            "second tuple value must be greater or equal to first tuple value"
        )
    if minElements == optElements == 0:
        return And([])

    if optElements:

        def makeOptionalList(n):
            if n > 1:
                return Opt(self + makeOptionalList(n - 1))
            else:
                return Opt(self)

        if minElements:
            if minElements == 1:
                ret = self + makeOptionalList(optElements)
            else:
                ret = And([self] * minElements) + makeOptionalList(optElements)
        else:
            ret = makeOptionalList(optElements)
    else:
        if minElements == 1:
            ret = self
        else:
            ret = And([self] * minElements)
    return ret

def urlunsplit(components):
    """Combine the elements of a tuple as returned by urlsplit() into a
    complete URL as a string. The data argument can be any five-item iterable.
    This may result in a slightly different, but equivalent URL, if the URL that
    was parsed originally had unnecessary delimiters (for example, a ? with an
    empty query; the RFC states that these are equivalent)."""
    scheme, netloc, url, query, fragment, _coerce_result = (
                                          _coerce_args(*components))
    if netloc or (scheme and scheme in uses_netloc and url[:2] != '//'):
        if url and url[:1] != '/': url = '/' + url
        url = '//' + (netloc or '') + url
    if scheme:
        url = scheme + ':' + url
    if query:
        url = url + '?' + query
    if fragment:
        url = url + '#' + fragment
    return _coerce_result(url)

def _to_unicode(string):
  if sys.version < '3':
    return string.encode('utf-8')
  else:
    return string

def process_common_addends(rv, do, key2=None, key1=True):
    """Apply ``do`` to addends of ``rv`` that (if ``key1=True``) share at least
    a common absolute value of their coefficient and the value of ``key2`` when
    applied to the argument. If ``key1`` is False ``key2`` must be supplied and
    will be the only key applied.
    """

    # collect by absolute value of coefficient and key2
    absc = defaultdict(list)
    if key1:
        for a in rv.args:
            c, a = a.as_coeff_Mul()
            if c < 0:
                c = -c
                a = -a  # put the sign on `a`
            absc[(c, key2(a) if key2 else 1)].append(a)
    elif key2:
        for a in rv.args:
            absc[(S.One, key2(a))].append(a)
    else:
        raise ValueError('must have at least one key')

    args = []
    hit = False
    for k in absc:
        v = absc[k]
        c, _ = k
        if len(v) > 1:
            e = Add(*v, evaluate=False)
            new = do(e)
            if new != e:
                e = new
                hit = True
            args.append(c*e)
        else:
            args.append(c*v[0])
    if hit:
        rv = Add(*args)

    return rv

def subset_glyphs(self, s):
    if self.Format == 1:
        indices = self.Coverage.subset(s.glyphs)
        pairs = self.PairSet
        count = len(pairs)
        self.PairSet = [pairs[i] for i in indices if i < count]
        for p in self.PairSet:
            p.PairValueRecord = [
                r for r in p.PairValueRecord if r.SecondGlyph in s.glyphs
            ]
            p.PairValueCount = len(p.PairValueRecord)
        # Remove empty pairsets
        indices = [i for i, p in enumerate(self.PairSet) if p.PairValueCount]
        self.Coverage.remap(indices)
        self.PairSet = _list_subset(self.PairSet, indices)
        self.PairSetCount = len(self.PairSet)
        return bool(self.PairSetCount)
    elif self.Format == 2:
        class1_map = [
            c
            for c in self.ClassDef1.subset(
                s.glyphs.intersection(self.Coverage.glyphs), remap=True
            )
            if c < self.Class1Count
        ]
        class2_map = [
            c
            for c in self.ClassDef2.subset(s.glyphs, remap=True, useClass0=False)
            if c < self.Class2Count
        ]
        self.Class1Record = [self.Class1Record[i] for i in class1_map]
        for c in self.Class1Record:
            c.Class2Record = [c.Class2Record[i] for i in class2_map]
        self.Class1Count = len(class1_map)
        self.Class2Count = len(class2_map)
        # If only Class2 0 left, no need to keep anything.
        return bool(
            self.Class1Count
            and (self.Class2Count > 1)
            and self.Coverage.subset(s.glyphs)
        )
    else:
        assert 0, "unknown format: %s" % self.Format

def _gens(self):
    """Return a list of polynomial generators. """
    one = self.domain.one
    _gens = []
    for i in range(self.ngens):
        expv = self.monomial_basis(i)
        poly = self.zero
        poly[expv] = one
        _gens.append(poly)
    return tuple(_gens)

def _check_if_there_are_closed_cycles(cls, expr, permutation):
    args = list(expr.args)
    subranks = expr.subranks
    cyclic_form = permutation.cyclic_form
    cumulative_subranks = [0] + list(accumulate(subranks))
    cyclic_min = [min(i) for i in cyclic_form]
    cyclic_max = [max(i) for i in cyclic_form]
    cyclic_keep = []
    for i, cycle in enumerate(cyclic_form):
        flag = True
        for j in range(len(cumulative_subranks) - 1):
            if cyclic_min[i] >= cumulative_subranks[j] and cyclic_max[i] < cumulative_subranks[j+1]:
                # Found a sinkable cycle.
                args[j] = _permute_dims(args[j], Permutation([[k - cumulative_subranks[j] for k in cycle]]))
                flag = False
                break
        if flag:
            cyclic_keep.append(cycle)
    return _array_tensor_product(*args), Permutation(cyclic_keep, size=permutation.size)

def prune_post_subset(self, font, options):
    visitor = NameRecordVisitor()
    visitor.visit(font)
    nameIDs = set(options.name_IDs) | visitor.seen
    if "*" in options.name_IDs:
        nameIDs |= {n.nameID for n in self.names if n.nameID < 256}
    self.names = [n for n in self.names if n.nameID in nameIDs]
    if not options.name_legacy:
        # TODO(behdad) Sometimes (eg Apple Color Emoji) there's only a macroman
        # entry for Latin and no Unicode names.
        self.names = [n for n in self.names if n.isUnicode()]
    # TODO(behdad) Option to keep only one platform's
    if "*" not in options.name_languages:
        # TODO(behdad) This is Windows-platform specific!
        self.names = [n for n in self.names if n.langID in options.name_languages]
    if options.obfuscate_names:
        namerecs = []
        # Preserve names to be scrambled or dropped elsewhere so that other
        # parts of the font don't break.
        needRemapping = visitor.seen.intersection(NAME_IDS_TO_OBFUSCATE)
        if needRemapping:
            _remap_select_name_ids(font, needRemapping)
        for n in self.names:
            if n.nameID in [1, 4]:
                n.string = ".\x7f".encode("utf_16_be") if n.isUnicode() else ".\x7f"
            elif n.nameID in [2, 6]:
                n.string = "\x7f".encode("utf_16_be") if n.isUnicode() else "\x7f"
            elif n.nameID == 3:
                n.string = ""
            elif n.nameID in [16, 17, 18]:
                continue
            namerecs.append(n)
        self.names = namerecs
    return True  # Required table

def to_tree(self, tagname=None, value=None, namespace=None):
    namespace = getattr(self, "namespace", namespace)
    if value is not None:
        if namespace is not None:
            tagname = "{%s}%s" % (namespace, tagname)
        el = Element(tagname)
        el.text = safe_string(value)
        whitespace(el)
        return el

def _parse_symbols(symbols):
    if isinstance(symbols, str):
        return _symbols(symbols, seq=True) if symbols else ()
    elif isinstance(symbols, Expr):
        return (symbols,)
    elif is_sequence(symbols):
        if all(isinstance(s, str) for s in symbols):
            return _symbols(symbols)
        elif all(isinstance(s, Expr) for s in symbols):
            return symbols

    raise GeneratorsError("expected a string, Symbol or expression or a non-empty sequence of strings, Symbols or expressions")

def _eval_real_imag(self, real):
    zero = False
    t_not_re_im = None

    for t in self.args:
        if (t.is_complex or t.is_infinite) is False and t.is_extended_real is False:
            return False
        elif t.is_imaginary:  # I
            real = not real
        elif t.is_extended_real:  # 2
            if not zero:
                z = t.is_zero
                if not z and zero is False:
                    zero = z
                elif z:
                    if all(a.is_finite for a in self.args):
                        return True
                    return
        elif t.is_extended_real is False:
            # symbolic or literal like `2 + I` or symbolic imaginary
            if t_not_re_im:
                return  # complex terms might cancel
            t_not_re_im = t
        elif t.is_imaginary is False:  # symbolic like `2` or `2 + I`
            if t_not_re_im:
                return  # complex terms might cancel
            t_not_re_im = t
        else:
            return

    if t_not_re_im:
        if t_not_re_im.is_extended_real is False:
            if real:  # like 3
                return zero  # 3*(smthng like 2 + I or i) is not real
        if t_not_re_im.is_imaginary is False:  # symbolic 2 or 2 + I
            if not real:  # like I
                return zero  # I*(smthng like 2 or 2 + I) is not real
    elif zero is False:
        return real  # can't be trumped by 0
    elif real:
        return real  # doesn't matter what zero is

def memoized_rl(expr: _S) -> _T:
    if expr in cache:
        return cache[expr]
    else:
        result = rule(expr)
        cache[expr] = result
        return result

def __init__(self, constraint, x0):
    self.constraint = constraint

    if isinstance(constraint, NonlinearConstraint):
        def fun(x):
            x = np.asarray(x)
            return np.atleast_1d(constraint.fun(x))
    elif isinstance(constraint, LinearConstraint):
        def fun(x):
            if issparse(constraint.A):
                A = constraint.A
            else:
                A = np.atleast_2d(constraint.A)

            res = A.dot(x)
            # x either has shape (N, S) or (N)
            # (M, N) x (N, S) --> (M, S)
            # (M, N) x (N,)   --> (M,)
            # However, if (M, N) is a matrix then:
            # (M, N) * (N,)   --> (M, 1), we need this to be (M,)
            if x.ndim == 1 and res.ndim == 2:
                # deal with case that constraint.A is an np.matrix
                # see gh20041
                res = np.asarray(res)[:, 0]

            return res
    elif isinstance(constraint, Bounds):
        def fun(x):
            return np.asarray(x)
    else:
        raise ValueError("`constraint` of an unknown type is passed.")

    self.fun = fun

    lb = np.asarray(constraint.lb, dtype=float)
    ub = np.asarray(constraint.ub, dtype=float)

    x0 = np.asarray(x0)

    # find out the number of constraints
    f0 = fun(x0)
    self.num_constr = m = f0.size
    self.parameter_count = x0.size

    if lb.ndim == 0:
        lb = np.resize(lb, m)
    if ub.ndim == 0:
        ub = np.resize(ub, m)

    self.bounds = (lb, ub)

def clean_forms(
    elt: DictionaryObject, stack: List[DictionaryObject]
) -> Tuple[List[str], List[str]]:
    nonlocal to_delete
    # elt in recursive call is a new ContentStream object, so we have to check the indirect_reference
    if (elt in stack) or (
        hasattr(elt, "indirect_reference")
        and any(
            elt.indirect_reference == getattr(x, "indirect_reference", -1)
            for x in stack
        )
    ):
        # to prevent infinite looping
        return [], []  # pragma: no cover
    try:
        d = cast(
            Dict[Any, Any],
            cast(DictionaryObject, elt["/Resources"])["/XObject"],
        )
    except KeyError:
        d = {}
    images = []
    forms = []
    for k, v in d.items():
        o = v.get_object()
        try:
            content: Any = None
            if (
                to_delete & ObjectDeletionFlag.XOBJECT_IMAGES
                and o["/Subtype"] == "/Image"
            ):
                content = NullObject()  # to delete the image keeping the entry
                images.append(k)
            if o["/Subtype"] == "/Form":
                forms.append(k)
                if isinstance(o, ContentStream):
                    content = o
                else:
                    content = ContentStream(o, self)
                    content.update(
                        {
                            k1: v1
                            for k1, v1 in o.items()
                            if k1 not in ["/Length", "/Filter", "/DecodeParms"]
                        }
                    )
                    try:
                        content.indirect_reference = o.indirect_reference
                    except AttributeError:  # pragma: no cover
                        pass
                stack.append(elt)
                clean_forms(content, stack)  # clean subforms
            if content is not None:
                if isinstance(v, IndirectObject):
                    self._objects[v.idnum - 1] = content
                else:
                    # should only occur in a PDF not respecting PDF spec
                    # where streams must be indirected.
                    d[k] = self._add_object(content)  # pragma: no cover
        except (TypeError, KeyError):
            pass
    for im in images:
        del d[im]  # for clean-up
    if isinstance(elt, StreamObject):  # for /Form
        if not isinstance(elt, ContentStream):  # pragma: no cover
            e = ContentStream(elt, self)
            e.update(elt.items())
            elt = e
        clean(elt, images, forms, text_filters)  # clean the content
    return images, forms

def parseImpl(self, instring, loc, doActions=True):
    result = (
        instring[loc] == self.firstQuoteChar
        and self.re_match(instring, loc)
        or None
    )
    if not result:
        raise ParseException(instring, loc, self.errmsg, self)

    loc = result.end()
    ret = result.group()

    if self.unquoteResults:
        # strip off quotes
        ret = ret[self.quoteCharLen : -self.endQuoteCharLen]

        if isinstance(ret, str_type):
            if self.convertWhitespaceEscapes:
                ret = "".join(
                    self.ws_map[match.group(1)]
                    if match.group(1)
                    else match.group(2)[-1]
                    if match.group(2)
                    else match.group(3)
                    for match in self.unquote_scan_re.finditer(ret)
                )
            else:
                ret = "".join(
                    match.group(1)[-1] if match.group(1) else match.group(2)
                    for match in self.unquote_scan_re.finditer(ret)
                )

            # replace escaped quotes
            if self.escQuote:
                ret = ret.replace(self.escQuote, self.endQuoteChar)

    return loc, ret

def get_by_attribute_text_selector(
    attr_name: str, text: Union[str, Pattern[str]], exact: bool = None
) -> str:
    return f"internal:attr=[{attr_name}={escape_for_attribute_selector(text, exact=exact)}]"

def _try_cast(
    arr: list | np.ndarray,
    dtype: np.dtype,
    copy: bool,
) -> ArrayLike:
    """
    Convert input to numpy ndarray and optionally cast to a given dtype.

    Parameters
    ----------
    arr : ndarray or list
        Excludes: ExtensionArray, Series, Index.
    dtype : np.dtype
    copy : bool
        If False, don't copy the data if not needed.

    Returns
    -------
    np.ndarray or ExtensionArray
    """
    is_ndarray = isinstance(arr, np.ndarray)

    if dtype == object:
        if not is_ndarray:
            subarr = construct_1d_object_array_from_listlike(arr)
            return subarr
        return ensure_wrapped_if_datetimelike(arr).astype(dtype, copy=copy)

    elif dtype.kind == "U":
        # TODO: test cases with arr.dtype.kind in "mM"
        if is_ndarray:
            arr = cast(np.ndarray, arr)
            shape = arr.shape
            if arr.ndim > 1:
                arr = arr.ravel()
        else:
            shape = (len(arr),)
        return lib.ensure_string_array(arr, convert_na_value=False, copy=copy).reshape(
            shape
        )

    elif dtype.kind in "mM":
        if is_ndarray:
            arr = cast(np.ndarray, arr)
            if arr.ndim == 2 and arr.shape[1] == 1:
                # GH#60081: DataFrame Constructor converts 1D data to array of
                # shape (N, 1), but maybe_cast_to_datetime assumes 1D input
                return maybe_cast_to_datetime(arr[:, 0], dtype).reshape(arr.shape)
        return maybe_cast_to_datetime(arr, dtype)

    # GH#15832: Check if we are requesting a numeric dtype and
    # that we can convert the data to the requested dtype.
    elif dtype.kind in "iu":
        # this will raise if we have e.g. floats

        subarr = maybe_cast_to_integer_array(arr, dtype)
    elif not copy:
        subarr = np.asarray(arr, dtype=dtype)
    else:
        subarr = np.array(arr, dtype=dtype, copy=copy)

    return subarr

def collect_type_table(self):
    self._typesdict = {}
    self._generate("collecttype")
    #
    all_decls = sorted(self._typesdict, key=str)
    #
    # prepare all FUNCTION bytecode sequences first
    self.cffi_types = []
    for tp in all_decls:
        if tp.is_raw_function:
            assert self._typesdict[tp] is None
            self._typesdict[tp] = len(self.cffi_types)
            self.cffi_types.append(tp)     # placeholder
            for tp1 in tp.args:
                assert isinstance(tp1, (model.VoidType,
                                        model.BasePrimitiveType,
                                        model.PointerType,
                                        model.StructOrUnionOrEnum,
                                        model.FunctionPtrType))
                if self._typesdict[tp1] is None:
                    self._typesdict[tp1] = len(self.cffi_types)
                self.cffi_types.append(tp1)   # placeholder
            self.cffi_types.append('END')     # placeholder
    #
    # prepare all OTHER bytecode sequences
    for tp in all_decls:
        if not tp.is_raw_function and self._typesdict[tp] is None:
            self._typesdict[tp] = len(self.cffi_types)
            self.cffi_types.append(tp)        # placeholder
            if tp.is_array_type and tp.length is not None:
                self.cffi_types.append('LEN') # placeholder
    assert None not in self._typesdict.values()
    #
    # collect all structs and unions and enums
    self._struct_unions = {}
    self._enums = {}
    for tp in all_decls:
        if isinstance(tp, model.StructOrUnion):
            self._struct_unions[tp] = None
        elif isinstance(tp, model.EnumType):
            self._enums[tp] = None
    for i, tp in enumerate(sorted(self._struct_unions,
                                  key=lambda tp: tp.name)):
        self._struct_unions[tp] = i
    for i, tp in enumerate(sorted(self._enums,
                                  key=lambda tp: tp.name)):
        self._enums[tp] = i
    #
    # emit all bytecode sequences now
    for tp in all_decls:
        method = getattr(self, '_emit_bytecode_' + tp.__class__.__name__)
        method(tp, self._typesdict[tp])
    #
    # consistency check
    for op in self.cffi_types:
        assert isinstance(op, CffiOp)
    self.cffi_types = tuple(self.cffi_types)    # don't change any more

def xml(self) -> str:
    """Return XML string for this element, suitable for testing purposes.

    Pretty printed for readability and without an XML declaration at the top.
    """
    return serialize_for_reading(self)

def _edge_value(G, edge_attr):
    """Returns a function that returns a value from G[u][v].

    Suppose there exists an edge between u and v.  Then we return a function
    expecting u and v as arguments.  For Graph and DiGraph, G[u][v] is
    the edge attribute dictionary, and the function (essentially) returns
    G[u][v][edge_attr].  However, we also handle cases when `edge_attr` is None
    and when it is a function itself. For MultiGraph and MultiDiGraph, G[u][v]
    is a dictionary of all edges between u and v.  In this case, the returned
    function sums the value of `edge_attr` for every edge between u and v.

    Parameters
    ----------
    G : graph
       A NetworkX graph

    edge_attr : {None, str, callable}
        Specification of how the value of the edge attribute should be obtained
        from the edge attribute dictionary, G[u][v].  For multigraphs, G[u][v]
        is a dictionary of all the edges between u and v.  This allows for
        special treatment of multiedges.

    Returns
    -------
    value : function
        A function expecting two nodes as parameters. The nodes should
        represent the from- and to- node of an edge. The function will
        return a value from G[u][v] that depends on `edge_attr`.

    """

    if edge_attr is None:
        # topological count of edges

        if G.is_multigraph():

            def value(u, v):
                return len(G[u][v])

        else:

            def value(u, v):
                return 1

    elif not callable(edge_attr):
        # assume it is a key for the edge attribute dictionary

        if edge_attr == "weight":
            # provide a default value
            if G.is_multigraph():

                def value(u, v):
                    return sum(d.get(edge_attr, 1) for d in G[u][v].values())

            else:

                def value(u, v):
                    return G[u][v].get(edge_attr, 1)

        else:
            # otherwise, the edge attribute MUST exist for each edge
            if G.is_multigraph():

                def value(u, v):
                    return sum(d[edge_attr] for d in G[u][v].values())

            else:

                def value(u, v):
                    return G[u][v][edge_attr]

    else:
        # Advanced:  Allow users to specify something else.
        #
        # Alternative default value:
        #     edge_attr = lambda u,v: G[u][v].get('thickness', .5)
        #
        # Function on an attribute:
        #     edge_attr = lambda u,v: abs(G[u][v]['weight'])
        #
        # Handle Multi(Di)Graphs differently:
        #     edge_attr = lambda u,v: numpy.prod([d['size'] for d in G[u][v].values()])
        #
        # Ignore multiple edges
        #     edge_attr = lambda u,v: 1 if len(G[u][v]) else 0
        #
        value = edge_attr

    return value

def get_domain(value):
    """ domain = dot-atom / domain-literal / obs-domain
        obs-domain = atom *("." atom))

    """
    domain = Domain()
    leader = None
    if value[0] in CFWS_LEADER:
        leader, value = get_cfws(value)
    if not value:
        raise errors.HeaderParseError(
            "expected domain but found '{}'".format(value))
    if value[0] == '[':
        token, value = get_domain_literal(value)
        if leader is not None:
            token[:0] = [leader]
        domain.append(token)
        return domain, value
    try:
        token, value = get_dot_atom(value)
    except errors.HeaderParseError:
        token, value = get_atom(value)
    if value and value[0] == '@':
        raise errors.HeaderParseError('Invalid Domain')
    if leader is not None:
        token[:0] = [leader]
    domain.append(token)
    if value and value[0] == '.':
        domain.defects.append(errors.ObsoleteHeaderDefect(
            "domain is not a dot-atom (contains CFWS)"))
        if domain[0].token_type == 'dot-atom':
            domain[:] = domain[0]
        while value and value[0] == '.':
            domain.append(DOT)
            token, value = get_atom(value[1:])
            domain.append(token)
    return domain, value

def print_(*args, **kwargs):
    """The new-style print function for Python 2.4 and 2.5."""
    fp = kwargs.pop("file", sys.stdout)
    if fp is None:
        return

    def write(data):
        if not isinstance(data, basestring):
            data = str(data)
        # If the file has an encoding, encode unicode with it.
        if (isinstance(fp, file) and
                isinstance(data, unicode) and
                fp.encoding is not None):
            errors = getattr(fp, "errors", None)
            if errors is None:
                errors = "strict"
            data = data.encode(fp.encoding, errors)
        fp.write(data)
    want_unicode = False
    sep = kwargs.pop("sep", None)
    if sep is not None:
        if isinstance(sep, unicode):
            want_unicode = True
        elif not isinstance(sep, str):
            raise TypeError("sep must be None or a string")
    end = kwargs.pop("end", None)
    if end is not None:
        if isinstance(end, unicode):
            want_unicode = True
        elif not isinstance(end, str):
            raise TypeError("end must be None or a string")
    if kwargs:
        raise TypeError("invalid keyword arguments to print()")
    if not want_unicode:
        for arg in args:
            if isinstance(arg, unicode):
                want_unicode = True
                break
    if want_unicode:
        newline = unicode("\n")
        space = unicode(" ")
    else:
        newline = "\n"
        space = " "
    if sep is None:
        sep = space
    if end is None:
        end = newline
    for i, arg in enumerate(args):
        if i:
            write(sep)
        write(arg)
    write(end)

def __new__(cls, shape, dtype=None, buf=None, offset=0, strides=None,
            formats=None, names=None, titles=None,
            byteorder=None, aligned=False,
            mask=ma.nomask, hard_mask=False, fill_value=None, keep_mask=True,
            copy=False,
            **options):

    self = np.recarray.__new__(cls, shape, dtype=dtype, buf=buf, offset=offset,
                               strides=strides, formats=formats, names=names,
                               titles=titles, byteorder=byteorder,
                               aligned=aligned,)

    mdtype = ma.make_mask_descr(self.dtype)
    if mask is ma.nomask or not np.size(mask):
        if not keep_mask:
            self._mask = tuple([False] * len(mdtype))
    else:
        mask = np.array(mask, copy=copy)
        if mask.shape != self.shape:
            (nd, nm) = (self.size, mask.size)
            if nm == 1:
                mask = np.resize(mask, self.shape)
            elif nm == nd:
                mask = np.reshape(mask, self.shape)
            else:
                msg = (f"Mask and data not compatible: data size is {nd},"
                       " mask size is {nm}.")
                raise ma.MAError(msg)
        if not keep_mask:
            self.__setmask__(mask)
            self._sharedmask = True
        else:
            if mask.dtype == mdtype:
                _mask = mask
            else:
                _mask = np.array([tuple([m] * len(mdtype)) for m in mask],
                                 dtype=mdtype)
            self._mask = _mask
    return self

def parse(self):
    """Parse the file, and return a :class:`fontTools.feaLib.ast.FeatureFile`
    object representing the root of the abstract syntax tree containing the
    parsed contents of the file."""
    statements = self.doc_.statements
    while self.next_token_type_ is not None or self.cur_comments_:
        self.advance_lexer_(comments=True)
        if self.cur_token_type_ is Lexer.COMMENT:
            statements.append(
                self.ast.Comment(self.cur_token_, location=self.cur_token_location_)
            )
        elif self.is_cur_keyword_("include"):
            statements.append(self.parse_include_())
        elif self.cur_token_type_ is Lexer.GLYPHCLASS:
            statements.append(self.parse_glyphclass_definition_())
        elif self.is_cur_keyword_(("anon", "anonymous")):
            statements.append(self.parse_anonymous_())
        elif self.is_cur_keyword_("anchorDef"):
            statements.append(self.parse_anchordef_())
        elif self.is_cur_keyword_("languagesystem"):
            statements.append(self.parse_languagesystem_())
        elif self.is_cur_keyword_("lookup"):
            statements.append(self.parse_lookup_(vertical=False))
        elif self.is_cur_keyword_("markClass"):
            statements.append(self.parse_markClass_())
        elif self.is_cur_keyword_("feature"):
            statements.append(self.parse_feature_block_())
        elif self.is_cur_keyword_("conditionset"):
            statements.append(self.parse_conditionset_())
        elif self.is_cur_keyword_("variation"):
            statements.append(self.parse_feature_block_(variation=True))
        elif self.is_cur_keyword_("table"):
            statements.append(self.parse_table_())
        elif self.is_cur_keyword_("valueRecordDef"):
            statements.append(self.parse_valuerecord_definition_(vertical=False))
        elif (
            self.cur_token_type_ is Lexer.NAME
            and self.cur_token_ in self.extensions
        ):
            statements.append(self.extensions[self.cur_token_](self))
        elif self.cur_token_type_ is Lexer.SYMBOL and self.cur_token_ == ";":
            continue
        else:
            raise FeatureLibError(
                "Expected feature, languagesystem, lookup, markClass, "
                'table, or glyph class definition, got {} "{}"'.format(
                    self.cur_token_type_, self.cur_token_
                ),
                self.cur_token_location_,
            )
    # Report any missing glyphs at the end of parsing
    if self.missing:
        error = [
            " %s (first found at %s)" % (name, loc)
            for name, loc in self.missing.items()
        ]
        raise FeatureLibError(
            "The following glyph names are referenced but are missing from the "
            "glyph set:\n" + ("\n".join(error)),
            None,
        )
    return self.doc_

def addpackage(sitedir, name, known_paths):
    """Process a .pth file within the site-packages directory:
       For each line in the file, either combine it with sitedir to a path
       and add that to known_paths, or execute it if it starts with 'import '.
    """
    if known_paths is None:
        known_paths = _init_pathinfo()
        reset = True
    else:
        reset = False
    fullname = os.path.join(sitedir, name)
    try:
        st = os.lstat(fullname)
    except OSError:
        return
    if ((getattr(st, 'st_flags', 0) & stat.UF_HIDDEN) or
        (getattr(st, 'st_file_attributes', 0) & stat.FILE_ATTRIBUTE_HIDDEN)):
        _trace(f"Skipping hidden .pth file: {fullname!r}")
        return
    _trace(f"Processing .pth file: {fullname!r}")
    try:
        # locale encoding is not ideal especially on Windows. But we have used
        # it for a long time. setuptools uses the locale encoding too.
        f = io.TextIOWrapper(io.open_code(fullname), encoding="locale")
    except OSError:
        return
    with f:
        for n, line in enumerate(f):
            if line.startswith("#"):
                continue
            if line.strip() == "":
                continue
            try:
                if line.startswith(("import ", "import\t")):
                    exec(line)
                    continue
                line = line.rstrip()
                dir, dircase = makepath(sitedir, line)
                if not dircase in known_paths and os.path.exists(dir):
                    sys.path.append(dir)
                    known_paths.add(dircase)
            except Exception as exc:
                print("Error processing line {:d} of {}:\n".format(n+1, fullname),
                      file=sys.stderr)
                import traceback
                for record in traceback.format_exception(exc):
                    for line in record.splitlines():
                        print('  '+line, file=sys.stderr)
                print("\nRemainder of file ignored", file=sys.stderr)
                break
    if reset:
        known_paths = None
    return known_paths

def __init__(self,
             count=None,
             numFmt=(),
            ):
    self.numFmt = numFmt

def _create_outline_item(
    action_ref: Union[None, IndirectObject],
    title: str,
    color: Union[Tuple[float, float, float], str, None],
    italic: bool,
    bold: bool,
) -> TreeObject:
    outline_item = TreeObject()
    if action_ref is not None:
        outline_item[NameObject("/A")] = action_ref
    outline_item.update(
        {
            NameObject("/Title"): create_string_object(title),
        }
    )
    if color:
        if isinstance(color, str):
            color = hex_to_rgb(color)
        outline_item.update(
            {NameObject("/C"): ArrayObject([FloatObject(c) for c in color])}
        )
    if italic or bold:
        format_flag = 0
        if italic:
            format_flag += OutlineFontFlag.italic
        if bold:
            format_flag += OutlineFontFlag.bold
        outline_item.update({NameObject("/F"): NumberObject(format_flag)})
    return outline_item

def _normal_order_factor(product, recursive_limit=10, _recursive_depth=0):
    """
    Helper function for normal_order: Normal order a multiplication expression
    with bosonic or fermionic operators. In general the resulting operator
    expression will not be equivalent to original product.
    """

    factors = _expand_powers(product)

    n = 0
    new_factors = []
    while n < len(factors) - 1:

        if (isinstance(factors[n], BosonOp) and
                factors[n].is_annihilation):
            # boson
            if not isinstance(factors[n + 1], BosonOp):
                new_factors.append(factors[n])
            else:
                if factors[n + 1].is_annihilation:
                    new_factors.append(factors[n])
                else:
                    if factors[n].args[0] != factors[n + 1].args[0]:
                        new_factors.append(factors[n + 1] * factors[n])
                    else:
                        new_factors.append(factors[n + 1] * factors[n])
                    n += 1

        elif (isinstance(factors[n], FermionOp) and
              factors[n].is_annihilation):
            # fermion
            if not isinstance(factors[n + 1], FermionOp):
                new_factors.append(factors[n])
            else:
                if factors[n + 1].is_annihilation:
                    new_factors.append(factors[n])
                else:
                    if factors[n].args[0] != factors[n + 1].args[0]:
                        new_factors.append(-factors[n + 1] * factors[n])
                    else:
                        new_factors.append(-factors[n + 1] * factors[n])
                    n += 1

        else:
            new_factors.append(factors[n])

        n += 1

    if n == len(factors) - 1:
        new_factors.append(factors[-1])

    if new_factors == factors:
        return product
    else:
        expr = Mul(*new_factors).expand()
        return normal_order(expr,
                            recursive_limit=recursive_limit,
                            _recursive_depth=_recursive_depth + 1)

def coset_enumeration_c(fp_grp, Y, max_cosets=None, draft=None,
                                                incomplete=False):
    """
    >>> from sympy.combinatorics.free_groups import free_group
    >>> from sympy.combinatorics.fp_groups import FpGroup, coset_enumeration_c
    >>> F, x, y = free_group("x, y")
    >>> f = FpGroup(F, [x**3, y**3, x**-1*y**-1*x*y])
    >>> C = coset_enumeration_c(f, [x])
    >>> C.table
    [[0, 0, 1, 2], [1, 1, 2, 0], [2, 2, 0, 1]]

    """
    # Initialize a coset table C for < X|R >
    X = fp_grp.generators
    R = fp_grp.relators
    C = CosetTable(fp_grp, Y, max_cosets=max_cosets)
    if draft:
        C.table = draft.table[:]
        C.p = draft.p[:]
        C.deduction_stack = draft.deduction_stack
        for alpha, x in product(range(len(C.table)), X):
            if C.table[alpha][C.A_dict[x]] is not None:
                C.deduction_stack.append((alpha, x))
    A = C.A
    # replace all the elements by cyclic reductions
    R_cyc_red = [rel.identity_cyclic_reduction() for rel in R]
    R_c = list(chain.from_iterable((rel.cyclic_conjugates(), (rel**-1).cyclic_conjugates()) \
            for rel in R_cyc_red))
    R_set = set()
    for conjugate in R_c:
        R_set = R_set.union(conjugate)
    # a list of subsets of R_c whose words start with "x".
    R_c_list = []
    for x in C.A:
        r = {word for word in R_set if word[0] == x}
        R_c_list.append(r)
        R_set.difference_update(r)
    for w in Y:
        C.scan_and_fill_c(0, w)
    for x in A:
        C.process_deductions(R_c_list[C.A_dict[x]], R_c_list[C.A_dict_inv[x]])
    alpha = 0
    while alpha < len(C.table):
        if C.p[alpha] == alpha:
            try:
                for x in C.A:
                    if C.p[alpha] != alpha:
                        break
                    if C.table[alpha][C.A_dict[x]] is None:
                        C.define_c(alpha, x)
                        C.process_deductions(R_c_list[C.A_dict[x]], R_c_list[C.A_dict_inv[x]])
            except ValueError as e:
                if incomplete:
                    return C
                raise e
        alpha += 1
    return C

def optimize(p):
    'Optimize a pickle string by removing unused PUT opcodes'
    put = 'PUT'
    get = 'GET'
    oldids = set()          # set of all PUT ids
    newids = {}             # set of ids used by a GET opcode
    opcodes = []            # (op, idx) or (pos, end_pos)
    proto = 0
    protoheader = b''
    for opcode, arg, pos, end_pos in _genops(p, yield_end_pos=True):
        if 'PUT' in opcode.name:
            oldids.add(arg)
            opcodes.append((put, arg))
        elif opcode.name == 'MEMOIZE':
            idx = len(oldids)
            oldids.add(idx)
            opcodes.append((put, idx))
        elif 'FRAME' in opcode.name:
            pass
        elif 'GET' in opcode.name:
            if opcode.proto > proto:
                proto = opcode.proto
            newids[arg] = None
            opcodes.append((get, arg))
        elif opcode.name == 'PROTO':
            if arg > proto:
                proto = arg
            if pos == 0:
                protoheader = p[pos:end_pos]
            else:
                opcodes.append((pos, end_pos))
        else:
            opcodes.append((pos, end_pos))
    del oldids

    # Copy the opcodes except for PUTS without a corresponding GET
    out = io.BytesIO()
    # Write the PROTO header before any framing
    out.write(protoheader)
    pickler = pickle._Pickler(out, proto)
    if proto >= 4:
        pickler.framer.start_framing()
    idx = 0
    for op, arg in opcodes:
        frameless = False
        if op is put:
            if arg not in newids:
                continue
            data = pickler.put(idx)
            newids[arg] = idx
            idx += 1
        elif op is get:
            data = pickler.get(newids[arg])
        else:
            data = p[op:arg]
            frameless = len(data) > pickler.framer._FRAME_SIZE_TARGET
        pickler.framer.commit_frame(force=frameless)
        if frameless:
            pickler.framer.file_write(data)
        else:
            pickler.write(data)
    pickler.framer.end_framing()
    return out.getvalue()

def parseGSUBGPOS(lines, font, tableTag):
    container = ttLib.getTableClass(tableTag)()
    lookupMap = DeferredMapping()
    featureMap = DeferredMapping()
    assert tableTag in ("GSUB", "GPOS")
    log.debug("Parsing %s", tableTag)
    self = getattr(ot, tableTag)()
    self.Version = 0x00010000
    fields = {
        "script table begin": (
            "ScriptList",
            lambda lines: parseScriptList(lines, featureMap),
        ),
        "feature table begin": (
            "FeatureList",
            lambda lines: parseFeatureList(lines, lookupMap, featureMap),
        ),
        "lookup": ("LookupList", None),
    }
    for attr, parser in fields.values():
        setattr(self, attr, None)
    while lines.peek() is not None:
        typ = lines.peek()[0].lower()
        if typ not in fields:
            log.debug("Skipping %s", lines.peek())
            next(lines)
            continue
        attr, parser = fields[typ]
        if typ == "lookup":
            if self.LookupList is None:
                self.LookupList = ot.LookupList()
                self.LookupList.Lookup = []
            _, name, _ = lines.peek()
            lookup = parseLookup(lines, tableTag, font, lookupMap)
            if lookupMap is not None:
                assert name not in lookupMap, "Duplicate lookup name: %s" % name
                lookupMap[name] = len(self.LookupList.Lookup)
            else:
                assert int(name) == len(self.LookupList.Lookup), "%d %d" % (
                    name,
                    len(self.Lookup),
                )
            self.LookupList.Lookup.append(lookup)
        else:
            assert getattr(self, attr) is None, attr
            setattr(self, attr, parser(lines))
    if self.LookupList:
        self.LookupList.LookupCount = len(self.LookupList.Lookup)
    if lookupMap is not None:
        lookupMap.applyDeferredMappings()
        if os.environ.get(LOOKUP_DEBUG_ENV_VAR):
            if "Debg" not in font:
                font["Debg"] = newTable("Debg")
                font["Debg"].data = {}
            debug = (
                font["Debg"]
                .data.setdefault(LOOKUP_DEBUG_INFO_KEY, {})
                .setdefault(tableTag, {})
            )
            for name, lookup in lookupMap.items():
                debug[str(lookup)] = ["", name, ""]

        featureMap.applyDeferredMappings()
    container.table = self
    return container

def user_log_path(self) -> Path:
    """:return: log path tied to the user"""
    return Path(self.user_log_dir)

def _tensorize(self, value):
    import tensorflow as tf

    if value is None:
        return value

    default_dtype = {}

    if isinstance(value, (np.number, np.ndarray)) and np.issubdtype(value.dtype, np.integer):
        default_dtype = {"dtype": tf.int64}
    elif isinstance(value, (np.number, np.ndarray)) and np.issubdtype(value.dtype, np.floating):
        default_dtype = {"dtype": tf.float32}

    if config.PIL_AVAILABLE and "PIL" in sys.modules:
        import PIL.Image

        if isinstance(value, PIL.Image.Image):
            value = np.asarray(value)
    if config.TORCHVISION_AVAILABLE and "torchvision" in sys.modules:
        try:
            from torchvision.io import VideoReader

            if isinstance(value, VideoReader):
                return value  # TODO(QL): set output to tf tensors ?
        except ImportError:
            pass
    if config.TORCHCODEC_AVAILABLE and "torchcodec" in sys.modules:
        from torchcodec.decoders import AudioDecoder, VideoDecoder

        if isinstance(value, (VideoDecoder, AudioDecoder)):
            return value  # TODO(QL): set output to jax arrays ?

    return tf.convert_to_tensor(value, **{**default_dtype, **self.tf_tensor_kwargs})

def f(rv):
    if not rv.is_Mul:
        return rv

    # XXX handle products of powers? or let power-reducing handle it?
    args = {tan: [], cot: [], None: []}
    for a in Mul.make_args(rv):
        if a.func in (tan, cot):
            args[type(a)].append(a.args[0])
        else:
            args[None].append(a)
    t = args[tan]
    c = args[cot]
    if len(t) < 2 and len(c) < 2:
        return rv
    args = args[None]
    while len(t) > 1:
        t1 = t.pop()
        t2 = t.pop()
        args.append(1 - (tan(t1)/tan(t1 + t2) + tan(t2)/tan(t1 + t2)))
    if t:
        args.append(tan(t.pop()))
    while len(c) > 1:
        t1 = c.pop()
        t2 = c.pop()
        args.append(1 + cot(t1)*cot(t1 + t2) + cot(t2)*cot(t1 + t2))
    if c:
        args.append(cot(c.pop()))
    return Mul(*args)

def __floordiv__(p1, p2):
    ring = p1.ring

    if not p2:
        raise ZeroDivisionError("polynomial division")
    elif ring.is_element(p2):
        return p1.quo(p2)
    elif isinstance(p2, PolyElement):
        if isinstance(ring.domain, PolynomialRing) and ring.domain.ring == p2.ring:
            pass
        elif isinstance(p2.ring.domain, PolynomialRing) and p2.ring.domain.ring == ring:
            return p2.__rtruediv__(p1)
        else:
            return NotImplemented

    try:
        p2 = ring.domain_new(p2)
    except CoercionFailed:
        return NotImplemented
    else:
        return p1.quo_ground(p2)

def stripped_value(self):
    token = self[0]
    if token.token_type == 'cfws':
        token = self[1]
    if token.token_type.endswith(
            ('quoted-string', 'attribute', 'extended-attribute')):
        return token.stripped_value
    return self.value

def parseImpl(self, instring, loc, doActions=True):
    self_expr_parse = self.expr._parse
    self_skip_ignorables = self._skipIgnorables
    check_ender = self.not_ender is not None
    if check_ender:
        try_not_ender = self.not_ender.try_parse

    # must be at least one (but first see if we are the stopOn sentinel;
    # if so, fail)
    if check_ender:
        try_not_ender(instring, loc)
    loc, tokens = self_expr_parse(instring, loc, doActions)
    try:
        hasIgnoreExprs = not not self.ignoreExprs
        while 1:
            if check_ender:
                try_not_ender(instring, loc)
            if hasIgnoreExprs:
                preloc = self_skip_ignorables(instring, loc)
            else:
                preloc = loc
            loc, tmptokens = self_expr_parse(instring, preloc, doActions)
            tokens += tmptokens
    except (ParseException, IndexError):
        pass

    return loc, tokens

def __init__(self, name, obtype, doc):
    assert isinstance(name, str)
    self.name = name

    assert isinstance(obtype, type) or isinstance(obtype, tuple)
    if isinstance(obtype, tuple):
        for contained in obtype:
            assert isinstance(contained, type)
    self.obtype = obtype

    assert isinstance(doc, str)
    self.doc = doc

def parseImpl(self, instring, loc=0, doActions=True):
    if self.exact:
        if loc < self.retreat:
            raise ParseException(instring, loc, self.errmsg)
        start = loc - self.retreat
        _, ret = self.expr._parse(instring, start)
    else:
        # retreat specified a maximum lookbehind window, iterate
        test_expr = self.expr + StringEnd()
        instring_slice = instring[max(0, loc - self.retreat) : loc]
        last_expr = ParseException(instring, loc, self.errmsg)
        for offset in range(1, min(loc, self.retreat + 1) + 1):
            try:
                # print('trying', offset, instring_slice, repr(instring_slice[loc - offset:]))
                _, ret = test_expr._parse(
                    instring_slice, len(instring_slice) - offset
                )
            except ParseBaseException as pbe:
                last_expr = pbe
            else:
                break
        else:
            raise last_expr
    return loc, ret

def collect_lookups(self, feature_indices):
    return sum(
        (
            r.Feature.LookupListIndex
            for vr in self.FeatureVariationRecord
            for r in vr.FeatureTableSubstitution.SubstitutionRecord
            if r.FeatureIndex in feature_indices
        ),
        [],
    )

def parse_STAT_axis_value_(self):
    assert self.is_cur_keyword_("AxisValue")
    self.expect_symbol_("{")
    locations = []
    names = []
    flags = 0
    while self.next_token_ != "}" or self.cur_comments_:
        self.advance_lexer_(comments=True)
        if self.cur_token_type_ is Lexer.COMMENT:
            continue
        elif self.is_cur_keyword_("name"):
            location = self.cur_token_location_
            platformID, platEncID, langID, string = self.parse_stat_name_()
            name = self.ast.STATNameStatement(
                "stat", platformID, platEncID, langID, string, location=location
            )
            names.append(name)
        elif self.is_cur_keyword_("location"):
            location = self.parse_STAT_location()
            locations.append(location)
        elif self.is_cur_keyword_("flag"):
            flags = self.expect_stat_flags()
        elif self.cur_token_ == ";":
            continue
        else:
            raise FeatureLibError(
                f"Unexpected token {self.cur_token_} " f"in AxisValue",
                self.cur_token_location_,
            )
    self.expect_symbol_("}")
    if not names:
        raise FeatureLibError('Expected "Axis Name"', self.cur_token_location_)
    if not locations:
        raise FeatureLibError('Expected "Axis location"', self.cur_token_location_)
    if len(locations) > 1:
        for location in locations:
            if len(location.values) > 1:
                raise FeatureLibError(
                    "Only one value is allowed in a "
                    "Format 4 Axis Value Record, but "
                    f"{len(location.values)} were found.",
                    self.cur_token_location_,
                )
        format4_tags = []
        for location in locations:
            tag = location.tag
            if tag in format4_tags:
                raise FeatureLibError(
                    f"Axis tag {tag} already " "defined.", self.cur_token_location_
                )
            format4_tags.append(tag)

    return self.ast.STATAxisValueStatement(
        names, locations, flags, self.cur_token_location_
    )

def _select_equations(eqs, funcs, key=lambda x: x):
    eq_dict = {e.lhs: e.rhs for e in eqs}
    return [Eq(f, eq_dict[key(f)]) for f in funcs]

def _insert_filtered_annotations(
    self,
    annots: Union[IndirectObject, List[DictionaryObject], None],
    page: PageObject,
    pages: Dict[int, PageObject],
    reader: PdfReader,
) -> List[Destination]:
    outlist = ArrayObject()
    if isinstance(annots, IndirectObject):
        annots = cast("List[Any]", annots.get_object())
    if annots is None:
        return outlist
    if not isinstance(annots, list):
        logger_warning(f"Expected list of annotations, got {annots} of type {annots.__class__.__name__}.", __name__)
        return outlist
    for an in annots:
        ano = cast("DictionaryObject", an.get_object())
        if (
            ano["/Subtype"] != "/Link"
            or "/A" not in ano
            or cast("DictionaryObject", ano["/A"])["/S"] != "/GoTo"
            or "/Dest" in ano
        ):
            if "/Dest" not in ano:
                outlist.append(self._add_object(ano.clone(self)))
            else:
                d = ano["/Dest"]
                if isinstance(d, str):
                    # it is a named dest
                    if str(d) in self.get_named_dest_root():
                        outlist.append(ano.clone(self).indirect_reference)
                else:
                    d = cast("ArrayObject", d)
                    p = self._get_cloned_page(d[0], pages, reader)
                    if p is not None:
                        anc = ano.clone(self, ignore_fields=("/Dest",))
                        anc[NameObject("/Dest")] = ArrayObject([p, *d[1:]])
                        outlist.append(self._add_object(anc))
        else:
            d = cast("DictionaryObject", ano["/A"]).get("/D", NullObject())
            if d is None or isinstance(d, NullObject):
                continue
            if isinstance(d, str):
                # it is a named dest
                if str(d) in self.get_named_dest_root():
                    outlist.append(ano.clone(self).indirect_reference)
            else:
                d = cast("ArrayObject", d)
                p = self._get_cloned_page(d[0], pages, reader)
                if p is not None:
                    anc = ano.clone(self, ignore_fields=("/D",))
                    cast("DictionaryObject", anc["/A"])[
                        NameObject("/D")
                    ] = ArrayObject([p, *d[1:]])
                    outlist.append(self._add_object(anc))
    return outlist

def _iter_process_parents(pid, max_depth=10):
    """Select a way to obtain process information from the system.

    * `/proc` is used if supported.
    * The system `ps` utility is used as a fallback option.
    """
    for impl in (proc, ps):
        try:
            iterator = impl.iter_process_parents(pid, max_depth)
        except EnvironmentError:
            continue
        return iterator
    raise ShellDetectionFailure("compatible proc fs or ps utility is required")

def normalize(self):
    """
    Normalise the geometry of this designspace:

    - scale all the locations of all masters and instances to the -1 - 0 - 1 value.
    - we need the axis data to do the scaling, so we do those last.
    """
    # masters
    for item in self.sources:
        item.location = self.normalizeLocation(item.location)
    # instances
    for item in self.instances:
        # glyph masters for this instance
        for _, glyphData in item.glyphs.items():
            glyphData["instanceLocation"] = self.normalizeLocation(
                glyphData["instanceLocation"]
            )
            for glyphMaster in glyphData["masters"]:
                glyphMaster["location"] = self.normalizeLocation(
                    glyphMaster["location"]
                )
        item.location = self.normalizeLocation(item.location)
    # the axes
    for axis in self.axes:
        # scale the map first
        newMap = []
        for inputValue, outputValue in axis.map:
            newOutputValue = self.normalizeLocation({axis.name: outputValue}).get(
                axis.name
            )
            newMap.append((inputValue, newOutputValue))
        if newMap:
            axis.map = newMap
        # finally the axis values
        minimum = self.normalizeLocation({axis.name: axis.minimum}).get(axis.name)
        maximum = self.normalizeLocation({axis.name: axis.maximum}).get(axis.name)
        default = self.normalizeLocation({axis.name: axis.default}).get(axis.name)
        # and set them in the axis.minimum
        axis.minimum = minimum
        axis.maximum = maximum
        axis.default = default
    # now the rules
    for rule in self.rules:
        newConditionSets = []
        for conditions in rule.conditionSets:
            newConditions = []
            for cond in conditions:
                if cond.get("minimum") is not None:
                    minimum = self.normalizeLocation(
                        {cond["name"]: cond["minimum"]}
                    ).get(cond["name"])
                else:
                    minimum = None
                if cond.get("maximum") is not None:
                    maximum = self.normalizeLocation(
                        {cond["name"]: cond["maximum"]}
                    ).get(cond["name"])
                else:
                    maximum = None
                newConditions.append(
                    dict(name=cond["name"], minimum=minimum, maximum=maximum)
                )
            newConditionSets.append(newConditions)
        rule.conditionSets = newConditionSets

def _select_struct_union_class(self, token: str) -> type:
    """Given a token (either STRUCT or UNION), selects the
    appropriate AST class.
    """
    if token == "struct":
        return c_ast.Struct
    else:
        return c_ast.Union

def __new__(cls, *shape):
    if len(shape) == 0:
        return S.Zero
    shape = map(_sympify, shape)
    obj = Expr.__new__(cls, *shape)
    return obj

def create_longformer_inputs(onnx_model, batch_size, sequence_length, global_length, samples):
    """Create dummy inputs for Longformer model.

    Args:
        onnx_model (OnnxModel): ONNX model
        batch_size (int): batch size
        sequence_length (int): sequence length
        global_length (int): number of global tokens
        samples (int): number of samples

    Raises:
        RuntimeError: symbolic is not supported. Use the tool convert_longformer_to_onnx.py to export ONNX model instead.

    Returns:
        List[Dict]: list of inputs
    """
    symbols = {"batch_size": batch_size, "sequence_length": sequence_length}

    dummy_inputs = {}
    for graph_input in onnx_model.get_graph_inputs_excluding_initializers():
        shape = get_shape_from_type_proto(graph_input.type)
        for i, dim in enumerate(shape):
            if isinstance(dim, str):
                if dim not in symbols:
                    raise RuntimeError(f"symbol is not supported: {dim}")
                else:
                    shape[i] = symbols[dim]

        elem_type = graph_input.type.tensor_type.elem_type
        assert elem_type in [TensorProto.FLOAT, TensorProto.INT32, TensorProto.INT64]
        data_type = (
            numpy.float32
            if elem_type == TensorProto.FLOAT
            else (numpy.int64 if elem_type == TensorProto.INT64 else numpy.int32)
        )

        if "global" in graph_input.name:
            data = numpy.zeros(shape, dtype=data_type)
            data[:, :global_length] = 1
        else:
            data = numpy.ones(shape, dtype=data_type)
        dummy_inputs[graph_input.name] = data

    all_inputs = [dummy_inputs for _ in range(samples)]
    return all_inputs

def parseImpl(self, instring, loc, doActions=True):
    instrlen = len(instring)
    if instrlen > 0 and loc < instrlen:
        if (
            instring[loc] in self.wordChars
            or instring[loc - 1] not in self.wordChars
        ):
            raise ParseException(instring, loc, self.errmsg, self)
    return loc, []

def iter_fields(
    self,
    exclude: t.Optional[t.Container[str]] = None,
    only: t.Optional[t.Container[str]] = None,
) -> t.Iterator[t.Tuple[str, t.Any]]:
    """This method iterates over all fields that are defined and yields
    ``(key, value)`` tuples.  Per default all fields are returned, but
    it's possible to limit that to some fields by providing the `only`
    parameter or to exclude some using the `exclude` parameter.  Both
    should be sets or tuples of field names.
    """
    for name in self.fields:
        if (
            (exclude is None and only is None)
            or (exclude is not None and name not in exclude)
            or (only is not None and name in only)
        ):
            try:
                yield name, getattr(self, name)
            except AttributeError:
                pass

def xpath_tokenizer(pattern, namespaces=None, with_prefixes=True):
    # ElementTree uses '', lxml used None originally.
    default_namespace = (namespaces.get(None) or namespaces.get('')) if namespaces else None
    parsing_attribute = False
    for token in xpath_tokenizer_re.findall(pattern):
        ttype, tag = token
        if tag and tag[0] != "{":
            if ":" in tag and with_prefixes:
                prefix, uri = tag.split(":", 1)
                try:
                    if not namespaces:
                        raise KeyError
                    yield ttype, "{%s}%s" % (namespaces[prefix], uri)
                except KeyError:
                    raise SyntaxError("prefix %r not found in prefix map" % prefix)
            elif tag.isdecimal():
                yield token  # index
            elif default_namespace and not parsing_attribute:
                yield ttype, "{%s}%s" % (default_namespace, tag)
            else:
                yield token
            parsing_attribute = False
        else:
            yield token
            parsing_attribute = ttype == '@'

def _accumulate_edges_subset(betweenness, S, P, sigma, s, targets):
    """edge_betweenness_centrality_subset helper."""
    delta = dict.fromkeys(S, 0)
    target_set = set(targets)
    while S:
        w = S.pop()
        for v in P[w]:
            if w in target_set:
                c = (sigma[v] / sigma[w]) * (1.0 + delta[w])
            else:
                c = delta[w] / len(P[w])
            if (v, w) not in betweenness:
                betweenness[(w, v)] += c
            else:
                betweenness[(v, w)] += c
            delta[v] += c
        if w != s:
            betweenness[w] += delta[w]
    return betweenness

def can_assign(self) -> bool:
    for item in self.items:
        if not item.can_assign():
            return False
    return True

def apply(
    self, data: DataFrame, func: Callable[..., DataFrame],
    *args, **kwargs,
) -> DataFrame:
    """Apply a DataFrame -> DataFrame mapping to each group."""
    grouper, groups = self._get_groups(data)

    if not grouper:
        return self._reorder_columns(func(data, *args, **kwargs), data)

    parts = {}
    for key, part_df in data.groupby(grouper, sort=False, observed=False):
        parts[key] = func(part_df, *args, **kwargs)
    stack = []
    for key in groups:
        if key in parts:
            if isinstance(grouper, list):
                # Implies that we had a MultiIndex so key is iterable
                group_ids = dict(zip(grouper, cast(Iterable, key)))
            else:
                group_ids = {grouper: key}
            stack.append(parts[key].assign(**group_ids))

    res = pd.concat(stack, ignore_index=True)
    return self._reorder_columns(res, data)

def _create_unverified_context(protocol=None, *, cert_reqs=CERT_NONE,
                           check_hostname=False, purpose=Purpose.SERVER_AUTH,
                           certfile=None, keyfile=None,
                           cafile=None, capath=None, cadata=None):
    """Create a SSLContext object for Python stdlib modules

    All Python stdlib modules shall use this function to create SSLContext
    objects in order to keep common settings in one place. The configuration
    is less restrict than create_default_context()'s to increase backward
    compatibility.
    """
    if not isinstance(purpose, _ASN1Object):
        raise TypeError(purpose)

    # SSLContext sets OP_NO_SSLv2, OP_NO_SSLv3, OP_NO_COMPRESSION,
    # OP_CIPHER_SERVER_PREFERENCE, OP_SINGLE_DH_USE and OP_SINGLE_ECDH_USE
    # by default.
    if purpose == Purpose.SERVER_AUTH:
        # verify certs and host name in client mode
        if protocol is None:
            protocol = PROTOCOL_TLS_CLIENT
    elif purpose == Purpose.CLIENT_AUTH:
        if protocol is None:
            protocol = PROTOCOL_TLS_SERVER
    else:
        raise ValueError(purpose)

    context = SSLContext(protocol)
    context.check_hostname = check_hostname
    if cert_reqs is not None:
        context.verify_mode = cert_reqs
    if check_hostname:
        context.check_hostname = True

    if keyfile and not certfile:
        raise ValueError("certfile must be specified")
    if certfile or keyfile:
        context.load_cert_chain(certfile, keyfile)

    # load CA root certs
    if cafile or capath or cadata:
        context.load_verify_locations(cafile, capath, cadata)
    elif context.verify_mode != CERT_NONE:
        # no explicit cafile, capath or cadata but the verify mode is
        # CERT_OPTIONAL or CERT_REQUIRED. Let's try to load default system
        # root CA certificates for the given purpose. This may fail silently.
        context.load_default_certs(purpose)
    # OpenSSL 1.1.1 keylog file
    if hasattr(context, 'keylog_filename'):
        keylogfile = os.environ.get('SSLKEYLOGFILE')
        if keylogfile and not sys.flags.ignore_environment:
            context.keylog_filename = keylogfile
    return context

def clean(
    content: ContentStream,
    images: List[str],
    forms: List[str],
    text_filters: Optional[Dict[str, Any]] = None
) -> None:
    nonlocal jump_operators, to_delete

    font_id = None
    font_ids_to_delete = []
    if text_filters and to_delete & ObjectDeletionFlag.TEXT:
        font_ids_to_delete = text_filters.get("font_ids", [])

    i = 0
    while i < len(content.operations):
        operands, operator = content.operations[i]
        if operator == b"Tf":
            font_id = operands[0]
        if (
            (
                operator == b"INLINE IMAGE"
                and (to_delete & ObjectDeletionFlag.INLINE_IMAGES)
            )
            or (operator in jump_operators)
            or (
                operator == b"Do"
                and (to_delete & ObjectDeletionFlag.XOBJECT_IMAGES)
                and (operands[0] in images)
            )
        ):
            if (
                not to_delete & ObjectDeletionFlag.TEXT
                or (to_delete & ObjectDeletionFlag.TEXT and not text_filters)
                or (to_delete & ObjectDeletionFlag.TEXT and font_id in font_ids_to_delete)
            ):
                del content.operations[i]
            else:
                i += 1
        else:
            i += 1
    content.get_data()  # this ensures ._data is rebuilt from the .operations

def sub(self, tokens):
    if len(tokens) == 2: # -a
        x = tokens[1]

        if self._obj_is_sympy_Matrix(x):
            return sympy.MatMul(-1, x)

        return -x
    if len(tokens) == 3: # a - b
        lh = tokens[0]
        rh = tokens[2]

        if self._obj_is_sympy_Matrix(lh) or self._obj_is_sympy_Matrix(rh):
            return sympy.MatAdd(lh, sympy.MatMul(-1, rh))

        return sympy.Add(lh, -rh)

def streamline(self) -> ParserElement:
    # collapse any _PendingSkip's
    if self.exprs:
        if any(
            isinstance(e, ParseExpression)
            and e.exprs
            and isinstance(e.exprs[-1], _PendingSkip)
            for e in self.exprs[:-1]
        ):
            deleted_expr_marker = NoMatch()
            for i, e in enumerate(self.exprs[:-1]):
                if e is deleted_expr_marker:
                    continue
                if (
                    isinstance(e, ParseExpression)
                    and e.exprs
                    and isinstance(e.exprs[-1], _PendingSkip)
                ):
                    e.exprs[-1] = e.exprs[-1] + self.exprs[i + 1]
                    self.exprs[i + 1] = deleted_expr_marker
            self.exprs = [e for e in self.exprs if e is not deleted_expr_marker]

    super().streamline()

    # link any IndentedBlocks to the prior expression
    prev: ParserElement
    cur: ParserElement
    for prev, cur in zip(self.exprs, self.exprs[1:]):
        # traverse cur or any first embedded expr of cur looking for an IndentedBlock
        # (but watch out for recursive grammar)
        seen = set()
        while True:
            if id(cur) in seen:
                break
            seen.add(id(cur))
            if isinstance(cur, IndentedBlock):
                prev.add_parse_action(
                    lambda s, l, t, cur_=cur: setattr(
                        cur_, "parent_anchor", col(l, s)
                    )
                )
                break
            subs = cur.recurse()
            next_first = next(iter(subs), None)
            if next_first is None:
                break
            cur = typing.cast(ParserElement, next_first)

    self.mayReturnEmpty = all(e.mayReturnEmpty for e in self.exprs)
    return self

def _eval_nseries(self, x, n, logx, cdir=0):
    from .function import PoleError
    from sympy.functions.elementary.integers import ceiling
    from sympy.series.order import Order

    def coeff_exp(term, x):
        lt = term.as_coeff_exponent(x)
        if lt[0].has(x):
            try:
                lt = term.leadterm(x)
            except ValueError:
                return term, S.Zero
        return lt

    ords = []

    try:
        for t in self.args:
            coeff, exp = t.leadterm(x)
            if not coeff.has(x):
                ords.append((t, exp))
            else:
                raise ValueError

        n0 = sum(t[1] for t in ords if t[1].is_number)
        facs = []
        for t, m in ords:
            n1 = ceiling(n - n0 + (m if m.is_number else 0))
            s = t.nseries(x, n=n1, logx=logx, cdir=cdir)
            ns = s.getn()
            if ns is not None:
                if ns < n1:  # less than expected
                    n -= n1 - ns    # reduce n
            facs.append(s)

    except (ValueError, NotImplementedError, TypeError, PoleError):
        # XXX: Catching so many generic exceptions around a large block of
        # code will mask bugs. Whatever purpose catching these exceptions
        # serves should be handled in a different way.
        n0 = sympify(sum(t[1] for t in ords if t[1].is_number))
        if n0.is_nonnegative:
            n0 = S.Zero
        facs = [t.nseries(x, n=ceiling(n-n0), logx=logx, cdir=cdir) for t in self.args]
        from sympy.simplify.powsimp import powsimp
        res = powsimp(self.func(*facs).expand(), combine='exp', deep=True)
        if res.has(Order):
            res += Order(x**n, x)
        return res

    res = S.Zero
    ords2 = [Add.make_args(factor) for factor in facs]

    for fac in product(*ords2):
        ords3 = [coeff_exp(term, x) for term in fac]
        coeffs, powers = zip(*ords3)
        power = sum(powers)
        if (power - n).is_negative:
            res += Mul(*coeffs)*(x**power)

    def max_degree(e, x):
        if e is x:
            return S.One
        if e.is_Atom:
            return S.Zero
        if e.is_Add:
            return max(max_degree(a, x) for a in e.args)
        if e.is_Mul:
            return Add(*[max_degree(a, x) for a in e.args])
        if e.is_Pow:
            return max_degree(e.base, x)*e.exp
        return S.Zero

    if self.is_polynomial(x):
        from sympy.polys.polyerrors import PolynomialError
        from sympy.polys.polytools import degree
        try:
            if max_degree(self, x) >= n or degree(self, x) != degree(res, x):
                res += Order(x**n, x)
        except PolynomialError:
            pass
        else:
            return res

    if res != self:
        if (self - res).subs(x, 0) == S.Zero and n > 0:
            lt = self._eval_as_leading_term(x, logx=logx, cdir=cdir)
            if lt == S.Zero:
                return res
        res += Order(x**n, x)
    return res

def _test_color_function(self):
    if not callable(self.f):
        raise ValueError("Color function is not callable.")
    try:
        result = self.f(0, 0, 0, 0, 0)
        if len(result) != 3:
            raise ValueError("length should be equal to 3")
    except TypeError:
        raise ValueError("Color function needs to accept x,y,z,u,v, "
                         "as arguments even if it doesn't use all of them.")
    except AssertionError:
        raise ValueError("Color function needs to return 3-tuple r,g,b.")
    except Exception:
        pass  # color function probably not valid at 0,0,0,0,0

def __init__(self, base_array: typing.Union[ArrayContraction, ArrayDiagonal, ArrayTensorProduct]):

    expr: Basic
    diagonalized: tuple[tuple[int, ...], ...]
    contraction_indices: list[tuple[int]]
    if isinstance(base_array, ArrayContraction):
        mapping = _get_mapping_from_subranks(base_array.subranks)
        expr = base_array.expr
        contraction_indices = base_array.contraction_indices
        diagonalized = ()
    elif isinstance(base_array, ArrayDiagonal):

        if isinstance(base_array.expr, ArrayContraction):
            mapping = _get_mapping_from_subranks(base_array.expr.subranks)
            expr = base_array.expr.expr
            diagonalized = ArrayContraction._push_indices_down(base_array.expr.contraction_indices, base_array.diagonal_indices)
            contraction_indices = base_array.expr.contraction_indices
        elif isinstance(base_array.expr, ArrayTensorProduct):
            mapping = {}
            expr = base_array.expr
            diagonalized = base_array.diagonal_indices
            contraction_indices = []
        else:
            mapping = {}
            expr = base_array.expr
            diagonalized = base_array.diagonal_indices
            contraction_indices = []

    elif isinstance(base_array, ArrayTensorProduct):
        expr = base_array
        contraction_indices = []
        diagonalized = ()
    else:
        raise NotImplementedError()

    if isinstance(expr, ArrayTensorProduct):
        args = list(expr.args)
    else:
        args = [expr]

    args_with_ind: list[_ArgE] = [_ArgE(arg) for arg in args]
    for i, contraction_tuple in enumerate(contraction_indices):
        for j in contraction_tuple:
            arg_pos, rel_pos = mapping[j]
            args_with_ind[arg_pos].indices[rel_pos] = i
    self.args_with_ind: list[_ArgE] = args_with_ind
    self.number_of_contraction_indices: int = len(contraction_indices)
    self._track_permutation: list[list[int]] | None = None

    mapping = _get_mapping_from_subranks(base_array.subranks)

    # Trick: add diagonalized indices as negative indices into the editor object:
    for i, e in enumerate(diagonalized):
        for j in e:
            arg_pos, rel_pos = mapping[j]
            self.args_with_ind[arg_pos].indices[rel_pos] = -1 - i

def _extract_stack_trace_information_from_stack(
    st: List[inspect.FrameInfo], is_internal: bool, title: str = None
) -> ParsedStackTrace:
    playwright_module_path = str(Path(playwright.__file__).parents[0])
    last_internal_api_name = ""
    api_name = ""
    parsed_frames: List[StackFrame] = []
    for frame in st:
        # Sync and Async implementations can have event handlers. When these are sync, they
        # get evaluated in the context of the event loop, so they contain the stack trace of when
        # the message was received. _impl_to_api_mapping is glue between the user-code and internal
        # code to translate impl classes to api classes. We want to ignore these frames.
        if playwright._impl._impl_to_api_mapping.__file__ == frame.filename:
            continue
        is_playwright_internal = frame.filename.startswith(playwright_module_path)

        method_name = ""
        if "self" in frame[0].f_locals:
            method_name = frame[0].f_locals["self"].__class__.__name__ + "."
        method_name += frame[0].f_code.co_name

        if not is_playwright_internal:
            parsed_frames.append(
                {
                    "file": frame.filename,
                    "line": frame.lineno,
                    "column": 0,
                    "function": method_name,
                }
            )
        if is_playwright_internal:
            last_internal_api_name = method_name
        elif last_internal_api_name:
            api_name = last_internal_api_name
            last_internal_api_name = ""
    if not api_name:
        api_name = last_internal_api_name

    return {
        "frames": parsed_frames,
        "apiName": "" if is_internal else api_name,
        "title": title,
    }

def run(self):
    dist = self.distribution
    settings = {}

    for cmd in dist.command_options:
        if cmd == 'saveopts':
            continue  # don't save our own options!

        for opt, (src, val) in dist.get_option_dict(cmd).items():
            if src == "command line":
                settings.setdefault(cmd, {})[opt] = val

    edit_config(self.filename, settings, self.dry_run)

