def _getEffectiveFormatTuple(self):
    """Try to use the version specified in the document, or a sufficiently
    recent version to be able to encode what the document contains.
    """
    minVersion = self.documentObject.formatTuple
    if (
        any(
            hasattr(axis, "values")
            or axis.axisOrdering is not None
            or axis.axisLabels
            for axis in self.documentObject.axes
        )
        or self.documentObject.locationLabels
        or any(source.localisedFamilyName for source in self.documentObject.sources)
        or self.documentObject.variableFonts
        or any(
            instance.locationLabel or instance.userLocation
            for instance in self.documentObject.instances
        )
    ):
        if minVersion < (5, 0):
            minVersion = (5, 0)
    if self.documentObject.axisMappings:
        if minVersion < (5, 1):
            minVersion = (5, 1)
    return minVersion

def prune_post_subset(self, font, options):
    table = self.table

    store = table.MultiVarStore
    if store is not None:
        usedVarIdxes = set()
        table.collect_varidxes(usedVarIdxes)
        varidx_map = store.subset_varidxes(usedVarIdxes)
        table.remap_varidxes(varidx_map)

    axisIndicesList = table.AxisIndicesList.Item
    if axisIndicesList is not None:
        usedIndices = set()
        for glyph in table.VarCompositeGlyphs.VarCompositeGlyph:
            for comp in glyph.components:
                if comp.axisIndicesIndex is not None:
                    usedIndices.add(comp.axisIndicesIndex)
        usedIndices = sorted(usedIndices)
        table.AxisIndicesList.Item = _list_subset(axisIndicesList, usedIndices)
        mapping = {old: new for new, old in enumerate(usedIndices)}
        for glyph in table.VarCompositeGlyphs.VarCompositeGlyph:
            for comp in glyph.components:
                if comp.axisIndicesIndex is not None:
                    comp.axisIndicesIndex = mapping[comp.axisIndicesIndex]

    conditionList = table.ConditionList
    if conditionList is not None:
        conditionTables = conditionList.ConditionTable
        usedIndices = set()
        for glyph in table.VarCompositeGlyphs.VarCompositeGlyph:
            for comp in glyph.components:
                if comp.conditionIndex is not None:
                    usedIndices.add(comp.conditionIndex)
        usedIndices = sorted(usedIndices)
        conditionList.ConditionTable = _list_subset(conditionTables, usedIndices)
        mapping = {old: new for new, old in enumerate(usedIndices)}
        for glyph in table.VarCompositeGlyphs.VarCompositeGlyph:
            for comp in glyph.components:
                if comp.conditionIndex is not None:
                    comp.conditionIndex = mapping[comp.conditionIndex]

    return True

def preParse(self, instring: str, loc: int) -> int:
    if loc == 0:
        return loc
    else:
        ret = self.skipper.preParse(instring, loc)
        if "\n" in self.orig_whiteChars:
            while instring[ret : ret + 1] == "\n":
                ret = self.skipper.preParse(instring, ret + 1)
        return ret

def processRules(rules, location, glyphNames):
    """Apply these rules at this location to these glyphnames.

    Return a new list of glyphNames with substitutions applied.

    - rule order matters
    """
    newNames = []
    for rule in rules:
        if evaluateRule(rule, location):
            for name in glyphNames:
                swap = False
                for a, b in rule.subs:
                    if name == a:
                        swap = True
                        break
                if swap:
                    newNames.append(b)
                else:
                    newNames.append(name)
            glyphNames = newNames
            newNames = []
    return glyphNames

def __getitem__(self, idx):
    if (not isinstance(idx, str) and isinstance(idx, abc.Iterable)):
        idx = tuple(idx)
        d = len(idx)
        if not (1 <= d <= 2):
            raise ValueError('index cannot be {0}-dimensional'.format(d))
        elif d == 2:
            x, y = idx
            x_slice = isinstance(x, slice)
            y_slice = isinstance(y, slice)
            if x_slice and not y_slice:
                y = slice(y, y + 1)
            elif not x_slice and y_slice:
                x = slice(x, x + 1)
            elif not (x_slice or y_slice):
                if not (isinstance(x, numbers.Integral) and
                        isinstance(y, numbers.Integral)):
                    raise TypeError('x and y must be integral, not ' +
                                    repr((x, y)))
                if x < 0:
                    x += self.width
                if y < 0:
                    y += self.height
                if x >= self.width:
                    raise IndexError('x must be less than width')
                elif y >= self.height:
                    raise IndexError('y must be less than height')
                elif x < 0:
                    raise IndexError('x cannot be less than 0')
                elif y < 0:
                    raise IndexError('y cannot be less than 0')
                with iter(self) as iterator:
                    iterator.seek(y)
                    return iterator.__next__(x)
            if not (x.step is None and y.step is None):
                raise ValueError('slicing with step is unsupported')
            elif (x.start is None and x.stop is None and
                  y.start is None and y.stop is None):
                return self.clone()
            cloned = self.clone()
            try:
                cloned.crop(x.start, y.start, x.stop, y.stop)
            except ValueError as e:
                raise IndexError(str(e))
            return cloned
        else:
            return self[idx[0]]
    elif isinstance(idx, numbers.Integral):
        if idx < 0:
            idx += self.height
        elif idx >= self.height:
            raise IndexError('index must be less than height, but got ' +
                             repr(idx))
        elif idx < 0:
            raise IndexError('index cannot be less than zero, but got ' +
                             repr(idx))
        with iter(self) as iterator:
            iterator.seek(idx)
            return next(iterator)
    elif isinstance(idx, slice):
        return self[:, idx]
    raise TypeError('unsupported index type: ' + repr(idx))

def _fill_in_vars(self, args):
    defaults = symbols('x,y,z,u,v')
    v_error = ValueError("Could not find what to plot.")
    if len(args) == 0:
        return defaults
    if not isinstance(args, (tuple, list)):
        raise v_error
    if len(args) == 0:
        return defaults
    for s in args:
        if s is not None and not isinstance(s, Symbol):
            raise v_error
    # when vars are given explicitly, any vars
    # not given are marked 'unbound' as to not
    # be accidentally used in an expression
    vars = [Symbol('unbound%i' % (i)) for i in range(1, 6)]
    # interpret as t
    if len(args) == 1:
        vars[3] = args[0]
    # interpret as u,v
    elif len(args) == 2:
        if args[0] is not None:
            vars[3] = args[0]
        if args[1] is not None:
            vars[4] = args[1]
    # interpret as x,y,z
    elif len(args) >= 3:
        # allow some of x,y,z to be
        # left unbound if not given
        if args[0] is not None:
            vars[0] = args[0]
        if args[1] is not None:
            vars[1] = args[1]
        if args[2] is not None:
            vars[2] = args[2]
        # interpret the rest as t
        if len(args) >= 4:
            vars[3] = args[3]
            # ...or u,v
            if len(args) >= 5:
                vars[4] = args[4]
    return vars

def _pass_image_data(x, alpha=None, bytes=False, norm=True):
    """
    Helper function to pass ndarray of shape (...,3) or (..., 4)
    through `to_rgba()`, see `to_rgba()` for docstring.
    """
    if x.shape[2] == 3:
        if alpha is None:
            alpha = 1
        if x.dtype == np.uint8:
            alpha = np.uint8(alpha * 255)
        m, n = x.shape[:2]
        xx = np.empty(shape=(m, n, 4), dtype=x.dtype)
        xx[:, :, :3] = x
        xx[:, :, 3] = alpha
    elif x.shape[2] == 4:
        xx = x
    else:
        raise ValueError("Third dimension must be 3 or 4")
    if xx.dtype.kind == 'f':
        # If any of R, G, B, or A is nan, set to 0
        if np.any(nans := np.isnan(x)):
            if x.shape[2] == 4:
                xx = xx.copy()
            xx[np.any(nans, axis=2), :] = 0

        if norm and (xx.max() > 1 or xx.min() < 0):
            raise ValueError("Floating point image RGB values "
                             "must be in the 0..1 range.")
        if bytes:
            xx = (xx * 255).astype(np.uint8)
    elif xx.dtype == np.uint8:
        if not bytes:
            xx = xx.astype(np.float32) / 255
    else:
        raise ValueError("Image RGB array must be uint8 or "
                         "floating point; found %s" % xx.dtype)
    # Account for any masked entries in the original array
    # If any of R, G, B, or A are masked for an entry, we set alpha to 0
    if np.ma.is_masked(x):
        xx[np.any(np.ma.getmaskarray(x), axis=2), 3] = 0
    return xx

