def clone_reader_document_root(self, reader: PdfReader) -> None:
    """
    Copy the reader document root to the writer and all sub-elements,
    including pages, threads, outlines,... For partial insertion, ``append``
    should be considered.

    Args:
        reader: PdfReader from which the document root should be copied.

    """
    self._info_obj = None
    if self.incremental:
        self._objects = [None] * (cast(int, reader.trailer["/Size"]) - 1)
        for i in range(len(self._objects)):
            o = reader.get_object(i + 1)
            if o is not None:
                self._objects[i] = o.replicate(self)
    else:
        self._objects.clear()
    self._root_object = reader.root_object.clone(self)
    self._pages = self._root_object.raw_get("/Pages")

    assert len(self._objects) <= cast(int, reader.trailer["/Size"])  # for pytest
    # must be done here before rewriting
    if self.incremental:
        self._original_hash = [
            (obj.hash_bin() if obj is not None else 0) for obj in self._objects
        ]
    self._flatten()
    assert self.flattened_pages is not None
    for p in self.flattened_pages:
        self._replace_object(cast(IndirectObject, p.indirect_reference).idnum, p)
        if not self.incremental:
            p[NameObject("/Parent")] = self._pages
    if not self.incremental:
        cast(DictionaryObject, self._pages.get_object())[
            NameObject("/Kids")
        ] = ArrayObject([p.indirect_reference for p in self.flattened_pages])

def _parse(self, file, fp, default_netrc):
    lexer = _netrclex(fp)
    while 1:
        # Look for a machine, default, or macdef top-level keyword
        saved_lineno = lexer.lineno
        toplevel = tt = lexer.get_token()
        if not tt:
            break
        elif tt[0] == '#':
            if lexer.lineno == saved_lineno and len(tt) == 1:
                lexer.instream.readline()
            continue
        elif tt == 'machine':
            entryname = lexer.get_token()
        elif tt == 'default':
            entryname = 'default'
        elif tt == 'macdef':
            entryname = lexer.get_token()
            self.macros[entryname] = []
            while 1:
                line = lexer.instream.readline()
                if not line:
                    raise NetrcParseError(
                        "Macro definition missing null line terminator.",
                        file, lexer.lineno)
                if line == '\n':
                    # a macro definition finished with consecutive new-line
                    # characters. The first \n is encountered by the
                    # readline() method and this is the second \n.
                    break
                self.macros[entryname].append(line)
            continue
        else:
            raise NetrcParseError(
                "bad toplevel token %r" % tt, file, lexer.lineno)

        if not entryname:
            raise NetrcParseError("missing %r name" % tt, file, lexer.lineno)

        # We're looking at start of an entry for a named machine or default.
        login = account = password = ''
        self.hosts[entryname] = {}
        while 1:
            prev_lineno = lexer.lineno
            tt = lexer.get_token()
            if tt.startswith('#'):
                if lexer.lineno == prev_lineno:
                    lexer.instream.readline()
                continue
            if tt in {'', 'machine', 'default', 'macdef'}:
                self.hosts[entryname] = (login, account, password)
                lexer.push_token(tt)
                break
            elif tt == 'login' or tt == 'user':
                login = lexer.get_token()
            elif tt == 'account':
                account = lexer.get_token()
            elif tt == 'password':
                password = lexer.get_token()
            else:
                raise NetrcParseError("bad follower token %r" % tt,
                                      file, lexer.lineno)
        self._security_check(fp, default_netrc, self.hosts[entryname][0])

def closure_glyphs(self, s):
    if self.table.VarCompositeGlyphs is None:
        return

    glyphMap = {glyphName: i for i, glyphName in enumerate(self.table.Coverage.glyphs)}
    glyphRecords = self.table.VarCompositeGlyphs.VarCompositeGlyph

    glyphs = s.glyphs
    covered = set()
    new = set(glyphs)
    while new:
        oldNew = new
        new = set()
        for glyphName in oldNew:
            if glyphName in covered:
                continue
            idx = glyphMap.get(glyphName)
            if idx is None:
                continue
            glyph = glyphRecords[idx]
            for comp in glyph.components:
                name = comp.glyphName
                glyphs.add(name)
                if name not in covered:
                    new.add(name)

def parse_STAT_design_axis(self):
    assert self.is_cur_keyword_("DesignAxis")
    names = []
    axisTag = self.expect_tag_()
    if (
        axisTag not in ("ital", "opsz", "slnt", "wdth", "wght")
        and not axisTag.isupper()
    ):
        log.warning(f"Unregistered axis tag {axisTag} should be uppercase.")
    axisOrder = self.expect_number_()
    self.expect_symbol_("{")
    while self.next_token_ != "}" or self.cur_comments_:
        self.advance_lexer_()
        if self.cur_token_type_ is Lexer.COMMENT:
            continue
        elif self.is_cur_keyword_("name"):
            location = self.cur_token_location_
            platformID, platEncID, langID, string = self.parse_stat_name_()
            name = self.ast.STATNameStatement(
                "stat", platformID, platEncID, langID, string, location=location
            )
            names.append(name)
        elif self.cur_token_ == ";":
            continue
        else:
            raise FeatureLibError(
                f'Expected "name", got {self.cur_token_}', self.cur_token_location_
            )

    self.expect_symbol_("}")
    return self.ast.STATDesignAxisStatement(
        axisTag, axisOrder, names, self.cur_token_location_
    )

def _lower_contraction_to_addends(cls, expr, contraction_indices):
    if isinstance(expr, ArrayAdd):
        raise NotImplementedError()
    if not isinstance(expr, ArrayTensorProduct):
        return expr, contraction_indices
    subranks = expr.subranks
    cumranks = list(accumulate([0] + subranks))
    contraction_indices_remaining = []
    contraction_indices_args = [[] for i in expr.args]
    backshift = set()
    for contraction_group in contraction_indices:
        for j in range(len(expr.args)):
            if not isinstance(expr.args[j], ArrayAdd):
                continue
            if all(cumranks[j] <= k < cumranks[j+1] for k in contraction_group):
                contraction_indices_args[j].append([k - cumranks[j] for k in contraction_group])
                backshift.update(contraction_group)
                break
        else:
            contraction_indices_remaining.append(contraction_group)
    if len(contraction_indices_remaining) == len(contraction_indices):
        return expr, contraction_indices
    total_rank = get_rank(expr)
    shifts = list(accumulate([1 if i in backshift else 0 for i in range(total_rank)]))
    contraction_indices_remaining = [Tuple.fromiter(j - shifts[j] for j in i) for i in contraction_indices_remaining]
    ret = _array_tensor_product(*[
        _array_contraction(arg, *contr) for arg, contr in zip(expr.args, contraction_indices_args)
    ])
    return ret, contraction_indices_remaining

def get_model_dir(self, model_name, root_dir, opt=True, suffix="", create=True):
    engine_name = self.engine_type.name.lower()
    if engine_name != "ort_cuda" and not suffix:
        suffix = f".{engine_name}" if opt else ""
    directory_name = self.get_cached_model_name(model_name) + suffix
    onnx_model_dir = os.path.join(root_dir, directory_name)
    if create:
        os.makedirs(onnx_model_dir, exist_ok=True)
    return onnx_model_dir

