def _combine_inverse(lhs, rhs):
    """
    Returns lhs/rhs, but treats arguments like symbols, so things
    like oo/oo return 1 (instead of a nan) and ``I`` behaves like
    a symbol instead of sqrt(-1).
    """
    from sympy.simplify.simplify import signsimp
    from .symbol import Dummy
    if lhs == rhs:
        return S.One

    def check(l, r):
        if l.is_Float and r.is_comparable:
            # if both objects are added to 0 they will share the same "normalization"
            # and are more likely to compare the same. Since Add(foo, 0) will not allow
            # the 0 to pass, we use __add__ directly.
            return l.__add__(0) == r.evalf().__add__(0)
        return False
    if check(lhs, rhs) or check(rhs, lhs):
        return S.One
    if any(i.is_Pow or i.is_Mul for i in (lhs, rhs)):
        # gruntz and limit wants a literal I to not combine
        # with a power of -1
        d = Dummy('I')
        _i = {S.ImaginaryUnit: d}
        i_ = {d: S.ImaginaryUnit}
        a = lhs.xreplace(_i).as_powers_dict()
        b = rhs.xreplace(_i).as_powers_dict()
        blen = len(b)
        for bi in tuple(b.keys()):
            if bi in a:
                a[bi] -= b.pop(bi)
                if not a[bi]:
                    a.pop(bi)
        if len(b) != blen:
            lhs = Mul(*[k**v for k, v in a.items()]).xreplace(i_)
            rhs = Mul(*[k**v for k, v in b.items()]).xreplace(i_)
    rv = lhs/rhs
    srv = signsimp(rv)
    return srv if srv.is_Number else rv

def deflate(f, *G):
    ring = f.ring
    polys = [f] + list(G)

    J = [0]*ring.ngens

    for p in polys:
        for monom in p.itermonoms():
            for i, m in enumerate(monom):
                J[i] = igcd(J[i], m)

    for i, b in enumerate(J):
        if not b:
            J[i] = 1

    J = tuple(J)

    if all(b == 1 for b in J):
        return J, polys

    H = []

    for p in polys:
        h = ring.zero

        for I, coeff in p.iterterms():
            N = [ i // j for i, j in zip(I, J) ]
            h[tuple(N)] = coeff

        H.append(h)

    return J, H

def _collect_build_outputs(self) -> Tuple[List[str], Dict[str, str]]:
    files: List[str] = []
    mapping: Dict[str, str] = {}
    build = self.get_finalized_command("build")

    for cmd_name in build.get_sub_commands():
        cmd = self.get_finalized_command(cmd_name)
        if hasattr(cmd, "get_outputs"):
            files.extend(cmd.get_outputs() or [])
        if hasattr(cmd, "get_output_mapping"):
            mapping.update(cmd.get_output_mapping() or {})

    return files, mapping

def decode(self, code: bytes) -> Iterator[int]:
    log.debug("decode: %r, %r", self, code)
    d = self.code2cid
    for i in iter(code):
        if i in d:
            x = d[i]
            if isinstance(x, int):
                yield x
                d = self.code2cid
            else:
                d = cast(dict[int, object], x)
        else:
            d = self.code2cid

