        return self.lower.nodes_and_weights
    else:
        raise NotImplementedError

def __pow__(self, n):
    """raise polynomial to power `n`

    Examples
    ========

    >>> from sympy.polys.domains import ZZ
    >>> from sympy.polys.rings import ring

    >>> _, x, y = ring('x, y', ZZ)
    >>> p = x + y**2
    >>> p**3
    x**3 + 3*x**2*y**2 + 3*x*y**4 + y**6

    """
    if not isinstance(n, int):
        raise TypeError("exponent must be an integer, got %s" % n)
    elif n < 0:
        raise ValueError("exponent must be a non-negative integer, got %s" % n)

    ring = self.ring

    if not n:
        if self:
            return ring.one
        else:
            raise ValueError("0**0")
    elif len(self) == 1:
        monom, coeff = list(self.items())[0]
        p = ring.zero
        if coeff == ring.domain.one:
            p[ring.monomial_pow(monom, n)] = coeff
        else:
            p[ring.monomial_pow(monom, n)] = coeff**n
        # p._check()
        return p

    # For ring series, we need negative and rational exponent support only
    # with monomials.
    n = int(n)
    if n < 0:
        raise ValueError("Negative exponent")

    elif n == 1:
        return self.copy()
    elif n == 2:
        return self.square()
    elif n == 3:
        return self*self.square()
    elif len(self) <= 5: # TODO: use an actual density measure
        return self._pow_multinomial(n)
    else:
        return self._pow_generic(n)

def _write_a_body_pr(self, rotation, is_horizontal) -> None:
    # Write the <a:bodyPr> element.
    attributes = []

    if rotation is None and is_horizontal:
        rotation = -5400000

    if rotation is not None:
        if rotation == 16200000:
            # 270 deg/stacked angle.
            attributes.append(("rot", 0))
            attributes.append(("vert", "wordArtVert"))
        elif rotation == 16260000:
            # 271 deg/East Asian vertical.
            attributes.append(("rot", 0))
            attributes.append(("vert", "eaVert"))
        else:
            attributes.append(("rot", rotation))
            attributes.append(("vert", "horz"))

    self._xml_empty_tag("a:bodyPr", attributes)

def _get_poly_coeffs(poly, order):
    cs = [0 for _ in range(order+1)]
    for c, m in zip(poly.coeffs(), poly.monoms()):
        cs[-1-m[0]] = c
    return cs

def user_documents_dir(self) -> str:
    """:returns: documents directory tied to the user, from ``$XDG_DOCUMENTS_DIR`` if set, else platform default"""
    if path := os.environ.get("XDG_DOCUMENTS_DIR", "").strip():
        return os.path.expanduser(path)  # noqa: PTH111
    return super().user_documents_dir

def _parse_link_dest_title(
    link_text: str, start: int = 0, is_inline: bool = False
) -> tuple[Group, Group]:
    if start >= len(link_text):
        raise ParseError()
    if link_text[start] == "<":
        right_bracket = find_next(link_text, ">", start + 1, disallowed="<\n")
        if right_bracket < 0:
            raise ParseError()
        i = right_bracket + 1
        link_dest = Group(start, i, link_text[start:i])
    else:
        escaped = False
        pairs = 0
        i = start
        while i < len(link_text):
            c = link_text[i]
            if escaped:
                escaped = False
            elif c == "\\":
                escaped = True
            elif c in WHITESPACE:
                break
            elif c in ASCII_CONTROL:
                raise ParseError("Invalid character in link destination")
            elif c == "(":
                pairs += 1
            elif c == ")":
                if pairs > 0:
                    pairs -= 1
                elif is_inline:
                    link_dest = Group(start, i, link_text[start:i])
                    return link_dest, _EMPTY_GROUP
                else:
                    raise ParseError("unmatched parenthesis")
            i += 1
        else:
            if is_inline:
                raise ParseError("No right parenthesis is found")
        link_dest = Group(start, i, link_text[start:i])
        if not link_dest.text:
            raise ParseError("Empty link destination")
    prev = i
    i = _parse_link_separator(link_text, i)
    if i >= len(link_text) or link_text[i] == "\n" or link_text[i] == ")" and is_inline:
        return link_dest, _EMPTY_GROUP
    if link_text[i] == '"':
        end = find_next(link_text, '"', i + 1)
    elif link_text[i] == "'":
        end = find_next(link_text, "'", i + 1)
    elif link_text[i] == "(":
        end = find_next(link_text, ")", i + 1, disallowed="(")
    elif "\n" in link_text[prev:i]:
        return link_dest, _EMPTY_GROUP
    else:
        raise ParseError()
    if 0 < i < len(link_text) and link_text[i - 1] not in WHITESPACE:
        raise ParseError()
    if end < 0:
        raise ParseError()
    if "\n\n" in link_text[i:end]:
        raise ParseError()
    link_title = Group(i, end + 1, link_text[i : end + 1])
    return link_dest, link_title

def preproc_callback(self, match, ctx):
    proc = match.group(2)

    if proc == 'if':
        # store the current stack
        self.preproc_stack.append(ctx.stack[:])
    elif proc in ['else', 'elseif']:
        # restore the stack back to right before #if
        if self.preproc_stack:
            ctx.stack = self.preproc_stack[-1][:]
    elif proc == 'end':
        # remove the saved stack of previous #if
        if self.preproc_stack:
            self.preproc_stack.pop()

    # #if and #elseif should follow by an expr
    if proc in ['if', 'elseif']:
        ctx.stack.append('preproc-expr')

    # #error can be optionally follow by the error msg
    if proc in ['error']:
        ctx.stack.append('preproc-error')

    yield match.start(), Comment.Preproc, '#' + proc
    ctx.pos = match.end()

def _rescale_data(X, y, sample_weight, inplace=False):
    """Rescale data sample-wise by square root of sample_weight.

    For many linear models, this enables easy support for sample_weight because

        (y - X w)' S (y - X w)

    with S = diag(sample_weight) becomes

        ||y_rescaled - X_rescaled w||_2^2

    when setting

        y_rescaled = sqrt(S) y
        X_rescaled = sqrt(S) X

    The parameter `inplace` only takes effect for dense X and dense y.

    Returns
    -------
    X_rescaled : {array-like, sparse matrix}

    y_rescaled : {array-like, sparse matrix}

    sample_weight_sqrt : array-like of shape (n_samples,)
    """
    # Assume that _validate_data and _check_sample_weight have been called by
    # the caller.
    xp, _ = get_namespace(X, y, sample_weight)
    n_samples = X.shape[0]
    sample_weight_sqrt = xp.sqrt(sample_weight)

    if sp.issparse(X) or sp.issparse(y):
        sw_matrix = sparse.dia_matrix(
            (sample_weight_sqrt, 0), shape=(n_samples, n_samples)
        )

    if sp.issparse(X):
        X = safe_sparse_dot(sw_matrix, X)
    else:
        if inplace:
            X *= sample_weight_sqrt[:, None]
        else:
            X = X * sample_weight_sqrt[:, None]

    if sp.issparse(y):
        y = safe_sparse_dot(sw_matrix, y)
    else:
        if inplace:
            if y.ndim == 1:
                y *= sample_weight_sqrt
            else:
                y *= sample_weight_sqrt[:, None]
        else:
            if y.ndim == 1:
                y = y * sample_weight_sqrt
            else:
                y = y * sample_weight_sqrt[:, None]
    return X, y, sample_weight_sqrt

def streamline(self) -> ParserElement:
    if self.streamlined:
        return self

    super().streamline()
    if self.exprs:
        self.saveAsList = any(e.saveAsList for e in self.exprs)
        self.mayReturnEmpty = any(e.mayReturnEmpty for e in self.exprs)
        self.skipWhitespace = all(
            e.skipWhitespace and not isinstance(e, White) for e in self.exprs
        )
    else:
        self.saveAsList = False
        self.mayReturnEmpty = True
    return self

def __init__(self, plotter, markers=None, dashes=None, order=None):
    """Map the levels of the `style` variable to distinct values.

    Parameters
    ----------
    # TODO add generic parameters

    """
    super().__init__(plotter)

    data = plotter.plot_data.get("style", pd.Series(dtype=float))

    if data.notna().any():

        # Cast to list to handle numpy/pandas datetime quirks
        if variable_type(data) == "datetime":
            data = list(data)

        # Find ordered unique values
        levels = categorical_order(data, order)

        markers = self._map_attributes(
            markers, levels, unique_markers(len(levels)), "markers",
        )
        dashes = self._map_attributes(
            dashes, levels, unique_dashes(len(levels)), "dashes",
        )

        # Build the paths matplotlib will use to draw the markers
        paths = {}
        filled_markers = []
        for k, m in markers.items():
            if not isinstance(m, mpl.markers.MarkerStyle):
                m = mpl.markers.MarkerStyle(m)
            paths[k] = m.get_path().transformed(m.get_transform())
            filled_markers.append(m.is_filled())

        # Mixture of filled and unfilled markers will show line art markers
        # in the edge color, which defaults to white. This can be handled,
        # but there would be additional complexity with specifying the
        # weight of the line art markers without overwhelming the filled
        # ones with the edges. So for now, we will disallow mixtures.
        if any(filled_markers) and not all(filled_markers):
            err = "Filled and line art markers cannot be mixed"
            raise ValueError(err)

        lookup_table = {}
        for key in levels:
            lookup_table[key] = {}
            if markers:
                lookup_table[key]["marker"] = markers[key]
                lookup_table[key]["path"] = paths[key]
            if dashes:
                lookup_table[key]["dashes"] = dashes[key]

        self.levels = levels
        self.lookup_table = lookup_table

def __init__(
    self, featurefile, glyphNames=(), followIncludes=True, includeDir=None, **kwargs
):
    if "glyphMap" in kwargs:
        from fontTools.misc.loggingTools import deprecateArgument

        deprecateArgument("glyphMap", "use 'glyphNames' (iterable) instead")
        if glyphNames:
            raise TypeError(
                "'glyphNames' and (deprecated) 'glyphMap' are " "mutually exclusive"
            )
        glyphNames = kwargs.pop("glyphMap")
    if kwargs:
        raise TypeError(
            "unsupported keyword argument%s: %s"
            % ("" if len(kwargs) == 1 else "s", ", ".join(repr(k) for k in kwargs))
        )

    self.glyphNames_ = set(glyphNames)
    self.doc_ = self.ast.FeatureFile()
    self.anchors_ = SymbolTable()
    self.glyphclasses_ = SymbolTable()
    self.lookups_ = SymbolTable()
    self.valuerecords_ = SymbolTable()
    self.symbol_tables_ = {self.anchors_, self.valuerecords_}
    self.next_token_type_, self.next_token_ = (None, None)
    self.cur_comments_ = []
    self.next_token_location_ = None
    lexerClass = IncludingLexer if followIncludes else NonIncludingLexer
    self.lexer_ = lexerClass(featurefile, includeDir=includeDir)
    self.missing = {}
    self.advance_lexer_(comments=True)

def parseImpl(self, instring, loc, doActions=True):
    if instring[loc : loc + self.matchLen].upper() == self.match:
        return loc + self.matchLen, self.returnString
    raise ParseException(instring, loc, self.errmsg, self)

def _replace_object(
    self,
    indirect_reference: Union[int, IndirectObject],
    obj: PdfObject,
) -> PdfObject:
    if isinstance(indirect_reference, IndirectObject):
        if indirect_reference.pdf != self:
            raise ValueError("PDF must be self")
        indirect_reference = indirect_reference.idnum
    gen = self._objects[indirect_reference - 1].indirect_reference.generation  # type: ignore
    if (
        getattr(obj, "indirect_reference", None) is not None
        and obj.indirect_reference.pdf != self  # type: ignore
    ):
        obj = obj.clone(self)
    self._objects[indirect_reference - 1] = obj
    obj.indirect_reference = IndirectObject(indirect_reference, gen, self)

    assert isinstance(obj, PdfObject), "mypy"
    return obj

def empty(shape: int | tuple[int, ...],
         *,
         dtype: DType | None = None,
         device: Device | None = None,
         **kwargs: object) -> Array:
    return torch.empty(shape, dtype=dtype, device=device, **kwargs)

def f(rv):
    if not rv.is_Mul:
        return rv

    n, d = rv.as_numer_denom()
    if n.is_Atom or d.is_Atom:
        return rv

    def ok(k, e):
        # initial filtering of factors
        return (
            (e.is_integer or k.is_positive) and (
            k.func in (sin, cos) or (half and
            k.is_Add and
            len(k.args) >= 2 and
            any(any(isinstance(ai, cos) or ai.is_Pow and ai.base is cos
            for ai in Mul.make_args(a)) for a in k.args))))

    n = n.as_powers_dict()
    ndone = [(k, n.pop(k)) for k in list(n.keys()) if not ok(k, n[k])]
    if not n:
        return rv

    d = d.as_powers_dict()
    ddone = [(k, d.pop(k)) for k in list(d.keys()) if not ok(k, d[k])]
    if not d:
        return rv

    # factoring if necessary

    def factorize(d, ddone):
        newk = []
        for k in d:
            if k.is_Add and len(k.args) > 1:
                knew = factor(k) if half else factor_terms(k)
                if knew != k:
                    newk.append((k, knew))
        if newk:
            for i, (k, knew) in enumerate(newk):
                del d[k]
                newk[i] = knew
            newk = Mul(*newk).as_powers_dict()
            for k in newk:
                v = d[k] + newk[k]
                if ok(k, v):
                    d[k] = v
                else:
                    ddone.append((k, v))
            del newk
    factorize(n, ndone)
    factorize(d, ddone)

    # joining
    t = []
    for k in n:
        if isinstance(k, sin):
            a = cos(k.args[0], evaluate=False)
            if a in d and d[a] == n[k]:
                t.append(tan(k.args[0])**n[k])
                n[k] = d[a] = None
            elif half:
                a1 = 1 + a
                if a1 in d and d[a1] == n[k]:
                    t.append((tan(k.args[0]/2))**n[k])
                    n[k] = d[a1] = None
        elif isinstance(k, cos):
            a = sin(k.args[0], evaluate=False)
            if a in d and d[a] == n[k]:
                t.append(tan(k.args[0])**-n[k])
                n[k] = d[a] = None
        elif half and k.is_Add and k.args[0] is S.One and \
                isinstance(k.args[1], cos):
            a = sin(k.args[1].args[0], evaluate=False)
            if a in d and d[a] == n[k] and (d[a].is_integer or \
                    a.is_positive):
                t.append(tan(a.args[0]/2)**-n[k])
                n[k] = d[a] = None

    if t:
        rv = Mul(*(t + [b**e for b, e in n.items() if e]))/\
            Mul(*[b**e for b, e in d.items() if e])
        rv *= Mul(*[b**e for b, e in ndone])/Mul(*[b**e for b, e in ddone])

    return rv

def _write_c_tick_lbl_skip(self, val) -> None:
    # Write the <c:tickLblSkip> element.
    if val is None:
        return

    attributes = [("val", val)]

    self._xml_empty_tag("c:tickLblSkip", attributes)

def parseImpl(self, instring, loc, doActions=True):
    result = self.re_match(instring, loc)
    if not result:
        raise ParseException(instring, loc, self.errmsg, self)

    loc = result.end()
    ret = ParseResults(result.group())
    d = result.groupdict()
    if d:
        for k, v in d.items():
            ret[k] = v
    return loc, ret

def pending(self):
    self._checkClosed()
    if self._sslobj is not None:
        return self._sslobj.pending()
    else:
        return 0

def find_all(
    self, node_type: t.Union[t.Type[_NodeBound], t.Tuple[t.Type[_NodeBound], ...]]
) -> t.Iterator[_NodeBound]:
    """Find all the nodes of a given type.  If the type is a tuple,
    the check is performed for any of the tuple items.
    """
    for child in self.iter_child_nodes():
        if isinstance(child, node_type):
            yield child  # type: ignore
        yield from child.find_all(node_type)

def __init__(self, name, old_mod, new_mod, old_attr=None, new_attr=None):
    super(MovedAttribute, self).__init__(name)
    if PY3:
        if new_mod is None:
            new_mod = name
        self.mod = new_mod
        if new_attr is None:
            if old_attr is None:
                new_attr = name
            else:
                new_attr = old_attr
        self.attr = new_attr
    else:
        self.mod = old_mod
        if old_attr is None:
            old_attr = name
        self.attr = old_attr

def _wrap_specfun(cls, name, f, wrap):
    if wrap:
        def f_wrapped(ctx, *args, **kwargs):
            convert = ctx.convert
            args = [convert(a) for a in args]
            prec = ctx.prec
            try:
                ctx.prec += 10
                retval = f(ctx, *args, **kwargs)
            finally:
                ctx.prec = prec
            return +retval
    else:
        f_wrapped = f
    setattr(cls, name, f_wrapped)

def is_animated(self) -> bool:
    if self._n_frames is not None:
        return self._n_frames != 1

    current = self.tell()
    if current:
        return True

    try:
        self._seek(1, False)
        is_animated = True
    except EOFError:
        is_animated = False

    self.seek(current)
    return is_animated

def parse_primary(self, with_namespace: bool = False) -> nodes.Expr:
    """Parse a name or literal value. If ``with_namespace`` is enabled, also
    parse namespace attr refs, for use in assignments."""
    token = self.stream.current
    node: nodes.Expr
    if token.type == "name":
        next(self.stream)
        if token.value in ("true", "false", "True", "False"):
            node = nodes.Const(token.value in ("true", "True"), lineno=token.lineno)
        elif token.value in ("none", "None"):
            node = nodes.Const(None, lineno=token.lineno)
        elif with_namespace and self.stream.current.type == "dot":
            # If namespace attributes are allowed at this point, and the next
            # token is a dot, produce a namespace reference.
            next(self.stream)
            attr = self.stream.expect("name")
            node = nodes.NSRef(token.value, attr.value, lineno=token.lineno)
        else:
            node = nodes.Name(token.value, "load", lineno=token.lineno)
    elif token.type == "string":
        next(self.stream)
        buf = [token.value]
        lineno = token.lineno
        while self.stream.current.type == "string":
            buf.append(self.stream.current.value)
            next(self.stream)
        node = nodes.Const("".join(buf), lineno=lineno)
    elif token.type in ("integer", "float"):
        next(self.stream)
        node = nodes.Const(token.value, lineno=token.lineno)
    elif token.type == "lparen":
        next(self.stream)
        node = self.parse_tuple(explicit_parentheses=True)
        self.stream.expect("rparen")
    elif token.type == "lbracket":
        node = self.parse_list()
    elif token.type == "lbrace":
        node = self.parse_dict()
    else:
        self.fail(f"unexpected {describe_token(token)!r}", token.lineno)
    return node

def _dijkstra(G, source, weight, pred=None, paths=None, cutoff=None, target=None):
    """Uses Dijkstra's algorithm to find shortest weighted paths from a
    single source.

    This is a convenience function for :func:`_dijkstra_multisource`
    with all the arguments the same, except the keyword argument
    `sources` set to ``[source]``.

    """
    return _dijkstra_multisource(
        G, [source], weight, pred=pred, paths=paths, cutoff=cutoff, target=target
    )

def create_spacyLanguage(config, bytes):
    lang_cls = spacy.util.get_lang_class(config["nlp"]["lang"])
    lang_inst = lang_cls.from_config(config)
    return lang_inst.from_bytes(bytes)

def valid_contexto(label: str, pos: int, exception: bool = False) -> bool:
    cp_value = ord(label[pos])

    if cp_value == 0x00b7:
        if 0 < pos < len(label)-1:
            if ord(label[pos - 1]) == 0x006c and ord(label[pos + 1]) == 0x006c:
                return True
        return False

    elif cp_value == 0x0375:
        if pos < len(label)-1 and len(label) > 1:
            return _is_script(label[pos + 1], 'Greek')
        return False

    elif cp_value == 0x05f3 or cp_value == 0x05f4:
        if pos > 0:
            return _is_script(label[pos - 1], 'Hebrew')
        return False

    elif cp_value == 0x30fb:
        for cp in label:
            if cp == '\u30fb':
                continue
            if _is_script(cp, 'Hiragana') or _is_script(cp, 'Katakana') or _is_script(cp, 'Han'):
                return True
        return False

    elif 0x660 <= cp_value <= 0x669:
        for cp in label:
            if 0x6f0 <= ord(cp) <= 0x06f9:
                return False
        return True

    elif 0x6f0 <= cp_value <= 0x6f9:
        for cp in label:
            if 0x660 <= ord(cp) <= 0x0669:
                return False
        return True

    return False

def __round__(self, ndigits=None):
    """round(self, ndigits)

    Rounds half toward even.
    """
    if ndigits is None:
        d = self._denominator
        floor, remainder = divmod(self._numerator, d)
        if remainder * 2 < d:
            return floor
        elif remainder * 2 > d:
            return floor + 1
        # Deal with the half case:
        elif floor % 2 == 0:
            return floor
        else:
            return floor + 1
    shift = 10**abs(ndigits)
    # See _operator_fallbacks.forward to check that the results of
    # these operations will always be Fraction and therefore have
    # round().
    if ndigits > 0:
        return Fraction(round(self * shift), shift)
    else:
        return Fraction(round(self / shift) * shift)

def parseImpl(self, instring, loc, doActions=True):
    if instring[loc] not in self.initChars:
        raise ParseException(instring, loc, self.errmsg, self)

    start = loc
    loc += 1
    instrlen = len(instring)
    bodychars = self.bodyChars
    maxloc = start + self.maxLen
    maxloc = min(maxloc, instrlen)
    while loc < maxloc and instring[loc] in bodychars:
        loc += 1

    throwException = False
    if loc - start < self.minLen:
        throwException = True
    elif self.maxSpecified and loc < instrlen and instring[loc] in bodychars:
        throwException = True
    elif self.asKeyword:
        if (
            start > 0
            and instring[start - 1] in bodychars
            or loc < instrlen
            and instring[loc] in bodychars
        ):
            throwException = True

    if throwException:
        raise ParseException(instring, loc, self.errmsg, self)

    return loc, instring[start:loc]

def _eval_trace(self):
    from sympy.matrices.expressions.trace import Trace
    return conjugate(Trace(self.arg))

def _extend_mode_to_code(mode, is_filter=False):
    """Convert an extension mode to the corresponding integer code.
    """
    if mode == 'nearest':
        return 0
    elif mode == 'wrap':
        return 1
    elif mode in ['reflect', 'grid-mirror']:
        return 2
    elif mode == 'mirror':
        return 3
    elif mode == 'constant':
        return 4
    elif mode == 'grid-wrap' and is_filter:
        return 1
    elif mode == 'grid-wrap':
        return 5
    elif mode == 'grid-constant' and is_filter:
        return 4
    elif mode == 'grid-constant':
        return 6
    else:
        raise RuntimeError('boundary mode not supported')

def b(self):
    a, b = self._mpi_
    return self.ctx.make_mpf((b, b))

def get_mapping_for_index(self, ind) -> list[_IndPos]:
    if ind >= self.number_of_contraction_indices:
        raise ValueError("index value exceeding the index range")
    positions: list[_IndPos] = []
    for i, arg_with_ind in enumerate(self.args_with_ind):
        for j, arg_ind in enumerate(arg_with_ind.indices):
            if ind == arg_ind:
                positions.append(_IndPos(i, j))
    return positions

def preParse(self, instring: str, loc: int) -> int:
    if col(loc, instring) != self.col:
        instrlen = len(instring)
        if self.ignoreExprs:
            loc = self._skipIgnorables(instring, loc)
        while (
            loc < instrlen
            and instring[loc].isspace()
            and col(loc, instring) != self.col
        ):
            loc += 1
    return loc

def remove_dot_segments(path):
    """Remove '.' and '..' segments from a URI path.

    Follows the rules specified in Section 5.2.4 of RFC 3986.
    """
    output = []
    while path:
        if path.startswith('../'):
            path = path[3:]
        elif path.startswith('./'):
            path = path[2:]
        elif path.startswith('/./') or path == '/.':
            path = '/' + path[3:]
        elif path.startswith('/../') or path == '/..':
            path = '/' + path[4:]
            if len(output) > 0:
                del output[-1]
        elif path in ['.', '..']:
            path = ''
        else:
            if path.startswith('/'):
                slash = path.find('/', 1)
            else:
                slash = path.find('/')
            if slash < 0:
                slash = len(path)
            output.append(path[:slash])
            path = path[slash:]
    return ''.join(output)

def _nest_permutation(cls, expr, permutation):
    if isinstance(expr, ArrayTensorProduct):
        return _permute_dims(*cls._check_if_there_are_closed_cycles(expr, permutation))
    elif isinstance(expr, ArrayContraction):
        # Invert tree hierarchy: put the contraction above.
        cycles = permutation.cyclic_form
        newcycles = ArrayContraction._convert_outer_indices_to_inner_indices(expr, *cycles)
        newpermutation = Permutation(newcycles)
        new_contr_indices = [tuple(newpermutation(j) for j in i) for i in expr.contraction_indices]
        return _array_contraction(PermuteDims(expr.expr, newpermutation), *new_contr_indices)
    elif isinstance(expr, ArrayAdd):
        return _array_add(*[PermuteDims(arg, permutation) for arg in expr.args])
    return None

def pow_cos_sin(a, two):
    """Return ``a`` as a tuple (r, c, s) such that
    ``a = (r or 1)*(c or 1)*(s or 1)``.

    Three arguments are returned (radical, c-factor, s-factor) as
    long as the conditions set by ``two`` are met; otherwise None is
    returned. If ``two`` is True there will be one or two non-None
    values in the tuple: c and s or c and r or s and r or s or c with c
    being a cosine function (if possible) else a sine, and s being a sine
    function (if possible) else oosine. If ``two`` is False then there
    will only be a c or s term in the tuple.

    ``two`` also require that either two cos and/or sin be present (with
    the condition that if the functions are the same the arguments are
    different or vice versa) or that a single cosine or a single sine
    be present with an optional radical.

    If the above conditions dictated by ``two`` are not met then None
    is returned.
    """
    c = s = None
    co = S.One
    if a.is_Mul:
        co, a = a.as_coeff_Mul()
        if len(a.args) > 2 or not two:
            return None
        if a.is_Mul:
            args = list(a.args)
        else:
            args = [a]
        a = args.pop(0)
        if isinstance(a, cos):
            c = a
        elif isinstance(a, sin):
            s = a
        elif a.is_Pow and a.exp is S.Half:  # autoeval doesn't allow -1/2
            co *= a
        else:
            return None
        if args:
            b = args[0]
            if isinstance(b, cos):
                if c:
                    s = b
                else:
                    c = b
            elif isinstance(b, sin):
                if s:
                    c = b
                else:
                    s = b
            elif b.is_Pow and b.exp is S.Half:
                co *= b
            else:
                return None
        return co if co is not S.One else None, c, s
    elif isinstance(a, cos):
        c = a
    elif isinstance(a, sin):
        s = a
    if c is None and s is None:
        return
    co = co if co is not S.One else None
    return co, c, s

def _FieldToJsonObject(self, field, value):
  """Converts field value according to ProtoJSON Specification."""
  if field.cpp_type == descriptor.FieldDescriptor.CPPTYPE_MESSAGE:
    return self._MessageToJsonObject(value)
  elif field.cpp_type == descriptor.FieldDescriptor.CPPTYPE_ENUM:
    if self.use_integers_for_enums:
      return value
    if field.enum_type.full_name == 'google.protobuf.NullValue':
      return None
    enum_value = field.enum_type.values_by_number.get(value, None)
    if enum_value is not None:
      return enum_value.name
    else:
      if field.enum_type.is_closed:
        raise SerializeToJsonError(
            'Enum field contains an integer value '
            'which can not mapped to an enum value.'
        )
      else:
        return value
  elif field.cpp_type == descriptor.FieldDescriptor.CPPTYPE_STRING:
    if field.type == descriptor.FieldDescriptor.TYPE_BYTES:
      # Use base64 Data encoding for bytes
      return base64.b64encode(value).decode('utf-8')
    else:
      return str(value)
  elif field.cpp_type == descriptor.FieldDescriptor.CPPTYPE_BOOL:
    return bool(value)
  elif field.cpp_type in _INT64_TYPES:
    return str(value)
  elif field.cpp_type in _FLOAT_TYPES:
    if math.isinf(value):
      if value < 0.0:
        return _NEG_INFINITY
      else:
        return _INFINITY
    if math.isnan(value):
      return _NAN
    elif field.cpp_type == descriptor.FieldDescriptor.CPPTYPE_FLOAT:
      return type_checkers.ToShortestFloat(value)

  return value

def get_contraction_indices(self) -> list[list[int]]:
    contraction_indices: list[list[int]] = [[] for i in range(self.number_of_contraction_indices)]
    current_position: int = 0
    for arg_with_ind in self.args_with_ind:
        for j in arg_with_ind.indices:
            if j is not None:
                contraction_indices[j].append(current_position)
            current_position += 1
    return contraction_indices

def setter(self, value):
    # The setter rewrites paths using forward slashes
    if value is not None:
        value = posix(value)
    setattr(self, private_name, value)

def _ConvertBool(value, require_str):
  """Convert a boolean value.

  Args:
    value: A scalar value to convert.
    require_str: If True, value must be a str.

  Returns:
    The bool parsed.

  Raises:
    ParseError: If a boolean value couldn't be consumed.
  """
  if require_str:
    if value == 'true':
      return True
    elif value == 'false':
      return False
    else:
      raise ParseError('Expected "true" or "false", not {0}'.format(value))

  if not isinstance(value, bool):
    raise ParseError('Expected true or false without quotes')
  return value

def standardize(ctx, f, intervals, options):
    if options.get("ignore"):
        f = wrapsafe(f)
    finite = []
    infinite = []
    for k, points in enumerate(intervals):
        a, b = ctx._as_points(points)
        if b < a:
            return False, (lambda: ctx.zero)
        if a == ctx.ninf or b == ctx.inf:
            infinite.append((k, (a,b)))
        else:
            finite.append((k, (int(a), int(b))))
    if finite:
        f = fold_finite(ctx, f, finite)
        if not infinite:
            return False, lambda: f(*([0]*len(intervals)))
    if infinite:
        f = standardize_infinite(ctx, f, infinite)
        f = fold_infinite(ctx, f, infinite)
        args = [0] * len(intervals)
        d = infinite[0][0]
        def g(k):
            args[d] = k
            return f(*args)
        return True, g

def resolve(self, name):
    for scope in reversed(self.scopes_):
        item = scope.get(name)
        if item:
            return item
    return None

def _write_c_max(self, max_val) -> None:
    # Write the <c:max> element.

    if max_val is None:
        return

    attributes = [("val", max_val)]

    self._xml_empty_tag("c:max", attributes)

def _update_legend_data(
    self,
    update,
    var,
    verbosity,
    title,
    title_kws,
    attr_names,
    other_props,
):
    """Generate legend tick values and formatted labels."""
    brief_ticks = 6
    mapper = getattr(self, f"_{var}_map", None)
    if mapper is None:
        return

    brief = mapper.map_type == "numeric" and (
        verbosity == "brief"
        or (verbosity == "auto" and len(mapper.levels) > brief_ticks)
    )
    if brief:
        if isinstance(mapper.norm, mpl.colors.LogNorm):
            locator = mpl.ticker.LogLocator(numticks=brief_ticks)
        else:
            locator = mpl.ticker.MaxNLocator(nbins=brief_ticks)
        limits = min(mapper.levels), max(mapper.levels)
        levels, formatted_levels = locator_to_legend_entries(
            locator, limits, self.plot_data[var].infer_objects().dtype
        )
    elif mapper.levels is None:
        levels = formatted_levels = []
    else:
        levels = formatted_levels = mapper.levels

    if not title and self.variables.get(var, None) is not None:
        update((self.variables[var], "title"), self.variables[var], **title_kws)

    other_props = {} if other_props is None else other_props

    for level, formatted_level in zip(levels, formatted_levels):
        if level is not None:
            attr = mapper(level)
            if isinstance(attr_names, list):
                attr = {name: attr for name in attr_names}
            elif attr_names is not None:
                attr = {attr_names: attr}
            attr.update({k: v[level] for k, v in other_props.items() if level in v})
            update(self.variables[var], formatted_level, **attr)

def parseImpl(self, instring, loc, doActions=True):
    startloc = loc
    instrlen = len(instring)
    self_expr_parse = self.expr._parse
    self_failOn_canParseNext = (
        self.failOn.canParseNext if self.failOn is not None else None
    )
    self_preParse = self.preParse if self.callPreparse else None

    tmploc = loc
    while tmploc <= instrlen:
        if self_failOn_canParseNext is not None:
            # break if failOn expression matches
            if self_failOn_canParseNext(instring, tmploc):
                break

        if self_preParse is not None:
            # skip grammar-ignored expressions
            tmploc = self_preParse(instring, tmploc)

        try:
            self_expr_parse(instring, tmploc, doActions=False, callPreParse=False)
        except (ParseException, IndexError):
            # no match, advance loc in string
            tmploc += 1
        else:
            # matched skipto expr, done
            break

    else:
        # ran off the end of the input string without matching skipto expr, fail
        raise ParseException(instring, loc, self.errmsg, self)

    # build up return values
    loc = tmploc
    skiptext = instring[startloc:loc]
    skipresult = ParseResults(skiptext)

    if self.includeMatch:
        loc, mat = self_expr_parse(instring, loc, doActions, callPreParse=False)
        skipresult += mat

    return loc, skipresult

def as_base_exp(self):
    e1 = None
    bases = []
    nc = 0
    for m in self.args:
        b, e = m.as_base_exp()
        if not b.is_commutative:
            nc += 1
        if e1 is None:
            e1 = e
        elif e != e1 or nc > 1 or not e.is_Integer:
            return self, S.One
        bases.append(b)
    return self.func(*bases), e1

def forward(a, b):
    if isinstance(b, Fraction):
        return monomorphic_operator(a, b)
    elif isinstance(b, int):
        return monomorphic_operator(a, Fraction(b))
    elif isinstance(b, float):
        return fallback_operator(float(a), b)
    elif isinstance(b, complex):
        return fallback_operator(complex(a), b)
    else:
        return NotImplemented

def from_tree(cls, node):
    """
    Create object from XML
    """
    # strip known namespaces from attributes
    attrib = dict(node.attrib)
    for key, ns in cls.__namespaced__:
        if ns in attrib:
            attrib[key] = attrib[ns]
            del attrib[ns]

    # strip attributes with unknown namespaces
    for key in list(attrib):
        if key.startswith('{'):
            del attrib[key]
        elif key in KEYWORDS:
            attrib["_" + key] = attrib[key]
            del attrib[key]
        elif "-" in key:
            n = key.replace("-", "_")
            attrib[n] = attrib[key]
            del attrib[key]

    if node.text and "attr_text" in cls.__attrs__:
        attrib["attr_text"] = node.text

    for el in node:
        tag = localname(el)
        if tag in KEYWORDS:
            tag = "_" + tag
        desc = getattr(cls, tag, None)
        if desc is None or isinstance(desc, property):
            continue

        if hasattr(desc, 'from_tree'):
            #descriptor manages conversion
            obj = desc.from_tree(el)
        else:
            if hasattr(desc.expected_type, "from_tree"):
                #complex type
                obj = desc.expected_type.from_tree(el)
            else:
                #primitive
                obj = el.text

        if isinstance(desc, NestedSequence):
            attrib[tag] = obj
        elif isinstance(desc, Sequence):
            attrib.setdefault(tag, [])
            attrib[tag].append(obj)
        elif isinstance(desc, MultiSequencePart):
            attrib.setdefault(desc.store, [])
            attrib[desc.store].append(obj)
        else:
            attrib[tag] = obj

    return cls(**attrib)

def _addSource(self, sourceObject):
    sourceElement = ET.Element("source")
    if sourceObject.filename is not None:
        sourceElement.attrib["filename"] = sourceObject.filename
    if sourceObject.name is not None:
        if sourceObject.name.find("temp_master") != 0:
            # do not save temporary source names
            sourceElement.attrib["name"] = sourceObject.name
    if sourceObject.familyName is not None:
        sourceElement.attrib["familyname"] = sourceObject.familyName
    if sourceObject.styleName is not None:
        sourceElement.attrib["stylename"] = sourceObject.styleName
    if sourceObject.layerName is not None:
        sourceElement.attrib["layer"] = sourceObject.layerName
    if sourceObject.localisedFamilyName:
        languageCodes = list(sourceObject.localisedFamilyName.keys())
        languageCodes.sort()
        for code in languageCodes:
            if code == "en":
                continue  # already stored in the element attribute
            localisedFamilyNameElement = ET.Element("familyname")
            localisedFamilyNameElement.attrib[XML_LANG] = code
            localisedFamilyNameElement.text = sourceObject.getFamilyName(code)
            sourceElement.append(localisedFamilyNameElement)
    if sourceObject.copyLib:
        libElement = ET.Element("lib")
        libElement.attrib["copy"] = "1"
        sourceElement.append(libElement)
    if sourceObject.copyGroups:
        groupsElement = ET.Element("groups")
        groupsElement.attrib["copy"] = "1"
        sourceElement.append(groupsElement)
    if sourceObject.copyFeatures:
        featuresElement = ET.Element("features")
        featuresElement.attrib["copy"] = "1"
        sourceElement.append(featuresElement)
    if sourceObject.copyInfo or sourceObject.muteInfo:
        infoElement = ET.Element("info")
        if sourceObject.copyInfo:
            infoElement.attrib["copy"] = "1"
        if sourceObject.muteInfo:
            infoElement.attrib["mute"] = "1"
        sourceElement.append(infoElement)
    if sourceObject.muteKerning:
        kerningElement = ET.Element("kerning")
        kerningElement.attrib["mute"] = "1"
        sourceElement.append(kerningElement)
    if sourceObject.mutedGlyphNames:
        for name in sourceObject.mutedGlyphNames:
            glyphElement = ET.Element("glyph")
            glyphElement.attrib["name"] = name
            glyphElement.attrib["mute"] = "1"
            sourceElement.append(glyphElement)
    if self.effectiveFormatTuple >= (5, 0):
        self._addLocationElement(
            sourceElement, designLocation=sourceObject.location
        )
    else:
        # Pre-version 5.0 code was validating and filling in the location
        # dict while writing it out, as preserved below.
        locationElement, sourceObject.location = self._makeLocationElement(
            sourceObject.location
        )
        sourceElement.append(locationElement)
    self.root.findall(".sources")[0].append(sourceElement)

def infer_map_type(self, palette, norm, input_format, var_type):
    """Determine how to implement the mapping."""
    if palette in QUAL_PALETTES:
        map_type = "categorical"
    elif norm is not None:
        map_type = "numeric"
    elif isinstance(palette, (dict, list)):
        map_type = "categorical"
    elif input_format == "wide":
        map_type = "categorical"
    else:
        map_type = var_type

    return map_type

def prune(self, klass):
    if self.op != "~":
        raise NotImplementedError("UnaryOp only support invert type ops")

    operand = self.operand
    operand = operand.prune(klass)

    if operand is not None and (
        (issubclass(klass, ConditionBinOp) and operand.condition is not None)
        or (
            not issubclass(klass, ConditionBinOp)
            and issubclass(klass, FilterBinOp)
            and operand.filter is not None
        )
    ):
        return operand.invert()
    return None

def parseImpl(self, instring, loc, doActions=True):
    if self.initExprGroups:
        self.opt1map = dict(
            (id(e.expr), e) for e in self.exprs if isinstance(e, Opt)
        )
        opt1 = [e.expr for e in self.exprs if isinstance(e, Opt)]
        opt2 = [
            e
            for e in self.exprs
            if e.mayReturnEmpty and not isinstance(e, (Opt, Regex, ZeroOrMore))
        ]
        self.optionals = opt1 + opt2
        self.multioptionals = [
            e.expr.set_results_name(e.resultsName, list_all_matches=True)
            for e in self.exprs
            if isinstance(e, _MultipleMatch)
        ]
        self.multirequired = [
            e.expr.set_results_name(e.resultsName, list_all_matches=True)
            for e in self.exprs
            if isinstance(e, OneOrMore)
        ]
        self.required = [
            e for e in self.exprs if not isinstance(e, (Opt, ZeroOrMore, OneOrMore))
        ]
        self.required += self.multirequired
        self.initExprGroups = False

    tmpLoc = loc
    tmpReqd = self.required[:]
    tmpOpt = self.optionals[:]
    multis = self.multioptionals[:]
    matchOrder = []

    keepMatching = True
    failed = []
    fatals = []
    while keepMatching:
        tmpExprs = tmpReqd + tmpOpt + multis
        failed.clear()
        fatals.clear()
        for e in tmpExprs:
            try:
                tmpLoc = e.try_parse(instring, tmpLoc, raise_fatal=True)
            except ParseFatalException as pfe:
                pfe.__traceback__ = None
                pfe.parser_element = e
                fatals.append(pfe)
                failed.append(e)
            except ParseException:
                failed.append(e)
            else:
                matchOrder.append(self.opt1map.get(id(e), e))
                if e in tmpReqd:
                    tmpReqd.remove(e)
                elif e in tmpOpt:
                    tmpOpt.remove(e)
        if len(failed) == len(tmpExprs):
            keepMatching = False

    # look for any ParseFatalExceptions
    if fatals:
        if len(fatals) > 1:
            fatals.sort(key=lambda e: -e.loc)
            if fatals[0].loc == fatals[1].loc:
                fatals.sort(key=lambda e: (-e.loc, -len(str(e.parser_element))))
        max_fatal = fatals[0]
        raise max_fatal

    if tmpReqd:
        missing = ", ".join([str(e) for e in tmpReqd])
        raise ParseException(
            instring,
            loc,
            f"Missing one or more required elements ({missing})",
        )

    # add any unmatched Opts, in case they have default values defined
    matchOrder += [e for e in self.exprs if isinstance(e, Opt) and e.expr in tmpOpt]

    total_results = ParseResults([])
    for e in matchOrder:
        loc, results = e._parse(instring, loc, doActions)
        total_results += results

    return loc, total_results

def _hog_normalize_block(block, method, eps=1e-5):
    if method == 'L1':
        out = block / (np.sum(np.abs(block)) + eps)
    elif method == 'L1-sqrt':
        out = np.sqrt(block / (np.sum(np.abs(block)) + eps))
    elif method == 'L2':
        out = block / np.sqrt(np.sum(block**2) + eps**2)
    elif method == 'L2-Hys':
        out = block / np.sqrt(np.sum(block**2) + eps**2)
        out = np.minimum(out, 0.2)
        out = out / np.sqrt(np.sum(out**2) + eps**2)
    else:
        raise ValueError('Selected block normalization method is invalid.')

    return out

def select(result):
    for elem in result:
        parent = elem.getparent()
        if parent is None:
            continue
        try:
            # FIXME: what if the selector is "*" ?
            elems = list(parent.iterchildren(elem.tag))
            if elems[index] is elem:
                yield elem
        except IndexError:
            pass

def parse_table_vhea_(self, table):
    statements = table.statements
    fields = ("VertTypoAscender", "VertTypoDescender", "VertTypoLineGap")
    while self.next_token_ != "}" or self.cur_comments_:
        self.advance_lexer_(comments=True)
        if self.cur_token_type_ is Lexer.COMMENT:
            statements.append(
                self.ast.Comment(self.cur_token_, location=self.cur_token_location_)
            )
        elif self.cur_token_type_ is Lexer.NAME and self.cur_token_ in fields:
            key = self.cur_token_.lower()
            value = self.expect_number_()
            statements.append(
                self.ast.VheaField(key, value, location=self.cur_token_location_)
            )
            if self.next_token_ != ";":
                raise FeatureLibError(
                    "Incomplete statement", self.next_token_location_
                )
        elif self.cur_token_ == ";":
            continue
        else:
            raise FeatureLibError(
                "Expected VertTypoAscender, "
                "VertTypoDescender or VertTypoLineGap",
                self.cur_token_location_,
            )

def blocking(self) -> bool:
    """:returns: whether blocking is enabled by default."""
    return self._lock.blocking

def streamline(self) -> ParserElement:
    # collapse any _PendingSkip's
    if self.exprs:
        if any(
            isinstance(e, ParseExpression)
            and e.exprs
            and isinstance(e.exprs[-1], _PendingSkip)
            for e in self.exprs[:-1]
        ):
            deleted_expr_marker = NoMatch()
            for i, e in enumerate(self.exprs[:-1]):
                if e is deleted_expr_marker:
                    continue
                if (
                    isinstance(e, ParseExpression)
                    and e.exprs
                    and isinstance(e.exprs[-1], _PendingSkip)
                ):
                    e.exprs[-1] = e.exprs[-1] + self.exprs[i + 1]
                    self.exprs[i + 1] = deleted_expr_marker
            self.exprs = [e for e in self.exprs if e is not deleted_expr_marker]

    super().streamline()

    # link any IndentedBlocks to the prior expression
    prev: ParserElement
    cur: ParserElement
    for prev, cur in zip(self.exprs, self.exprs[1:]):
        # traverse cur or any first embedded expr of cur looking for an IndentedBlock
        # (but watch out for recursive grammar)
        seen = set()
        while True:
            if id(cur) in seen:
                break
            seen.add(id(cur))
            if isinstance(cur, IndentedBlock):
                prev.add_parse_action(
                    lambda s, l, t, cur_=cur: setattr(
                        cur_, "parent_anchor", col(l, s)
                    )
                )
                break
            subs = cur.recurse()
            next_first = next(iter(subs), None)
            if next_first is None:
                break
            cur = typing.cast(ParserElement, next_first)

    self.mayReturnEmpty = all(e.mayReturnEmpty for e in self.exprs)
    return self

def f(rv):
    if not rv.is_Mul:
        return rv

    if first:
        # sort them by location in numerator and denominator
        # so the code below can just deal with positive exponents
        n, d = rv.as_numer_denom()
        if d is not S.One:
            newn = TR14(n, first=False)
            newd = TR14(d, first=False)
            if newn != n or newd != d:
                rv = newn/newd
            return rv

    other = []
    process = []
    for a in rv.args:
        if a.is_Pow:
            b, e = a.as_base_exp()
            if not (e.is_integer or b.is_positive):
                other.append(a)
                continue
            a = b
        else:
            e = S.One
        m = as_f_sign_1(a)
        if not m or m[1].func not in (cos, sin):
            if e is S.One:
                other.append(a)
            else:
                other.append(a**e)
            continue
        g, f, si = m
        process.append((g, e.is_Number, e, f, si, a))

    # sort them to get like terms next to each other
    process = list(ordered(process))

    # keep track of whether there was any change
    nother = len(other)

    # access keys
    keys = (g, t, e, f, si, a) = list(range(6))

    while process:
        A = process.pop(0)
        if process:
            B = process[0]

            if A[e].is_Number and B[e].is_Number:
                # both exponents are numbers
                if A[f] == B[f]:
                    if A[si] != B[si]:
                        B = process.pop(0)
                        take = min(A[e], B[e])

                        # reinsert any remainder
                        # the B will likely sort after A so check it first
                        if B[e] != take:
                            rem = [B[i] for i in keys]
                            rem[e] -= take
                            process.insert(0, rem)
                        elif A[e] != take:
                            rem = [A[i] for i in keys]
                            rem[e] -= take
                            process.insert(0, rem)

                        if isinstance(A[f], cos):
                            t = sin
                        else:
                            t = cos
                        other.append((-A[g]*B[g]*t(A[f].args[0])**2)**take)
                        continue

            elif A[e] == B[e]:
                # both exponents are equal symbols
                if A[f] == B[f]:
                    if A[si] != B[si]:
                        B = process.pop(0)
                        take = A[e]
                        if isinstance(A[f], cos):
                            t = sin
                        else:
                            t = cos
                        other.append((-A[g]*B[g]*t(A[f].args[0])**2)**take)
                        continue

        # either we are done or neither condition above applied
        other.append(A[a]**A[e])

    if len(other) != nother:
        rv = Mul(*other)

    return rv

def get_loads(self):
    """
    return the position of the applied load and angle (for concentrated loads)
    """
    return self._loads

def evaluate(self, x, a=None):
    f = self

    if isinstance(x, list) and a is None:
        (X, a), x = x[0], x[1:]
        f = f.evaluate(X, a)

        if not x:
            return f
        else:
            x = [ (Y.drop(X), a) for (Y, a) in x ]
            return f.evaluate(x)

    ring = f.ring
    i = ring.index(x)
    a = ring.domain.convert(a)

    if ring.ngens == 1:
        result = ring.domain.zero

        for (n,), coeff in f.iterterms():
            result += coeff*a**n

        return result
    else:
        poly = ring.drop(x).zero

        for monom, coeff in f.iterterms():
            n, monom = monom[i], monom[:i] + monom[i+1:]
            coeff = coeff*a**n

            if monom in poly:
                coeff = coeff + poly[monom]

                if coeff:
                    poly[monom] = coeff
                else:
                    del poly[monom]
            else:
                if coeff:
                    poly[monom] = coeff

        return poly

def parseImpl(self, instring, loc, doActions=True):
    if self.initExprGroups:
        self.opt1map = dict(
            (id(e.expr), e) for e in self.exprs if isinstance(e, Opt)
        )
        opt1 = [e.expr for e in self.exprs if isinstance(e, Opt)]
        opt2 = [
            e
            for e in self.exprs
            if e.mayReturnEmpty and not isinstance(e, (Opt, Regex, ZeroOrMore))
        ]
        self.optionals = opt1 + opt2
        self.multioptionals = [
            e.expr.set_results_name(e.resultsName, list_all_matches=True)
            for e in self.exprs
            if isinstance(e, _MultipleMatch)
        ]
        self.multirequired = [
            e.expr.set_results_name(e.resultsName, list_all_matches=True)
            for e in self.exprs
            if isinstance(e, OneOrMore)
        ]
        self.required = [
            e for e in self.exprs if not isinstance(e, (Opt, ZeroOrMore, OneOrMore))
        ]
        self.required += self.multirequired
        self.initExprGroups = False

    tmpLoc = loc
    tmpReqd = self.required[:]
    tmpOpt = self.optionals[:]
    multis = self.multioptionals[:]
    matchOrder = []

    keepMatching = True
    failed = []
    fatals = []
    while keepMatching:
        tmpExprs = tmpReqd + tmpOpt + multis
        failed.clear()
        fatals.clear()
        for e in tmpExprs:
            try:
                tmpLoc = e.try_parse(instring, tmpLoc, raise_fatal=True)
            except ParseFatalException as pfe:
                pfe.__traceback__ = None
                pfe.parser_element = e
                fatals.append(pfe)
                failed.append(e)
            except ParseException:
                failed.append(e)
            else:
                matchOrder.append(self.opt1map.get(id(e), e))
                if e in tmpReqd:
                    tmpReqd.remove(e)
                elif e in tmpOpt:
                    tmpOpt.remove(e)
        if len(failed) == len(tmpExprs):
            keepMatching = False

    # look for any ParseFatalExceptions
    if fatals:
        if len(fatals) > 1:
            fatals.sort(key=lambda e: -e.loc)
            if fatals[0].loc == fatals[1].loc:
                fatals.sort(key=lambda e: (-e.loc, -len(str(e.parser_element))))
        max_fatal = fatals[0]
        raise max_fatal

    if tmpReqd:
        missing = ", ".join([str(e) for e in tmpReqd])
        raise ParseException(
            instring,
            loc,
            f"Missing one or more required elements ({missing})",
        )

    # add any unmatched Opts, in case they have default values defined
    matchOrder += [e for e in self.exprs if isinstance(e, Opt) and e.expr in tmpOpt]

    total_results = ParseResults([])
    for e in matchOrder:
        loc, results = e._parse(instring, loc, doActions)
        total_results += results

    return loc, total_results

def find_largest(numbers: list) -> float:
    """Return the largest number from a list."""
    if not numbers:
        return None
    return max(numbers)

def find_smallest(numbers: list) -> float:
    """Return the smallest number from a list."""
    if not numbers:
        return None
    return min(numbers)

def calculate_average(numbers: list) -> float:
    """Calculate and return the average of a list of numbers."""
    if not numbers:
        return 0.0
    return sum(numbers) / len(numbers)

def is_even(number: int) -> bool:
    """Return True if the number is even, False otherwise."""
    return number % 2 == 0

def factorial(n: int) -> int:
    """Return the factorial of a non-negative integer."""
    if n == 0:
        return 1
    return n * factorial(n - 1)

def count_vowels(text: str) -> int:
    """Count and return the number of vowels in a string."""
    # Define vowels
    vowels = "aeiouAEIOU"
    return sum(1 for ch in text if ch in vowels)

def reverse_string(text: str) -> str:
    """Return the reverse of the given string."""
    return text[::-1]

def is_prime(n: int) -> bool:
    """Return True if n is a prime number."""
    if n < 2:
        return False
    # Check divisibility up to square root
    for i in range(2, int(n ** 0.5) + 1):
        if n % i == 0:
            return False
    return True

def celsius_to_fahrenheit(celsius: float) -> float:
    """Convert temperature from Celsius to Fahrenheit."""
    return (celsius * 9 / 5) + 32

def remove_duplicates(items: list) -> list:
    """Return a new list with duplicate values removed."""
    return list(set(items))

def linear_search(items: list, target) -> int:
    """Search for target in list, return index or -1 if not found."""
    for index, item in enumerate(items):
        if item == target:
            return index
    return -1

def bubble_sort(items: list) -> list:
    """Sort a list using bubble sort algorithm."""
    # Work on a copy to avoid mutating original
    result = items.copy()
    n = len(result)
    for i in range(n):
        for j in range(0, n - i - 1):
            if result[j] > result[j + 1]:
                result[j], result[j + 1] = result[j + 1], result[j]
    return result

def calculate_bmi(weight_kg: float, height_m: float) -> float:
    """Calculate Body Mass Index given weight and height."""
    if height_m <= 0:
        raise ValueError("Height must be greater than zero")
    return round(weight_kg / (height_m ** 2), 2)

def word_count(text: str) -> int:
    """Return the number of words in a string."""
    if not text.strip():
        return 0
    return len(text.split())

def is_anagram(word1: str, word2: str) -> bool:
    """Check if two words are anagrams of each other."""
    return sorted(word1.lower()) == sorted(word2.lower())

def flatten_list(nested: list) -> list:
    """Flatten a one-level nested list into a single list."""
    return [item for sublist in nested for item in sublist]

def get_unique_words(text: str) -> list:
    """Return a sorted list of unique words from a text string."""
    words = text.lower().split()
    return sorted(set(words))

def power(base: float, exponent: int) -> float:
    """Return base raised to the power of exponent."""
    return base ** exponent

def sum_of_digits(number: int) -> int:
    """Return the sum of all digits in a number."""
    # Work with absolute value to handle negatives
    return sum(int(d) for d in str(abs(number)))

def is_palindrome(s):
    s = s.replace(" ", "").lower()
    return s == s[::-1]

def find_largest(nums):
    largest = nums[0]
    for n in nums:
        if n > largest:
            largest = n
    return largest

def find_smallest(nums):
    smallest = nums[0]
    for n in nums:
        if n < smallest:
            smallest = n
    return smallest

def calculate_average(nums):
    total = 0
    for n in nums:
        total += n
    return total / len(nums)

def factorial(n):
    result = 1
    for i in range(1, n + 1):
        result *= i
    return result

def is_prime(n):
    if n < 2:
        return False
    for i in range(2, n):
        if n % i == 0:
            return False
    return True

def count_vowels(text):
    count = 0
    for ch in text:
        if ch in "aeiouAEIOU":
            count += 1
    return count

def reverse_list(items):
    result = []
    for i in range(len(items) - 1, -1, -1):
        result.append(items[i])
    return result

def binary_search(items, target):
    left = 0
    right = len(items) - 1
    while left <= right:
        mid = (left + right) // 2
        if items[mid] == target:
            return mid
        elif items[mid] < target:
            left = mid + 1
        else:
            right = mid - 1
    return -1

def remove_duplicates(lst):
    result = []
    for item in lst:
        if item not in result:
            result.append(item)
    return result

def word_frequency(text):
    words = text.lower().split()
    freq = {}
    for word in words:
        if word in freq:
            freq[word] += 1
        else:
            freq[word] = 1
    return freq

def selection_sort(arr):
    n = len(arr)
    for i in range(n):
        min_idx = i
        for j in range(i + 1, n):
            if arr[j] < arr[min_idx]:
                min_idx = j
        arr[i], arr[min_idx] = arr[min_idx], arr[i]
    return arr

def sum_even_numbers(numbers):
    total = 0
    for n in numbers:
        if n % 2 == 0:
            total += n
    return total

def capitalize_words(text):
    words = text.split()
    result = []
    for word in words:
        result.append(word.capitalize())
    return " ".join(result)

def is_sorted(lst):
    for i in range(len(lst) - 1):
        if lst[i] > lst[i + 1]:
            return False
    return True

def get_second_largest(numbers):
    unique = list(set(numbers))
    unique.sort()
    if len(unique) < 2:
        return None
    return unique[-2]

def count_occurrences(lst, target):
    count = 0
    for item in lst:
        if item == target:
            count += 1
    return count

def check(a, b, c, d, e, f):
    if a > 0:
        if b > 0:
            if c > 0:
                if d > 0:
                    if e > 0:
                        return a+b+c+d+e+f
                    else:
                        return a+b+c+d
                else:
                    return a+b+c
            else:
                return a+b
        else:
            return a
    else:
        return 0

def find(a,b,c,d,e,f):
    x=a
    if b>x:
        if c>b:
            if d>c:
                if e>d:
                    if f>e:
                        x=f
                    else:
                        x=e
                else:
                    x=d
            else:
                x=c
        else:
            x=b
    return x

def proc(a,b,c,d,e):
    r=0
    for i in range(a):
        for j in range(b):
            if i>j:
                if i%2==0:
                    if j%2==0:
                        r+=i*j
                    else:
                        r+=i
                else:
                    if j>5:
                        r+=j
    return r

def do_stuff(x,y,z,w,v,u):
    if x==1:
        if y==1:
            if z==1:
                return x+y+z
            elif z==2:
                if w>0:
                    return w*z
                else:
                    return z
        elif y==2:
            return y*x
    elif x==2:
        if y>x:
            return y-x
        else:
            return x-y
    return 0

def calc(a,b,c,d,e,f,g):
    t=0
    for i in range(len(a)):
        for j in range(len(b)):
            for k in range(len(c)):
                if a[i]>b[j]:
                    if b[j]>c[k]:
                        t+=a[i]*b[j]*c[k]
    return t

def process(data,flag1,flag2,flag3,mode,extra):
    result=[]
    if flag1:
        if flag2:
            if flag3:
                for i in data:
                    if mode==1:
                        if i>0:
                            result.append(i*extra)
                        else:
                            result.append(i)
                    else:
                        result.append(i+extra)
            else:
                result=data
        else:
            result=data[::-1]
    else:
        for i in data:
            result.append(i*2)
    return result

def solve(a,b,c,d,e):
    if a>b:
        if b>c:
            if c>d:
                if d>e:
                    return a
                else:
                    return e
            else:
                if d>c:
                    return d
                else:
                    return c
        else:
            if c>a:
                return c
            else:
                return a
    else:
        if b>c:
            return b
        else:
            return c

def fn(x,y,z,p,q,r,s):
    out=0
    for i in range(x):
        for j in range(y):
            if i%2==0:
                if j%3==0:
                    if p>q:
                        out+=i+j+z
                    else:
                        out+=i*j
                else:
                    out+=r
            else:
                out+=s
    return out

def handle(a,b,c,d,e,f):
    if type(a)==int:
        if type(b)==int:
            if a>0 and b>0:
                if c:
                    if d:
                        return a+b+e+f
                    else:
                        return a+b+e
                else:
                    return a+b
            else:
                return 0
        else:
            return b
    else:
        return a

def run(n,m,p,q,r,s):
    res=[]
    for i in range(n):
        for j in range(m):
            for k in range(p):
                if i+j+k > q:
                    if i*j > r:
                        res.append(i+j+k+s)
                    else:
                        res.append(i+j+k)
    return res
